    async function __naaRisuFetchResponse(url, options = {}, timeoutMs) {
        let body = options.body;
        if (typeof body === 'string') {
            try {
                body = JSON.parse(body);
            } catch (_) {
                /* non-JSON string body: pass through (may fail server-side) */
            }
        }
        const result = await Risu.risuFetch(url, {
            method: options.method || 'GET',
            headers: options.headers || {},
            ...(body != null ? { body } : {}),
            rawResponse: true,
            ...(Number.isFinite(timeoutMs) && timeoutMs > 0 ? { requestTimeoutMs: timeoutMs } : {}),
        });
        if (!result || typeof result !== 'object') throw new Error('risuFetch returned an invalid result.');
        const headerMap = {};
        if (result.headers && typeof result.headers === 'object') {
            for (const key of Object.keys(result.headers)) headerMap[key.toLowerCase()] = String(result.headers[key]);
        }
        let bytes;
        if (result.data instanceof Uint8Array) bytes = result.data;
        else if (result.data == null) bytes = new Uint8Array(0);
        else if (typeof result.data === 'string') bytes = new TextEncoder().encode(result.data);
        else bytes = new TextEncoder().encode(JSON.stringify(result.data));
        const status = typeof result.status === 'number' ? result.status : result.ok ? 200 : 500;
        const shim = {
            ok: status >= 200 && status < 300,
            status,
            statusText: result.ok ? 'OK' : 'Error',
            headers: { get: (name) => headerMap[safeString(name).toLowerCase()] ?? null },
            arrayBuffer: async () => bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength),
            text: async () => new TextDecoder().decode(bytes),
            json: async () => JSON.parse(new TextDecoder().decode(bytes)),
            clone: () => shim,
        };
        return shim;
    }

