    function analyzerPromptPanelContextValue(context = {}, keys = []) {
        if (!context || typeof context !== 'object' || Array.isArray(context)) return '';
        const sources = [
            context,
            context.meta,
            context.assetMeta,
            context.regenerationPlan,
            context.regenPlan,
            context.plan,
            context.selected,
            context.display,
        ];
        for (const source of sources) {
            if (!source || typeof source !== 'object' || Array.isArray(source)) continue;
            for (const key of keys) {
                const value = safeString(source[key]).trim();
                if (value) return value;
            }
        }
        return '';
    }

    function analyzerPromptPanelHasImageContext(context = {}) {
        return Boolean(
            analyzerPromptPanelContextValue(context, [
                'sourceImageMarkerId',
                'source_image_marker_id',
            ]) ||
                analyzerPromptPanelContextValue(context, [
                    'sourceImageToken',
                    'source_image_token',
                ]) ||
                analyzerPromptPanelContextValue(context, [
                    'sourceImageMarkup',
                    'source_image_markup',
                    'originalMarkup',
                ]),
        );
    }

    function analyzerPromptPanelImageMatchesContext(image = {}, context = {}) {
        const markerId = analyzerPromptPanelContextValue(context, [
            'sourceImageMarkerId',
            'source_image_marker_id',
        ]);
        const imageMarkerId = analyzerPromptPanelContextValue(image, [
            'source_image_marker_id',
            'sourceImageMarkerId',
        ]);
        if (markerId && imageMarkerId && markerId === imageMarkerId) return true;
        const sourceToken = analyzerPromptPanelContextValue(context, [
            'sourceImageToken',
            'source_image_token',
        ]);
        const imageToken = analyzerPromptPanelContextValue(image, [
            'source_image_token',
            'sourceImageToken',
        ]);
        if (sourceToken && imageToken && sourceToken === imageToken) return true;
        const sourceMarkup = analyzerPromptPanelContextValue(context, [
            'sourceImageMarkup',
            'source_image_markup',
            'originalMarkup',
        ]);
        const imageMarkup = analyzerPromptPanelContextValue(image, [
            'source_image_markup',
            'sourceImageMarkup',
        ]);
        return Boolean(sourceMarkup && imageMarkup && sourceMarkup === imageMarkup);
    }

    function normalizeAnalyzerDecisionForPromptPanel(input = null, context = {}) {
        if (!input || typeof input !== 'object' || Array.isArray(input)) return null;
        const cloned = cloneJson(input);
        if (!cloned || typeof cloned !== 'object' || Array.isArray(cloned)) return null;
        const images = Array.isArray(cloned.images)
            ? cloned.images.filter(
                  (image) => image && typeof image === 'object' && !Array.isArray(image),
              )
            : [];
        if (images.length && analyzerPromptPanelHasImageContext(context)) {
            const matched = images.find((image) =>
                analyzerPromptPanelImageMatchesContext(image, context),
            );
            if (matched) return normalizeAnalyzerDecisionForPromptPanel(matched);
            if (images.length === 1) return normalizeAnalyzerDecisionForPromptPanel(images[0]);
            return null;
        }
        if (images.length) {
            if (images.length === 1) return normalizeAnalyzerDecisionForPromptPanel(images[0]);
            return null;
        }
        return Object.keys(cloned).length ? cloned : null;
    }

    function analyzerPromptPanelSelectedIdText(value) {
        if (value === null || value === undefined || typeof value === 'boolean') return '';
        if (Array.isArray(value)) {
            const values = [];
            for (const item of value) {
                const text = analyzerPromptPanelSelectedIdText(item);
                if (text && !values.includes(text)) values.push(text);
            }
            return values.join(', ');
        }
        if (typeof value === 'object') {
            for (const key of [
                'id',
                'optionId',
                'option_id',
                'selectedId',
                'selected_id',
                'sizeId',
                'size_id',
                'valueId',
                'value_id',
            ]) {
                const text = analyzerPromptPanelSelectedIdText(value?.[key]);
                if (text) return text;
            }
            return '';
        }
        return safeString(value).trim();
    }

    function appendAnalyzerPromptPanelSelectedIdLine(
        lines,
        seen,
        label,
        value,
        emptyText = '',
    ) {
        const cleanLabel = safeString(label).trim();
        const text = analyzerPromptPanelSelectedIdText(value) || safeString(emptyText).trim();
        if (!cleanLabel || !text || seen.has(cleanLabel)) return;
        seen.add(cleanLabel);
        lines.push(cleanLabel + ': ' + text);
    }

    function analyzerPromptPanelContinuityStateObject(decision = {}) {
        const state = decision?.visual_continuity_state || decision?.visualContinuityState;
        return state && typeof state === 'object' && !Array.isArray(state) ? state : null;
    }

    function analyzerPromptPanelContinuityPhaseState(state = {}, aliases = []) {
        for (const alias of aliases) {
            const value = state?.[alias];
            if (value && typeof value === 'object' && !Array.isArray(value)) return value;
        }
        return null;
    }

    function analyzerPromptPanelSceneStateObject(state = {}) {
        for (const alias of ['scene', 'scene_state', 'sceneState', 'location', 'background']) {
            const value = state?.[alias];
            if (value && typeof value === 'object' && !Array.isArray(value)) return value;
        }
        return null;
    }

    function analyzerPromptPanelSceneTagValue(state = {}, aliases = []) {
        if (!state || typeof state !== 'object' || Array.isArray(state)) return [];
        for (const alias of aliases) {
            const tags = normalizeDanbooruTagList(state?.[alias]);
            if (tags.length) return tags;
        }
        return [];
    }

    function appendAnalyzerPromptPanelContinuityStateLines(lines, seen, decision = {}) {
        const state = analyzerPromptPanelContinuityStateObject(decision);
        if (!state) return;
        const sceneState = analyzerPromptPanelSceneStateObject(state);
        for (const [phase, aliases] of [
            ['previous', ['previous', 'previous_state', 'previousState']],
            ['applied', ['applied', 'applied_state', 'appliedState', 'merged', 'mergedState']],
            ['saved', ['saved', 'saved_state', 'savedState', 'stored', 'storedState']],
        ]) {
            const phaseState = analyzerPromptPanelContinuityPhaseState(state, aliases);
            const scenePhaseState =
                analyzerPromptPanelContinuityPhaseState(sceneState, aliases) || phaseState;
            if (scenePhaseState) {
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    `visual_continuity.${phase}.scene_background_tags`,
                    analyzerPromptPanelSceneTagValue(scenePhaseState, [
                        'scene_background_tags',
                        'sceneBackgroundTags',
                        'background_tags',
                        'backgroundTags',
                        'previous_background_tags',
                        'previousBackgroundTags',
                    ]),
                );
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    `visual_continuity.${phase}.scene_location_tags`,
                    analyzerPromptPanelSceneTagValue(scenePhaseState, [
                        'scene_location_tags',
                        'sceneLocationTags',
                        'location_tags',
                        'locationTags',
                        'nsfw_scene_location_tag',
                        'nsfwSceneLocationTag',
                    ]),
                );
            }
            if (!phaseState) continue;
            for (const groupId of VISUAL_CONTINUITY_CHARACTER_GROUP_IDS) {
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    `visual_continuity.${phase}.${groupId}`,
                    phaseState[groupId],
                    '(none)',
                );
                const countKey = visualContinuityCountKey(groupId);
                if (countKey && phaseState[countKey] !== undefined) {
                    appendAnalyzerPromptPanelSelectedIdLine(
                        lines,
                        seen,
                        `visual_continuity.${phase}.${countKey}`,
                        phaseState[countKey],
                    );
                }
            }
        }
        appendAnalyzerPromptPanelSelectedIdLine(
            lines,
            seen,
            'visual_continuity.clear',
            state.clear || state.cleared || decision.visual_continuity_clear,
            '(none)',
        );
    }

    function analyzerPromptPanelSelectedIdLines(decision = null) {
        if (!decision || typeof decision !== 'object' || Array.isArray(decision)) return [];
        const lines = [];
        const seen = new Set();
        for (const [label, aliases] of [
            ['rating_id', ['rating_id', 'ratingId']],
            ['composition_id', ['composition_id', 'compositionId']],
            ['preset_id', ['preset_id', 'presetId']],
            [
                'selected_variant_id',
                [
                    'selected_variant_id',
                    'selectedVariantId',
                    'selected_variant_ids',
                    'selectedVariantIds',
                ],
            ],
            ['variant_id', ['variant_id', 'variantId']],
            ['camera_id', ['camera_id', 'cameraId']],
            ['size_id', ['size_id', 'sizeId']],
            ['outfit_id', ['outfit_id', 'selected_outfit_id', 'selectedOutfitId']],
            [
                'lorebook_prompt_key',
                ['lorebook_prompt_key', 'selected_lorebook_prompt_key', 'selectedLorebookPromptKey'],
            ],
        ]) {
            for (const alias of aliases) {
                const text = analyzerPromptPanelSelectedIdText(decision?.[alias]);
                if (text) {
                    appendAnalyzerPromptPanelSelectedIdLine(lines, seen, label, text);
                    break;
                }
            }
        }
        if (decision.comp && typeof decision.comp === 'object' && !Array.isArray(decision.comp)) {
            for (const [groupId, selected] of Object.entries(decision.comp)) {
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    'comp.' + groupId,
                    selected,
                    '(none)',
                );
            }
        }
        if (
            decision.modifiers &&
            typeof decision.modifiers === 'object' &&
            !Array.isArray(decision.modifiers)
        ) {
            for (const [groupId, selected] of Object.entries(decision.modifiers)) {
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    'modifiers.' + groupId,
                    selected,
                    '(none)',
                );
            }
        }
        if (Array.isArray(decision.modifier_items)) {
            for (const item of decision.modifier_items) {
                if (!item || typeof item !== 'object' || Array.isArray(item)) continue;
                const groupId = safeString(item.groupId ?? item.group_id).trim();
                const optionId = analyzerPromptPanelSelectedIdText(
                    item.optionId ?? item.option_id ?? item.id,
                );
                if (!groupId || !optionId) continue;
                appendAnalyzerPromptPanelSelectedIdLine(
                    lines,
                    seen,
                    'modifiers.' + groupId,
                    optionId,
                );
            }
        }
        appendAnalyzerPromptPanelSelectedIdLine(
            lines,
            seen,
            'scene_background_tags',
            decision.scene_background_tags ||
                decision.sceneBackgroundTags ||
                decision.background_tags ||
                decision.backgroundTags,
        );
        appendAnalyzerPromptPanelSelectedIdLine(
            lines,
            seen,
            'nsfw_scene_location_tag',
            decision.nsfw_scene_location_tag || decision.nsfwSceneLocationTag,
        );
        appendAnalyzerPromptPanelContinuityStateLines(lines, seen, decision);
        if (typeof decision.reason === 'string' || typeof decision.reason === 'number') {
            appendAnalyzerPromptPanelSelectedIdLine(lines, seen, 'reason', decision.reason);
        }
        return lines;
    }

    function analyzerPromptPanelSelectedIdSummaryText(decision = null) {
        return analyzerPromptPanelSelectedIdLines(decision).join('\n');
    }

    function normalizeDisplayRegenerationPlan(plan = null) {
        if (!plan || typeof plan !== 'object' || Array.isArray(plan)) return null;
        const characters = (Array.isArray(plan.characters) ? plan.characters : [])
            .map((character) => ({
                prompt: safeString(character?.prompt).trim(),
                uc: safeString(character?.uc).trim(),
                centerX: Number.isFinite(Number(character?.centerX))
                    ? Number(character.centerX)
                    : 0.5,
                centerY: Number.isFinite(Number(character?.centerY))
                    ? Number(character.centerY)
                    : 0.5,
            }))
            .filter((character) => character.prompt || character.uc);
        const characterReferences = (
            Array.isArray(plan.characterReferences) ? plan.characterReferences : []
        )
            .map((reference) => {
                const asset = reference?.asset || {};
                return {
                    promptKey: safeString(reference?.promptKey).trim(),
                    outfitId: safeString(reference?.outfitId).trim(),
                    asset: {
                        name: safeString(asset?.name || asset?.[0]).trim(),
                        key: safeString(asset?.key || asset?.path || asset?.[1]).trim(),
                        ext: safeString(asset?.ext || asset?.extension || asset?.[2]).trim(),
                    },
                };
            })
            .filter((reference) => reference.asset.key);
        const normalized = {
            globalPositive: safeString(plan.globalPositive).trim(),
            negativePrompt: safeString(plan.negativePrompt).trim(),
            characters,
            characterReferences,
            width: intBetween(plan.width, DEFAULT_CONFIG.novelai.width, 1, 8192),
            height: intBetween(plan.height, DEFAULT_CONFIG.novelai.height, 1, 8192),
            sizeId: safeString(plan.sizeId).trim(),
            seed: normalizeNovelAISeed(plan.seed),
            seedFixed: Boolean(plan.seedFixed && normalizeNovelAISeed(plan.seed)),
            validated:
                plan.validated && typeof plan.validated === 'object'
                    ? cloneJson(plan.validated)
                    : {},
            sourceImageToken: safeString(plan.sourceImageToken).trim(),
            sourceImageMarkup: safeString(plan.sourceImageMarkup).trim(),
            sourceImageMarkerId: safeString(plan.sourceImageMarkerId).trim(),
            chatKey: safeString(plan.chatKey).trim(),
            charIndex: nonNegativeIntegerOr(plan.charIndex, -1),
            chatIndex: nonNegativeIntegerOr(plan.chatIndex, -1),
            messageIndex: nonNegativeIntegerOr(plan.messageIndex, -1),
            slotId: safeString(plan.slotId || plan.imageSlotId).trim(),
            characterName: safeString(plan.characterName).trim(),
            selectedLorebookPromptKey: safeString(plan.selectedLorebookPromptKey).trim(),
            requestedLorebookPromptKey: safeString(plan.requestedLorebookPromptKey).trim(),
            selectedOutfitId: safeString(plan.selectedOutfitId).trim(),
            requestedOutfitId: safeString(plan.requestedOutfitId).trim(),
            matchedIdentityKey: safeString(plan.matchedIdentityKey).trim(),
            matchedIdentityName: safeString(plan.matchedIdentityName).trim(),
            basePromptApplied: Boolean(plan.basePromptApplied),
            basePromptPreview: safeString(plan.basePromptPreview).trim(),
            assetName: safeString(plan.assetName).trim(),
            analyzerDecision: normalizeAnalyzerDecisionForPromptPanel(
                plan.analyzerDecision || plan.analyzer_decision || plan.analyzer,
                plan,
            ),
        };
        if (!normalized.globalPositive && !normalized.characters.length) return null;
        return normalized;
    }

    function markerIdFromImageSlotMarkup(markup = '') {
        const text = safeString(markup).trim();
        if (!text) return '';
        const regex = imageTokenMarkerBlockRegex();
        const match = regex.exec(text);
        if (!match) return '';
        return safeString(parseImageTokenMarkerMeta(match[1])?.id).trim();
    }

    function scopedImageSlotId(slotId = '', chatKey = '') {
        const cleanSlotId = safeString(slotId).trim();
        if (!cleanSlotId) return '';
        if (cleanSlotId.startsWith('chat:')) return cleanSlotId;
        const cleanChatKey = safeString(chatKey).trim();
        return cleanChatKey ? `chat:${stableStringHash(cleanChatKey)}:${cleanSlotId}` : cleanSlotId;
    }

    function imageSlotIdFromParts(parts = {}) {
        const chatKey = safeString(
            parts.chatKey || parts.currentChatKey || parts.chatId || parts.chatroomKey,
        ).trim();
        const explicit = safeString(parts.slotId || parts.imageSlotId).trim();
        if (explicit) return scopedImageSlotId(explicit, chatKey);
        const sourceImageMarkup = safeString(
            parts.sourceImageMarkup || parts.originalMarkup || parts.sourceMarkup,
        ).trim();
        const markerId = safeString(
            parts.sourceImageMarkerId ||
                parts.markerId ||
                markerIdFromImageSlotMarkup(sourceImageMarkup),
        ).trim();
        if (markerId) return scopedImageSlotId(`marker:${markerId}`, chatKey);
        const sourceImageToken = safeString(
            parts.sourceImageToken ||
                parts.tokenName ||
                parseSupportedImageMarkup(sourceImageMarkup)?.tokenName ||
                rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(sourceImageMarkup)),
        ).trim();
        const sourceHash = sourceImageMarkup ? stableStringHash(sourceImageMarkup) : '';
        if (sourceImageToken && sourceHash)
            return scopedImageSlotId(`source:${sourceImageToken}:${sourceHash}`, chatKey);
        if (sourceImageToken) return scopedImageSlotId(`token:${sourceImageToken}`, chatKey);
        if (sourceHash) return scopedImageSlotId(`source:${sourceHash}`, chatKey);
        const assetName = safeString(parts.assetName).trim();
        return assetName ? scopedImageSlotId(`asset:${assetName}`, chatKey) : '';
    }

    function displayAssetMapKey(sourceImageToken = '', chatKey = '') {
        const cleanToken = safeString(sourceImageToken).trim();
        if (!cleanToken) return '';
        const cleanChatKey = safeString(chatKey).trim();
        return cleanChatKey ? `chat:${stableStringHash(cleanChatKey)}:${cleanToken}` : cleanToken;
    }

    function setDisplayAssetMapping(sourceImageToken = '', assetName = '', chatKey = '') {
        const key = displayAssetMapKey(sourceImageToken, chatKey);
        const cleanAssetName = safeString(assetName).trim();
        if (!key || !cleanAssetName) return;
        displayAssetMap.set(key, cleanAssetName);
    }

    function getDisplayAssetMapping(sourceImageToken = '', chatKey = '') {
        const key = displayAssetMapKey(sourceImageToken, chatKey);
        return key ? displayAssetMap.get(key) || '' : '';
    }

    function displayAssetSlotGeneratedEntryId(assetName = '') {
        const clean = safeString(assetName).trim();
        return clean ? `generated:${clean}` : '';
    }

    function displayAssetSlotOriginalEntryId(slotId = '') {
        return `original:${safeString(slotId).trim() || 'source'}`;
    }

    function rawAssetImageSrc(assetName = '') {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        return cleanAssetName ? `{{raw::${cleanAssetName}}}` : '';
    }

    function chatGeneratedAssetImageSrc(assetName = '') {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        return rawAssetImageSrc(cleanAssetName);
    }

    function storedDisplaySlotEntryImgSrc(entry = {}) {
        const value = safeString(entry?.imgSrc).trim();
        if (!value || normalizeImageDataUrl(value)) return '';
        return isRawAssetImageSrc(value) ? value : '';
    }

    function runtimeDisplaySlotEntryImgSrc(entry = {}) {
        const value = safeString(entry?.imgSrc).trim();
        if (!value) return '';
        if (isZoomBlobPreviewSrc(value)) return value;
        if (isRawAssetImageSrc(value)) return value;
        return normalizeZoomAssetPreviewUrl(value) ? value : '';
    }

    function normalizeDisplayAssetSlotEntry(entry = {}, slotId = '') {
        if (!entry || typeof entry !== 'object' || Array.isArray(entry)) return null;
        const type =
            safeString(entry.type || 'generated').trim() === 'original' ? 'original' : 'generated';
        const assetName = safeString(entry.assetName || entry.asset_name).trim();
        const sourceImageMarkup = safeString(entry.sourceImageMarkup).trim();
        const storedImgSrc = storedDisplaySlotEntryImgSrc(entry);
        const runtimeImgSrc = runtimeDisplaySlotEntryImgSrc(entry);
        const imgSrc =
            type === 'generated'
                ? rawAssetImageSrc(assetName) || runtimeImgSrc || storedImgSrc
                : runtimeImgSrc || storedImgSrc;
        const entryId =
            safeString(entry.entryId || entry.id).trim() ||
            (type === 'original'
                ? displayAssetSlotOriginalEntryId(slotId)
                : displayAssetSlotGeneratedEntryId(assetName));
        if (!entryId) return null;
        if (type === 'generated' && !assetName && !imgSrc) return null;
        if (type === 'original' && !sourceImageMarkup && !imgSrc && !assetName) return null;
        return {
            entryId,
            type,
            label: safeString(entry.label).trim(),
            assetName,
            seed: normalizeNovelAISeed(entry.seed),
            promptKey: safeString(entry.promptKey || entry.lorebookPromptKey).trim(),
            width: intBetween(entry.width, 0, 0, 8192),
            height: intBetween(entry.height, 0, 0, 8192),
            sizeId: normalizeZoomRegenerateSizePresetId(entry.sizeId || entry.size_id),
            sourceImageMarkup,
            imgSrc,
            createdAt: Number.isFinite(Number(entry.createdAt)) ? Number(entry.createdAt) : 0,
            charIndex: nonNegativeIntegerOr(entry.charIndex, -1),
            chatIndex: nonNegativeIntegerOr(entry.chatIndex, -1),
            messageIndex: nonNegativeIntegerOr(entry.messageIndex, -1),
        };
    }

    function normalizeDisplayAssetSlot(slot = {}) {
        if (!slot || typeof slot !== 'object' || Array.isArray(slot)) return null;
        const slotId = imageSlotIdFromParts(slot);
        if (!slotId) return null;
        const sourceImageMarkup = safeString(slot.sourceImageMarkup).trim();
        const sourceImageToken = safeString(
            slot.sourceImageToken ||
                parseSupportedImageMarkup(sourceImageMarkup)?.tokenName ||
                rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(sourceImageMarkup)),
        ).trim();
        const entries = [];
        const seen = new Set();
        for (const entry of Array.isArray(slot.entries) ? slot.entries : []) {
            const normalized = normalizeDisplayAssetSlotEntry(entry, slotId);
            if (!normalized || seen.has(normalized.entryId)) continue;
            seen.add(normalized.entryId);
            entries.push(normalized);
            if (normalized.assetName) displayAssetSlotMap.set(normalized.assetName, slotId);
        }
        const originalEntries = entries.filter((entry) => entry.type === 'original').slice(0, 1);
        const originalAssetNames = new Set(
            [...originalEntries.map((entry) => entry.assetName), sourceImageToken].filter(Boolean),
        );
        const generatedEntries = entries
            .filter(
                (entry) =>
                    entry.type === 'generated' &&
                    (!entry.assetName || !originalAssetNames.has(entry.assetName)),
            )
            .slice(-39);
        const finalEntries = [...originalEntries, ...generatedEntries];
        const currentEntryId = safeString(slot.currentEntryId).trim();
        const fallbackCurrent =
            finalEntries.find((entry) => entry.entryId === currentEntryId)?.entryId ||
            generatedEntries.slice(-1)[0]?.entryId ||
            originalEntries[0]?.entryId ||
            '';
        return {
            slotId,
            chatKey: safeString(slot.chatKey).trim(),
            sourceImageToken,
            sourceImageMarkerId: safeString(slot.sourceImageMarkerId).trim(),
            sourceImageMarkup,
            charIndex: nonNegativeIntegerOr(slot.charIndex, -1),
            chatIndex: nonNegativeIntegerOr(slot.chatIndex, -1),
            messageIndex: nonNegativeIntegerOr(slot.messageIndex, -1),
            currentEntryId: fallbackCurrent,
            entries: finalEntries,
        };
    }

    function displayAssetSlotOriginalEntry(slotId, meta = {}, sourceImageMarkup = '', imgSrc = '') {
        const rawSourceMarkup = safeString(sourceImageMarkup || meta.sourceImageMarkup).trim();
        const sourceMarkup = extractFirstSupportedImageMarkup(rawSourceMarkup) || rawSourceMarkup;
        const sourceAssetName = safeString(
            meta.sourceImageToken ||
                parseSupportedImageMarkup(sourceMarkup)?.tokenName ||
                rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(sourceMarkup)),
        ).trim();
        const sourceName = sanitizeOriginalAssetNamePart(
            sourceAssetName || 'original',
            'original',
        );
        const slotHash = stableStringHash(slotId || sourceMarkup);
        const originalAssetName = sanitizeOriginalAssetNamePart(
            `${sourceName}_original_${slotHash}`,
            `original_${slotHash}`,
        );
        return normalizeDisplayAssetSlotEntry(
            {
                entryId: displayAssetSlotOriginalEntryId(slotId),
                type: 'original',
                label: 'Original',
                assetName: sourceAssetName || originalAssetName,
                promptKey: meta.promptKey,
                width: meta.width,
                height: meta.height,
            sourceImageMarkup: sourceMarkup,
            imgSrc:
                imgSrc ||
                (sourceAssetName ? rawAssetImageSrc(sourceAssetName) : '') ||
                imageSrcFromOriginalMarkup(sourceMarkup),
            createdAt: 0,
            ...locationMetaFromParts(meta),
        },
        slotId,
    );
    }

    function displayAssetSlotGeneratedEntry(
        assetName,
        meta = {},
        sourceImageMarkup = '',
        imgSrc = '',
    ) {
        const cleanAssetName = safeString(assetName).trim();
        if (!cleanAssetName) return null;
        return normalizeDisplayAssetSlotEntry({
            entryId: displayAssetSlotGeneratedEntryId(cleanAssetName),
            type: 'generated',
            label: safeString(meta.label).trim(),
            assetName: cleanAssetName,
            seed: meta.seed,
            promptKey: meta.promptKey,
            width: meta.width,
            height: meta.height,
            sizeId: meta.sizeId || meta.size_id || meta.regenerationPlan?.sizeId,
            sourceImageMarkup: sourceImageMarkup || meta.sourceImageMarkup,
            imgSrc: rawAssetImageSrc(cleanAssetName),
            createdAt: Number.isFinite(Number(meta.createdAt))
                ? Number(meta.createdAt)
                : Date.now(),
            ...locationMetaFromParts(meta),
        });
    }

    function upsertDisplayAssetSlotEntry(slotId, entry, options = {}) {
        const cleanSlotId = safeString(slotId).trim();
        const normalizedEntry = normalizeDisplayAssetSlotEntry(entry, cleanSlotId);
        if (!cleanSlotId || !normalizedEntry) return null;
        const previous = displayAssetSlots.get(cleanSlotId) || {
            slotId: cleanSlotId,
            chatKey: '',
            sourceImageToken: '',
            sourceImageMarkerId: '',
            sourceImageMarkup: '',
            currentEntryId: '',
            entries: [],
        };
        const entries = previous.entries.filter((item) => item.entryId !== normalizedEntry.entryId);
        entries.push(normalizedEntry);
        const next = normalizeDisplayAssetSlot({
            ...previous,
            chatKey: safeString(options.chatKey || previous.chatKey).trim(),
            sourceImageToken: safeString(
                options.sourceImageToken || previous.sourceImageToken,
            ).trim(),
            sourceImageMarkerId: safeString(
                options.sourceImageMarkerId || previous.sourceImageMarkerId,
            ).trim(),
            sourceImageMarkup: safeString(
                options.sourceImageMarkup ||
                    normalizedEntry.sourceImageMarkup ||
                    previous.sourceImageMarkup,
            ).trim(),
            ...locationMetaFromParts({
                ...previous,
                ...normalizedEntry,
                ...options,
            }),
            currentEntryId: options.current ? normalizedEntry.entryId : previous.currentEntryId,
            entries,
        });
        if (!next) return null;
        displayAssetSlots.set(cleanSlotId, next);
        if (normalizedEntry.assetName)
            displayAssetSlotMap.set(normalizedEntry.assetName, cleanSlotId);
        return next;
    }

    function ensureDisplayAssetSlotBase(parts = {}, options = {}) {
        const slotId = imageSlotIdFromParts(parts);
        if (!slotId) return null;
        const sourceImageMarkup = safeString(
            parts.sourceImageMarkup || parts.originalMarkup || parts.sourceMarkup,
        ).trim();
        const sourceImageToken = safeString(parts.sourceImageToken).trim();
        const sourceImageMarkerId = safeString(
            parts.sourceImageMarkerId || markerIdFromImageSlotMarkup(sourceImageMarkup),
        ).trim();
        const chatKey = safeString(parts.chatKey || parts.meta?.chatKey).trim();
        let slot = displayAssetSlots.get(slotId) || null;
        if (!slot) {
            slot = normalizeDisplayAssetSlot({
                slotId,
                chatKey,
                sourceImageToken,
                sourceImageMarkerId,
                sourceImageMarkup,
                entries: [],
            });
            if (slot) displayAssetSlots.set(slotId, slot);
        }
        if (sourceImageMarkup) {
            const previousOriginalEntry =
                slot?.entries?.find?.((entry) => entry?.type === 'original') || null;
            const originalImgSrc =
                options.originalImgSrc ||
                runtimeDisplaySlotEntryImgSrc(previousOriginalEntry) ||
                '';
            const originalEntry = displayAssetSlotOriginalEntry(
                slotId,
                parts.meta || parts,
                sourceImageMarkup,
                originalImgSrc,
            );
            if (originalEntry) {
                slot = upsertDisplayAssetSlotEntry(slotId, originalEntry, {
                    chatKey,
                    sourceImageToken,
                    sourceImageMarkerId,
                    sourceImageMarkup,
                    current: Boolean(options.currentOriginal),
                });
            }
        }
        return slot ? displayAssetSlots.get(slotId) || slot : null;
    }

    function recordGeneratedAssetSlot(assetName, meta = {}, sourceImageMarkup = '', options = {}) {
        const cleanAssetName = safeString(assetName).trim();
        if (!cleanAssetName) return null;
        const sourceMarkup = safeString(sourceImageMarkup || meta.sourceImageMarkup).trim();
        const sourceAssetName = safeString(
            parseSupportedImageMarkup(sourceMarkup)?.tokenName ||
                rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(sourceMarkup)),
        ).trim();
        if (sourceAssetName && sourceAssetName === cleanAssetName) {
            return ensureDisplayAssetSlotBase(
                {
                    ...meta,
                    assetName: cleanAssetName,
                    sourceImageMarkup: sourceMarkup,
                    meta,
                },
                {
                    ...options,
                    currentOriginal: options.current === true,
                    originalImgSrc: options.imgSrc,
                },
            );
        }
        const slot = ensureDisplayAssetSlotBase(
            {
                ...meta,
                assetName: cleanAssetName,
                sourceImageMarkup: sourceMarkup,
                meta,
            },
            options,
        );
        if (!slot) return null;
        const existingEntry = slot.entries.find(
            (item) => item.entryId === displayAssetSlotGeneratedEntryId(cleanAssetName),
        );
        const effectiveMeta =
            existingEntry &&
            !Number.isFinite(Number(meta.createdAt)) &&
            Number.isFinite(Number(existingEntry.createdAt))
                ? { ...meta, createdAt: existingEntry.createdAt }
                : meta;
        const entry = displayAssetSlotGeneratedEntry(
            cleanAssetName,
            effectiveMeta,
            sourceMarkup || slot.sourceImageMarkup || meta.sourceImageMarkup,
            options.imgSrc,
        );
        if (!entry) return slot;
        return upsertDisplayAssetSlotEntry(slot.slotId, entry, {
            chatKey: meta.chatKey || slot.chatKey,
            sourceImageToken: meta.sourceImageToken || slot.sourceImageToken,
            sourceImageMarkerId: meta.sourceImageMarkerId || slot.sourceImageMarkerId,
            sourceImageMarkup: sourceMarkup || slot.sourceImageMarkup || meta.sourceImageMarkup,
            current: options.current !== false,
        });
    }

    function displayAssetSlotForAsset(assetName = '', slotId = '') {
        const cleanSlotId = safeString(slotId).trim();
        if (cleanSlotId && displayAssetSlots.has(cleanSlotId))
            return displayAssetSlots.get(cleanSlotId) || null;
        const cleanAssetName = safeString(assetName).trim();
        const mappedSlotId = cleanAssetName ? displayAssetSlotMap.get(cleanAssetName) || '' : '';
        return mappedSlotId ? displayAssetSlots.get(mappedSlotId) || null : null;
    }

    function currentDisplayAssetSlotEntry(slot = {}) {
        if (!slot?.entries?.length) return null;
        const currentEntryId = safeString(slot.currentEntryId).trim();
        return (
            slot.entries.find((entry) => entry.entryId === currentEntryId) ||
            slot.entries.filter((entry) => entry.type === 'generated').slice(-1)[0] ||
            slot.entries[0] ||
            null
        );
    }

    function persistDisplayAssetSlotCurrentEntry(slot = {}, entryId = '', reason = '') {
        if (!isChatHistoryStorageEnabled()) return null;
        const cleanSlotId = safeString(slot?.slotId).trim();
        const cleanEntryId = safeString(entryId).trim();
        if (!cleanSlotId || !cleanEntryId || !Array.isArray(slot?.entries)) return null;
        if (!slot.entries.some((entry) => safeString(entry?.entryId).trim() === cleanEntryId))
            return null;
        const nextSlot = normalizeDisplayAssetSlot({
            ...slot,
            currentEntryId: cleanEntryId,
        });
        if (!nextSlot) return null;
        displayAssetSlots.set(nextSlot.slotId, nextSlot);
        nextSlot.entries.forEach((entry) => {
            const assetName = safeString(entry?.assetName).trim();
            if (assetName) displayAssetSlotMap.set(assetName, nextSlot.slotId);
        });
        scheduleDisplayAssetMapSave(reason || 'display-slot-current-entry');
        return nextSlot;
    }

    function removeGeneratedAssetHistoryEntryFromSlot(slot = {}, assetName = '', entryId = '') {
        if (!slot || typeof slot !== 'object' || Array.isArray(slot)) {
            return { removed: false, slot: null, removedEntry: null, fallbackEntry: null };
        }
        const cleanAssetName = safeString(assetName).trim();
        const cleanEntryId = safeString(entryId).trim();
        const entries = Array.isArray(slot.entries) ? slot.entries : [];
        const target = entries.find((entry) => {
            if (!entry || entry.type !== 'generated') return false;
            const entryAssetName = safeString(entry.assetName).trim();
            const entryIdValue = safeString(entry.entryId).trim();
            return cleanEntryId ? entryIdValue === cleanEntryId : entryAssetName === cleanAssetName;
        });
        if (!target) return { removed: false, slot, removedEntry: null, fallbackEntry: null };
        const targetEntryId = safeString(target.entryId).trim();
        const nextEntries = entries.filter(
            (entry) => safeString(entry?.entryId).trim() !== targetEntryId,
        );
        const deletingCurrent = safeString(slot.currentEntryId).trim() === targetEntryId;
        const originalEntry = nextEntries.find((entry) => entry?.type === 'original') || null;
        const generatedFallback =
            nextEntries.filter((entry) => entry?.type === 'generated').slice(-1)[0] || null;
        const fallbackEntry = deletingCurrent
            ? originalEntry || generatedFallback
            : nextEntries.find(
                  (entry) =>
                      safeString(entry?.entryId).trim() === safeString(slot.currentEntryId).trim(),
              ) ||
              originalEntry ||
              generatedFallback ||
              null;
        return {
            removed: true,
            removedEntry: target,
            fallbackEntry,
            slot: {
                ...slot,
                currentEntryId: safeString(fallbackEntry?.entryId).trim(),
                entries: nextEntries,
            },
        };
    }

    function displayAssetSlotForGalleryItem(item = {}) {
        const assetName = safeString(item?.assetName).trim();
        const storedMeta = displayAssetMetaMap.get(assetName) || {};
        const itemMeta = item?.meta || {};
        const meta = {
            ...itemMeta,
            ...storedMeta,
            originalDisplay:
                Boolean(itemMeta.originalDisplay) || Boolean(storedMeta.originalDisplay),
            originalDisplayNatural:
                Boolean(itemMeta.originalDisplayNatural) ||
                Boolean(storedMeta.originalDisplayNatural),
            sourceImageToken:
                safeString(itemMeta.sourceImageToken).trim() ||
                safeString(storedMeta.sourceImageToken).trim(),
            sourceImageMarkup:
                safeString(itemMeta.sourceImageMarkup).trim() ||
                safeString(storedMeta.sourceImageMarkup).trim(),
            displaySrc:
                safeString(itemMeta.displaySrc).trim() || safeString(storedMeta.displaySrc).trim(),
            chatKey: safeString(itemMeta.chatKey || item?.chatKey || storedMeta.chatKey).trim(),
            slotId: safeString(item?.slotId || itemMeta.slotId || storedMeta.slotId).trim(),
        };
        const mappedSlotId = displayAssetSlotMap.get(assetName) || '';
        const expectedChatPrefix = meta.chatKey ? `chat:${stableStringHash(meta.chatKey)}:` : '';
        const slotId =
            imageSlotIdFromParts({ ...meta, slotId: meta.slotId || item?.slotId }) ||
            (expectedChatPrefix
                ? mappedSlotId.startsWith(expectedChatPrefix)
                    ? mappedSlotId
                    : ''
                : mappedSlotId) ||
            imageSlotIdFromParts({
                ...meta,
                assetName,
                sourceImageMarkup: meta.sourceImageMarkup || item?.originalMarkup,
                originalMarkup: item?.originalMarkup,
                chatKey: meta.chatKey || item?.chatKey,
            });
        if (!slotId) return null;
        ensureDisplayAssetSlotBase(
            {
                ...meta,
                slotId,
                assetName,
                sourceImageMarkup: meta.sourceImageMarkup || item?.originalMarkup,
                originalMarkup: item?.originalMarkup,
                chatKey: meta.chatKey || item?.chatKey,
                meta,
            },
            { originalImgSrc: item?.originalImgSrc },
        );
        if (assetName && !meta.originalDisplay) {
            recordGeneratedAssetSlot(
                assetName,
                { ...meta, slotId },
                meta.sourceImageMarkup || item?.originalMarkup,
                {
                    current: false,
                    imgSrc: item?.imgSrc,
                },
            );
        }
        return displayAssetSlots.get(slotId) || null;
    }

    function normalizeDisplayAssetMeta(meta = {}) {
        const dataUrl = normalizeImageDataUrl(meta.dataUrl);
        const regenerationPlan = normalizeDisplayRegenerationPlan(
            meta.regenerationPlan || meta.regenPlan || meta.plan,
        );
        const seed = normalizeNovelAISeed(meta.seed || regenerationPlan?.seed);
        const promptKey = safeString(
            meta.promptKey ||
                meta.lorebookPromptKey ||
                regenerationPlan?.matchedIdentityKey ||
                regenerationPlan?.selectedLorebookPromptKey,
        ).trim();
        const width = intBetween(meta.width, 0, 0, 8192);
        const height = intBetween(meta.height, 0, 0, 8192);
        const chatKey = safeString(meta.chatKey || regenerationPlan?.chatKey).trim();
        const locationMeta = locationMetaFromParts({
            ...regenerationPlan,
            ...meta,
            chatKey,
        });
        return {
            seed,
            promptKey,
            seedFixed: Boolean((meta.seedFixed || regenerationPlan?.seedFixed) && seed),
            width,
            height,
            dataUrl,
            regenerationPlan,
            analyzerDecision: normalizeAnalyzerDecisionForPromptPanel(
                meta.analyzerDecision || regenerationPlan?.analyzerDecision,
                {
                    ...meta,
                    regenerationPlan,
                },
            ),
            originalDisplay: Boolean(meta.originalDisplay),
            sourceImageToken: safeString(meta.sourceImageToken).trim(),
            sourceImageMarkerId: safeString(meta.sourceImageMarkerId).trim(),
            sourceImageMarkup: safeString(meta.sourceImageMarkup).trim(),
            chatKey,
            ...locationMeta,
            slotId: imageSlotIdFromParts({ ...meta, chatKey }),
        };
    }

    function normalizeDisplayAssetSlotRegenerationPlan(slotId = '', plan = null, meta = {}) {
        const rawPlan =
            plan && typeof plan === 'object' && !Array.isArray(plan)
                ? plan.regenerationPlan || plan.regenPlan || plan.plan || plan
                : null;
        const regenerationPlan = normalizeDisplayRegenerationPlan(rawPlan);
        const cleanSlotId = safeString(
            slotId || meta.slotId || regenerationPlan?.slotId || rawPlan?.slotId,
        ).trim();
        if (!cleanSlotId || !regenerationPlan) return null;
        const sourceImageToken = safeString(
            meta.sourceImageToken || regenerationPlan.sourceImageToken,
        ).trim();
        const sourceImageMarkerId = safeString(
            meta.sourceImageMarkerId || regenerationPlan.sourceImageMarkerId,
        ).trim();
        const sourceImageMarkup = safeString(
            meta.sourceImageMarkup || regenerationPlan.sourceImageMarkup,
        ).trim();
        const chatKey = safeString(meta.chatKey || regenerationPlan.chatKey).trim();
        const locationMeta = locationMetaFromParts({
            ...regenerationPlan,
            ...meta,
            chatKey,
        });
        const lastAssetName = safeString(
            meta.lastAssetName || meta.assetName || regenerationPlan.assetName,
        ).trim();
        const normalizedPlan = normalizeDisplayRegenerationPlan({
            ...regenerationPlan,
            slotId: cleanSlotId,
            sourceImageToken,
            sourceImageMarkerId,
            sourceImageMarkup,
            chatKey,
            ...locationMeta,
            assetName: lastAssetName || regenerationPlan.assetName,
        });
        if (!normalizedPlan) return null;
        return {
            slotId: cleanSlotId,
            regenerationPlan: normalizedPlan,
            sourceImageToken,
            sourceImageMarkerId,
            sourceImageMarkup,
            chatKey,
            ...locationMeta,
            lastAssetName,
            updatedAt: Number.isFinite(Number(meta.updatedAt)) ? Number(meta.updatedAt) : Date.now(),
        };
    }

    function upsertDisplayAssetSlotRegenerationPlan(slotId = '', plan = null, meta = {}) {
        const record = normalizeDisplayAssetSlotRegenerationPlan(slotId, plan, meta);
        if (!record) return null;
        displayAssetSlotPlanMap.set(record.slotId, record);
        return record;
    }

    function displayAssetSlotRegenerationPlanRecord(slotId = '') {
        const cleanSlotId = safeString(slotId).trim();
        if (!cleanSlotId) return null;
        const record = displayAssetSlotPlanMap.get(cleanSlotId);
        return normalizeDisplayAssetSlotRegenerationPlan(cleanSlotId, record?.regenerationPlan, record);
    }

    function displayMetaWithSlotRegenerationPlan(meta = {}, slotId = '') {
        const baseMeta = meta && typeof meta === 'object' && !Array.isArray(meta) ? meta : {};
        if (regenerationPlanFromDisplayMeta(baseMeta)) return baseMeta;
        const cleanSlotId = safeString(slotId || baseMeta.slotId).trim();
        const record = displayAssetSlotRegenerationPlanRecord(cleanSlotId);
        if (!record?.regenerationPlan) return baseMeta;
        const sourceImageToken = safeString(
            baseMeta.sourceImageToken || record.sourceImageToken || record.regenerationPlan.sourceImageToken,
        ).trim();
        const sourceImageMarkerId = safeString(
            baseMeta.sourceImageMarkerId ||
                record.sourceImageMarkerId ||
                record.regenerationPlan.sourceImageMarkerId,
        ).trim();
        const sourceImageMarkup = safeString(
            baseMeta.sourceImageMarkup ||
                record.sourceImageMarkup ||
                record.regenerationPlan.sourceImageMarkup,
        ).trim();
        const chatKey = safeString(
            baseMeta.chatKey || record.chatKey || record.regenerationPlan.chatKey,
        ).trim();
        const locationMeta = locationMetaFromParts({
            ...record.regenerationPlan,
            ...record,
            ...baseMeta,
            chatKey,
        });
        return {
            ...baseMeta,
            sourceImageToken,
            sourceImageMarkerId,
            sourceImageMarkup,
            chatKey,
            ...locationMeta,
            slotId: cleanSlotId || record.slotId,
            regenerationPlan: normalizeDisplayRegenerationPlan({
                ...record.regenerationPlan,
                sourceImageToken,
                sourceImageMarkerId,
                sourceImageMarkup,
                chatKey,
                ...locationMeta,
                slotId: cleanSlotId || record.slotId,
                assetName: safeString(baseMeta.assetName || record.regenerationPlan.assetName).trim(),
            }),
        };
    }

    async function saveDisplayAssetMap() {
        const obj = {};
        for (const [key, value] of displayAssetMap) obj[key] = value;
        await Risu.pluginStorage.setItem(STORAGE_DISPLAY_MAP, JSON.stringify(obj));
        const revObj = {};
        for (const [key, value] of reverseAssetMap) revObj[key] = value;
        await Risu.pluginStorage.setItem(STORAGE_DISPLAY_MAP + '_reverse', JSON.stringify(revObj));
        const metaObj = {};
        for (const [key, value] of displayAssetMetaMap) {
            const meta = normalizeDisplayAssetMeta(value);
            const persistedMeta = {
                seed: meta.seed,
                promptKey: meta.promptKey,
                seedFixed: meta.seedFixed,
                width: meta.width,
                height: meta.height,
            };
            if (meta.regenerationPlan) persistedMeta.regenerationPlan = meta.regenerationPlan;
            if (meta.originalDisplay) persistedMeta.originalDisplay = true;
            if (meta.sourceImageToken) persistedMeta.sourceImageToken = meta.sourceImageToken;
            if (meta.sourceImageMarkerId)
                persistedMeta.sourceImageMarkerId = meta.sourceImageMarkerId;
            if (meta.sourceImageMarkup) persistedMeta.sourceImageMarkup = meta.sourceImageMarkup;
            if (meta.chatKey) persistedMeta.chatKey = meta.chatKey;
            if (meta.charIndex >= 0) persistedMeta.charIndex = meta.charIndex;
            if (meta.chatIndex >= 0) persistedMeta.chatIndex = meta.chatIndex;
            if (meta.messageIndex >= 0) persistedMeta.messageIndex = meta.messageIndex;
            if (meta.slotId) persistedMeta.slotId = meta.slotId;
            if (
                persistedMeta.seed ||
                persistedMeta.promptKey ||
                persistedMeta.seedFixed ||
                persistedMeta.width ||
                persistedMeta.height ||
                persistedMeta.regenerationPlan ||
                persistedMeta.originalDisplay ||
                persistedMeta.chatKey ||
                persistedMeta.charIndex >= 0 ||
                persistedMeta.chatIndex >= 0 ||
                persistedMeta.messageIndex >= 0 ||
                persistedMeta.slotId
            ) {
                metaObj[key] = persistedMeta;
            }
        }
        await Risu.pluginStorage.setItem(STORAGE_DISPLAY_META, JSON.stringify(metaObj));
        const slotObj = {};
        for (const [_slotId, value] of displayAssetSlots) {
            const slot = normalizeDisplayAssetSlot(value);
            if (!slot || !slot.entries.length) continue;
            const persistedSlot = {
                slotId: slot.slotId,
                chatKey: slot.chatKey,
                sourceImageToken: slot.sourceImageToken,
                sourceImageMarkerId: slot.sourceImageMarkerId,
                sourceImageMarkup: slot.sourceImageMarkup,
                currentEntryId: slot.currentEntryId,
                entries: slot.entries.map((entry) => ({
                    entryId: entry.entryId,
                    type: entry.type,
                    label: entry.label,
                    assetName: entry.assetName,
                    seed: entry.seed,
                    promptKey: entry.promptKey,
                    width: entry.width,
                    height: entry.height,
                    sizeId: entry.sizeId,
                    sourceImageMarkup: entry.sourceImageMarkup,
                    imgSrc: storedDisplaySlotEntryImgSrc(entry),
                    createdAt: entry.createdAt,
                })),
            };
            if (slot.charIndex >= 0) persistedSlot.charIndex = slot.charIndex;
            if (slot.chatIndex >= 0) persistedSlot.chatIndex = slot.chatIndex;
            if (slot.messageIndex >= 0) persistedSlot.messageIndex = slot.messageIndex;
            persistedSlot.entries = persistedSlot.entries.map((entry, index) => {
                const sourceEntry = slot.entries[index] || {};
                if (sourceEntry.charIndex >= 0) entry.charIndex = sourceEntry.charIndex;
                if (sourceEntry.chatIndex >= 0) entry.chatIndex = sourceEntry.chatIndex;
                if (sourceEntry.messageIndex >= 0) entry.messageIndex = sourceEntry.messageIndex;
                return entry;
            });
            slotObj[slot.slotId] = persistedSlot;
        }
        await Risu.pluginStorage.setItem(STORAGE_DISPLAY_SLOTS, JSON.stringify(slotObj));
        const slotPlanObj = {};
        for (const [_slotId, value] of displayAssetSlotPlanMap) {
            const slotPlanRecord = normalizeDisplayAssetSlotRegenerationPlan(
                value?.slotId || _slotId,
                value?.regenerationPlan,
                value,
            );
            if (!slotPlanRecord?.regenerationPlan) continue;
            const persistedSlotPlan = {
                slotId: slotPlanRecord.slotId,
                regenerationPlan: slotPlanRecord.regenerationPlan,
                sourceImageToken: slotPlanRecord.sourceImageToken,
                sourceImageMarkerId: slotPlanRecord.sourceImageMarkerId,
                sourceImageMarkup: slotPlanRecord.sourceImageMarkup,
                chatKey: slotPlanRecord.chatKey,
                lastAssetName: slotPlanRecord.lastAssetName,
                updatedAt: slotPlanRecord.updatedAt,
            };
            if (slotPlanRecord.charIndex >= 0)
                persistedSlotPlan.charIndex = slotPlanRecord.charIndex;
            if (slotPlanRecord.chatIndex >= 0)
                persistedSlotPlan.chatIndex = slotPlanRecord.chatIndex;
            if (slotPlanRecord.messageIndex >= 0)
                persistedSlotPlan.messageIndex = slotPlanRecord.messageIndex;
            slotPlanObj[slotPlanRecord.slotId] = persistedSlotPlan;
        }
        await Risu.pluginStorage.setItem(
            STORAGE_DISPLAY_SLOT_PLANS,
            JSON.stringify(slotPlanObj),
        );
    }

    function scheduleDisplayAssetMapSave(reason = '') {
        if (displayAssetMapSaveTimer) clearTimeout(displayAssetMapSaveTimer);
        displayAssetMapSaveTimer = setTimeout(() => {
            displayAssetMapSaveTimer = null;
            saveDisplayAssetMap().catch((error) => {

            });
        }, 180);
    }

    async function loadDisplayAssetMap() {
        try {
            const raw = await Risu.pluginStorage.getItem(STORAGE_DISPLAY_MAP);
            if (raw) {
                const obj = JSON.parse(raw);
                if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
                    for (const [key, value] of Object.entries(obj)) {
                        if (typeof key === 'string' && typeof value === 'string' && key && value)
                            displayAssetMap.set(key, value);
                    }
                }
            }
        } catch (_) {}
        try {
            const raw = await Risu.pluginStorage.getItem(STORAGE_DISPLAY_MAP + '_reverse');
            if (raw) {
                const obj = JSON.parse(raw);
                if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
                    for (const [key, value] of Object.entries(obj)) {
                        if (typeof key === 'string' && typeof value === 'string' && key && value)
                            reverseAssetMap.set(key, value);
                    }
                }
            }
        } catch (_) {}
        try {
            const raw = await Risu.pluginStorage.getItem(STORAGE_DISPLAY_META);
            if (raw) {
                const obj = JSON.parse(raw);
                if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
                    for (const [key, value] of Object.entries(obj)) {
                        if (typeof key !== 'string' || !key || !value || typeof value !== 'object')
                            continue;
                        const meta = normalizeDisplayAssetMeta(value);
                        if (
                            meta.seed ||
                            meta.promptKey ||
                            meta.seedFixed ||
                            meta.regenerationPlan ||
                            meta.originalDisplay ||
                            meta.charIndex >= 0 ||
                            meta.chatIndex >= 0 ||
                            meta.messageIndex >= 0 ||
                            meta.slotId
                        )
                            displayAssetMetaMap.set(key, meta);
                    }
                }
            }
        } catch (_) {}
        try {
            const raw = await Risu.pluginStorage.getItem(STORAGE_DISPLAY_SLOTS);
            if (raw) {
                const obj = JSON.parse(raw);
                if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
                    for (const value of Object.values(obj)) {
                        const slot = normalizeDisplayAssetSlot(value);
                        if (slot) displayAssetSlots.set(slot.slotId, slot);
                    }
                }
            }
        } catch (_) {}
        try {
            const raw = await Risu.pluginStorage.getItem(STORAGE_DISPLAY_SLOT_PLANS);
            if (raw) {
                const obj = JSON.parse(raw);
                if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
                    for (const [slotId, value] of Object.entries(obj)) {
                        const record = normalizeDisplayAssetSlotRegenerationPlan(
                            slotId,
                            value?.regenerationPlan,
                            value,
                        );
                        if (record) displayAssetSlotPlanMap.set(record.slotId, record);
                    }
                }
            }
        } catch (_) {}
    }

    function cloneJson(value) {
        return JSON.parse(JSON.stringify(value));
    }

    function deepMerge(base, patch) {
        const output = cloneJson(base);
        if (!patch || typeof patch !== 'object') return output;
        for (const [key, value] of Object.entries(patch)) {
            if (
                value &&
                typeof value === 'object' &&
                !Array.isArray(value) &&
                output[key] &&
                typeof output[key] === 'object' &&
                !Array.isArray(output[key])
            ) {
                output[key] = deepMerge(output[key], value);
            } else if (value !== undefined) {
                output[key] = value;
            }
        }
        return output;
    }

    function safeString(value) {
        return value === null || value === undefined ? '' : String(value);
    }

    function normalizeUiChoice(value, allowedValues, fallback = '') {
        const clean = safeString(value).trim();
        return allowedValues.includes(clean) ? clean : fallback;
    }

    function normalizeSettingsUiState(value = {}) {
        const state = value && typeof value === 'object' ? value : {};
        return {
            activeSettingsTab: normalizeUiChoice(
                state.activeSettingsTab || state.settingsTab,
                SETTINGS_TAB_VALUES,
                '',
            ),
            activeSubtab: normalizeUiChoice(
                state.activeSubtab || state.characterSubtab,
                CHARACTER_SUBTAB_VALUES,
                '',
            ),
            activeSettingSubtab: normalizeUiChoice(
                state.activeSettingSubtab || state.settingSubtab,
                SETTING_SUBTAB_VALUES,
                '',
            ),
            selectedSourceId: safeString(state.selectedSourceId).trim(),
            assetMetadataSourceFilter: normalizeUiChoice(
                state.assetMetadataSourceFilter,
                SOURCE_FILTER_VALUES,
                '',
            ),
            bodyScrollTop: Math.max(0, Number(state.bodyScrollTop) || 0),
        };
    }

    function parseSettingsUiState(raw) {
        if (!raw) return {};
        try {
            return normalizeSettingsUiState(typeof raw === 'string' ? JSON.parse(raw) : raw);
        } catch (_) {
            return {};
        }
    }

    function readSessionSettingsUiState() {
        try {
            return parseSettingsUiState(globalThis.sessionStorage?.getItem(STORAGE_UI_STATE));
        } catch (_) {
            return {};
        }
    }

    function writeSessionSettingsUiState(state = settingsUiState) {
        try {
            globalThis.sessionStorage?.setItem(
                STORAGE_UI_STATE,
                JSON.stringify(normalizeSettingsUiState(state)),
            );
        } catch (_) {}
    }

    async function loadSettingsUiState() {
        let next = readSessionSettingsUiState();
        if (!Object.values(next).some(Boolean)) {
            try {
                next = parseSettingsUiState(await Risu.pluginStorage.getItem(STORAGE_UI_STATE));
            } catch (_) {
                next = {};
            }
        }
        settingsUiState = normalizeSettingsUiState(next);
        writeSessionSettingsUiState(settingsUiState);
        return settingsUiState;
    }

    function settingsScrollContainer() {
        return (
            document.querySelector?.('.naa-body') ||
            document.querySelector?.('.naa-modal') ||
            null
        );
    }

    function persistSettingsUiState(patch = {}) {
        const scrollElement = settingsScrollContainer();
        settingsUiState = normalizeSettingsUiState({
            ...settingsUiState,
            ...(scrollElement ? { bodyScrollTop: scrollElement.scrollTop } : {}),
            ...patch,
        });
        writeSessionSettingsUiState(settingsUiState);
        try {
            void Risu.pluginStorage
                .setItem(STORAGE_UI_STATE, JSON.stringify(settingsUiState))
                .catch(() => {});
        } catch (_) {}
    }

    function captureCurrentSettingsUiState(patch = {}) {
        const promptConfig = getCharacterPromptConfig();
        persistSettingsUiState({
            activeSettingsTab,
            activeSettingSubtab,
            activeSubtab: promptConfig.activeSubtab,
            selectedSourceId: promptConfig.selectedSourceId,
            assetMetadataSourceFilter: promptConfig.assetMetadataSourceFilter,
            ...patch,
        });
    }

    function applySettingsUiState() {
        const state = normalizeSettingsUiState(settingsUiState);
        if (state.activeSettingsTab) activeSettingsTab = state.activeSettingsTab;
        if (state.activeSettingSubtab) activeSettingSubtab = state.activeSettingSubtab;
        const promptConfig = getCharacterPromptConfig();
        if (state.activeSubtab) promptConfig.activeSubtab = state.activeSubtab;
        if (state.selectedSourceId) promptConfig.selectedSourceId = state.selectedSourceId;
        if (state.assetMetadataSourceFilter)
            promptConfig.assetMetadataSourceFilter = state.assetMetadataSourceFilter;
    }

    function restoreSettingsScrollPosition() {
        const top = Number(settingsUiState?.bodyScrollTop) || 0;
        if (!top) return;
        const schedule =
            globalThis.requestAnimationFrame || ((callback) => setTimeout(callback, 0));
        schedule(() => {
            const scrollElement = settingsScrollContainer();
            if (scrollElement) {
                scrollElement.scrollTop = top;
            }
        });
    }

    function bindSettingsUiStateDomPersistence() {
        const scrollElement = settingsScrollContainer();
        if (!scrollElement) return;
        scrollElement.addEventListener?.('scroll', () => {
            settingsUiState = normalizeSettingsUiState({
                ...settingsUiState,
                bodyScrollTop: scrollElement.scrollTop,
            });
            writeSessionSettingsUiState(settingsUiState);
        });
    }

    function escapeHtml(value) {
        return safeString(value)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

