    function attachTagTesterSizeSelectToGeneratedImageHeader() {
        const select = document.getElementById('sizeSelect');
        const heading = Array.from(document.querySelectorAll('.image-column > h2')).find(
            (node) => safeString(node.textContent).trim() === 'Generated Image',
        );
        if (!select || !heading || heading.querySelector('#sizeSelect')) return;
        const sizeLine = select.closest('.size-line');
        const control = document.createElement('label');
        const label = document.createElement('span');
        heading.classList.add('naa-tag-tester-generated-head');
        control.className = 'naa-tag-tester-size-control';
        control.setAttribute('aria-label', 'Image resolution');
        label.textContent = 'Resolution';
        control.appendChild(label);
        control.appendChild(select);
        heading.appendChild(control);
        if (sizeLine && !sizeLine.querySelector('select')) sizeLine.remove();
    }

    function attachTagTesterOutputFolderPathInput() {
        const input = document.getElementById('outputFolderPath');
        const button = document.getElementById('openFolderBtn');
        if (!input || !button) return;
        let saveButton = document.getElementById('saveOutputFolderPathBtn');
        if (!saveButton) {
            saveButton = document.createElement('button');
            saveButton.id = 'saveOutputFolderPathBtn';
            saveButton.type = 'button';
            saveButton.textContent = 'Save path';
            saveButton.title = 'Save the Tag Tester output folder path.';
        }
        input.type = 'text';
        input.removeAttribute('readonly');
        input.placeholder = 'Local output folder';
        input.setAttribute('aria-label', 'Local output folder');
        input.classList.add('header-output-folder');
        if (button.previousElementSibling !== saveButton) button.before(saveButton);
        if (saveButton.previousElementSibling !== input) saveButton.before(input);
        saveButton.onclick = async () => {
            const originalText = saveButton.textContent || 'Save path';
            try {
                saveButton.disabled = true;
                saveButton.textContent = 'Saving...';
                const bridge =
                    globalThis.NAA_TAG_TESTER_SAVE_OUTPUT_FOLDER ||
                    saveTagTesterDevServerOutputFolder;
                const data = await bridge({ outputDir: tagTesterOutputFolderPathFromInput() });
                setTagTesterOutputFolderPath(data?.outputDir);
            } catch (error) {
                const status = document.getElementById('folderStatus');
                if (status) status.textContent = `Save path failed: ${error?.message || error}`;
            } finally {
                saveButton.disabled = false;
                saveButton.textContent = originalText;
            }
        };
    }

    function updateTagTesterReferenceGridStatus() {
        const grid = tagTesterReferenceGridFromDom(document);
        const summary = document.querySelector('[data-naa-tag-tester-reference-summary]');
        if (!grid) return;
        const count = grid.querySelectorAll('[data-naa-tag-tester-reference-card]').length;
        const selectedCard = selectedTagTesterReferenceCardFromDom(document);
        const referenceEnabled = isTagTesterReferenceImageEnabled(document);
        if (summary) {
            summary.textContent = tagTesterReferenceGridStatusText(
                count,
                safeString(selectedCard?.getAttribute('data-reference-label')).trim(),
                referenceEnabled,
            );
        }
        updateTagTesterSelectedReferencePreview(selectedCard);
    }

    function updateTagTesterSelectedReferencePreview(card = null) {
        const preview = document.querySelector('[data-naa-tag-tester-reference-selected]');
        if (!preview) return;
        const selectedCard =
            card || document.querySelector('[data-naa-tag-tester-reference-card].selected');
        const img = preview.querySelector('[data-naa-tag-tester-selected-img]');
        const status = preview.querySelector('[data-naa-tag-tester-selected-status]');
        if (!selectedCard) {
            if (img) {
                img.removeAttribute('src');
                img.setAttribute('hidden', '');
            }
            if (status) {
                status.textContent = '선택된 레퍼런스 없음';
                status.removeAttribute('hidden');
            }
            return;
        }
        const sourceImg = selectedCard.querySelector('[data-naa-tag-tester-reference-img]');
        const sourceStatus = selectedCard.querySelector('[data-naa-tag-tester-reference-status]');
        const source = safeString(sourceImg?.getAttribute('src')).trim();
        if (img) {
            img.alt = [
                selectedCard.getAttribute('data-reference-character-name'),
                selectedCard.getAttribute('data-reference-outfit-name'),
            ]
                .map((value) => safeString(value).trim())
                .filter(Boolean)
                .join(' · ');
            if (source) {
                img.src = source;
                img.removeAttribute('hidden');
            } else {
                img.removeAttribute('src');
                img.setAttribute('hidden', '');
            }
        }
        if (status) {
            const loadingText = safeString(sourceStatus?.textContent).trim() || t('loading');
            status.textContent = source ? '' : loadingText;
            if (source) status.setAttribute('hidden', '');
            else status.removeAttribute('hidden');
        }
    }

    function tagTesterRenderedPromptObjectFromDom() {
        try {
            const text = safeString(document.getElementById('promptObjectOut')?.textContent).trim();
            return text ? JSON.parse(text) : null;
        } catch (_) {
            return null;
        }
    }

    function tagTesterFemaleRolePromptPartsFromDom() {
        const female = tagTesterRenderedPromptObjectFromDom()?.prompt?.female || {};
        return ROLE_PROMPT_FIELDS.map((field) => safeString(female?.[field]).trim()).filter(
            Boolean,
        );
    }

    function tagTesterFramingFromDom() {
        return safeString(tagTesterRenderedPromptObjectFromDom()?.prompt?.framing).trim() || 'cowboy shot';
    }

    function tagTesterPresetInfoFromDomOrContext(context = null) {
        const renderedPreset = tagTesterRenderedPromptObjectFromDom()?.preset;
        if (isPlainObject(renderedPreset)) return renderedPreset;
        const input = context && typeof context === 'object' ? context : currentTagTesterLaunchContext() || {};
        const presetId = safeString(input.presetId || input.preset_id).trim();
        const presetKey = safeString(input.presetKey || input.preset_key).trim();
        const presetPath = safeString(input.presetPath || input.preset_path).trim();
        const ratingId = safeString(input.ratingId || input.rating_id).trim();
        const compositionId = safeString(input.compositionId || input.composition_id).trim();
        const wantedPreset = presetId || presetPath || presetKey;
        if (!wantedPreset) return null;
        const catalog = getActivePresetCatalog();
        const resolved = findTreePreset(catalog, wantedPreset, {
            ratingId,
            compositionId,
            pathString: presetPath,
        });
        if (resolved) return resolved;
        const path = normalizePresetPathId(presetPath || presetId || presetKey)
            .split('.')
            .filter(Boolean);
        return {
            id: presetPath || presetId || presetKey,
            key: presetKey,
            localId: presetKey || presetId,
            pathString: presetPath,
            legacyPathString: presetPath.replace(/\./g, '/'),
            ratingId: ratingId || path[0] || '',
            compositionId: compositionId || path[1] || '',
            path,
        };
    }

    function tagTesterContextForPromptKey(promptKey = '') {
        const key = safeString(promptKey).trim();
        const context = currentTagTesterLaunchContext();
        return key && key === safeString(context?.promptKey).trim() ? context : null;
    }

    function tagTesterMainPromptForPromptKey(promptKey = '') {
        const key = safeString(promptKey).trim();
        if (!key) return '';
        const promptConfig = getCharacterPromptConfig();
        const stored = safeString(promptConfig.lorebookPrompts?.[key]).trim();
        if (stored) return stored;
        const contextPrompt = safeString(tagTesterContextForPromptKey(key)?.basePrompt).trim();
        if (contextPrompt) return contextPrompt;
        const memberPrompt = safeString(
            promptConfig.characterIdentityPrompts?.[memberKeyFromLorebookPromptKey(key)],
        ).trim();
        if (memberPrompt) return memberPrompt;
        return safeString(
            getActiveIdentityPrompts().find((entry) => entry.key === key)?.prompt,
        ).trim();
    }

    function tagTesterNegativePromptForPromptKey(promptKey = '') {
        const key = safeString(promptKey).trim();
        if (!key) return '';
        const promptConfig = getCharacterPromptConfig();
        const stored = safeString(promptConfig.lorebookNegativePrompts?.[key]).trim();
        if (stored) return stored;
        return safeString(tagTesterContextForPromptKey(key)?.negativePrompt).trim();
    }

    function buildTagTesterPromptPayload({
        promptKey = '',
        characterName = '',
        outfitId = '',
        outfitName = '',
        outfit = null,
    } = {}) {
        const key = safeString(promptKey).trim();
        if (!key) return null;
        const normalizedOutfit = outfit ? normalizeOutfitPromptEntry(outfit) : null;
        const cleanOutfitId = safeString(outfitId || normalizedOutfit?.id).trim();
        const cleanOutfitName = safeString(outfitName || normalizedOutfit?.label).trim();
        const cleanCharacterName =
            safeString(characterName).trim() ||
            characterNameForPromptKey(key, characterPromptSourceContextForPromptKey(key)?.source);
        const framing = tagTesterFramingFromDom();
        const mainPrompt = tagTesterMainPromptForPromptKey(key);
        const negativePrompt = tagTesterNegativePromptForPromptKey(key);
        const presetInfo = tagTesterPresetInfoFromDomOrContext(
            tagTesterContextForPromptKey(key) || currentTagTesterLaunchContext(),
        );
        const outfitPrompt = normalizedOutfit
            ? outfitPromptToString(normalizedOutfit, framing, presetInfo)
            : '';
        const femalePrompt = joinPromptParts([
            mainPrompt,
            ...tagTesterFemaleRolePromptPartsFromDom(),
            outfitPrompt,
        ]);
        return {
            promptKey: key,
            characterName: cleanCharacterName,
            outfitId: cleanOutfitId,
            outfitName: cleanOutfitName,
            mainPrompt,
            negativePrompt,
            outfitPrompt,
            femalePrompt,
        };
    }

    function tagTesterPromptPayloadFromLaunchContext(context = null) {
        const launchContext = normalizeTagTesterLaunchContext(
            context || currentTagTesterLaunchContext() || {},
        );
        const promptKey = safeString(launchContext.promptKey).trim();
        if (!promptKey) return null;
        return buildTagTesterPromptPayload({
            promptKey,
            characterName: launchContext.loreTitle || launchContext.characterName,
            outfitId: launchContext.outfit?.id,
            outfitName: launchContext.outfit?.label,
            outfit: launchContext.outfit,
        });
    }

    function tagTesterPromptPayloadForReferenceCard(card = null) {
        if (!card) return tagTesterPromptPayloadFromLaunchContext();
        const promptKey = safeString(card.getAttribute('data-prompt-key')).trim();
        if (!promptKey) return tagTesterPromptPayloadFromLaunchContext();
        const outfitId = safeString(card.getAttribute('data-outfit-id')).trim();
        const referenceType = safeString(card.getAttribute('data-reference-type')).trim();
        const savedOutfit =
            referenceType === 'outfit' && outfitId
                ? findOutfitPromptById(promptKey, outfitId)
                : null;
        const launchContext = currentTagTesterLaunchContext();
        const launchOutfit = launchContext?.outfit
            ? normalizeOutfitPromptEntry(launchContext.outfit)
            : null;
        const launchOutfitId = safeString(launchOutfit?.id).trim();
        const matchesLaunchPrompt = promptKey === safeString(launchContext?.promptKey).trim();
        const contextOutfit =
            matchesLaunchPrompt && launchOutfit && (!outfitId || outfitId === launchOutfitId)
                ? launchOutfit
                : null;
        const outfit =
            (!outfitId || tagTesterLaunchContext) && contextOutfit
                ? contextOutfit
                : savedOutfit || contextOutfit || null;
        return buildTagTesterPromptPayload({
            promptKey,
            characterName:
                safeString(card.getAttribute('data-reference-character-name')).trim() ||
                characterNameForPromptKey(
                    promptKey,
                    characterPromptSourceContextForPromptKey(promptKey)?.source,
                ),
            outfitId: outfitId || contextOutfit?.id,
            outfitName:
                safeString(card.getAttribute('data-reference-outfit-name')).trim() ||
                contextOutfit?.label,
            outfit,
        });
    }

    function selectedTagTesterPromptPayloadFromDom() {
        return tagTesterPromptPayloadForReferenceCard(selectedTagTesterReferenceCardFromDom());
    }

    function buildSfwFreeDanbooruComparison(payload = {}) {
        const sfwFreeDanbooru = getSfwFreeDanbooruConfig();
        const context = normalizeTagTesterLaunchContext(currentTagTesterLaunchContext() || {});
        const contextPositiveTags = normalizeTagTesterContextTags(context.sfwFreePositiveTags);
        const contextNegativeTags = normalizeTagTesterContextTags(context.sfwFreeNegativeTags);
        const sfwFreeDanbooruEnabled = Boolean(
            context.sfwFreeEnabled || contextPositiveTags.length || contextNegativeTags.length,
        );
        const replacesPresetScene = sfwFreeDanbooruEnabled;
        const presetOnly = safeString(payload.femalePrompt).trim();
        const fixedPrompt = joinPromptParts([payload.mainPrompt, payload.outfitPrompt]);
        const positive = normalizeSfwFreeDanbooruTags(
            contextPositiveTags,
            {
                config: sfwFreeDanbooru,
                kind: 'positive',
                maxTags: SFW_FREE_DANBOORU_MAX_POSITIVE_TAGS,
                identityPrompt: payload.mainPrompt,
                outfitPrompt: payload.outfitPrompt,
                protectedPrompt: replacesPresetScene ? fixedPrompt : payload.femalePrompt,
            },
        );
        const negative = normalizeSfwFreeDanbooruTags(
            contextNegativeTags,
            {
                config: sfwFreeDanbooru,
                kind: 'negative',
                maxTags: SFW_FREE_DANBOORU_MAX_NEGATIVE_TAGS,
                protectedPrompt: payload.negativePrompt,
            },
        );
        const freeBasePrompt = replacesPresetScene ? fixedPrompt : presetOnly;
        const preservedNegative = payload.negativePrompt;
        return {
            sfwFreeDanbooruEnabled,
            replacesPresetScene,
            presetOnly,
            sfwFreeDanbooru: joinPromptParts([freeBasePrompt, positive.filteredTags.join(', ')]),
            negative: joinPromptParts([preservedNegative, negative.filteredTags.join(', ')]),
            rawPositiveTags: positive.rawTags,
            rawNegativeTags: negative.rawTags,
            filteredPositiveTags: positive.filteredTags,
            filteredNegativeTags: negative.filteredTags,
        };
    }

    function syncTagTesterPromptFromSelectedReference() {
        const payload = selectedTagTesterPromptPayloadFromDom();
        if (!payload?.femalePrompt) return null;
        const comparison = buildSfwFreeDanbooruComparison(payload);
        const nextPayload = {
            ...payload,
            femalePrompt: comparison.sfwFreeDanbooruEnabled
                ? comparison.sfwFreeDanbooru
                : comparison.presetOnly,
            negativePrompt: comparison.sfwFreeDanbooruEnabled
                ? comparison.negative
                : payload.negativePrompt,
            sfwFreeDanbooru: comparison,
        };
        const femalePrompt = document.getElementById('femalePromptOut');
        if (femalePrompt) femalePrompt.value = nextPayload.femalePrompt;
        const femaleId = document.getElementById('femaleIdOut');
        if (femaleId && nextPayload.characterName) femaleId.value = nextPayload.characterName;
        return nextPayload;
    }

    function queueTagTesterPromptSync() {
        setTimeout(() => {
            if (document.querySelector('[data-naa-tag-tester-reference-grid]'))
                syncTagTesterPromptFromSelectedReference();
        }, 0);
    }

    function setNovelAICharCaption(captions, prompt, allowEmpty = false) {
        if (!Array.isArray(captions)) return false;
        const cleanPrompt = safeString(prompt).trim();
        if (!cleanPrompt && !allowEmpty) return false;
        if (!captions[0]) {
            captions[0] = {
                char_caption: cleanPrompt,
                centers: [{ x: 0.5, y: 0.5 }],
            };
            return true;
        }
        captions[0].char_caption = cleanPrompt;
        if (!Array.isArray(captions[0].centers) || !captions[0].centers.length) {
            captions[0].centers = [{ x: 0.5, y: 0.5 }];
        }
        return true;
    }

    function applyTagTesterPromptPayloadToNovelAIBody(body = {}, payload = null) {
        const femalePrompt = safeString(payload?.femalePrompt).trim();
        if (!femalePrompt || !body?.parameters) return false;
        const parameters = body.parameters;
        const positiveCaptions = parameters.v4_prompt?.caption?.char_captions;
        const negativeCaptions = parameters.v4_negative_prompt?.caption?.char_captions;
        const appliedToV4 = setNovelAICharCaption(positiveCaptions, femalePrompt);
        setNovelAICharCaption(negativeCaptions, payload?.negativePrompt || '', true);
        if (!appliedToV4) {
            body.input = joinPromptParts([body.input, femalePrompt]);
            if (payload?.negativePrompt) {
                parameters.negative_prompt = joinPromptParts([
                    parameters.negative_prompt,
                    payload.negativePrompt,
                ]);
            }
        }
        return true;
    }

    function applySelectedTagTesterPromptToNovelAIBody(body = {}) {
        const payload = syncTagTesterPromptFromSelectedReference();
        applyTagTesterPromptPayloadToNovelAIBody(body, payload);
        return payload;
    }

    function bindTagTesterReferenceGrid(root = document) {
        const grid = root.querySelector?.('[data-naa-tag-tester-reference-grid]');
        if (!grid) return;
        grid.addEventListener('click', (event) => {
            const card = event.target?.closest?.('[data-naa-tag-tester-reference-card]');
            if (!card || !grid.contains(card)) return;
            grid.querySelectorAll('[data-naa-tag-tester-reference-card].selected').forEach(
                (selectedCard) => {
                    selectedCard.classList.remove('selected');
                    selectedCard.setAttribute('aria-checked', 'false');
                },
            );
            card.classList.add('selected');
            card.setAttribute('aria-checked', 'true');
            updateTagTesterReferenceGridStatus();
            syncTagTesterPromptFromSelectedReference();
        });
        root.querySelector?.('[data-naa-tag-tester-reference-enabled]')?.addEventListener(
            'change',
            () => {
                updateTagTesterReferenceGridStatus();
                syncTagTesterPromptFromSelectedReference();
            },
        );
        if (!tagTesterPromptSyncEventsBound) {
            document.addEventListener('click', queueTagTesterPromptSync, true);
            document.addEventListener('change', queueTagTesterPromptSync, true);
            document.addEventListener('input', queueTagTesterPromptSync, true);
            tagTesterPromptSyncEventsBound = true;
        }
        updateTagTesterReferenceGridStatus();
    }

    async function loadTagTesterReferenceGridThumbnails(root = document) {
        const cards = Array.from(
            root?.querySelectorAll?.('[data-naa-tag-tester-reference-card][data-asset-key]') || [],
        );
        for (const card of cards) {
            const asset = normalizeCharacterReferenceAsset({
                name: card.getAttribute('data-asset-name'),
                key: card.getAttribute('data-asset-key'),
                ext: card.getAttribute('data-asset-ext'),
            });
            if (!asset) continue;
            const img = card.querySelector('[data-naa-tag-tester-reference-img]');
            const status = card.querySelector('[data-naa-tag-tester-reference-status]');
            try {
                const previewUrl = await loadSettingsPreviewBlobUrlCached(asset);
                if (img) {
                    if (img.getAttribute('src') !== previewUrl) img.src = previewUrl;
                    img.removeAttribute('hidden');
                }
                if (status) {
                    status.textContent = '';
                    status.setAttribute('hidden', '');
                }
                if (card.classList.contains('selected'))
                    updateTagTesterSelectedReferencePreview(card);
            } catch (error) {
                if (status) {
                    status.textContent = '실패';
                    status.removeAttribute('hidden');
                }
                if (card.classList.contains('selected'))
                    updateTagTesterSelectedReferencePreview(card);

            }
        }
    }

    function isTagTesterRetryableNovelAIError(error) {
        const message = error?.message || String(error);
        if (error?.name === 'AbortError' || error?.code === 'REQUEST_ABORTED') return false;
        return (
            error?.name === 'TimeoutError' ||
            message.includes('HTTP 429') ||
            /Concurrent generation is locked|timed out/i.test(message)
        );
    }

    function abortTagTesterNovelAIImage(
        reason = 'Tag Tester NovelAI image request was cancelled.',
    ) {
        const controller = tagTesterNovelAIAbortController;
        if (!controller) return false;
        tagTesterNovelAIAbortController = null;
        try {
            controller.abort(
                requestAbortError(
                    reason,
                    'Tag Tester NovelAI image request was cancelled.',
                    'Tag Tester NovelAI image',
                ),
            );
        } catch (_) {
            try {
                controller.abort();
            } catch (_) {}
        }

        return true;
    }

    async function setPromptSeedSetting(promptKey, seed, fixed) {
        const key = safeString(promptKey).trim();
        if (!key) return null;
        const cleanSeed = normalizeNovelAISeed(seed);
        const promptConfig = getCharacterPromptConfig();
        promptConfig.seedSettings ||= {};
        if (cleanSeed || fixed) {
            promptConfig.seedSettings[key] = {
                seed: cleanSeed,
                fixed: Boolean(fixed && cleanSeed),
            };
        } else {
            delete promptConfig.seedSettings[key];
        }
        await saveConfig();
        return promptConfig.seedSettings[key] || { seed: '', fixed: false };
    }

    function validateSfwFreeAnalyzerDecision(
        image,
        token,
        index,
        lorebookPromptKey,
        requestedLorebookPromptKey,
        previousBackgroundTags,
        freeDanbooruConfig,
    ) {
        const sourceImageMarkup = safeString(token.inner || token.full).trim();
        const requestedOutfitId = safeString(image?.outfit_id || image?.outfitId).trim();
        const outfitId =
            lorebookPromptKey && findOutfitPromptById(lorebookPromptKey, requestedOutfitId)
                ? requestedOutfitId
                : '';
        const sfwFreeCompositionId = normalizeSfwFreeCompositionId(
            image?.sfw_free_composition_id ||
                image?.sfwFreeCompositionId ||
                image?.composition_id ||
                image?.compositionId,
        );
        const sfwFreeCompositionPrompt = compositionPromptForId(sfwFreeCompositionId);
        const sceneBackgroundTags =
            normalizeSceneBackgroundTags(
                image?.scene_background_tags ||
                    image?.sceneBackgroundTags ||
                    image?.background_tags ||
                    image?.backgroundTags,
            ) || [];
        const effectiveSceneBackgroundTags = sceneBackgroundTags.length
            ? sceneBackgroundTags
            : normalizeSceneBackgroundTags(previousBackgroundTags);
        const sfwFreeCharacterPrompt = normalizeSfwFreeCharacterPrompt(
            image?.sfw_free_character_prompt,
            {
                config: freeDanbooruConfig,
                allowNsfwTags: false,
            },
        );
        const sfwFreePositive = normalizeSfwFreeDanbooruTags(
            [
                ...effectiveSceneBackgroundTags,
                ...normalizeDanbooruTagList(image?.sfw_free_positive_tags),
            ],
            {
                config: freeDanbooruConfig,
                kind: 'positive',
                maxTags: SFW_FREE_DANBOORU_MAX_POSITIVE_TAGS,
                allowNsfwTags: false,
            },
        );
        const sfwFreeNegative = normalizeSfwFreeDanbooruTags(
            image?.sfw_free_negative_tags,
            {
                config: freeDanbooruConfig,
                kind: 'negative',
                maxTags: SFW_FREE_DANBOORU_MAX_NEGATIVE_TAGS,
            },
        );
        return {
            source_image_token: token.tokenName,
            source_image_markup: sourceImageMarkup,
            source_image_markup_type: token.markupType,
            source_image_marker_id: imageTokenOccurrenceId(token, index),
            character_name: safeString(image?.character_name || token.characterName).trim(),
            lorebook_prompt_key: lorebookPromptKey,
            requested_lorebook_prompt_key: requestedLorebookPromptKey,
            outfit_id: outfitId,
            requested_outfit_id: requestedOutfitId,
            decision: 'generate',
            preset_id: 'sfw_free',
            preset_key: 'sfw_free',
            preset_path: 'sfw.free',
            rating_id: 'sfw',
            composition_id: sfwFreeCompositionId,
            composition_prompt: sfwFreeCompositionPrompt,
            sfw_free_composition_id: sfwFreeCompositionId,
            comp: {},
            comp_items: [],
            modifiers: {},
            modifier_items: [],
            sex_scene_state: 'none',
            visual_continuity_clear: [],
            visual_continuity_counts: {},
            scene_background_tags: effectiveSceneBackgroundTags,
            nsfw_scene_location_tag: '',
            sfw_free_character_prompt: freeDanbooruConfig.enabled
                ? sfwFreeCharacterPrompt.filteredPrompt
                : emptySfwFreeCharacterPrompt(),
            sfw_free_character_prompt_raw: sfwFreeCharacterPrompt.rawPrompt,
            sfw_free_character_prompt_removed: sfwFreeCharacterPrompt.removedPrompt,
            sfw_free_positive_tags: freeDanbooruConfig.enabled
                ? sfwFreePositive.filteredTags
                : [],
            sfw_free_negative_tags: freeDanbooruConfig.enabled
                ? sfwFreeNegative.filteredTags
                : [],
            sfw_free_positive_tags_raw: sfwFreePositive.rawTags,
            sfw_free_negative_tags_raw: sfwFreeNegative.rawTags,
            sfw_free_positive_tags_removed: sfwFreePositive.removedTags,
            sfw_free_negative_tags_removed: sfwFreeNegative.removedTags,
            sfw_free_danbooru: {
                enabled: freeDanbooruConfig.enabled,
                mode: freeDanbooruConfig.mode,
                compositionId: sfwFreeCompositionId,
                compositionPrompt: sfwFreeCompositionPrompt,
            },
            reason: safeString(image?.reason).trim(),
            negative_prompt_extra: safeString(image?.negative_prompt_extra).trim(),
        };
    }

    function validateAnalyzerImagePlan(
        result,
        catalog,
        imageTokens,
        identityCandidates = [],
        options = {},
    ) {
        if (!result || typeof result !== 'object')
            throw new Error('Analyzer image plan is not an object.');
        const tokens = Array.isArray(imageTokens) ? imageTokens : [];
        const identityCandidateList = Array.isArray(identityCandidates) ? identityCandidates : [];
        const identityKeySet = new Set(
            identityCandidateList
                .map((candidate) => safeString(candidate?.key).trim())
                .filter(Boolean),
        );
        const images = Array.isArray(result.images) ? result.images : [];
        const previousBackgroundTags =
            options?.visualContinuity?.previousBackgroundTags ||
            options?.previousBackgroundTags ||
            [];
        if (!images.length && tokens.length > 0)
            throw new Error('Analyzer returned no image decisions.');
        if (images.length !== tokens.length)
            throw new Error(
                `Analyzer returned ${images.length} image decisions for ${tokens.length} image tokens.`,
            );
        const usedTokenIndexes = new Set();
        return {
            images: images.map((image, index) => {
                const sourceImageToken = safeString(
                    image?.source_image_token || tokens[index]?.tokenName || '',
                ).trim();
                const token = resolveAnalyzerDecisionToken(
                    tokens,
                    sourceImageToken,
                    index,
                    usedTokenIndexes,
                );
                if (!token) throw new Error(`Unknown source_image_token: ${sourceImageToken}`);
                const presetId = safeString(image?.preset_id).trim();
                const requestedLorebookPromptKey = safeString(image?.lorebook_prompt_key).trim();
                let lorebookPromptKey =
                    requestedLorebookPromptKey && identityKeySet.has(requestedLorebookPromptKey)
                        ? requestedLorebookPromptKey
                        : '';
                if (!lorebookPromptKey) {
                    const matchedIdentity = findIdentityPromptForImageDecision(
                        {
                            source_image_token: token.tokenName,
                            character_name: safeString(
                                image?.character_name || token.characterName,
                            ).trim(),
                        },
                        identityCandidateList,
                    );
                    lorebookPromptKey = safeString(matchedIdentity?.key).trim();
                }
                const sfwFreeDecisionConfig =
                    sfwFreeDanbooruConfigForPromptKey(lorebookPromptKey);
                if (isSfwFreeAnalyzerDecision({ preset_id: presetId })) {
                    if (!sfwFreeDecisionConfig.enabled)
                        throw new Error('SFW free analyzer decision returned while disabled.');
                    return validateSfwFreeAnalyzerDecision(
                        image,
                        token,
                        index,
                        lorebookPromptKey,
                        requestedLorebookPromptKey,
                        previousBackgroundTags,
                        sfwFreeDecisionConfig,
                    );
                }
                const presetInfo = findTreePreset(catalog, presetId, {
                    ratingId: image?.rating_id,
                    compositionId: image?.composition_id,
                    pathString: image?.preset_path,
                });
                if (!presetInfo) throw new Error(`Unknown preset_id: ${presetId}`);
                const sfwFreeConfig = freeDanbooruConfigForPresetInfo(
                    presetInfo,
                    effectiveCharxScopedSettingsForPromptKey(lorebookPromptKey),
                );
                if (isSfwPresetInfo(presetInfo) && sfwFreeConfig.enabled) {
                    return validateSfwFreeAnalyzerDecision(
                        image,
                        token,
                        index,
                        lorebookPromptKey,
                        requestedLorebookPromptKey,
                        previousBackgroundTags,
                        sfwFreeConfig,
                    );
                }
                const applicableComps = applicableCompGroups(catalog, presetInfo);
                const localModifierGroups = normalizeModifierGroups(presetInfo.node?.modifiers, {
                    source: 'local',
                });
                const requestedComp = isPlainObject(image?.comp) ? image.comp : {};
                const requestedModifiers = isPlainObject(image?.modifiers) ? image.modifiers : {};
                const requestedOutfitId = safeString(image?.outfit_id || image?.outfitId).trim();
                let outfitId =
                    lorebookPromptKey && findOutfitPromptById(lorebookPromptKey, requestedOutfitId)
                        ? requestedOutfitId
                        : '';
                const catalogOutfitSelection = outfitId
                    ? null
                    : findCatalogOutfitCompSelection(catalog, requestedOutfitId, presetInfo);
                const comp = {};
                const compItems = [];
                for (const { key, group } of applicableComps) {
                    const item = selectCompListItem(group, requestedComp[key], presetInfo);
                    if (Array.isArray(item)) {
                        comp[key] = item.map((entry) => entry.id);
                        compItems.push(
                            ...item
                                .map((entry) =>
                                    resolvedModifierSelectionEntry(entry, group, 'global'),
                                )
                                .filter(Boolean),
                        );
                        continue;
                    }
                    if (!item) continue;
                    comp[key] = item.id;
                    const resolved = resolvedModifierSelectionEntry(item, group, 'global');
                    if (resolved) compItems.push(resolved);
                }
                if (catalogOutfitSelection) {
                    outfitId = requestedOutfitId;
                    comp[catalogOutfitSelection.key] = catalogOutfitSelection.item.id;
                    const resolved = resolvedModifierSelectionEntry(
                        catalogOutfitSelection.item,
                        catalogOutfitSelection.group,
                        'global',
                    );
                    if (resolved) compItems.push(resolved);
                }
                const modifiers = {};
                const modifierItems = [];
                for (const group of localModifierGroups) {
                    const key = safeString(group.id).trim();
                    if (!key) continue;
                    const item = selectCompListItem(group, requestedModifiers[key], presetInfo);
                    if (Array.isArray(item)) {
                        modifiers[key] = item.map((entry) => entry.id);
                        modifierItems.push(
                            ...item
                                .map((entry) =>
                                    resolvedModifierSelectionEntry(
                                        {
                                            ...entry,
                                            exclude_variant_id: cameraExclusionForSelectedComp(
                                                group,
                                                entry,
                                            ),
                                        },
                                        group,
                                        'local',
                                    ),
                                )
                                .filter(Boolean),
                        );
                        continue;
                    }
                    if (!item) continue;
                    modifiers[key] = item.id;
                    const resolved = resolvedModifierSelectionEntry(
                        {
                            ...item,
                            exclude_variant_id: cameraExclusionForSelectedComp(group, item),
                        },
                        group,
                        'local',
                    );
                    if (resolved) modifierItems.push(resolved);
                }
                const sourceImageMarkup = safeString(token.inner || token.full).trim();
                const nsfwSceneEligible = isNsfwPresetInfo(presetInfo);
                const nsfwSceneLocationTag = nsfwSceneEligible
                    ? normalizeNsfwSceneLocationTag(image?.nsfw_scene_location_tag, presetInfo)
                    : '';
                const sceneBackgroundTags =
                    normalizeSceneBackgroundTags(
                        image?.scene_background_tags ||
                            image?.sceneBackgroundTags ||
                            image?.background_tags ||
                            image?.backgroundTags,
                    ) || [];
                const effectiveSceneBackgroundTags = sceneBackgroundTags.length
                    ? sceneBackgroundTags
                    : normalizeSceneBackgroundTags(previousBackgroundTags);
                const freeDanbooruConfig = sfwFreeConfig;
                const sfwFreeEligible = freeDanbooruConfig.enabled;
                const sfwFreeCharacterPrompt = normalizeSfwFreeCharacterPrompt(
                    image?.sfw_free_character_prompt,
                    {
                        config: freeDanbooruConfig,
                        allowNsfwTags: freeDanbooruConfig.allowNsfwTags,
                    },
                );
                const sfwFreePositiveSource = [
                    ...effectiveSceneBackgroundTags,
                    ...normalizeDanbooruTagList(image?.sfw_free_positive_tags),
                ];
                const sfwFreePositive = normalizeSfwFreeDanbooruTags(
                    sfwFreePositiveSource,
                    {
                        config: freeDanbooruConfig,
                        kind: 'positive',
                        maxTags: SFW_FREE_DANBOORU_MAX_POSITIVE_TAGS,
                        allowNsfwTags: freeDanbooruConfig.allowNsfwTags,
                    },
                );
                const sfwFreeNegative = normalizeSfwFreeDanbooruTags(
                    image?.sfw_free_negative_tags,
                    {
                        config: freeDanbooruConfig,
                        kind: 'negative',
                        maxTags: SFW_FREE_DANBOORU_MAX_NEGATIVE_TAGS,
                    },
                );
                return {
                    source_image_token: token.tokenName,
                    source_image_markup: sourceImageMarkup,
                    source_image_markup_type: token.markupType,
                    source_image_marker_id: imageTokenOccurrenceId(token, index),
                    character_name: safeString(image?.character_name || token.characterName).trim(),
                    lorebook_prompt_key: lorebookPromptKey,
                    requested_lorebook_prompt_key: requestedLorebookPromptKey,
                    outfit_id: outfitId,
                    requested_outfit_id: requestedOutfitId,
                    decision: 'generate',
                    preset_id: presetInfo.id,
                    preset_key: presetInfo.key,
                    preset_path: presetInfo.pathString,
                    rating_id: presetInfo.ratingId,
                    composition_id: presetInfo.compositionId,
                    composition_prompt: presetInfo.compositionPrompt,
                    comp,
                    comp_items: compItems,
                    modifiers,
                    modifier_items: modifierItems,
                    sex_scene_state: normalizeVisualContinuitySexSceneState(
                        image?.sex_scene_state,
                    ),
                    visual_continuity_clear: normalizeVisualContinuityClearIds(
                        image?.visual_continuity_clear,
                    ),
                    visual_continuity_counts: normalizeVisualContinuityCountDeltas(
                        image?.visual_continuity_counts ||
                            image?.visual_continuity_count_delta,
                    ),
                    scene_background_tags: effectiveSceneBackgroundTags,
                    nsfw_scene_location_tag: nsfwSceneLocationTag,
                    sfw_free_character_prompt: sfwFreeEligible
                        ? sfwFreeCharacterPrompt.filteredPrompt
                        : emptySfwFreeCharacterPrompt(),
                    sfw_free_character_prompt_raw: sfwFreeCharacterPrompt.rawPrompt,
                    sfw_free_character_prompt_removed: sfwFreeCharacterPrompt.removedPrompt,
                    sfw_free_positive_tags: sfwFreeEligible ? sfwFreePositive.filteredTags : [],
                    sfw_free_negative_tags: sfwFreeEligible ? sfwFreeNegative.filteredTags : [],
                    sfw_free_positive_tags_raw: sfwFreePositive.rawTags,
                    sfw_free_negative_tags_raw: sfwFreeNegative.rawTags,
                    reason: safeString(image?.reason).trim(),
                    negative_prompt_extra: safeString(image?.negative_prompt_extra).trim(),
                };
            }),
        };
    }

    function normalizeTurnMessageTextForAnalyzer(messageOrText) {
        const text =
            messageOrText && typeof messageOrText === 'object'
                ? safeString(messageOrText?.data || messageOrText?.content)
                : safeString(messageOrText);
        return stripImageTokenMarkers(text).slice(0, 1600).trim();
    }

    function isAssistantChatRole(role) {
        const cleanRole = safeString(role).trim().toLowerCase();
        return (
            cleanRole === 'char' ||
            cleanRole === 'assistant' ||
            cleanRole === 'bot' ||
            cleanRole === 'model'
        );
    }

    function isUserChatRole(role) {
        const cleanRole = safeString(role).trim().toLowerCase();
        return cleanRole === 'user' || cleanRole === 'human';
    }

    function focusedTurnMessagesForAnalyzer(
        messages,
        currentMessageIndex = -1,
        latestAssistantResponse = '',
    ) {
        const list = Array.isArray(messages) ? messages : [];
        const explicitIndex = Number(currentMessageIndex);
        const boundary =
            Number.isInteger(explicitIndex) && explicitIndex >= 0 && explicitIndex <= list.length
                ? explicitIndex
                : list.length;
        let currentUserIndex = -1;
        let currentUserInput = '';
        for (let index = boundary - 1; index >= 0; index--) {
            const message = list[index];
            if (!isUserChatRole(message?.role || message?.type)) continue;
            const text = normalizeTurnMessageTextForAnalyzer(message);
            if (!text) continue;
            currentUserIndex = index;
            currentUserInput = text;
            break;
        }
        const previousAssistantBoundary = currentUserIndex >= 0 ? currentUserIndex : boundary;
        let previousAssistantResponse = '';
        for (let index = previousAssistantBoundary - 1; index >= 0; index--) {
            const message = list[index];
            if (!isAssistantChatRole(message?.role || message?.type)) continue;
            const text = normalizeTurnMessageTextForAnalyzer(message);
            if (!text) continue;
            previousAssistantResponse = text;
            break;
        }
        return {
            previousAssistantResponse,
            currentUserInput,
            latestAssistantResponse: normalizeTurnMessageTextForAnalyzer(latestAssistantResponse),
        };
    }

    const IMAGE_TOKEN_EXTENSION_REGEX = /\.(?:png|jpe?g|webp|gif|avif|bmp|tiff?)$/i;
    const IDENTITY_NAME_SEPARATOR_REGEX = /[\s._()[\]{}<>'"?:,;|\/\\+&=~!@#$%^*`-]+/g;

    function imageTokenFileStem(value) {
        let text = safeString(value).trim();
        if (!text) return '';
        text = text.replace(/[?#].*$/g, '');
        const segments = text.split(/[\\/]+/g).filter(Boolean);
        if (segments.length) text = segments[segments.length - 1];
        return text.replace(IMAGE_TOKEN_EXTENSION_REGEX, '').trim();
    }

    function normalizedImageTokenAlias(value) {
        return imageTokenFileStem(value)
            .toLocaleLowerCase()
            .replace(IDENTITY_NAME_SEPARATOR_REGEX, ' ')
            .replace(/\s+/g, ' ')
            .trim();
    }

    const ACTIVE_MODULE_ASSET_TOKEN_CACHE_MS = 2500;
    let activeModuleAssetTokenCache = {
        at: 0,
        tokens: new Set(),
        moduleCount: 0,
        assetCount: 0,
    };

    function normalizedModuleAssetTokenAlias(value) {
        return safeString(value).trim().toLowerCase();
    }

    function moduleAssetTokenAliases(value) {
        const raw = safeString(value).trim();
        const stem = imageTokenFileStem(raw);
        return uniqueStringList([raw, stem]).map(normalizedModuleAssetTokenAlias).filter(Boolean);
    }

    function pushModuleId(ids, value) {
        const id = safeString(value).trim();
        if (id) ids.push(id);
    }

    function collectModuleIdsFromCharacter(character, chatIndex) {
        const ids = [];
        (Array.isArray(character?.modules) ? character.modules : []).forEach((id) =>
            pushModuleId(ids, id),
        );
        const chats = Array.isArray(character?.chats) ? character.chats : [];
        const preferredChatIndex =
            Number.isInteger(chatIndex) && chatIndex >= 0 ? chatIndex : Number(character?.chatPage);
        const chat =
            Number.isInteger(preferredChatIndex) && preferredChatIndex >= 0
                ? chats[preferredChatIndex]
                : null;
        (Array.isArray(chat?.modules) ? chat.modules : []).forEach((id) => pushModuleId(ids, id));
        return ids;
    }

    async function loadActiveModuleAssetTokenSet() {
        const now = Date.now();
        if (now - activeModuleAssetTokenCache.at < ACTIVE_MODULE_ASSET_TOKEN_CACHE_MS)
            return activeModuleAssetTokenCache.tokens;
        const tokens = new Set();
        let moduleCount = 0;
        let assetCount = 0;
        try {
            const db =
                typeof Risu.getDatabase === 'function'
                    ? await Risu.getDatabase([
                          'modules',
                          'enabledModules',
                          'moduleIntergration',
                          'moduleIntegration',
                      ])
                    : null;
            const modules = Array.isArray(db?.modules) ? db.modules : [];
            const activeIds = [];
            (Array.isArray(db?.enabledModules) ? db.enabledModules : []).forEach((id) =>
                pushModuleId(activeIds, id),
            );
            const integrationText = safeString(db?.moduleIntergration || db?.moduleIntegration);
            integrationText
                .split(',')
                .map((id) => id.trim())
                .filter(Boolean)
                .forEach((id) => pushModuleId(activeIds, id));
            const character = await getCurrentCharacterSnapshot();
            const chatIndex = await getSafeCurrentChatIndex();
            collectModuleIdsFromCharacter(character, chatIndex).forEach((id) =>
                pushModuleId(activeIds, id),
            );
            const activeIdSet = new Set(activeIds);
            for (const module of modules) {
                const moduleId = safeString(module?.id).trim();
                const namespace = safeString(module?.namespace).trim();
                if (!activeIdSet.has(moduleId) && (!namespace || !activeIdSet.has(namespace)))
                    continue;
                moduleCount += 1;
                for (const asset of Array.isArray(module?.assets) ? module.assets : []) {
                    const name = safeString(asset?.[0] || asset?.name).trim();
                    if (!name) continue;
                    assetCount += 1;
                    moduleAssetTokenAliases(name).forEach((alias) => tokens.add(alias));
                }
            }
        } catch (error) {

        }
        activeModuleAssetTokenCache = { at: now, tokens, moduleCount, assetCount };
        return tokens;
    }

    function imageTokenMatchesActiveModuleAsset(token, moduleAssetTokens) {
        if (safeString(token?.markupType).trim() === 'charx_regex') return false;
        if (!moduleAssetTokens?.size) return false;
        return moduleAssetTokenAliases(token?.tokenName || token).some((alias) =>
            moduleAssetTokens.has(alias),
        );
    }

    function filterPluginProcessableImageTokens(tokens = [], moduleAssetTokens = new Set()) {
        return (Array.isArray(tokens) ? tokens : [])
            .filter(isProcessableImageToken)
            .filter((token) => !imageTokenMatchesActiveModuleAsset(token, moduleAssetTokens));
    }

    function imageTokenCharacterName(tokenName) {
        const clean = imageTokenFileStem(tokenName);
        const firstSegment = splitIdentityWords(clean)[0] || clean;
        return firstSegment.trim();
    }

    function parseImageTokenCharacterName(tokenName) {
        return imageTokenCharacterName(tokenName);
    }

    function createImageTokenMarkerId() {
        imageTokenMarkerCounter = (imageTokenMarkerCounter + 1) % 1000000;
        return `${Date.now().toString(36)}_${imageTokenMarkerCounter.toString(36)}_${Math.random()
            .toString(36)
            .slice(2, 7)}`;
    }

    function imageTokenOccurrenceId(token = {}, fallbackIndex = 0) {
        const markerId = safeString(token?.markerId).trim();
        if (markerId) return markerId;
        const index = Number.isFinite(Number(token?.index))
            ? Number(token.index)
            : Number.isFinite(Number(fallbackIndex))
              ? Number(fallbackIndex)
              : 0;
        const offset = Number.isFinite(Number(token?.offset)) ? Number(token.offset) : index;
        const tokenName = safeString(token?.tokenName).trim();
        const sourceMarkup = safeString(token?.inner || token?.full || tokenName).trim();
        const contextHash = stableStringHash(
            [
                tokenName,
                sourceMarkup,
                safeString(token?.before).slice(-120),
                safeString(token?.after).slice(0, 120),
                offset,
            ].join('|'),
        );
        return `occ:${index}:${offset}:${contextHash}`;
    }

    function resolveAnalyzerDecisionToken(
        tokens = [],
        sourceImageToken = '',
        decisionIndex = 0,
        usedTokenIndexes = null,
    ) {
        const list = Array.isArray(tokens) ? tokens : [];
        const cleanSourceImageToken = safeString(sourceImageToken).trim();
        const used = usedTokenIndexes instanceof Set ? usedTokenIndexes : null;
        const markAndReturn = (token, index) => {
            if (token && used && Number.isInteger(index) && index >= 0) used.add(index);
            return token || null;
        };
        const indexedToken = list[decisionIndex] || null;
        if (
            indexedToken &&
            (!cleanSourceImageToken ||
                safeString(indexedToken.tokenName).trim() === cleanSourceImageToken) &&
            (!used || !used.has(decisionIndex))
        ) {
            return markAndReturn(indexedToken, decisionIndex);
        }
        const exactIndex = list.findIndex(
            (token, index) =>
                (!used || !used.has(index)) &&
                safeString(token?.tokenName).trim() === cleanSourceImageToken,
        );
        if (exactIndex >= 0) return markAndReturn(list[exactIndex], exactIndex);
        if (indexedToken && (!used || !used.has(decisionIndex))) {
            return markAndReturn(indexedToken, decisionIndex);
        }
        const fallbackIndex = list.findIndex((_token, index) => !used || !used.has(index));
        return fallbackIndex >= 0 ? markAndReturn(list[fallbackIndex], fallbackIndex) : null;
    }

    function markerMetaValue(value) {
        return encodeURIComponent(
            safeString(value)
                .trim()
                .replace(/[\r\n]+/g, ' '),
        );
    }

    function unmarkerMetaValue(value) {
        try {
            return decodeURIComponent(safeString(value));
        } catch (_) {
            return safeString(value);
        }
    }

    function parseImageTokenMarkerMeta(rawMeta) {
        const meta = {};
        const text = safeString(rawMeta).trim();
        if (!text) return meta;
        for (const part of text.split('|')) {
            const clean = safeString(part).trim();
            if (!clean) continue;
            const eqIndex = clean.indexOf('=');
            if (eqIndex < 0) {
                if (!meta.id) meta.id = unmarkerMetaValue(clean);
                continue;
            }
            const key = clean.slice(0, eqIndex).trim();
            const value = clean.slice(eqIndex + 1).trim();
            if (key) meta[key] = unmarkerMetaValue(value);
        }
        return meta;
    }

    function imageTokenMarkerOpen(meta = {}) {
        const parts = [];
        if (meta.id) parts.push(`id=${markerMetaValue(meta.id)}`);
        if (meta.asset) parts.push(`asset=${markerMetaValue(meta.asset)}`);
        const suffix = parts.length ? `|${parts.join('|')}` : '';
        return `<!--${NAA_IMAGE_TOKEN_MARKER_PREFIX}${suffix}-->`;
    }

    function imageTokenMarkerBlockRegex() {
        return new RegExp(
            `<!--\\s*${NAA_IMAGE_TOKEN_MARKER_PREFIX}((?:\\|[^>]*)?)\\s*-->([\\s\\S]*?)<!--\\s*\\/${NAA_IMAGE_TOKEN_MARKER_PREFIX}\\s*-->`,
            'giu',
        );
    }

    const RISU_IMAGE_TOKEN_COMMAND_PATTERN = 'image|asset|img';

    function originalImageMarkupRegex() {
        return new RegExp(
            `\\{\\{(?:${RISU_IMAGE_TOKEN_COMMAND_PATTERN})::[^}]+\\}\\}|<img\\s+src\\s*=\\s*(?:"[^"]+"|'[^']+'|[^>\\s]+)\\s*\\/?>|<img\\s*=\\s*(?:"[^"]+"|'[^']+'|[^>\\s]+)\\s*\\/?>`,
            'giu',
        );
    }

    function hasOriginalImageMarkup(content, options = {}) {
        const text = safeString(content);
        if (originalImageMarkupRegex().test(text)) return true;
        return Boolean(
            collectCharxRegexImageTokenMatches(
                text,
                options.customImageTokenDetectors,
                [],
            ).length,
        );
    }

    function charxRegexScriptFlags(script = {}) {
        let flag = script?.ableFlag ? safeString(script.flag || 'g') : 'g';
        flag = flag.trim().replace(/[^dgimsuvy]/g, '');
        flag = flag
            .split('')
            .filter((value, index, values) => values.indexOf(value) === index)
            .join('');
        return flag || 'u';
    }

    function charxRegexAssetAliasSamples(assetAliases = null, limit = 8) {
        if (!(assetAliases instanceof Map)) return [];
        return Array.from(assetAliases.keys()).slice(0, Math.max(1, Number(limit) || 8));
    }



    function renderCharxRegexTemplate(template = '', match = []) {
        const literalDollar = '\u0000NAA_DOLLAR\u0000';
        return safeString(template)
            .replaceAll('$n', '\n')
            .replace(/\$\$/g, literalDollar)
            .replace(/\$&/g, safeString(match?.[0]))
            .replace(/\$<([^>]+)>/g, (full, name) => {
                const value = match?.groups?.[safeString(name).trim()];
                return value === undefined ? full : safeString(value);
            })
            .replace(/\$(\d+)/g, (full, indexText) => {
                const index = Number(indexText);
                return Number.isInteger(index) && index < match.length
                    ? safeString(match[index])
                    : full;
            })
            .replaceAll(literalDollar, '$');
    }

    function charxRegexAssetAliasKey(value = '') {
        return safeString(value).trim().toLowerCase();
    }

    function charxRegexAssetAliasMap(assets = []) {
        const map = new Map();
        const addAlias = (alias, assetName) => {
            const cleanAlias = safeString(alias).trim();
            const cleanAssetName = safeString(assetName).trim();
            const key = charxRegexAssetAliasKey(cleanAlias);
            if (key && cleanAssetName && !map.has(key)) map.set(key, cleanAssetName);
        };
        for (const asset of Array.isArray(assets) ? assets : []) {
            const name = safeString(asset?.[0] || asset?.name).trim();
            if (!name) continue;
            const ext = safeString(asset?.[2] || '').trim().replace(/^\./, '');
            addAlias(name, name);
            addAlias(imageTokenFileStem(name), name);
            if (ext && !safeString(name).toLowerCase().endsWith(`.${ext.toLowerCase()}`)) {
                addAlias(`${name}.${ext}`, name);
            }
        }
        return map;
    }

    function resolveCharxRegexAssetRef(ref = '', assetAliases = new Map()) {
        const cleanRef = safeString(ref)
            .trim()
            .replace(/[?#].*$/g, '')
            .replace(/^['"]|['"]$/g, '');
        if (!cleanRef || !(assetAliases instanceof Map) || !assetAliases.size) return null;
        const candidates = [
            cleanRef,
            cleanRef.split(/[\\/]+/g).filter(Boolean).pop() || '',
            imageTokenFileStem(cleanRef),
        ];
        for (const candidate of candidates) {
            const key = charxRegexAssetAliasKey(candidate);
            if (key && assetAliases.has(key)) {
                return {
                    tokenName: cleanRef,
                    assetName: assetAliases.get(key),
                };
            }
        }
        return null;
    }

    function charxAssetRegexCharacterId(character = {}) {
        return safeString(character?.chaId || character?.id || character?.name).trim();
    }

    function charxAssetRegexStrictCharacterId(character = {}) {
        return safeString(character?.chaId || character?.id).trim();
    }

    function charxAssetRegexScriptSignature(customscript = []) {
        const scripts = (Array.isArray(customscript) ? customscript : []).map((script, index) => ({
            index,
            in: safeString(script?.in),
            out: safeString(script?.out),
            flag: safeString(script?.flag),
            ableFlag: Boolean(script?.ableFlag),
            type: safeString(script?.type),
            comment: safeString(script?.comment || script?.name),
        }));
        return stableStringHash(JSON.stringify(scripts));
    }

    function normalizeCharxAssetRegexAnalysisRecord(record = {}) {
        const source =
            record && typeof record === 'object' && !Array.isArray(record) ? record : {};
        const status = safeString(source.status || '').trim() || 'not_applicable';
        const detectors = (Array.isArray(source.detectors) ? source.detectors : [])
            .map((detector) => {
                const scriptIndex = Number(detector?.scriptIndex ?? detector?.script_index);
                const input = safeString(detector?.in).trim();
                const assetTemplate = safeString(
                    detector?.assetTemplate || detector?.asset_template,
                ).trim();
                return {
                    scriptIndex: Number.isInteger(scriptIndex) ? scriptIndex : -1,
                    in: input,
                    assetTemplate,
                };
            })
            .filter(
                (detector) =>
                    detector.scriptIndex >= 0 && detector.in && detector.assetTemplate,
            );
        return {
            status,
            analyzedAt: safeString(source.analyzedAt || source.analyzed_at).trim(),
            scriptSignature: safeString(
                source.scriptSignature || source.script_signature,
            ).trim(),
            detectors,
            error: safeString(source.error).trim(),
        };
    }

    function charxAssetRegexAnalysisMap(analysisMap = null) {
        if (analysisMap && typeof analysisMap === 'object' && !Array.isArray(analysisMap))
            return analysisMap;
        if (typeof getCharacterPromptConfig === 'function') {
            return getCharacterPromptConfig().charxAssetRegexAnalysis || {};
        }
        return {};
    }

    function charxAssetRegexAnalysisRecordForCharacter(character = {}, analysisMap = null) {
        const id = charxAssetRegexCharacterId(character);
        if (!id) return normalizeCharxAssetRegexAnalysisRecord({});
        return normalizeCharxAssetRegexAnalysisRecord(charxAssetRegexAnalysisMap(analysisMap)[id]);
    }

    function charxAssetRegexAnalysisRecordExists(targetOrId = '', analysisMap = null) {
        const id = safeString(
            typeof targetOrId === 'string' ? targetOrId : targetOrId?.id,
        ).trim();
        if (!id) return false;
        const map = charxAssetRegexAnalysisMap(analysisMap);
        return Object.prototype.hasOwnProperty.call(map, id);
    }

    function buildCharxRegexImageTokenDetectors(character = {}, analysisMap = null) {
        if (!character || safeString(character.type).trim() === 'group') return [];
        const characterId = charxAssetRegexCharacterId(character);
        const characterName = getCharacterName(character, 'Unnamed');
        const scripts = Array.isArray(character.customscript) ? character.customscript : [];
        const record = charxAssetRegexAnalysisRecordForCharacter(character, analysisMap);
        const currentScriptSignature = charxAssetRegexScriptSignature(scripts);
        const buildDebugBase = {
            characterId,
            characterName,
            recordStatus: record.status,
            detectorSpecCount: Array.isArray(record.detectors) ? record.detectors.length : 0,
            scriptCount: scripts.length,
            storedScriptSignature: record.scriptSignature,
            currentScriptSignature,
        };
        if (record.status !== 'done') {

            return [];
        }
        if (record.scriptSignature !== currentScriptSignature) {

            return [];
        }
        const assetAliases = charxRegexAssetAliasMap(character.additionalAssets);
        const detectors = [];
        for (const spec of record.detectors) {
            const script = scripts[spec.scriptIndex];
            const input = safeString(spec.in).trim();
            if (!script || !input || input !== safeString(script?.in).trim()) {

                continue;
            }
            let regex = null;
            const flags = charxRegexScriptFlags(script);
            try {
                regex = new RegExp(input, flags);
            } catch (error) {

                continue;
            }
            detectors.push({
                scriptName: safeString(script?.comment || script?.name).trim() || `regex_${detectors.length + 1}`,
                regex,
                assetTemplate: spec.assetTemplate,
                assetAliases,
            });
        }

        return detectors;
    }

    async function loadCurrentCharxRegexImageTokenDetectors(latest = null) {
        const character = latest?.character || (await getCurrentCharacterSnapshot());
        return buildCharxRegexImageTokenDetectors(
            character,
            getCharacterPromptConfig().charxAssetRegexAnalysis,
        );
    }

    function charxRegexImageTokenFromMatch(detector = {}, match = []) {
        const assetRef = renderCharxRegexTemplate(detector.assetTemplate, match);
        const resolved = resolveCharxRegexAssetRef(assetRef, detector.assetAliases);
        const tokenName = safeString(resolved?.assetName || assetRef).trim();
        if (!tokenName) return null;
        return {
            full: safeString(match?.[0]),
            tokenName,
            markupType: 'charx_regex',
            characterName: imageTokenCharacterName(tokenName),
            charxRegexScriptName: safeString(detector.scriptName).trim(),
            charxRegexAssetName: safeString(resolved?.assetName || tokenName).trim(),
        };
    }

    function rangeOverlapsAny(start, end, ranges = []) {
        return (Array.isArray(ranges) ? ranges : []).some(
            ([rangeStart, rangeEnd]) => start < rangeEnd && end > rangeStart,
        );
    }

    function collectCharxRegexImageTokenMatches(
        content,
        detectors = [],
        protectedRanges = [],
    ) {
        const text = safeString(content);
        const matches = [];
        const detectorList = Array.isArray(detectors) ? detectors : [];
        for (const detector of detectorList) {
            if (!(detector?.regex instanceof RegExp)) continue;
            const regex = new RegExp(detector.regex.source, detector.regex.flags);
            let match;
            while ((match = regex.exec(text))) {
                const full = safeString(match[0]);
                const offset = match.index;
                const end = offset + full.length;
                const protectedOverlap = full && rangeOverlapsAny(offset, end, protectedRanges);
                if (!protectedOverlap && full) {
                    const parsed = charxRegexImageTokenFromMatch(detector, match);
                    if (parsed) {
                        matches.push({
                            ...parsed,
                            offset,
                            end,
                        });
                    }
                }
                if (!regex.global && !regex.sticky) {
                    break;
                }
                if (!full) regex.lastIndex += 1;
            }
        }
        matches.sort((a, b) => a.offset - b.offset || b.full.length - a.full.length);
        const accepted = [];
        const ranges = protectedRanges.slice();
        for (const match of matches) {
            if (rangeOverlapsAny(match.offset, match.end, ranges)) {
                continue;
            }
            accepted.push(match);
            ranges.push([match.offset, match.end]);
        }
        return accepted;
    }

    function parseSupportedImageMarkup(markup) {
        const text = safeString(markup).trim();
        if (!text) return null;
        let match = new RegExp(
            `^\\{\\{(${RISU_IMAGE_TOKEN_COMMAND_PATTERN})::([^}]+)\\}\\}$`,
            'isu',
        ).exec(text);
        if (match) {
            const command = safeString(match[1]).trim().toLowerCase();
            const tokenName = safeString(match[2]).trim();
            return {
                full: text,
                tokenName,
                markupType: `risu_${command}`,
                characterName: imageTokenCharacterName(tokenName),
            };
        }
        match = /\{\{raw::([^}]+)\}\}/isu.exec(text);
        if (match && /\bnaa-generated-image\b|<img\b/isu.test(text)) {
            const tokenName = safeString(match[1]).trim();
            return {
                full: text,
                tokenName,
                markupType: 'naa_generated_html',
                characterName: imageTokenCharacterName(tokenName),
            };
        }
        match =
            /^<div\b(?=[^>]*\bclass\s*=\s*(?:"[^"]*\bnaa-generated-image\b[^"]*"|'[^']*\bnaa-generated-image\b[^']*'))[\s\S]*?<img\b[^>]*\bsrc\s*=\s*(?:"\{\{raw::([^}]+)\}\}"|'\{\{raw::([^}]+)\}\}'|\{\{raw::([^}\s]+)\}\})[^>]*>[\s\S]*?<\/div>$/isu.exec(
                text,
            );
        if (match) {
            const tokenName = safeString(match[1] || match[2] || match[3]).trim();
            return {
                full: text,
                tokenName,
                markupType: 'naa_generated_html',
                characterName: imageTokenCharacterName(tokenName),
            };
        }
        match = /^<img\s+src\s*=\s*(?:"([^"]+)"|'([^']+)'|([^>\s]+))\s*\/?>$/isu.exec(text);
        if (match) {
            const tokenName = safeString(match[1] || match[2] || match[3]).trim();
            return {
                full: text,
                tokenName,
                markupType: 'html_img_src',
                characterName: imageTokenCharacterName(tokenName),
            };
        }
        match = /^<img\s*=\s*(?:"([^"]+)"|'([^']+)'|([^>\s]+))\s*\/?>$/isu.exec(text);
        if (match) {
            const tokenName = safeString(match[1] || match[2] || match[3]).trim();
            return {
                full: text,
                tokenName,
                markupType: 'html_img_equals',
                characterName: imageTokenCharacterName(tokenName),
            };
        }
        return null;
    }

    function extractFirstSupportedImageMarkup(markup, options = {}) {
        const text = safeString(markup).trim();
        if (!text) return '';
        if (parseSupportedImageMarkup(text)) return text;
        if (
            collectCharxRegexImageTokenMatches(
                text,
                options.customImageTokenDetectors,
                [],
            ).length
        )
            return text;
        const markerRegex = imageTokenMarkerBlockRegex();
        let markerMatch;
        while ((markerMatch = markerRegex.exec(text))) {
            const inner = safeString(markerMatch[2]).trim();
            if (parseSupportedImageMarkup(inner)) return inner;
            if (
                collectCharxRegexImageTokenMatches(
                    inner,
                    options.customImageTokenDetectors,
                    [],
                ).length
            )
                return inner;
            const nested = extractFirstSupportedImageMarkup(inner, options);
            if (nested) return nested;
        }
        const regex = supportedImageMarkupRegex();
        let match;
        while ((match = regex.exec(text))) {
            const candidate = safeString(match[0]).trim();
            if (parseSupportedImageMarkup(candidate)) return candidate;
        }
        return '';
    }

    function extractMarkedImageTokenBlocks(content, options = {}) {
        const text = safeString(content);
        const blocks = [];
        const regex = imageTokenMarkerBlockRegex();
        let match;
        while ((match = regex.exec(text))) {
            const full = match[0];
            const meta = parseImageTokenMarkerMeta(match[1]);
            const inner = safeString(match[2]).trim();
            const parsed =
                parseSupportedImageMarkup(inner) ||
                collectCharxRegexImageTokenMatches(
                    inner,
                    options.customImageTokenDetectors,
                    [],
                )[0];
            if (!parsed) continue;
            blocks.push({
                ...parsed,
                full,
                inner,
                markerMeta: meta,
                markerId: safeString(meta.id).trim(),
                generatedAssetName: safeString(meta.asset).trim(),
                index: blocks.length,
                offset: match.index,
            });
        }
        return blocks;
    }

    function stripImageTokenMarkers(content) {
        return safeString(content).replace(imageTokenMarkerBlockRegex(), (_full, _meta, inner) =>
            safeString(inner),
        );
    }

    function supportedImageMarkupRegex() {
        return new RegExp(
            `<div\\b(?=[^>]*\\bclass\\s*=\\s*(?:"[^"]*\\bnaa-generated-image\\b[^"]*"|'[^']*\\bnaa-generated-image\\b[^']*'))[\\s\\S]*?<img\\b[^>]*\\bsrc\\s*=\\s*(?:"\\{\\{raw::[^}]+\\}\\}"|'\\{\\{raw::[^}]+\\}\\}'|\\{\\{raw::[^}\\s]+\\}\\})[^>]*>[\\s\\S]*?<\\/div>|\\{\\{(?:${RISU_IMAGE_TOKEN_COMMAND_PATTERN})::[^}]+\\}\\}|<img\\s+src\\s*=\\s*(?:"[^"]+"|'[^']+'|[^>\\s]+)\\s*\\/?>|<img\\s*=\\s*(?:"[^"]+"|'[^']+'|[^>\\s]+)\\s*\\/?>`,
            'giu',
        );
    }

    function extractImageTokens(content, options = {}) {
        const text = safeString(content);
        const tokens = [];
        const covered = [];
        for (const block of extractMarkedImageTokenBlocks(text, options)) {
            covered.push([block.offset, block.offset + block.full.length]);
            tokens.push(block);
        }
        const regex = supportedImageMarkupRegex();
        let match;
        while ((match = regex.exec(text))) {
            const offset = match.index;
            const end = offset + match[0].length;
            if (rangeOverlapsAny(offset, end, covered)) continue;
            const parsed = parseSupportedImageMarkup(match[0]);
            if (!parsed) continue;
            tokens.push({
                ...parsed,
                index: tokens.length,
                offset,
            });
            covered.push([offset, end]);
        }
        for (const custom of collectCharxRegexImageTokenMatches(
            text,
            options.customImageTokenDetectors,
            covered,
        )) {
            tokens.push({
                ...custom,
                index: tokens.length,
                offset: custom.offset,
            });
        }
        tokens.sort((a, b) => a.offset - b.offset);
        return tokens.map((token, index) => {
            const before = text.slice(Math.max(0, token.offset - 500), token.offset);
            const after = text.slice(
                token.offset + token.full.length,
                token.offset + token.full.length + 500,
            );
            return {
                ...token,
                index,
                before,
                after,
            };
        });
    }

    function isProcessableImageToken(token) {
        if (!token) return false;
        if (safeString(token.generatedAssetName).trim()) return false;
        return safeString(token.markupType).trim() !== 'naa_generated_html';
    }

    function wrapOutputImageTokens(content, options = {}) {
        const text = safeString(content);
        const tokens = [];
        const markerRegex = imageTokenMarkerBlockRegex();
        const protectedRanges = [];
        let markerMatch;
        while ((markerMatch = markerRegex.exec(text))) {
            protectedRanges.push([markerMatch.index, markerMatch.index + markerMatch[0].length]);
        }
        const matches = [];
        const regex = supportedImageMarkupRegex();
        let match;
        while ((match = regex.exec(text))) {
            const offset = match.index;
            const end = offset + match[0].length;
            if (rangeOverlapsAny(offset, end, protectedRanges)) continue;
            const parsed = parseSupportedImageMarkup(match[0]);
            if (!parsed) continue;
            matches.push({ ...parsed, full: match[0], offset, end });
            protectedRanges.push([offset, end]);
        }
        matches.push(
            ...collectCharxRegexImageTokenMatches(
                text,
                options.customImageTokenDetectors,
                protectedRanges,
            ),
        );
        matches.sort((a, b) => a.offset - b.offset);
        let output = '';
        let lastIndex = 0;
        for (const token of matches) {
            if (token.offset < lastIndex) continue;
            output += text.slice(lastIndex, token.offset);
            const markerId = createImageTokenMarkerId();
            const wrapped = `${imageTokenMarkerOpen({ id: markerId })}${token.full}<!--/${NAA_IMAGE_TOKEN_MARKER_PREFIX}-->`;
            output += wrapped;
            tokens.push({
                ...token,
                full: wrapped,
                inner: token.full,
                markerMeta: { id: markerId },
                markerId,
                generatedAssetName: '',
                index: tokens.length,
                offset: output.length - wrapped.length,
            });
            lastIndex = token.end;
        }
        output += text.slice(lastIndex);
        return {
            text: tokens.length ? output : text,
            tokens: extractImageTokens(tokens.length ? output : text, options),
        };
    }

    function streamImageTokenPlaceholderOpen(meta = {}) {
        const pairs = Object.entries(meta)
            .filter(([, value]) => safeString(value).trim())
            .map(([key, value]) => `${key}=${encodeURIComponent(safeString(value))}`);
        return `<!--${NAA_STREAM_IMAGE_TOKEN_PREFIX}${pairs.length ? `|${pairs.join('|')}` : ''}-->`;
    }

    function streamImageTokenPlaceholderRegex() {
        return new RegExp(`<!--${NAA_STREAM_IMAGE_TOKEN_PREFIX}([^>]*)-->`, 'giu');
    }

    function parseStreamImageTokenPlaceholderMeta(rawMeta) {
        const meta = {};
        const parts = safeString(rawMeta)
            .split('|')
            .map((part) => part.trim())
            .filter(Boolean);
        for (const part of parts) {
            const index = part.indexOf('=');
            if (index < 0) continue;
            const key = part.slice(0, index).trim();
            const value = part.slice(index + 1).trim();
            if (!key) continue;
            try {
                meta[key] = decodeURIComponent(value);
            } catch (_) {
                meta[key] = value;
            }
        }
        return meta;
    }

    function stableStreamImagePlaceholderId(markup, offset = 0) {
        const numericOffset = Number.isFinite(Number(offset)) ? Number(offset) : 0;
        const text = `${numericOffset}:${safeString(markup)}`;
        let hash = 2166136261;
        for (let i = 0; i < text.length; i++) {
            hash ^= text.charCodeAt(i);
            hash = Math.imul(hash, 16777619) >>> 0;
        }
        return `stream_${hash.toString(36)}_${text.length.toString(36)}`;
    }

    function hideStreamingImageTokens(content, options = {}) {
        const text = safeString(content);
        const protectedRanges = [];
        const protectMarkedBlocks = options.protectMarkedBlocks !== false;
        if (protectMarkedBlocks) {
            const markerRegex = imageTokenMarkerBlockRegex();
            let markerMatch;
            while ((markerMatch = markerRegex.exec(text))) {
                protectedRanges.push([
                    markerMatch.index,
                    markerMatch.index + markerMatch[0].length,
                ]);
            }
        }

        const matches = [];
        const regex = supportedImageMarkupRegex();
        let output = '';
        let lastIndex = 0;
        let changed = false;
        let match;
        while ((match = regex.exec(text))) {
            const offset = match.index;
            const end = offset + match[0].length;
            if (rangeOverlapsAny(offset, end, protectedRanges)) continue;
            const parsed = parseSupportedImageMarkup(match[0]);
            if (!parsed) continue;
            matches.push({ ...parsed, full: match[0], offset, end });
            protectedRanges.push([offset, end]);
        }
        matches.push(
            ...collectCharxRegexImageTokenMatches(
                text,
                options.customImageTokenDetectors,
                protectedRanges,
            ),
        );
        matches.sort((a, b) => a.offset - b.offset);
        for (const token of matches) {
            if (token.offset < lastIndex) continue;
            if (imageTokenMatchesActiveModuleAsset(token, options.moduleAssetTokens)) continue;
            output += text.slice(lastIndex, token.offset);
            output += streamImageTokenPlaceholderOpen({
                id: stableStreamImagePlaceholderId(token.full, token.offset),
                markup: token.full,
            });
            lastIndex = token.end;
            changed = true;
        }
        output += text.slice(lastIndex);
        return changed ? output : text;
    }

    function restoreStreamingImageTokenPlaceholders(content) {
        return safeString(content)
            .replace(streamImageTokenPlaceholderRegex(), (_full, rawMeta) => {
                const meta = parseStreamImageTokenPlaceholderMeta(rawMeta);
                return safeString(meta.markup);
            })
            .replace(
                /<div\b(?=[^>]*\bclass\s*=\s*(?:"[^"]*\bnaa-stream-image-disabled\b[^"]*"|'[^']*\bnaa-stream-image-disabled\b[^']*'))[^>]*\bdata-naa-original\s*=\s*(?:"([^"]*)"|'([^']*)')[^>]*>\s*<\/div>/giu,
                (_full, d1, d2) => decodeNaaOriginal(d1 || d2 || ''),
            );
    }

    function splitPreCheckBlock(content) {
        const text = safeString(content);
        const match = /<pre_check\b[^>]*>([\s\S]*?)<\/pre_check>/i.exec(text);
        if (!match) return { preCheck: '', displayText: text };
        return {
            preCheck: safeString(match[1]).trim(),
            displayText:
                `${text.slice(0, match.index)}${text.slice(match.index + match[0].length)}`.trim(),
        };
    }

    function makeOutputProcessKey(latest) {
        const text = safeString(latest?.data);
        let hash = 0;
        for (let i = 0; i < text.length; i++) {
            hash = (hash * 31 + text.charCodeAt(i)) >>> 0;
        }
        return [
            latest?.charIndex ?? -1,
            latest?.chatIndex ?? -1,
            latest?.messageIndex ?? -1,
            text.length,
            hash.toString(16),
        ].join(':');
    }

    function rememberProcessedOutputKey(key) {
        if (!key) return;
        if (!processedOutputKeys.includes(key)) processedOutputKeys.push(key);
        while (processedOutputKeys.length > MAX_PROCESSED_OUTPUT_KEYS) processedOutputKeys.shift();
    }

    function hasProcessedOutputKey(key) {
        return processedOutputKeys.includes(key);
    }

    function sleepMs(ms) {
        return new Promise((resolve) => setTimeout(resolve, Math.max(0, Number(ms) || 0)));
    }

    async function runWithConcurrency(items = [], limit = 5, worker, onProgress = null) {
        const list = Array.isArray(items) ? items : [];
        const concurrency = Math.max(1, Math.min(Number(limit) || 5, list.length || 1));
        const results = new Array(list.length);
        let nextIndex = 0;
        let completed = 0;
        async function runWorker() {
            while (nextIndex < list.length) {
                const index = nextIndex++;
                const item = list[index];
                results[index] = await worker(item, index);
                completed++;
                if (typeof onProgress === 'function')
                    await onProgress(completed, list.length, results[index], item, index);
            }
        }
        await Promise.all(Array.from({ length: concurrency }, () => runWorker()));
        return results;
    }

    function isCurrentChatUnavailableError(error) {
        const message = safeString(error?.message || error);
        return (
            /chatPage/i.test(message) ||
            /Cannot read properties of undefined/i.test(message) ||
            /Cannot read property/i.test(message)
        );
    }

    async function safeCurrentIndex(apiName) {
        const fn = Risu?.[apiName];
        if (typeof fn !== 'function') return -1;
        try {
            const value = await fn();
            const index = Number(value);
            return Number.isInteger(index) && index >= 0 ? index : -1;
        } catch (error) {
            if (isCurrentChatUnavailableError(error)) return -1;
            const now = Date.now();
            if (now - lastCurrentChatApiWarningAt > 10000) {
                lastCurrentChatApiWarningAt = now;

            }
            return -1;
        }
    }

    async function getSafeCurrentCharacterIndex() {
        return safeCurrentIndex('getCurrentCharacterIndex');
    }

    async function getSafeCurrentChatIndex() {
        return safeCurrentIndex('getCurrentChatIndex');
    }

    function currentChatKey(character, charIndex, chatIndex, chat = null) {
        const chatId = Number(chatIndex);
        if (!Number.isInteger(chatId) || chatId < 0) return '';
        const characterKey =
            safeString(character?.chaId || character?.id || character?.name).trim() ||
            (Number.isInteger(charIndex) && charIndex >= 0 ? String(charIndex) : 'current');
        const stableChatId = safeString(chat?.id || chat?.chatId).trim();
        return `${characterKey}:${stableChatId || chatId}`;
    }

    async function getCurrentOutputPendingKey() {
        const currentCharacter = await getCurrentCharacterSnapshot();
        const charIndex = await getSafeCurrentCharacterIndex();
        let chatIndex = await getSafeCurrentChatIndex();
        const characterChatPage = Number(currentCharacter?.chatPage);
        if (chatIndex < 0 && Number.isInteger(characterChatPage) && characterChatPage >= 0) {
            chatIndex = characterChatPage;
        }
        const chat =
            Array.isArray(currentCharacter?.chats) && chatIndex >= 0
                ? currentCharacter.chats[chatIndex]
                : null;
        return currentChatKey(currentCharacter, charIndex, chatIndex, chat);
    }

    async function getCurrentCharacterSnapshot() {
        if (typeof Risu.getCharacter !== 'function') return null;
        try {
            return await Risu.getCharacter();
        } catch (error) {
            const now = Date.now();
            if (now - lastCurrentChatApiWarningAt > 10000) {
                lastCurrentChatApiWarningAt = now;

            }
            return null;
        }
    }

    async function getLatestCurrentCharacterMessage() {
        const charIndex = await getSafeCurrentCharacterIndex();
        const currentCharacter = await getCurrentCharacterSnapshot();
        let chatIndex = await getSafeCurrentChatIndex();
        const characterChatPage = Number(currentCharacter?.chatPage);
        if (chatIndex < 0 && Number.isInteger(characterChatPage) && characterChatPage >= 0) {
            chatIndex = characterChatPage;
        }
        let character = currentCharacter;
        let chat =
            Array.isArray(currentCharacter?.chats) && chatIndex >= 0
                ? currentCharacter.chats[chatIndex]
                : null;
        if (
            !chat &&
            charIndex >= 0 &&
            chatIndex >= 0 &&
            typeof Risu.getChatFromIndex === 'function'
        ) {
            chat = await Risu.getChatFromIndex(charIndex, chatIndex);
            if (!character && typeof Risu.getCharacterFromIndex === 'function') {
                character = await Risu.getCharacterFromIndex(charIndex);
            }
        }
        if (!chat) return null;
        const messages = Array.isArray(chat?.message) ? chat.message : [];
        for (let index = messages.length - 1; index >= 0; index--) {
            const message = messages[index];
            if (safeString(message?.role).toLowerCase() === 'char') {
                return {
                    charIndex,
                    chatIndex,
                    character,
                    chat,
                    message,
                    messageIndex: index,
                    data: safeString(message?.data),
                    pendingKey: currentChatKey(character, charIndex, chatIndex, chat),
                    writeMode:
                        currentCharacter && currentCharacter === character
                            ? 'current-character'
                            : 'chat-index',
                };
            }
        }
        return null;
    }

    async function writeCurrentCharacterMessage(latest, data) {
        if (!latest) throw new Error('RisuAI chat write API is not available.');
        const chat = latest.chat;
        if (!chat || !Array.isArray(chat.message) || !chat.message[latest.messageIndex]) {
            throw new Error('Latest chat message is no longer available.');
        }
        chat.message[latest.messageIndex] = {
            ...chat.message[latest.messageIndex],
            data: safeString(data),
        };
        if (
            Number.isInteger(latest.charIndex) &&
            latest.charIndex >= 0 &&
            Number.isInteger(latest.chatIndex) &&
            latest.chatIndex >= 0 &&
            typeof Risu.setChatToIndex === 'function'
        ) {
            await Risu.setChatToIndex(latest.charIndex, latest.chatIndex, chat);
            return;
        }
        if (latest.writeMode === 'current-character' && typeof Risu.setCharacter === 'function') {
            const character = latest.character;
            if (!character || !Array.isArray(character.chats) || latest.chatIndex < 0) {
                throw new Error('Latest character chat is no longer available.');
            }
            character.chats[latest.chatIndex] = chat;
            await Risu.setCharacter(character);
            return;
        }
        throw new Error('RisuAI chat write API is not available.');
    }

    async function clearLatestLoadingSpinnerState(finalContent = '', reason = '') {
        const latest = await getLatestCurrentCharacterMessage();
        if (!latest || !/\bnaa-loading-image\b/.test(latest.data)) return false;
        const cleaned = replaceLoadingGeneratedImagesWithStableAssets(finalContent || latest.data);
        await writeCurrentCharacterMessage(latest, cleaned);

        return true;
    }

    async function clearLatestLoadingSpinnerStateToManualGeneration(finalContent = '', reason = '', options = {}) {
        const latest = await getLatestCurrentCharacterMessage();
        const latestData = safeString(latest?.data);
        const hasLatestLoading = /\bnaa-loading-image\b/.test(latestData);

        if (!latest || !hasLatestLoading) return null;
        const cleaned = replaceLoadingGeneratedImagesWithManualAssets(latest.data || finalContent, {
            ...options,
            chatKey: options.chatKey || latest.pendingKey,
        });
        await writeCurrentCharacterMessage(latest, cleaned);
        await saveDisplayAssetMap().catch(() => {});


        return cleaned;
    }

    async function finalizeNonGeneratingOutput(output, reason = '') {
        const cleaned = replaceLoadingGeneratedImagesWithStableAssets(output);
        try {
            await clearLatestLoadingSpinnerState(cleaned, reason);
        } catch (error) {

        }
        return cleaned;
    }

    function manualGenerationFallbackOutputForAnalyzerFailure(output, options = {}) {
        const before = safeString(output);
        const beforeLoadingCount = (before.match(/\bnaa-loading-image\b/g) || []).length;
        const beforeManualCount =
            (before.match(/\b(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["']/g) || [])
                .length;
        const beforeHasCharx = hasOriginalImageMarkup(before, options);
        let cleaned = replaceLoadingGeneratedImagesWithManualAssets(output, options);
        const afterLoadingConvert = safeString(cleaned);
        const afterLoadingConvertHasCharx = hasOriginalImageMarkup(afterLoadingConvert, options);
        if (afterLoadingConvertHasCharx) {
            cleaned = wrapRemainingCharxTokens(
                cleaned,
                (tokenName, originalMarkup) => {
                    if (originalMarkup && tokenName) reverseAssetMap.set(tokenName, originalMarkup);
                },
                false,
                {
                    ...options,
                    manualGeneration: true,
                },
            );
        }
        const after = safeString(cleaned);

        return cleaned;
    }

    async function finalizeAnalyzerFailureOutput(
        output,
        error = null,
        reason = '',
        options = {},
    ) {
        const cleaned = manualGenerationFallbackOutputForAnalyzerFailure(output, options);
        try {
            const latestCleaned = await clearLatestLoadingSpinnerStateToManualGeneration(
                cleaned,
                reason,
                options,
            );
            if (latestCleaned) {

                return latestCleaned;
            }
        } catch (clearError) {

        }

        return cleaned;
    }

    async function getCurrentChatForAssetReplacement() {
        const charIndex = await getSafeCurrentCharacterIndex();
        const character = await getCurrentCharacterSnapshot();
        let chatIndex = await getSafeCurrentChatIndex();
        const characterChatPage = Number(character?.chatPage);
        if (chatIndex < 0 && Number.isInteger(characterChatPage) && characterChatPage >= 0) {
            chatIndex = characterChatPage;
        }
        let chat =
            Array.isArray(character?.chats) && chatIndex >= 0 ? character.chats[chatIndex] : null;
        if (
            !chat &&
            charIndex >= 0 &&
            chatIndex >= 0 &&
            typeof Risu.getChatFromIndex === 'function'
        ) {
            chat = await Risu.getChatFromIndex(charIndex, chatIndex);
        }
        if (!chat || !Array.isArray(chat.message)) return null;
        return {
            charIndex,
            chatIndex,
            character,
            chatKey: currentChatKey(character, charIndex, chatIndex, chat),
            chat,
            writeMode:
                character && Array.isArray(character.chats) ? 'current-character' : 'chat-index',
        };
    }

    async function writeCurrentChatForAssetReplacement(snapshot) {
        if (!snapshot?.chat) return false;
        if (
            snapshot.charIndex >= 0 &&
            snapshot.chatIndex >= 0 &&
            typeof Risu.setChatToIndex === 'function'
        ) {
            await Risu.setChatToIndex(snapshot.charIndex, snapshot.chatIndex, snapshot.chat);
            return true;
        }
        if (
            snapshot.writeMode === 'current-character' &&
            snapshot.character &&
            Array.isArray(snapshot.character.chats) &&
            snapshot.chatIndex >= 0 &&
            typeof Risu.setCharacter === 'function'
        ) {
            snapshot.character.chats[snapshot.chatIndex] = snapshot.chat;
            await Risu.setCharacter(snapshot.character);
            return true;
        }
        return false;
    }

    async function replaceFirstGeneratedAssetInCurrentChat(
        assetName,
        replacementFactory,
        reason = '',
        options = {},
    ) {
        const snapshot = await getCurrentChatForAssetReplacement();
        if (!snapshot) return false;
        for (let index = snapshot.chat.message.length - 1; index >= 0; index--) {
            const message = snapshot.chat.message[index];
            const before = safeString(message?.data);
            const after = replaceFirstGeneratedAssetHtml(before, assetName, replacementFactory, options);
            if (after === before) continue;
            snapshot.chat.message[index] = { ...message, data: after };
            await writeCurrentChatForAssetReplacement(snapshot);
            invalidateZoomGeneratedItemsCache();

            return true;
        }
        return false;
    }

    async function findGeneratedAssetHtmlInRootDom(rootDoc, assetName, options = {}) {
        const cleanAssetName = safeString(assetName).trim();
        if (!rootDoc || !cleanAssetName) return '';
        const targetSlotId = safeString(options?.slotId).trim();
        const targetActionHtml = safeString(options?.actionHtml).trim();
        try {
            const nodes = await rootDoc.querySelectorAll(
                '.naa-generated-image, .x-risu-naa-generated-image',
            );
            const len = await nodes.length();
            for (let index = len - 1; index >= 0; index--) {
                const node = await nodes.at(index);
                const html = safeString(await node.getOuterHTML());
                if (targetActionHtml && html.includes(targetActionHtml)) return html;
                if (assetNameFromGeneratedImageHtml(html) !== cleanAssetName) continue;
                if (targetSlotId && slotIdFromGeneratedImageHtml(html) !== targetSlotId) continue;
                return html;
            }
        } catch (_) {}
        return '';
    }

    async function replaceFirstGeneratedAssetInRootDom(rootDoc, assetName, replacementHtml, options = {}) {
        const recordDebug =
            typeof recordZoomDebugEntry === 'function' ? recordZoomDebugEntry : () => {};
        const htmlSummary =
            typeof zoomDebugHtmlImageSummary === 'function'
                ? zoomDebugHtmlImageSummary
                : () => null;
        const cleanAssetName = safeString(assetName).trim();
        if (!rootDoc || !cleanAssetName) return false;
        const targetSlotId = safeString(options?.slotId).trim();
        const targetActionHtml = safeString(options?.actionHtml).trim();
        const replacementSummary = htmlSummary(replacementHtml);
        try {
            const nodes = await rootDoc.querySelectorAll(
                '.naa-generated-image, .x-risu-naa-generated-image',
            );
            const len = await nodes.length();
            recordDebug('root-dom-replace-start', 'Searching chat DOM for generated image replacement target.', {
                assetName: cleanAssetName,
                targetSlotId,
                hasActionHtml: Boolean(targetActionHtml),
                nodeCount: len,
                replacement: replacementSummary,
            });
            for (let index = len - 1; index >= 0; index--) {
                const node = await nodes.at(index);
                const html = await node.getOuterHTML();
                const nodeSummary = htmlSummary(html);
                if (targetActionHtml && html.includes(targetActionHtml)) {
                    await node.setOuterHTML(safeString(replacementHtml));
                    invalidateZoomHitTestCache();
                    recordDebug('root-dom-replace-success', 'Replaced generated image DOM by action HTML match.', {
                        assetName: cleanAssetName,
                        targetSlotId,
                        index,
                        node: nodeSummary,
                        replacement: replacementSummary,
                    });
                    return true;
                }
                if (assetNameFromGeneratedImageHtml(html) !== cleanAssetName) continue;
                if (targetSlotId && slotIdFromGeneratedImageHtml(html) !== targetSlotId) continue;
                await node.setOuterHTML(safeString(replacementHtml));
                invalidateZoomHitTestCache();
                recordDebug('root-dom-replace-success', 'Replaced generated image DOM by asset/slot match.', {
                    assetName: cleanAssetName,
                    targetSlotId,
                    index,
                    node: nodeSummary,
                    replacement: replacementSummary,
                });
                return true;
            }
        } catch (error) {
            recordDebug('root-dom-replace-error', 'Generated image DOM replacement failed.', {
                assetName: cleanAssetName,
                targetSlotId,
                error: error?.message || String(error),
                replacement: replacementSummary,
            });
        }
        recordDebug('root-dom-replace-miss', 'No generated image DOM replacement target matched.', {
            assetName: cleanAssetName,
            targetSlotId,
            hasActionHtml: Boolean(targetActionHtml),
            replacement: replacementSummary,
        });
        return false;
    }

