    async function findNaaZoomCloseActionAtPoint(rootDoc, x, y) {
        if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
        const closeButton = await rootDoc.querySelector(
            '[data-naa-zoom-action="close"], [x-risu-naa-zoom-action="close"]',
        );
        if (!closeButton) return null;
        const rect = await closeButton.getBoundingClientRect();
        if (!pointInsideRect(x, y, rect)) return null;
        return { action: 'close', index: NaN, html: '' };
    }

    async function findNaaZoomActionAtPoint(rootDoc, x, y) {
        if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
        const actions = await getCachedZoomActionHitEntries(rootDoc);
        for (const entry of actions) {
            if (!pointInsideRect(x, y, entry.rect)) continue;
            const html = entry.html;
            return {
                action: htmlFirstAttributeValue(html, [
                    'x-risu-naa-zoom-action',
                    'data-naa-zoom-action',
                ]),
                index: Number(
                    htmlFirstAttributeValue(html, ['x-risu-naa-zoom-index', 'data-naa-zoom-index']),
                ),
                sizePresetId: htmlFirstAttributeValue(html, [
                    'x-risu-naa-zoom-size-preset-id',
                    'data-naa-zoom-size-preset-id',
                ]),
                html,
            };
        }
        return null;
    }

    async function findNaaChatRegenerateActionAtPoint(rootDoc, x, y) {
        if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
        const actions = await rootDoc.querySelectorAll(
            '[data-naa-chat-regenerate-action], [x-risu-naa-chat-regenerate-action]',
        );
        const len = await actions.length();
        for (let i = 0; i < len; i++) {
            const el = await actions.at(i);
            const rect = await el.getBoundingClientRect();
            if (!pointInsideRect(x, y, rect)) continue;
            const html = await el.getOuterHTML();
            return {
                action: htmlFirstAttributeValue(html, [
                    'x-risu-naa-chat-regenerate-action',
                    'data-naa-chat-regenerate-action',
                ]),
                assetName: htmlFirstAttributeValue(html, [
                    'x-risu-naa-chat-regenerate-asset',
                    'data-naa-chat-regenerate-asset',
                ]),
                originalMarkup: htmlFirstAttributeValue(html, [
                    'x-risu-naa-chat-regenerate-original',
                    'data-naa-chat-regenerate-original',
                ]),
                html,
            };
        }
        return null;
    }

