    function imageSrcFromOriginalMarkup(markup) {
        const text = safeString(markup).trim();
        const innerMarkup = extractFirstSupportedImageMarkup(text) || text;
        if (/^data:image\//i.test(innerMarkup)) return innerMarkup;
        const src = htmlFirstAttributeValue(innerMarkup, ['src']);
        if (src) return src;
        const parsed = parseSupportedImageMarkup(innerMarkup);
        const tokenName = safeString(parsed?.tokenName).trim();
        return tokenName ? `{{raw::${tokenName}}}` : '';
    }

    function isRenderableZoomHistoryPreviewSrc(src = '') {
        return Boolean(normalizeZoomAssetPreviewUrl(src));
    }

    function zoomResolvedHistoryPreviewSrc(
        assetName = '',
        fallbackSrc = '',
        sourceMarkup = '',
        options = {},
    ) {
        const allowSourceFallback = options.allowSourceFallback !== false;
        const cleanSourceMarkup = extractFirstSupportedImageMarkup(sourceMarkup) || sourceMarkup;
        const cleanAssetName = safeString(assetName).trim();
        const cachedByAsset = cleanAssetName ? cachedImageTokenPreviewUrl(cleanAssetName) : '';
        if (cachedByAsset) return cachedByAsset;
        const directSrc = safeString(fallbackSrc).trim();
        if (isRenderableZoomHistoryPreviewSrc(directSrc)) return directSrc;
        if (!allowSourceFallback) return '';
        const markupSrc = cleanSourceMarkup ? imageSrcFromOriginalMarkup(cleanSourceMarkup) : '';
        const parsed = parseSupportedImageMarkup(cleanSourceMarkup);
        const tokenName = safeString(
            parsed?.tokenName ||
                rawAssetNameFromImageSrc(directSrc) ||
                rawAssetNameFromImageSrc(markupSrc),
        ).trim();
        const cachedByToken = tokenName ? cachedImageTokenPreviewUrl(tokenName) : '';
        if (cachedByToken) return cachedByToken;
        return isRenderableZoomHistoryPreviewSrc(markupSrc) ? markupSrc : '';
    }

    function zoomAssetAliasSet(value) {
        const raw = safeString(value).trim();
        const stem = imageTokenFileStem(raw);
        return new Set(
            uniqueStringList([
                raw,
                stem,
                raw.split(/[\\/]/).pop(),
                normalizedImageTokenAlias(raw),
                normalizedImageTokenAlias(stem),
            ])
                .map((item) => item.toLocaleLowerCase())
                .filter(Boolean),
        );
    }

    function assetEntryMatchesTokenName(asset = {}, tokenName = '') {
        const tokenAliases = zoomAssetAliasSet(tokenName);
        if (!tokenAliases.size) return false;
        return [asset.name, asset.key]
            .flatMap((value) => Array.from(zoomAssetAliasSet(value)))
            .some((alias) => tokenAliases.has(alias));
    }

    function findBestAssetEntryForTokenName(assets = [], tokenName = '') {
        const list = uniqueAssetEntries(assets);
        const cleanTokenName = safeString(tokenName).trim();
        if (!cleanTokenName || !list.length) return null;
        const exact = list.find((asset) => assetEntryMatchesTokenName(asset, cleanTokenName));
        if (exact) return exact;
        const wanted = normalizeAssetNameForMatch(cleanTokenName);
        if (!wanted) return null;
        return (
            list.find((asset) => normalizeAssetNameForMatch(asset.name) === wanted) ||
            list.find((asset) => normalizeAssetNameForMatch(asset.key) === wanted) ||
            list.find((asset) => normalizeAssetNameForMatch(asset.name).includes(wanted)) ||
            null
        );
    }

    function imageTokenPreviewCacheKeys(tokenName = '') {
        const raw = safeString(tokenName).trim();
        const stem = imageTokenFileStem(raw);
        return uniqueStringList([
            raw,
            stem,
            raw.split(/[\\/]/).pop(),
            normalizedImageTokenAlias(raw),
            normalizedImageTokenAlias(stem),
        ])
            .map((item) => safeString(item).trim().toLocaleLowerCase())
            .filter(Boolean);
    }

    function cachedImageTokenPreviewUrl(tokenName = '') {
        for (const key of imageTokenPreviewCacheKeys(tokenName)) {
            const cached = imageTokenPreviewUrlCache.get(key);
            const normalized = normalizeZoomAssetPreviewUrl(cached);
            if (normalized) return normalized;
        }
        return '';
    }

    function rememberImageTokenPreviewUrl(tokenName = '', previewUrl = '') {
        const normalized = normalizeZoomAssetPreviewUrl(previewUrl);
        const keys = imageTokenPreviewCacheKeys(tokenName);
        if (!normalized || !keys.length) return '';
        while (imageTokenPreviewUrlCache.size + keys.length > MAX_PREVIEW_DATA_URL_CACHE) {
            const oldestKey = imageTokenPreviewUrlCache.keys().next().value;
            if (!oldestKey) break;
            imageTokenPreviewUrlCache.delete(oldestKey);
        }
        keys.forEach((key) => imageTokenPreviewUrlCache.set(key, normalized));
        return normalized;
    }

    function forgetImageTokenPreviewUrl(tokenName = '') {
        for (const key of imageTokenPreviewCacheKeys(tokenName)) {
            const previous = imageTokenPreviewUrlCache.get(key);
            imageTokenPreviewUrlCache.delete(key);
            if (
                previous &&
                previous.startsWith('blob:') &&
                typeof URL === 'object' &&
                typeof URL.revokeObjectURL === 'function'
            ) {
                try {
                    URL.revokeObjectURL(previous);
                } catch (_) {}
            }
        }
    }

    function cachedChatRootImageTokenPreviewUrl(tokenName = '') {
        for (const key of imageTokenPreviewCacheKeys(tokenName)) {
            const cached = chatRootImageTokenPreviewUrlCache.get(key);
            const normalized = normalizeZoomAssetPreviewUrl(cached);
            if (normalized) return normalized;
        }
        return '';
    }

    function rememberChatRootImageTokenPreviewUrl(tokenName = '', previewUrl = '') {
        const normalized = normalizeZoomAssetPreviewUrl(previewUrl);
        const keys = imageTokenPreviewCacheKeys(tokenName);
        if (!normalized || !keys.length) return '';
        while (chatRootImageTokenPreviewUrlCache.size + keys.length > MAX_PREVIEW_DATA_URL_CACHE) {
            const oldestKey = chatRootImageTokenPreviewUrlCache.keys().next().value;
            const oldestUrl = oldestKey ? chatRootImageTokenPreviewUrlCache.get(oldestKey) : '';
            if (!oldestKey) break;
            chatRootImageTokenPreviewUrlCache.delete(oldestKey);
            if (oldestUrl && oldestUrl !== normalized) revokeBlobPreviewUrl(oldestUrl);
        }
        keys.forEach((key) => chatRootImageTokenPreviewUrlCache.set(key, normalized));
        return normalized;
    }

    function rootBlobUrlOptionsForChatDom() {
        const candidates = [];
        try {
            if (typeof Risu?.getSafeGlobalThis === 'function') {
                candidates.push({ source: 'risu-safe-global', value: Risu.getSafeGlobalThis() });
            }
        } catch (_) {}
        try {
            if (typeof safeGlobalThis !== 'undefined') {
                candidates.push({ source: 'safeGlobalThis', value: safeGlobalThis });
            }
        } catch (_) {}
        try {
            if (globalThis?.parent && globalThis.parent !== globalThis) {
                candidates.push({ source: 'globalThis.parent', value: globalThis.parent });
            }
        } catch (_) {}
        try {
            if (globalThis?.top && globalThis.top !== globalThis) {
                candidates.push({ source: 'globalThis.top', value: globalThis.top });
            }
        } catch (_) {}
        try {
            candidates.push({ source: 'globalThis', value: globalThis });
        } catch (_) {}

        for (const candidate of candidates) {
            try {
                const urlApi = candidate.value?.URL;
                const blobCtor = candidate.value?.Blob || Blob;
                if (
                    urlApi &&
                    typeof urlApi.createObjectURL === 'function' &&
                    typeof blobCtor === 'function'
                ) {
                    return {
                        urlApi,
                        blobCtor,
                        source: candidate.source,
                    };
                }
            } catch (_) {}
        }
        return {
            urlApi: typeof URL !== 'undefined' ? URL : null,
            blobCtor: typeof Blob !== 'undefined' ? Blob : null,
            source: 'fallback',
        };
    }

    function chatRootAssetUrlFromRenderedHtml(renderedHtml = '', asset = {}) {
        const renderedSrc = safeString(htmlFirstAttributeValue(renderedHtml, ['src'])).trim();
        const match = /^(https?:\/\/asset\.localhost)\/([^?#]*)(?:[?#].*)?$/i.exec(renderedSrc);
        if (!match) return '';
        const assetKey = safeString(asset?.key || asset?.[1] || asset).trim();
        if (!/^assets[\\/]/i.test(assetKey)) return '';
        let decodedPath = '';
        try {
            decodedPath = decodeURIComponent(match[2]);
        } catch (_) {
            decodedPath = match[2];
        }
        decodedPath = decodedPath.replace(/^\/+/, '');
        const lowerPath = decodedPath.toLocaleLowerCase();
        const slashIndex = lowerPath.lastIndexOf('/assets/');
        const backslashIndex = lowerPath.lastIndexOf('\\assets\\');
        const assetDirIndex = Math.max(slashIndex, backslashIndex);
        if (assetDirIndex < 0) return '';
        const separator = backslashIndex >= slashIndex ? '\\' : '/';
        const assetDirPrefix = decodedPath.slice(0, assetDirIndex + 8);
        const assetSuffix = assetKey
            .replace(/^assets[\\/]+/i, '')
            .split(/[\\/]+/)
            .filter(Boolean)
            .join(separator);
        if (!assetSuffix) return '';
        return `${match[1]}/${encodeURIComponent(assetDirPrefix + assetSuffix)}`;
    }

    async function findCurrentAssetForImageToken(tokenName = '', options = {}) {
        const cleanTokenName = safeString(tokenName).trim();
        if (!cleanTokenName) return null;
        const requestedCharIndex = nonNegativeIntegerOr(options?.charIndex, -1);
        const db =
            typeof Risu.getDatabase === 'function'
                ? await Risu.getDatabase([
                      'characters',
                      'modules',
                      'enabledModules',
                      'moduleIntergration',
                      'moduleIntegration',
                  ]).catch(() => null)
                : null;
        const sources = [];
        const seen = new Set();
        const pushSource = (source) => {
            if (!source || typeof source !== 'object') return;
            const key =
                safeString(source.chaId || source.id || source.name).trim() ||
                stableStringHash(JSON.stringify([source.name, source.desc, source.description]));
            if (seen.has(key)) return;
            seen.add(key);
            sources.push(source);
        };
        const charIndex =
            requestedCharIndex >= 0 ? requestedCharIndex : await getSafeCurrentCharacterIndex();
        if (requestedCharIndex < 0) {
            pushSource(await getCurrentCharacterSnapshot());
        }
        if (
            Number.isInteger(charIndex) &&
            charIndex >= 0 &&
            typeof Risu.getCharacterFromIndex === 'function'
        ) {
            pushSource(await Risu.getCharacterFromIndex(charIndex).catch(() => null));
        }
        if (Array.isArray(db?.characters) && Number.isInteger(charIndex) && charIndex >= 0) {
            pushSource(db.characters[charIndex]);
        }
        if (requestedCharIndex >= 0) {
            pushSource(await getCurrentCharacterSnapshot());
        }
        const assets = sources.flatMap((source) =>
            imageAssetsForCharacterWithModules(db, source, source),
        );
        const uniqueAssets = uniqueAssetEntries(assets);
        const matched = findBestAssetEntryForTokenName(assets, cleanTokenName);

        return matched;
    }





    function compactAssetKeyForPreview(key = '') {
        const value = safeString(key).trim();
        if (!value || value.length <= 42) return value;
        return `${value.slice(0, 18)}...${value.slice(-18)}`;
    }

    function zoomPreviewSrcKind(src = '') {
        const value = safeString(src).trim();
        if (!value) return 'empty';
        if (value === NAA_ZOOM_PLACEHOLDER_IMAGE) return 'placeholder';
        if (value.startsWith('blob:')) return 'blob';
        if (normalizeImageDataUrl(value)) return 'data-url';
        if (isRawAssetImageSrc(value)) return 'raw-template';
        if (isBareAssetReferenceSrc(value)) return 'bare-asset-name';
        if (/^https?:\/\//i.test(value) || value.startsWith('/')) return 'url';
        return 'other';
    }

    function isZoomBlobPreviewSrc(src = '') {
        return zoomPreviewSrcKind(src) === 'blob';
    }

    async function readImageTokenAssetBytes(tokenName = '', options = {}) {
        const cleanTokenName = safeString(
            rawAssetNameFromImageSrc(tokenName) || tokenName,
        ).trim();
        if (!cleanTokenName) throw new Error('Image token name is empty.');
        let asset = null;
        let assetError = null;
        try {
            asset = await findCurrentAssetForImageToken(cleanTokenName, options);
        } catch (error) {
            assetError = error;

        }
        if (asset?.key) {
            const ext = asset.ext || imageExtensionFromNameOrKey(asset.name, asset.key);
            try {
                const bytes = await readAssetEntryBytes(asset);

                return {
                    bytes,
                    ext,
                    asset,
                };
            } catch (error) {
                assetError = error;

            }
        }
        if (typeof Risu.readImage !== 'function') {
            throw assetError || new Error('RisuAI readImage API is not available.');
        }
        const directCandidates = uniqueStringList([
            cleanTokenName,
            cleanTokenName.startsWith('assets/') ? cleanTokenName.slice(7) : '',
            cleanTokenName.split(/[\\/]/).pop(),
        ]).filter(Boolean);
        let lastError = assetError;
        for (const candidate of directCandidates) {
            try {
                const data = await Risu.readImage(candidate);
                const bytes = normalizeReadImageDataToBytes(data);

                return {
                    bytes,
                    ext: imageExtensionFromNameOrKey(candidate, candidate),
                    asset: { name: candidate, key: candidate },
                };
            } catch (error) {
                lastError = error;

            }
        }

        throw lastError || new Error(`Could not read image token asset: ${cleanTokenName}`);
    }

    function assetBytesToZoomObjectUrl(bytes, ext = '', options = {}) {
        const normalizedBytes = normalizeReadImageDataToBytes(bytes);
        if (!normalizedBytes?.length) return '';
        const mime = imageMimeFromBytes(normalizedBytes, ext);
        const urlApi = options?.urlApi || URL;
        const blobCtor = options?.blobCtor || options?.Blob || Blob;
        if (
            typeof blobCtor !== 'function' ||
            (typeof urlApi !== 'object' && typeof urlApi !== 'function') ||
            typeof urlApi.createObjectURL !== 'function'
        ) {
            return '';
        }
        return urlApi.createObjectURL(new blobCtor([normalizedBytes], { type: mime }));
    }

    async function decodeImageUrlForDisplay(src = '') {
        const previewUrl = normalizeZoomAssetPreviewUrl(src);
        if (!previewUrl) return '';
        if (typeof Image !== 'function') {

            return previewUrl;
        }
        const startedAt = Date.now();
        return await new Promise((resolve) => {
            let settled = false;
            const finish = (status = 'ok', extra = {}) => {
                if (settled) return;
                settled = true;
                const ok = status === 'loaded' || status === 'decoded';

                resolve(ok ? previewUrl : '');
            };
            try {
                const image = new Image();
                image.onload = () => {
                    if (typeof image.decode === 'function') {
                        image
                            .decode()
                            .then(() =>
                                finish('decoded', {
                                    naturalWidth: image.naturalWidth || 0,
                                    naturalHeight: image.naturalHeight || 0,
                                }),
                            )
                            .catch((error) =>
                                finish('decode-error', {
                                    naturalWidth: image.naturalWidth || 0,
                                    naturalHeight: image.naturalHeight || 0,
                                    error: error?.message || String(error),
                                }),
                            );
                    } else {
                        finish('loaded', {
                            naturalWidth: image.naturalWidth || 0,
                            naturalHeight: image.naturalHeight || 0,
                        });
                    }
                };
                image.onerror = () => finish('image-error');
                image.src = previewUrl;
                if (image.complete) {
                    if (typeof image.decode === 'function') {
                        image
                            .decode()
                            .then(() =>
                                finish('decoded', {
                                    naturalWidth: image.naturalWidth || 0,
                                    naturalHeight: image.naturalHeight || 0,
                                }),
                            )
                            .catch((error) =>
                                finish('decode-error', {
                                    naturalWidth: image.naturalWidth || 0,
                                    naturalHeight: image.naturalHeight || 0,
                                    error: error?.message || String(error),
                                }),
                            );
                    } else {
                        finish('loaded', {
                            naturalWidth: image.naturalWidth || 0,
                            naturalHeight: image.naturalHeight || 0,
                        });
                    }
                }
                if (typeof setTimeout === 'function') setTimeout(() => finish('timeout'), 4000);
            } catch (error) {
                finish('exception', { error: error?.message || String(error) });
            }
        });
    }

    async function loadZoomImageTokenObjectUrl(tokenName = '', options = {}) {
        const cleanTokenName = safeString(tokenName).trim();
        const forceAssetRead = Boolean(options?.forceAssetRead);
        const charIndex = nonNegativeIntegerOr(options?.charIndex, -1);
        const cached = cachedImageTokenPreviewUrl(cleanTokenName);
        if (cached && (!forceAssetRead || isZoomBlobPreviewSrc(cached))) {

            return cached;
        }
        const loaded = await readImageTokenAssetBytes(cleanTokenName, options);
        const previewUrl = assetBytesToZoomObjectUrl(loaded.bytes, loaded.ext, options);

        rememberImageTokenPreviewUrl(loaded.asset?.name, previewUrl);
        rememberImageTokenPreviewUrl(loaded.asset?.key, previewUrl);
        return rememberImageTokenPreviewUrl(cleanTokenName, previewUrl) || previewUrl;
    }

    async function loadChatRootImageTokenObjectUrl(tokenName = '', options = {}) {
        const cleanTokenName = safeString(tokenName).trim();
        const cached = cachedChatRootImageTokenPreviewUrl(cleanTokenName);
        const renderedHtml = safeString(options?.renderedHtml || options?.actionHtml).trim();
        if (cached && !renderedHtml) return cached;
        const loaded = await readImageTokenAssetBytes(cleanTokenName, options);
        const rootBlobOptions = rootBlobUrlOptionsForChatDom();
        const rootSource = safeString(rootBlobOptions.source).trim();
        const assetLocalhostUrl = chatRootAssetUrlFromRenderedHtml(
            renderedHtml,
            loaded.asset,
        );
        let previewUrl = assetLocalhostUrl || '';
        if (!previewUrl && cached) return cached;
        if (!previewUrl) {
            previewUrl = assetBytesToZoomObjectUrl(loaded.bytes, loaded.ext, {
                ...options,
                urlApi: rootBlobOptions.urlApi,
                blobCtor: rootBlobOptions.blobCtor,
            });
        }
        if (!previewUrl && assetLocalhostUrl) previewUrl = assetLocalhostUrl;
        lastChatRootBlobUrlSource = previewUrl === assetLocalhostUrl ? 'asset-localhost' : rootSource;
        rememberChatRootImageTokenPreviewUrl(loaded.asset?.name, previewUrl);
        rememberChatRootImageTokenPreviewUrl(loaded.asset?.key, previewUrl);
        return rememberChatRootImageTokenPreviewUrl(cleanTokenName, previewUrl) || previewUrl;
    }

    async function loadDecodedZoomImageTokenObjectUrl(tokenName = '', options = {}) {
        const previewUrl = await loadZoomImageTokenObjectUrl(tokenName, options);
        return (await decodeImageUrlForDisplay(previewUrl)) || previewUrl;
    }

    function generatedChatImageNeedsAssetHydration(src = '') {
        const value = safeString(src).trim();
        return !normalizeZoomAssetPreviewUrl(value);
    }

    function generatedChatHydratedImgOuterHtml(html = '', previewUrl = '') {
        const cleanHtml = safeString(html).trim();
        const cleanPreviewUrl = safeString(previewUrl).trim();
        if (!cleanHtml || !cleanPreviewUrl) return '';
        let nextHtml = cleanHtml.replace(
            /\ssrc\s*=\s*(?:"[^"]*"|'[^']*')/i,
            ` src="${escapeHtml(cleanPreviewUrl)}"`,
        );
        if (nextHtml === cleanHtml && /^<img\b/i.test(nextHtml)) {
            nextHtml = nextHtml.replace(/^<img\b/i, `<img src="${escapeHtml(cleanPreviewUrl)}"`);
        }
        nextHtml = nextHtml.replace(
            /\snoimage(?:\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+))?(?=\s|\/?>)/gi,
            '',
        );
        if (!/\sx-risu-naa-chat-asset-hydrated\s*=/i.test(nextHtml)) {
            nextHtml = nextHtml.replace(/\s*\/>\s*$/i, ' x-risu-naa-chat-asset-hydrated="true">');
            if (!/\sx-risu-naa-chat-asset-hydrated\s*=/i.test(nextHtml)) {
                nextHtml = nextHtml.replace(
                    />\s*$/i,
                    ' x-risu-naa-chat-asset-hydrated="true">',
                );
            }
        }
        return nextHtml;
    }

    function decodeSwImagePathForParser(src = '') {
        const value = safeString(src).trim().replace(/^https?:\/\/[^/]+/i, '');
        const match = /^\/sw\/img\/([0-9a-f]+)(?:[/?#].*)?$/i.exec(value);
        if (!match) return '';
        const hex = match[1];
        let text = '';
        for (let i = 0; i + 1 < hex.length; i += 2) {
            const code = Number.parseInt(hex.slice(i, i + 2), 16);
            if (!Number.isFinite(code)) return '';
            text += String.fromCharCode(code);
        }
        try {
            return decodeURIComponent(escape(text));
        } catch (_) {
            return text;
        }
    }

    function parserStatusForGeneratedChatImage(item = {}) {
        if (item.hasNoImageAttr) return 'noimage';
        const srcKind = safeString(item.srcKind).trim();
        const srcValue = safeString(item.srcValue || item.srcPrefix).trim();
        if (srcKind === 'url' && decodeSwImagePathForParser(srcValue)) return 'risu-parser-url';
        if (srcKind === 'blob') return 'plugin-blob-fallback';
        if (item.needsHydration) return 'needs-plugin-hydration';
        return srcKind || 'unknown';
    }

    function generatedChatParserAssetMatchInfo(assets = [], assetName = '') {
        const uniqueAssets = uniqueAssetEntries(assets);
        const cleanAssetName = safeString(assetName).trim();
        const cleanLower = cleanAssetName.toLocaleLowerCase();
        const exact = uniqueAssets.find(
            (asset) => safeString(asset?.name).trim().toLocaleLowerCase() === cleanLower,
        );
        const matched = findBestAssetEntryForTokenName(uniqueAssets, cleanAssetName);
        return {
            assetCount: uniqueAssets.length,
            exactNameMatched: Boolean(exact),
            matched: Boolean(matched),
            matchedName: matched?.name || '',
            matchedKey: compactAssetKeyForPreview(matched?.key || ''),
            matchedExt: matched?.ext || '',
            sampleAssetNames: uniqueAssets.slice(0, matched ? 4 : 8).map((asset) => asset.name),
        };
    }

    function generatedChatParserCharacterInfo(character = null, index = -1) {
        return {
            index: nonNegativeIntegerOr(index, -1),
            id: safeString(character?.chaId || character?.id).trim(),
            name: safeString(character?.name).trim(),
            chatPage: nonNegativeIntegerOr(character?.chatPage, -1),
            additionalAssetCount: Array.isArray(character?.additionalAssets)
                ? character.additionalAssets.length
                : 0,
        };
    }

    function imageTokenNamesForParserPreview(data = '') {
        const names = [];
        const regex = /\{\{(?:image|img|asset|raw)::([^}]+)\}\}/giu;
        let match;
        while ((match = regex.exec(safeString(data))) && names.length < 12) {
            const name = safeString(match[1]).trim();
            if (name) names.push(name);
        }
        return uniqueStringList(names);
    }

    function generatedChatHistoryPendingBlockNeedsRestore(html = '') {
        return /\s(?:x-risu-naa-history-pending|data-naa-history-pending)\s*=/i.test(
            safeString(html),
        );
    }

    function generatedChatHistoryAnchorFallbackHtml(block = '', anchorAssetName = '', slot = null) {
        const cleanAnchorAssetName = safeString(anchorAssetName).trim();
        if (!cleanAnchorAssetName) return '';
        const originalMarkup =
            htmlFirstAttributeValue(block, ['x-risu-naa-original', 'data-naa-original']) ||
            safeString(slot?.sourceImageMarkup).trim() ||
            reverseAssetMap.get(cleanAnchorAssetName) ||
            '';
        const storedMeta = displayAssetMetaMap.get(cleanAnchorAssetName) || {};
        const anchorEntryId = displayAssetSlotGeneratedEntryId(cleanAnchorAssetName);
        return generatedAssetHtmlTemplate(cleanAnchorAssetName, originalMarkup, {
            ...storedMeta,
            slotId: safeString(slot?.slotId || slotIdFromGeneratedImageHtml(block)).trim(),
            renderedEntryId: anchorEntryId,
            sourceImageMarkup: originalMarkup || storedMeta.sourceImageMarkup,
            __naaSkipCurrentSlotRedirect: true,
        });
    }

    async function hydratePendingChatHistoryImagesInRootDom(rootDoc, reason = '') {
        if (!isChatHistoryStorageEnabled()) return 0;
        if (!rootDoc || typeof rootDoc.querySelectorAll !== 'function') return 0;
        const nodes = await rootDoc.querySelectorAll(
            '.naa-generated-image, .x-risu-naa-generated-image',
        );
        const len = await nodes.length();
        let hydrated = 0;
        for (let i = 0; i < len; i++) {
            const node = await nodes.at(i);
            const block = await node.getOuterHTML();
            const isPendingHistoryRestore = generatedChatHistoryPendingBlockNeedsRestore(block);
            const anchorAssetName = assetNameFromGeneratedImageHtml(block);
            if (!anchorAssetName) continue;
            const slotId = slotIdFromGeneratedImageHtml(block);
            const slot =
                displayAssetSlotForAsset('', slotId) ||
                displayAssetSlotForAsset(anchorAssetName, slotId);
            const renderedEntryId = htmlFirstAttributeValue(block, [
                'x-risu-naa-rendered-history-entry-id',
                'data-naa-rendered-history-entry-id',
            ]);
            const renderedEntry =
                renderedEntryId && slot?.entries?.find?.((entry) => entry.entryId === renderedEntryId);
            const savedCurrentEntry = currentDisplayAssetSlotEntry(slot);
            const currentEntry = isPendingHistoryRestore
                ? renderedEntry || savedCurrentEntry
                : savedCurrentEntry;
            const isOriginalDisplay =
                htmlFirstAttributeValue(block, [
                    'x-risu-naa-original-display',
                    'data-naa-original-display',
                ]) === 'true';
            const anchorEntryId = isOriginalDisplay
                ? displayAssetSlotOriginalEntryId(slot?.slotId || slotId)
                : displayAssetSlotGeneratedEntryId(anchorAssetName);
            const shouldRestoreSavedCurrent = Boolean(
                slot &&
                    currentEntry?.assetName &&
                    currentEntry.entryId &&
                    currentEntry.entryId !== anchorEntryId,
            );
            if (!isPendingHistoryRestore && !shouldRestoreSavedCurrent) continue;

            if (!slot || !currentEntry?.assetName || currentEntry.entryId === anchorEntryId) {
                const fallback = generatedChatHistoryAnchorFallbackHtml(
                    block,
                    anchorAssetName,
                    slot,
                );

                if (fallback) {
                    await node.setOuterHTML(fallback);
                    hydrated += 1;
                }
                continue;
            }
            const originalMarkup =
                htmlFirstAttributeValue(block, ['x-risu-naa-original', 'data-naa-original']) ||
                safeString(currentEntry.sourceImageMarkup || slot.sourceImageMarkup).trim() ||
                reverseAssetMap.get(anchorAssetName) ||
                '';
            const entryMeta = displayAssetMetaMap.get(currentEntry.assetName) || {};
            const charIndex = nonNegativeIntegerOr(
                currentEntry.charIndex >= 0
                    ? currentEntry.charIndex
                    : htmlIndexAttributeValue(block, [
                          'x-risu-naa-char-index',
                          'data-naa-char-index',
                      ]),
                -1,
            );
            let previewUrl = '';
            try {
                previewUrl = await loadChatRootImageTokenObjectUrl(
                    currentEntry.assetName,
                    {
                        ...(charIndex >= 0 ? { charIndex } : {}),
                        renderedHtml: block,
                    },
                );
            } catch (error) {

            }
            const replacement = previewUrl
                ? generatedAssetHtmlTemplate(currentEntry.assetName, originalMarkup, {
                      ...entryMeta,
                      slotId: slot.slotId,
                      originalDisplay: currentEntry.type === 'original',
                      originalDisplayNatural:
                          currentEntry.type === 'original' ||
                          Boolean(entryMeta.originalDisplayNatural),
                      displaySrc: previewUrl,
                      preferDisplaySrc: true,
                      renderedEntryId: currentEntry.entryId,
                      renderOnlyHistoryPreview: true,
                      persistentAssetName: anchorAssetName,
                      width:
                          currentEntry.type === 'original'
                              ? entryMeta.width
                              : currentEntry.width || entryMeta.width,
                      height:
                          currentEntry.type === 'original'
                              ? entryMeta.height
                              : currentEntry.height || entryMeta.height,
                      sourceImageMarkup:
                          entryMeta.sourceImageMarkup ||
                          currentEntry.sourceImageMarkup ||
                          slot.sourceImageMarkup ||
                          originalMarkup,
                      ...locationMetaFromParts({
                          ...slot,
                          ...currentEntry,
                          ...entryMeta,
                      }),
                      __naaSkipCurrentSlotRedirect: true,
                  })
                : generatedChatHistoryAnchorFallbackHtml(block, anchorAssetName, slot);

            if (!replacement) continue;
            await node.setOuterHTML(replacement);
            hydrated += 1;
        }
        if (hydrated) invalidateZoomHitTestCache();
        return hydrated;
    }

    async function hydrateGeneratedChatAssetImagesInRootDom(rootDoc, reason = '') {
        if (
            !rootDoc ||
            typeof rootDoc.querySelectorAll !== 'function' ||
            generatedChatImageHydrationInFlight
        ) {
            return 0;
        }
        generatedChatImageHydrationInFlight = true;
        let hydrated = 0;
        try {
            const blocks = await rootDoc.querySelectorAll(
                '.naa-generated-image, .x-risu-naa-generated-image',
            );
            const blockCount = await blocks.length();
            let pendingBlockCount = 0;
            let savedMismatchBlockCount = 0;
            if (isChatHistoryStorageEnabled()) {
                for (let i = 0; i < blockCount; i++) {
                    const blockNode = await blocks.at(i);
                    const blockHtml = await blockNode.getOuterHTML();
                    if (generatedChatHistoryPendingBlockNeedsRestore(blockHtml)) {
                        pendingBlockCount += 1;
                    }
                    const anchorAssetName = assetNameFromGeneratedImageHtml(blockHtml);
                    const slotId = slotIdFromGeneratedImageHtml(blockHtml);
                    const slot =
                        displayAssetSlotForAsset('', slotId) ||
                        displayAssetSlotForAsset(anchorAssetName, slotId);
                    const savedCurrentEntry = currentDisplayAssetSlotEntry(slot);
                    const isOriginalDisplay =
                        htmlFirstAttributeValue(blockHtml, [
                            'x-risu-naa-original-display',
                            'data-naa-original-display',
                        ]) === 'true';
                    const anchorEntryId = isOriginalDisplay
                        ? displayAssetSlotOriginalEntryId(slot?.slotId || slotId)
                        : displayAssetSlotGeneratedEntryId(anchorAssetName);
                    if (
                        slot &&
                        savedCurrentEntry?.entryId &&
                        savedCurrentEntry.entryId !== anchorEntryId
                    ) {
                        savedMismatchBlockCount += 1;
                    }
                }
            }
            if (
                blockCount > 0 &&
                (pendingBlockCount > 0 || savedMismatchBlockCount > 0 || reason !== 'interval')
            ) {
                recordZoomDebugEntry('chat-image-hydration-start', 'Generated chat image hydration started.', {
                    reason,
                    blockCount,
                    pendingBlockCount,
                    savedMismatchBlockCount,
                });
            }
            const pendingHydrated = await hydratePendingChatHistoryImagesInRootDom(rootDoc, reason);
            hydrated += pendingHydrated;
            if (pendingHydrated || reason !== 'interval') {
                recordZoomDebugEntry('chat-image-history-hydrated', 'Hydrated pending/current history chat blocks.', {
                    reason,
                    pendingHydrated,
                    totalHydrated: hydrated,
                });
            }
            const imgs = await rootDoc.querySelectorAll(
                '.naa-generated-image img, .x-risu-naa-generated-image img',
            );
            const len = await imgs.length();
            const probeItems = [];
            for (let i = 0; i < len; i++) {
                const img = await imgs.at(i);
                const html = await img.getOuterHTML();
                const currentSrc = htmlFirstAttributeValue(html, ['src']);
                const assetName =
                    htmlFirstAttributeValue(html, ['x-risu-naa-asset', 'data-naa-asset']) ||
                    rawAssetNameFromImageSrc(currentSrc);
                const charIndex = htmlIndexAttributeValue(html, [
                    'x-risu-naa-char-index',
                    'data-naa-char-index',
                ]);
                const chatIndex = htmlIndexAttributeValue(html, [
                    'x-risu-naa-chat-index',
                    'data-naa-chat-index',
                ]);
                const messageIndex = htmlIndexAttributeValue(html, [
                    'x-risu-naa-message-index',
                    'data-naa-message-index',
                ]);
                probeItems.push({
                    index: i,
                    assetName,
                    charIndex,
                    chatIndex,
                    messageIndex,
                    srcKind: zoomPreviewSrcKind(currentSrc),
                    srcPrefix: safeString(currentSrc).slice(0, 80),
                    srcValue: currentSrc,
                    decodedPath: decodeSwImagePathForParser(currentSrc),
                    needsHydration: generatedChatImageNeedsAssetHydration(currentSrc),
                    hasNoImageAttr: /\snoimage(?:\s|=|>)/i.test(html),
                });
            }
            if (probeItems.length) {
                await repairLegacyGeneratedChatParserSources(reason, probeItems);
            }
            for (let i = 0; i < len; i++) {
                const img = await imgs.at(i);
                const html = await img.getOuterHTML();
                const currentSrc = htmlFirstAttributeValue(html, ['src']);
                if (!generatedChatImageNeedsAssetHydration(currentSrc)) continue;
                const assetName =
                    htmlFirstAttributeValue(html, ['x-risu-naa-asset', 'data-naa-asset']) ||
                    rawAssetNameFromImageSrc(currentSrc);
                if (!assetName) continue;
                const charIndex = htmlIndexAttributeValue(html, [
                    'x-risu-naa-char-index',
                    'data-naa-char-index',
                ]);
                let previewUrl = '';
                try {
                    previewUrl = await loadChatRootImageTokenObjectUrl(assetName, {
                        charIndex,
                        renderedHtml: html,
                    });
                } catch (error) {
                    recordZoomDebugEntry('chat-image-hydration-preview-error', 'Failed to load preview for chat image hydration.', {
                        reason,
                        assetName,
                        charIndex,
                        currentSrcKind: zoomPreviewSrcKind(currentSrc),
                        error: error?.message || String(error),
                    });
                    continue;
                }
                if (!previewUrl) continue;
                const hydratedHtml = generatedChatHydratedImgOuterHtml(html, previewUrl);
                if (!hydratedHtml) continue;
                await img.setOuterHTML(hydratedHtml);
                hydrated += 1;
                recordZoomDebugEntry('chat-image-src-hydrated', 'Hydrated generated chat image src.', {
                    reason,
                    assetName,
                    charIndex,
                    beforeSrcKind: zoomPreviewSrcKind(currentSrc),
                    previewUrlKind: zoomPreviewSrcKind(previewUrl),
                    hydratedHtml: zoomDebugHtmlImageSummary(hydratedHtml),
                });
            }
            if (hydrated || reason !== 'interval') {
                recordZoomDebugEntry('chat-image-hydration-finish', 'Generated chat image hydration finished.', {
                    reason,
                    hydrated,
                });
            }
            return hydrated;
        } finally {
            generatedChatImageHydrationInFlight = false;
        }
    }

    function scheduleGeneratedChatImageHydration(reason = '', delayMs = 60) {
        if (!isActivePluginInstance()) return;
        if (safeString(reason).trim() !== 'interval') {
            recordZoomDebugEntry('chat-image-hydration-scheduled', 'Scheduled generated chat image hydration.', {
                reason,
                delayMs: Math.max(0, Number(delayMs) || 0),
                replacingExistingTimer: Boolean(generatedChatImageHydrationDelayTimer),
            });
        }
        if (generatedChatImageHydrationDelayTimer) {
            try {
                clearTimeout(generatedChatImageHydrationDelayTimer);
            } catch (_) {}
        }
        generatedChatImageHydrationDelayTimer = setTimeout(() => {
            generatedChatImageHydrationDelayTimer = null;
            if (!isActivePluginInstance() || typeof Risu.getRootDocument !== 'function') return;
            Risu.getRootDocument()
                .then((rootDoc) => hydrateGeneratedChatAssetImagesInRootDom(rootDoc, reason))
                .catch(() => {});
        }, Math.max(0, Number(delayMs) || 0));
    }

    function startGeneratedChatImageHydrationLoop() {
        if (generatedChatImageHydrationTimer || typeof setInterval !== 'function') return;
        generatedChatImageHydrationTimer = setInterval(() => {
            scheduleGeneratedChatImageHydration('interval', 0);
        }, GENERATED_CHAT_IMAGE_HYDRATION_INTERVAL_MS);
    }

    async function loadOriginalImageTokenPreviewUrl(markup = '', options = {}) {
        const cleanMarkup = extractFirstSupportedImageMarkup(markup) || safeString(markup).trim();
        const fallback = imageSrcFromOriginalMarkup(markup);
        const parsed = parseSupportedImageMarkup(cleanMarkup);
        const tokenName = safeString(
            parsed?.tokenName || rawAssetNameFromImageSrc(fallback),
        ).trim();
        if (!tokenName) return fallback;
        const previewUrl = await loadZoomImageTokenObjectUrl(tokenName, options);
        return previewUrl || fallback;
    }

    async function resolveOriginalMarkupPreviewUrl(markup = '', options = {}) {
        const fallback = imageSrcFromOriginalMarkup(markup);
        const cleanMarkup = extractFirstSupportedImageMarkup(markup) || safeString(markup).trim();
        const parsed = parseSupportedImageMarkup(cleanMarkup);
        const tokenName = safeString(
            parsed?.tokenName || rawAssetNameFromImageSrc(fallback),
        ).trim();
        try {
            return (await loadOriginalImageTokenPreviewUrl(markup, options)) || fallback;
        } catch (error) {

            return fallback;
        }
    }

    function zoomHydrationPriorityIndexes(totalCount = 0, activeIndex = 0, visibleLimit = 0) {
        const total = Math.max(0, Math.floor(Number(totalCount) || 0));
        if (!total) return [];
        const active = intBetween(activeIndex, 0, 0, total - 1);
        const limit = intBetween(visibleLimit, 0, 0, total);
        const indexes = [];
        const push = (index) => {
            const value = Number(index);
            if (!Number.isInteger(value) || value < 0 || value >= total) return;
            if (!indexes.includes(value)) indexes.push(value);
        };
        push(active);
        for (let index = 0; index < limit; index++) push(index);
        push(active - 1);
        push(active + 1);
        return indexes;
    }

    function splitZoomHydrationItems(items = [], activeIndex = 0, visibleLimit = 0) {
        const list = Array.isArray(items) ? items.filter(Boolean) : [];
        const priorityIndexes = zoomHydrationPriorityIndexes(
            list.length,
            activeIndex,
            visibleLimit,
        );
        const prioritySet = new Set(priorityIndexes);
        return {
            priority: priorityIndexes.map((index) => list[index]).filter(Boolean),
            deferred: list.filter((_item, index) => !prioritySet.has(index)),
        };
    }

    function zoomHydrationItemsForCurrentHistory(state = naaZoomGalleryState) {
        const selected = zoomGallerySelectedItem(state);
        const history = zoomHistoryItemsForGalleryItem(selected);
        const activeIndex = zoomPreviewHistoryIndexForState(state, history);
        return splitZoomHydrationItems(
            history,
            Math.max(0, activeIndex),
            ZOOM_VISIBLE_HISTORY_PREVIEW_HYDRATE_LIMIT,
        );
    }

    function rememberZoomHistoryPreviewInSlot(item = {}, previewUrl = '') {
        const normalized = normalizeZoomAssetPreviewUrl(previewUrl);
        const slotId = safeString(item?.slotId).trim();
        if (!normalized || !slotId) return false;
        const slot = displayAssetSlots.get(slotId);
        const entry = slot?.entries?.find(
            (candidate) =>
                safeString(candidate?.entryId).trim() === safeString(item?.entryId).trim() ||
                (item?.assetName &&
                    safeString(candidate?.assetName).trim() === safeString(item.assetName).trim()),
        );
        if (!entry) return false;
        entry.imgSrc = normalized;
        return true;
    }

    async function hydrateZoomGalleryPreviewUrls(items = []) {
        let changed = false;
        for (const item of Array.isArray(items) ? items : []) {
            if (item?.assetName && zoomPreviewSrcKind(item.imgSrc) !== 'blob') {
                try {
                    const nextImgSrc =
                        (await loadZoomImageTokenObjectUrl(item.assetName, {
                            forceAssetRead: true,
                        })) || item.imgSrc;
                    if (nextImgSrc !== item.imgSrc) {
                        item.imgSrc = nextImgSrc;
                        changed = true;
                    }
                } catch (_) {}
            }
            if (item?.originalMarkup) {
                const nextOriginalImgSrc = await resolveOriginalMarkupPreviewUrl(
                    item.originalMarkup,
                );
                if (nextOriginalImgSrc !== item.originalImgSrc) {
                    item.originalImgSrc = nextOriginalImgSrc;
                    changed = true;
                }
            }
        }
        return changed;
    }

    async function hydrateZoomHistoryPreviewUrls(items = []) {
        let changed = false;
        for (const item of Array.isArray(items) ? items : []) {
            const previousImgSrc = item?.imgSrc || '';
            if (isZoomBlobPreviewSrc(previousImgSrc)) continue;
            let nextImgSrc = '';
            if (item?.type === 'original') {
                if (item.assetName) {
                    try {
                        nextImgSrc = await loadZoomImageTokenObjectUrl(item.assetName, {
                            forceAssetRead: true,
                        });
                    } catch (_) {}
                }
                try {
                    nextImgSrc =
                        nextImgSrc ||
                        (await resolveOriginalMarkupPreviewUrl(item.sourceImageMarkup));
                } catch (_) {}

            } else if (item?.assetName) {
                try {
                    nextImgSrc = await loadZoomImageTokenObjectUrl(item.assetName, {
                        forceAssetRead: true,
                    });
                } catch (_) {}
            }
            if (nextImgSrc && nextImgSrc !== item.imgSrc) {
                item.imgSrc = nextImgSrc;
                rememberZoomHistoryPreviewInSlot(item, nextImgSrc);
                changed = true;
            }
        }
        return changed;
    }

    async function refreshZoomGalleryItemsFromCurrentChatDeferred(runId, state, rootDoc = null) {
        if (!state || runId !== naaZoomPreviewHydrationRunId || !naaZoomOverlayRef) return false;
        const currentSelected = zoomGallerySelectedItem(state);
        const renderOnlyHistoryPreview = Boolean(state.renderOnlyHistoryPreview);
        const persistentSlotId = safeString(state.persistentSlotId).trim();
        const renderedHistoryEntryId = safeString(state.renderedHistoryEntryId).trim();
        const selectedAssetName = safeString(
            (renderOnlyHistoryPreview
                ? state.persistentSelectedAssetName || state.clickedAssetName
                : state.clickedAssetName) || currentSelected?.assetName,
        ).trim();
        const selectedImgSrc = renderOnlyHistoryPreview
            ? ''
            : safeString(state.clickedImgSrc || currentSelected?.imgSrc).trim();
        let items;
        if (renderOnlyHistoryPreview) {
            const snapshot = await getCurrentChatForAssetReplacement().catch(() => null);
            const chatKey = currentChatKey(
                snapshot?.character,
                snapshot?.charIndex,
                snapshot?.chatIndex,
                snapshot?.chat,
            );
            items = collectGeneratedImageItemsFromChat(snapshot?.chat, chatKey);
        } else {
            items = await collectCurrentChatGeneratedImageItems();
        }
        const domLoadedSrcMap = await collectZoomDomLoadedImageSrcMap(rootDoc);
        items = applyZoomDomLoadedImageSrcMap(items, domLoadedSrcMap);
        if (
            runId !== naaZoomPreviewHydrationRunId ||
            !naaZoomOverlayRef ||
            naaZoomGalleryState !== state
        ) {
            return false;
        }
        let selectedIndex = -1;
        if (persistentSlotId && selectedAssetName) {
            selectedIndex = items.findIndex(
                (item) =>
                    safeString(item?.slotId || item?.meta?.slotId).trim() === persistentSlotId &&
                    safeString(item?.assetName).trim() === selectedAssetName,
            );
        }
        if (selectedIndex < 0 && persistentSlotId) {
            selectedIndex = items.findIndex(
                (item) => safeString(item?.slotId || item?.meta?.slotId).trim() === persistentSlotId,
            );
        }
        if (selectedIndex < 0 && selectedAssetName) {
            selectedIndex = items.findIndex(
                (item) => safeString(item?.assetName).trim() === selectedAssetName,
            );
        }
        if (selectedIndex >= 0) {
            const preferredImgSrc =
                selectedImgSrc && !normalizeImageDataUrl(selectedImgSrc) ? selectedImgSrc : '';
            items[selectedIndex] = {
                ...items[selectedIndex],
                imgSrc: preferredImgSrc || items[selectedIndex].imgSrc,
            };
        } else if (currentSelected?.assetName && !renderOnlyHistoryPreview) {
            selectedIndex = items.length;
            items = [...items, currentSelected];
        } else if (renderOnlyHistoryPreview) {
            items = Array.isArray(state.items) && state.items.length ? state.items : items;
            selectedIndex = intBetween(state.selectedIndex, 0, 0, Math.max(items.length - 1, 0));
        }
        if (items.length) {
            state.items = items;
            state.selectedIndex = Math.max(0, selectedIndex);
        }
        if (renderOnlyHistoryPreview && renderedHistoryEntryId) {
            const selectedItem = zoomGallerySelectedItem(state);
            const history = zoomHistoryItemsForGalleryItem(selectedItem);
            const renderedIndex = history.findIndex(
                (entry) => safeString(entry?.entryId).trim() === renderedHistoryEntryId,
            );
            if (renderedIndex >= 0) {
                state.view = 'history';
                state.historyIndex = renderedIndex;
            }
        }
        state.needsChatItemRefresh = false;
        await renderNaaZoomOverlayContent();
        return true;
    }

    async function hydrateZoomPreviewItems(runId, state, items = [], options = {}) {
        let changed = false;
        await runWithConcurrency(items, ZOOM_DEFERRED_PREVIEW_HYDRATE_CONCURRENCY, async (item) => {
            if (
                runId !== naaZoomPreviewHydrationRunId ||
                !naaZoomOverlayRef ||
                naaZoomGalleryState !== state
            ) {
                return null;
            }
            const itemChanged = options?.history
                ? await hydrateZoomHistoryPreviewUrls([item])
                : await hydrateZoomGalleryPreviewUrls([item]);
            changed = changed || itemChanged;
            return item;
        });
        return changed;
    }

    function scheduleDeferredZoomPreviewHydration(runId, state, items = [], historyItems = []) {
        const list = Array.isArray(items) ? items.filter(Boolean) : [];
        const historyList = Array.isArray(historyItems) ? historyItems.filter(Boolean) : [];
        if (!list.length && !historyList.length) return;
        if (zoomDeferredPreviewHydrationTimer) {
            try {
                clearTimeout(zoomDeferredPreviewHydrationTimer);
            } catch (_) {}
        }
        zoomDeferredPreviewHydrationTimer = setTimeout(() => {
            zoomDeferredPreviewHydrationTimer = null;
            (async () => {
                const galleryChanged = await hydrateZoomPreviewItems(runId, state, list);
                const historyChanged = await hydrateZoomPreviewItems(runId, state, historyList, {
                    history: true,
                });
                const changed = galleryChanged || historyChanged;

                return changed;
            })()
                .then(async (changed) => {
                    if (
                        changed &&
                        runId === naaZoomPreviewHydrationRunId &&
                        naaZoomOverlayRef &&
                        naaZoomGalleryState === state
                    ) {
                        await renderNaaZoomOverlayContent();
                    }
                })
                .catch((error) => {

                });
        }, ZOOM_DEFERRED_PREVIEW_HYDRATE_DELAY_MS);
    }

    async function hydrateZoomGalleryPreviewUrlsDeferred(runId, state, rootDoc = null) {
        if (!state || runId !== naaZoomPreviewHydrationRunId || !naaZoomOverlayRef) return;
        if (state.needsChatItemRefresh) {
            await refreshZoomGalleryItemsFromCurrentChatDeferred(runId, state, rootDoc);
            if (
                runId !== naaZoomPreviewHydrationRunId ||
                !naaZoomOverlayRef ||
                naaZoomGalleryState !== state
            ) {
                return;
            }
        }
        const items = Array.isArray(state.items) ? state.items : [];
        const selectedIndex = intBetween(state.selectedIndex, 0, 0, Math.max(items.length - 1, 0));
        const selected = items[selectedIndex];
        let selectedChanged = false;
        if (selected) {
            selectedChanged = await hydrateZoomGalleryPreviewUrls([selected]);
            if (
                runId !== naaZoomPreviewHydrationRunId ||
                !naaZoomOverlayRef ||
                naaZoomGalleryState !== state
            ) {
                return;
            }
            if (selectedChanged) await renderNaaZoomOverlayContent();
        }
        const historyHydration = zoomHydrationItemsForCurrentHistory(state);
        const historyChanged = await hydrateZoomPreviewItems(
            runId,
            state,
            historyHydration.priority,
            {
                history: true,
            },
        );
        if (
            historyChanged &&
            runId === naaZoomPreviewHydrationRunId &&
            naaZoomOverlayRef &&
            naaZoomGalleryState === state
        ) {
            await renderNaaZoomOverlayContent();
        }
        const rest = items.filter((item, index) => item && index !== selectedIndex);
        const galleryHydration = splitZoomHydrationItems(
            rest,
            0,
            ZOOM_VISIBLE_PREVIEW_HYDRATE_LIMIT,
        );
        const visibleRest = galleryHydration.priority;
        const deferredRest = galleryHydration.deferred;
        const restChanged = await hydrateZoomPreviewItems(runId, state, visibleRest);
        if (
            restChanged &&
            runId === naaZoomPreviewHydrationRunId &&
            naaZoomOverlayRef &&
            naaZoomGalleryState === state
        ) {
            await renderNaaZoomOverlayContent();
        }

        scheduleDeferredZoomPreviewHydration(runId, state, deferredRest, historyHydration.deferred);
    }

    function scheduleZoomGalleryPreviewHydration(rootDoc = null) {
        const state = naaZoomGalleryState;
        if (!state || !naaZoomOverlayRef) return;
        const runId = ++naaZoomPreviewHydrationRunId;
        if (naaZoomPreviewHydrationTimer) {
            try {
                clearTimeout(naaZoomPreviewHydrationTimer);
            } catch (_) {}
        }
        naaZoomPreviewHydrationTimer = setTimeout(() => {
            naaZoomPreviewHydrationTimer = null;
            hydrateZoomGalleryPreviewUrlsDeferred(runId, state, rootDoc).catch((error) => {

            });
        }, 0);
    }

    function imageSrcFromGeneratedBlock(block, assetName, meta = {}) {
        const cachedPreview = cachedImageTokenPreviewUrl(assetName);
        const htmlSrc = htmlFirstAttributeValue(block, ['src']);
        return (
            (normalizeZoomAssetPreviewUrl(cachedPreview) ? cachedPreview : '') ||
            (normalizeImageDataUrl(htmlSrc) ? '' : htmlSrc) ||
            (assetName ? `{{raw::${assetName}}}` : '')
        );
    }

    async function collectZoomDomLoadedImageSrcMap(rootDoc) {
        const srcMap = new Map();
        if (!rootDoc || typeof rootDoc.querySelectorAll !== 'function') return srcMap;
        const blocks = await rootDoc.querySelectorAll(
            '.naa-generated-image, .x-risu-naa-generated-image',
        );
        const len = await blocks.length();
        for (let i = 0; i < len; i++) {
            const el = await blocks.at(i);
            const html = await el.getOuterHTML();
            const assetName = assetNameFromGeneratedImageHtml(html);
            const slotId = slotIdFromGeneratedImageHtml(html);
            const src = htmlFirstAttributeValue(html, ['src']);
            if (assetName && src && !isRawAssetImageSrc(src) && !normalizeImageDataUrl(src)) {
                rememberImageTokenPreviewUrl(assetName, src);
                const cachedSrc = cachedImageTokenPreviewUrl(assetName) || src;
                if (slotId) srcMap.set(`${slotId}::${assetName}`, cachedSrc);
                if (!srcMap.has(assetName)) srcMap.set(assetName, cachedSrc);
            }
        }
        return srcMap;
    }

    function applyZoomDomLoadedImageSrcMap(items = [], domLoadedSrcMap = new Map()) {
        if (!domLoadedSrcMap?.size) return items;
        return (Array.isArray(items) ? items : []).map((item) => {
            const assetName = safeString(item?.assetName).trim();
            const slotId = safeString(item?.slotId || item?.meta?.slotId).trim();
            const src =
                (slotId && assetName ? domLoadedSrcMap.get(`${slotId}::${assetName}`) : '') ||
                domLoadedSrcMap.get(assetName);
            if (!src || !item || (item.imgSrc && !isRawAssetImageSrc(item.imgSrc))) return item;
            return { ...item, imgSrc: src };
        });
    }

    function collectGeneratedImageItemsFromChat(chat, chatKey = '') {
        const items = [];
        const messages = Array.isArray(chat?.message) ? chat.message : [];
        messages.forEach((message, messageIndex) => {
            const data = safeString(message?.data);
            const regex = naaGeneratedImageBlockRegex();
            let match;
            while ((match = regex.exec(data))) {
                const block = match[0];
                const assetName = assetNameFromGeneratedImageHtml(block);
                if (!assetName) continue;
                const meta = displayAssetMetaMap.get(assetName) || {};
                const originalMarkup =
                    htmlFirstAttributeValue(block, ['x-risu-naa-original', 'data-naa-original']) ||
                    safeString(meta.sourceImageMarkup).trim() ||
                    reverseAssetMap.get(assetName) ||
                    '';
                const seed = normalizeNovelAISeed(
                    htmlFirstAttributeValue(block, ['x-risu-naa-seed', 'data-naa-seed']) ||
                        meta.seed,
                );
                const htmlSlotId = htmlFirstAttributeValue(block, [
                    'x-risu-naa-slot-id',
                    'data-naa-slot-id',
                ]);
                const originalDisplayAttr =
                    htmlFirstAttributeValue(block, [
                        'x-risu-naa-original-display',
                        'data-naa-original-display',
                    ]) === 'true';
                const sourceImageToken = originalDisplayAttr
                    ? assetName
                    : safeString(meta.sourceImageToken).trim();
                const itemMeta = {
                    ...meta,
                    chatKey: safeString(meta.chatKey || chatKey).trim(),
                    messageIndex,
                    originalDisplay: originalDisplayAttr || Boolean(meta.originalDisplay),
                    originalDisplayNatural:
                        originalDisplayAttr || Boolean(meta.originalDisplayNatural),
                    sourceImageToken: originalDisplayAttr
                        ? assetName
                        : sourceImageToken || meta.sourceImageToken,
                    sourceImageMarkup: originalMarkup || meta.sourceImageMarkup,
                    displaySrc: originalDisplayAttr ? rawAssetImageSrc(assetName) : meta.displaySrc,
                };
                itemMeta.slotId = imageSlotIdFromParts({
                    ...itemMeta,
                    slotId: htmlSlotId || itemMeta.slotId,
                    assetName,
                    sourceImageToken: itemMeta.sourceImageToken,
                    sourceImageMarkup: originalMarkup || itemMeta.sourceImageMarkup,
                });
                const promptKey =
                    htmlFirstAttributeValue(block, [
                        'x-risu-naa-prompt-key',
                        'data-naa-prompt-key',
                    ]) || meta.promptKey;
                items.push({
                    type: 'current',
                    assetName,
                    html: block,
                    messageIndex,
                    order: items.length,
                    imgSrc: imageSrcFromGeneratedBlock(block, assetName, itemMeta),
                    originalMarkup,
                    seed: originalDisplayAttr ? '' : seed,
                    promptKey: safeString(promptKey).trim(),
                    seedFixed: Boolean(itemMeta.seedFixed),
                    width: originalDisplayAttr ? 0 : itemMeta.width,
                    height: originalDisplayAttr ? 0 : itemMeta.height,
                    chatKey: itemMeta.chatKey,
                    slotId: itemMeta.slotId,
                    meta: itemMeta,
                });
            }
        });
        return items;
    }

    async function collectCurrentChatGeneratedImageItems() {
        const snapshot = await getCurrentChatForAssetReplacement();
        const signature = zoomGeneratedItemsCacheSignature(snapshot);
        if (
            signature &&
            zoomGeneratedItemsCache.signature === signature &&
            Date.now() - zoomGeneratedItemsCache.at < ZOOM_GENERATED_ITEMS_CACHE_MS
        ) {
            return cloneZoomGalleryItems(zoomGeneratedItemsCache.items);
        }
        const chatKey = currentChatKey(
            snapshot?.character,
            snapshot?.charIndex,
            snapshot?.chatIndex,
            snapshot?.chat,
        );
        const items = collectGeneratedImageItemsFromChat(snapshot?.chat, chatKey);
        zoomGeneratedItemsCache = {
            signature,
            at: Date.now(),
            items: cloneZoomGalleryItems(items),
        };
        return cloneZoomGalleryItems(items);
    }

    function zoomTimelineKeyForItem(item = {}) {
        if (item.type === 'original') return `original::${safeString(item.sourceImageMarkup)}`;
        return `generated::${safeString(item.assetName || item.imgSrc)}`;
    }

    function zoomHistoryItemsForGalleryItem(item = {}) {
        const slot = displayAssetSlotForGalleryItem(item);
        if (!slot) return [];
        const sourceMarkup = safeString(slot.sourceImageMarkup || item.originalMarkup).trim();
        const originalEntries = slot.entries
            .filter((entry) => entry.type === 'original')
            .slice(0, 1);
        const generatedEntries = slot.entries
            .filter((entry) => entry.type === 'generated')
            .slice()
            .sort((a, b) => (a.createdAt || 0) - (b.createdAt || 0));
        return [...originalEntries, ...generatedEntries]
            .map((entry, index) => {
                const entryMeta = entry.assetName
                    ? displayAssetMetaMap.get(entry.assetName) || {}
                    : {};
                const entrySourceMarkup = safeString(
                    entry.sourceImageMarkup || entryMeta.sourceImageMarkup || sourceMarkup,
                ).trim();
                const storedFallbackSrc = safeString(entryMeta.displaySrc || entry.imgSrc).trim();
                const fallbackSrc = normalizeImageDataUrl(storedFallbackSrc)
                    ? ''
                    : storedFallbackSrc;
                const sourceFallbackSrc = imageSrcFromOriginalMarkup(entrySourceMarkup);
                const safeSourceFallbackSrc = normalizeImageDataUrl(sourceFallbackSrc)
                    ? ''
                    : sourceFallbackSrc;
                const imgSrc =
                    entry.type === 'original'
                        ? zoomResolvedHistoryPreviewSrc(
                              entry.assetName,
                              fallbackSrc || safeSourceFallbackSrc,
                              entrySourceMarkup,
                          ) ||
                          safeSourceFallbackSrc ||
                          NAA_ZOOM_PLACEHOLDER_IMAGE
                        : zoomResolvedHistoryPreviewSrc(
                              entry.assetName,
                              fallbackSrc,
                              entrySourceMarkup,
                              {
                                  allowSourceFallback: false,
                              },
                           ) ||
                           fallbackSrc ||
                           (entry.assetName ? `{{raw::${entry.assetName}}}` : NAA_ZOOM_PLACEHOLDER_IMAGE);
                return {
                    type: entry.type,
                    entryId: entry.entryId,
                    label:
                        entry.label ||
                        (entry.type === 'original'
                            ? 'Original'
                            : entry.seed
                              ? `Seed ${entry.seed}`
                              : `History ${index}`),
                    assetName: entry.assetName,
                    imgSrc,
                    seed: entry.seed || entryMeta.seed,
                    promptKey: entry.promptKey || entryMeta.promptKey || item.promptKey,
                    width: entry.width || entryMeta.width,
                    height: entry.height || entryMeta.height,
                    sourceImageMarkup: entrySourceMarkup,
                    slotId: slot.slotId,
                };
            })
            .filter((entry) => entry.type === 'original' || safeString(entry.assetName).trim());
    }

    function zoomAppliedHistoryIndexForState(state = naaZoomGalleryState, history = null) {
        const selected = zoomGallerySelectedItem(state);
        const items = Array.isArray(history) ? history : zoomHistoryItemsForGalleryItem(selected);
        if (!selected || !items.length) return -1;
        const slot = displayAssetSlotForGalleryItem(selected);
        if (slot?.currentEntryId)
            return items.findIndex((entry) => entry?.entryId === slot.currentEntryId);
        const selectedKey = zoomTimelineKeyForItem({
            type: 'generated',
            assetName: selected.assetName,
            imgSrc: selected.imgSrc,
            sourceImageMarkup: selected.originalMarkup,
        });
        return items.findIndex((entry) => zoomTimelineKeyForItem(entry) === selectedKey);
    }

    function zoomPreviewHistoryIndexForState(state = naaZoomGalleryState, history = null) {
        const selected = zoomGallerySelectedItem(state);
        const items = Array.isArray(history) ? history : zoomHistoryItemsForGalleryItem(selected);
        if (!items.length) return -1;
        if (state?.view === 'history') {
            return intBetween(state.historyIndex, 0, 0, Math.max(items.length - 1, 0));
        }
        return zoomAppliedHistoryIndexForState(state, items);
    }

    function zoomSelectedHistoryItemForState(state = naaZoomGalleryState, history = null) {
        const selected = zoomGallerySelectedItem(state);
        const items = Array.isArray(history) ? history : zoomHistoryItemsForGalleryItem(selected);
        const index = zoomPreviewHistoryIndexForState(state, items);
        return items[index] || null;
    }

    function zoomHistoryItemHasReadableImageSource(item = {}) {
        const src = safeString(item?.imgSrc).trim();
        return Boolean(
            safeString(item?.assetName).trim() ||
                rawAssetNameFromImageSrc(src) ||
                normalizeImageDataUrl(src) ||
                normalizeZoomAssetPreviewUrl(src),
        );
    }

    function zoomHistoryTagTesterSaveFileName(item = {}, extension = 'png') {
        const cleanExtension = /^jpe?g$/i.test(extension)
            ? 'jpg'
            : /^webp$/i.test(extension)
              ? 'webp'
              : 'png';
        const baseName = sanitizeAssetNamePart(
            item?.assetName || item?.label || item?.entryId,
            'zoom_history',
        ).slice(0, 96);
        return `${baseName || 'zoom_history'}_tag_tester_${Date.now()}.${cleanExtension}`;
    }

    async function readZoomHistoryItemImageBytes(item = {}) {
        let src = safeString(item?.imgSrc).trim();
        const dataUrl = normalizeImageDataUrl(src);
        if (dataUrl) return { ...dataUrlToImageBytes(dataUrl), source: 'data-url' };

        const assetName = safeString(item?.assetName || rawAssetNameFromImageSrc(src)).trim();
        let assetError = null;
        if (assetName) {
            try {
                const loaded = await readImageTokenAssetBytes(assetName);
                const bytes = normalizeReadImageDataToBytes(loaded?.bytes);
                const extension = loaded?.ext || imageExtensionFromNameOrKey(assetName, assetName);
                return {
                    bytes,
                    mime: imageMimeFromBytes(bytes, extension),
                    extension,
                    source: 'asset',
                    assetName,
                };
            } catch (error) {
                assetError = error;
            }
        }

        src = normalizeZoomAssetPreviewUrl(src);
        if (src && typeof fetch === 'function') {
            const response = await fetch(src);
            if (!response?.ok) {
                throw new Error(`Zoom history image fetch HTTP ${response?.status || 0}`);
            }
            const bytes = new Uint8Array(await response.arrayBuffer());
            const responseMime = safeString(response.headers?.get?.('content-type'))
                .split(';')[0]
                .trim()
                .toLowerCase();
            const mime = /^image\/(?:png|jpe?g|webp)$/i.test(responseMime)
                ? responseMime
                : imageMimeFromBytes(bytes);
            const extension =
                mime === 'image/jpeg' || mime === 'image/jpg'
                    ? 'jpg'
                    : mime === 'image/webp'
                      ? 'webp'
                      : 'png';
            return {
                bytes,
                mime,
                extension,
                source: 'fetch',
            };
        }

        throw assetError || new Error('Selected zoom history image is not readable.');
    }

    async function saveSelectedZoomHistoryImageToTagTesterFolder() {
        const selected = zoomGallerySelectedItem();
        const history = zoomHistoryItemsForGalleryItem(selected);
        const item = zoomSelectedHistoryItemForState(naaZoomGalleryState, history);
        if (!item) throw new Error('Selected zoom history image is unavailable.');
        const image = await readZoomHistoryItemImageBytes(item);
        const saved = await saveTagTesterImageBytesToDevServer(
            image.bytes,
            image.mime,
            zoomHistoryTagTesterSaveFileName(item, image.extension),
        );


        return saved;
    }

    function zoomLatestGeneratedHistoryItemWithSize(history = []) {
        const generated = (Array.isArray(history) ? history : []).filter(
            (entry) =>
                entry?.type === 'generated' &&
                zoomRegenerateSizePresetIdForDimensions(entry?.width, entry?.height),
        );
        return generated[generated.length - 1] || null;
    }

    function zoomGallerySelectedItem(state = naaZoomGalleryState) {
        const items = Array.isArray(state?.items) ? state.items : [];
        return items[intBetween(state?.selectedIndex, 0, 0, Math.max(items.length - 1, 0))] || null;
    }

    function zoomGalleryDisplayItem(state = naaZoomGalleryState) {
        const selected = zoomGallerySelectedItem(state);
        if (!selected) return null;
        if (state?.view === 'history') {
            const history = zoomHistoryItemsForGalleryItem(selected);
            const index = intBetween(state.historyIndex, 0, 0, Math.max(history.length - 1, 0));
            return history[index] || selected;
        }
        return selected;
    }

    function zoomRegenerationMetaForDisplay(selected = null, display = null) {
        const target = display || selected || {};
        const assetName = safeString(target?.assetName || selected?.assetName).trim();
        const storedMeta = assetName ? displayAssetMetaMap.get(assetName) || {} : {};
        const slot = displayAssetSlotForGalleryItem(selected || target || {});
        const slotId = safeString(
            target?.slotId || selected?.slotId || storedMeta.slotId || slot?.slotId,
        ).trim();
        const sourceImageMarkup = safeString(
            target?.sourceImageMarkup ||
                target?.originalMarkup ||
                selected?.originalMarkup ||
                storedMeta.sourceImageMarkup ||
                slot?.sourceImageMarkup ||
                '',
        ).trim();
        return displayMetaWithSlotRegenerationPlan(
            {
                ...(selected?.meta || {}),
                ...(target?.meta || {}),
                ...storedMeta,
                assetName,
                slotId,
                sourceImageMarkup,
                chatKey: safeString(
                    storedMeta.chatKey || target?.chatKey || selected?.chatKey || slot?.chatKey,
                ).trim(),
            },
            slotId,
        );
    }

    async function prepareZoomDisplayImageForRender(state = naaZoomGalleryState) {
        const selected = zoomGallerySelectedItem(state);
        const display = zoomGalleryDisplayItem(state);
        const assetName = safeString(display?.assetName).trim();
        if (!state || !display || !assetName) return false;
        const currentPreview = safeString(display.imgSrc).trim();
        if (normalizeZoomAssetPreviewUrl(currentPreview)) {
            await decodeImageUrlForDisplay(currentPreview);
            return false;
        }
        let previewUrl = '';
        try {
            previewUrl = await loadDecodedZoomImageTokenObjectUrl(assetName, {
                forceAssetRead: true,
            });
        } catch (error) {

        }
        if (!previewUrl) return false;
        if (state.view === 'history') {
            const slot = displayAssetSlotForGalleryItem(selected);
            const entry = slot?.entries?.find(
                (item) =>
                    item.entryId === display.entryId ||
                    (display.assetName && item.assetName === display.assetName),
            );
            if (entry) entry.imgSrc = previewUrl;
        } else if (selected && selected.assetName === assetName) {
            selected.imgSrc = previewUrl;
        }
        display.imgSrc = previewUrl;
        return true;
    }

