        const ariaLabel = safeString(item?.label || item?.assetName || `Image ${index + 1}`);
        const fillWidth = Boolean(options.fillWidth);
        const showOriginalBadge = Boolean(options.showOriginalBadge && item?.type === 'original');
        const thumbnailAspectRatio = '1216/832';
        const buttonWidth = 156;
        const imageWidth = 146;
        const widthStyle = fillWidth ? 'width:100%;' : `width:${buttonWidth}px;`;
        const imageWidthStyle = fillWidth ? 'width:100%;' : `width:${imageWidth}px;`;
        const ratioSlotStyle = `aspect-ratio:${thumbnailAspectRatio};`;
