    function zoomPromptPanelTextBlockHtml(title, value, emptyText = 'Empty') {
        const isAnalyzer = safeString(title) === 'info';
        const text = safeString(value).trim();
        const titleFont = isAnalyzer
            ? '700 12px Consolas,Menlo,monospace'
            : '700 11px Consolas,Menlo,monospace';
        const bodyFont = isAnalyzer
            ? '13px/1.5 Consolas,Menlo,monospace'
            : '11px/1.45 Consolas,Menlo,monospace';
        return (
            '<section style="display:grid;grid-template-rows:auto minmax(0,1fr);gap:6px;min-height:0;border:1px solid rgba(215,184,111,.18);border-radius:7px;background:rgba(8,5,7,.38);padding:10px;overflow:hidden;">' +
            '<h3 style="margin:0;color:#d7b86f;font:' +
            titleFont +
            ';letter-spacing:0;">' +
            escapeHtml(title) +
            '</h3>' +
            '<pre style="margin:0;min-height:0;max-height:100%;overflow-y:auto;overflow-x:hidden;white-space:pre-wrap;word-break:break-word;color:' +
            (text ? '#f1e5cf' : '#8f7f65') +
            ';font:' +
            bodyFont +
            ';">' +
            escapeHtml(text || emptyText) +
            '</pre>' +
            '</section>'
        );
    }

    function zoomPromptPanelDataForDisplay(display = {}, selected = {}) {
        const meta = zoomRegenerationMetaForDisplay(selected, display);
        const plan = regenerationPlanFromDisplayMeta(meta) || {};
        const characters = Array.isArray(plan.characters) ? plan.characters : [];
        const analyzerDecision = normalizeAnalyzerDecisionForPromptPanel(
            meta?.analyzerDecision || plan.analyzerDecision,
            {
                selected,
                display,
                meta,
                plan,
                ...selected,
                ...display,
                ...meta,
                ...plan,
            },
        );
        const selectedVariantId = safeString(
            meta?.selectedVariantId ||
                meta?.selected_variant_id ||
                plan?.selectedVariantId ||
                plan?.selected_variant_id ||
                meta?.validated?.selected_variant_id ||
                meta?.validated?.selectedVariantId ||
                plan?.validated?.selected_variant_id ||
                plan?.validated?.selectedVariantId,
        ).trim();
        const hasAnalyzerSelectedVariantId = safeString(
            analyzerDecision?.selected_variant_id ||
                analyzerDecision?.selectedVariantId ||
                analyzerDecision?.selected_variant_ids ||
                analyzerDecision?.selectedVariantIds ||
                analyzerDecision?.variant_id ||
                analyzerDecision?.variantId,
        ).trim();
        const analyzerReason = safeString(
            analyzerDecision?.reason ||
                meta?.reason ||
                meta?.validated?.reason ||
                meta?.regenerationPlan?.validated?.reason ||
                plan?.reason ||
                plan?.validated?.reason,
        ).trim();
        let analyzerDecisionForDisplay = analyzerDecision;
        if (analyzerReason && !safeString(analyzerDecisionForDisplay?.reason).trim()) {
            analyzerDecisionForDisplay = {
                ...(analyzerDecisionForDisplay || {}),
                reason: analyzerReason,
            };
        }
        if (selectedVariantId && !hasAnalyzerSelectedVariantId) {
            analyzerDecisionForDisplay = {
                ...(analyzerDecisionForDisplay || {}),
                selected_variant_id: selectedVariantId,
            };
        }
        const validated = isPlainObject(plan?.validated) ? cloneJson(plan.validated) : {};
        const selectedLorebookPromptKey = safeString(
            meta?.selectedLorebookPromptKey || plan?.selectedLorebookPromptKey,
        ).trim();
        const matchedIdentityKey = safeString(
            meta?.matchedIdentityKey || plan?.matchedIdentityKey,
        ).trim();
        const selectedOutfitId = safeString(
            meta?.selectedOutfitId ||
                plan?.selectedOutfitId ||
                analyzerDecisionForDisplay?.outfit_id ||
                analyzerDecisionForDisplay?.outfitId ||
                validated?.outfit_id ||
                validated?.outfitId,
        ).trim();
        const outfitPromptKey =
            selectedLorebookPromptKey ||
            matchedIdentityKey ||
            safeString(
                analyzerDecisionForDisplay?.lorebook_prompt_key ||
                    analyzerDecisionForDisplay?.lorebookPromptKey,
            ).trim();
        const resolvedOutfit = findOutfitPromptById(outfitPromptKey, selectedOutfitId);
        const selectedOutfitName = safeString(
            meta?.selectedOutfitName ||
                plan?.selectedOutfitName ||
                resolvedOutfit?.label ||
                resolvedOutfit?.name ||
                resolvedOutfit?.title,
        ).trim();
        return {
            mainPrompt: safeString(plan.globalPositive).trim(),
            femalePrompt: safeString(characters[0]?.prompt).trim(),
            malePrompt: safeString(characters[1]?.prompt).trim(),
            matchedIdentityName: safeString(
                meta?.matchedIdentityName || plan?.matchedIdentityName,
            ).trim(),
            selectedLorebookPromptKey,
            selectedOutfitId,
            selectedOutfitName,
            characterName: safeString(meta?.characterName || plan?.characterName).trim(),
            validated,
            sourceImageToken: safeString(
                meta?.sourceImageToken || plan.sourceImageToken || display?.sourceImageToken,
            ).trim(),
            sourceImageMarkerId: safeString(
                meta?.sourceImageMarkerId ||
                    plan.sourceImageMarkerId ||
                    display?.sourceImageMarkerId,
            ).trim(),
            sourceImageMarkup: safeString(
                meta?.sourceImageMarkup ||
                    plan.sourceImageMarkup ||
                    display?.sourceImageMarkup ||
                    selected?.originalMarkup,
            ).trim(),
            analyzerDecision: analyzerDecisionForDisplay,
        };
    }

    function zoomPromptPanelHtml(data = {}) {
        const analyzerDecision = normalizeAnalyzerDecisionForPromptPanel(
            data?.analyzerDecision,
            data,
        );
        return (
            '<aside data-naa-zoom-prompt-panel style="height:100%;max-height:100%;min-width:0;min-height:0;display:grid;grid-template-rows:repeat(4,minmax(0,1fr));gap:8px;overflow:hidden;padding:0;box-sizing:border-box;">' +
            zoomInfoPanelBoardHtml(data, analyzerDecision) +
            zoomPromptPanelTextBlockHtml('Main', data?.mainPrompt) +
            zoomPromptPanelTextBlockHtml('Female', data?.femalePrompt) +
            zoomPromptPanelTextBlockHtml('Male', data?.malePrompt) +
            '</aside>'
        );
    }

    function positiveImageDimension(...values) {
        for (const value of values) {
            const number = Number(value);
            if (Number.isFinite(number) && number > 0) return number;
        }
        return 0;
    }

    function zoomViewportSizeForDisplay(display = {}, fallback = {}) {
        const width = positiveImageDimension(
            display?.width,
            display?.meta?.width,
            display?.naturalWidth,
            fallback?.width,
            fallback?.meta?.width,
            fallback?.naturalWidth,
        );
        const height = positiveImageDimension(
            display?.height,
            display?.meta?.height,
            display?.naturalHeight,
            fallback?.height,
            fallback?.meta?.height,
            fallback?.naturalHeight,
        );
        if (!width || !height || typeof window === 'undefined') return null;
        const viewportWidth = positiveImageDimension(window.innerWidth);
        const viewportHeight = positiveImageDimension(window.innerHeight);
        if (!viewportWidth || !viewportHeight) return null;
        const availableWidth = Math.max(220, viewportWidth - 448);
        const availableHeight = Math.max(220, viewportHeight - 144);
        const ratio = width / height;
        let nextWidth = availableWidth;
        let nextHeight = nextWidth / ratio;
        if (nextHeight > availableHeight) {
            nextHeight = availableHeight;
            nextWidth = nextHeight * ratio;
        }
        return {
            width: Math.max(1, Math.floor(nextWidth)),
            height: Math.max(1, Math.floor(nextHeight)),
        };
    }

    function zoomViewportImageStyle(display = {}, fallback = {}) {
        return [
            'display:block',
            'width:100%',
            'height:100%',
            'max-width:100%',
            'max-height:100%',
            'min-width:0',
            'min-height:0',
            'object-fit:contain',
            'object-position:center center',
            'border-radius:0',
            'border:0',
            'background:transparent',
            'box-shadow:none',
            'box-sizing:border-box',
        ].join(';');
    }

    function zoomViewportImageFrameStyle(display = {}, fallback = {}) {
        return [
            'display:grid',
            'place-items:center',
            'align-self:center',
            'justify-self:center',
            'position:relative',
            'width:100%',
            'height:100%',
            'max-width:100%',
            'max-height:100%',
            'max-inline-size:100%',
            'max-block-size:100%',
            'min-width:0',
            'min-height:0',
            'overflow:hidden',
            'line-height:0',
            'box-sizing:border-box',
            'contain:layout paint',
        ]
            .filter(Boolean)
            .join(';');
    }

    function zoomStageLoadingSpinnerHtml() {
        return '<svg class="naa-loading-spinner" style="position:absolute;right:18px;top:18px;display:block;width:34px;height:34px;pointer-events:none;filter:drop-shadow(0 8px 18px rgba(0,0,0,.5));" width="34" height="34" viewBox="0 0 44 44" xmlns="http://www.w3.org/2000/svg" aria-label="Regenerating image"><circle cx="22" cy="22" r="18" fill="none" stroke="rgba(255,255,255,0.22)" stroke-width="4"/><g><animateTransform attributeName="transform" type="rotate" from="0 22 22" to="360 22 22" dur="0.75s" repeatCount="indefinite"/><circle cx="22" cy="22" r="18" fill="none" stroke="#fff" stroke-width="4" stroke-dasharray="28 85" stroke-linecap="round"/></g></svg>';
    }

    function zoomCloseButtonHtml() {
        return '<button class="naa-zoom-action" data-naa-zoom-action="close" style="border:1px solid #725a46;background:linear-gradient(180deg,#2a1a22,#1b1117);color:#f1e5cf;border-radius:6px;padding:8px 12px;font:12px Consolas,Menlo,monospace;cursor:pointer;box-shadow:0 10px 28px rgba(0,0,0,.36),0 0 0 1px rgba(234,215,173,.06) inset;">Close</button>';
    }

    function zoomTopBarHtml(
        state,
        display,
        selected,
        selectedIndex,
        totalCount,
        controlsHtml = '',
    ) {
        const imageNumber = totalCount ? intBetween(selectedIndex + 1, 1, 1, totalCount) : 0;
        const seed = normalizeNovelAISeed(display?.seed || selected?.seed);
        const regenerateState = safeString(state?.regenerateState || 'idle').trim();
        const regenerateMessage = safeString(state?.regenerateMessage).trim();
        const tagTesterSaveState = safeString(state?.tagTesterSaveState || '').trim();
        const tagTesterSaveMessage = safeString(state?.tagTesterSaveMessage).trim();
        const status =
            regenerateState === 'loading'
                ? '재생성 중...'
                : regenerateState === 'error'
                  ? regenerateMessage || '재생성 실패'
                  : regenerateState === 'done'
                    ? regenerateMessage || '재생성 완료'
                    : '';
        const tagTesterStatus =
            tagTesterSaveState === 'saving'
                ? 'Tag save...'
                : tagTesterSaveState === 'error'
                  ? tagTesterSaveMessage || 'Tag save failed'
                  : tagTesterSaveState === 'done'
                    ? tagTesterSaveMessage || 'Tag saved'
                    : '';
        const mergedStatus = status || tagTesterStatus;
        const statusIsError = regenerateState === 'error' || tagTesterSaveState === 'error';
        const statusHtml = mergedStatus
            ? '<span style="color:' +
              (statusIsError ? '#ff9a9a' : '#bca98c') +
              ';font:11px Consolas,Menlo,monospace;white-space:nowrap;">' +
              escapeHtml(mergedStatus) +
              '</span>'
            : '';
        return (
            '<div data-naa-zoom-topbar style="grid-column:1/-1;grid-row:1;display:flex;align-items:center;justify-content:space-between;gap:12px;min-width:0;min-height:38px;padding:8px 10px;background:linear-gradient(180deg,rgba(234,215,173,.032),rgba(234,215,173,.006)),#20151b;border:1px solid #4a3440;border-radius:8px;box-sizing:border-box;box-shadow:0 18px 42px rgba(0,0,0,.28),0 0 0 1px rgba(234,215,173,.055) inset;">' +
            '<div style="display:flex;align-items:center;gap:10px;min-width:0;overflow:hidden;">' +
            '<strong style="color:#f1e5cf;font:12px Consolas,Menlo,monospace;white-space:nowrap;">Image ' +
            escapeHtml(imageNumber ? `${imageNumber} / ${totalCount}` : '0 / 0') +
            '</strong><span style="color:#8f7f65;font:11px Consolas,Menlo,monospace;white-space:nowrap;">Seed: ' +
            escapeHtml(seed || 'none') +
            '</span>' +
            statusHtml +
            '</div>' +
            '<div data-naa-zoom-header-actions style="display:flex;align-items:center;justify-content:flex-end;gap:8px;min-width:0;flex:0 0 auto;">' +
            controlsHtml +
            zoomCloseButtonHtml() +
            '</div>' +
            '</div>'
        );
    }

    function zoomMainStageHtml(
        imgSrc,
        loading = false,
        display = {},
        fallback = {},
        promptPanelHtml = '',
    ) {
        const promptPanelMarkup = safeString(promptPanelHtml).trim();
        const hasPromptPanel = /\bdata-naa-zoom-prompt-panel\b/.test(promptPanelMarkup);
        const layoutStyle = hasPromptPanel
            ? 'grid-template-columns:minmax(0,3fr) minmax(280px,2fr);grid-template-rows:minmax(0,1fr);gap:12px;align-items:stretch;'
            : 'grid-template-columns:minmax(0,1fr);grid-template-rows:minmax(0,1fr);align-items:stretch;justify-items:stretch;';
        return (
            '<div data-naa-zoom-main-stage class="naa-zoom-stage" style="grid-column:2;grid-row:2;position:relative;display:grid;' +
            layoutStyle +
            'width:100%;height:100%;min-width:0;min-height:0;max-width:100%;max-height:100%;overflow:hidden;padding:0;">' +
            '<div data-naa-zoom-image-pane style="position:relative;display:grid;grid-template-columns:minmax(0,1fr);grid-template-rows:minmax(0,1fr);place-items:center;align-content:stretch;justify-content:stretch;width:100%;height:100%;min-width:0;min-height:0;max-width:100%;max-height:100%;overflow:hidden;box-sizing:border-box;contain:layout paint;">' +
            '<span class="naa-zoom-image-frame" style="' +
            zoomViewportImageFrameStyle(display, fallback) +
            '">' +
            '<img decoding="async" fetchpriority="high" src="' +
            escapeHtml(imgSrc) +
            '" style="' +
            zoomViewportImageStyle(display, fallback) +
            '">' +
            '</span>' +
            zoomStageClickZoneHtml('prev', 'Previous image', 'left') +
            zoomStageClickZoneHtml('next', 'Next image', 'right') +
            (loading ? zoomStageLoadingSpinnerHtml() : '') +
            '</div>' +
            (hasPromptPanel ? promptPanelMarkup : '') +
            '</div>'
        );
    }

    function zoomMainStageHtmlForState(state = naaZoomGalleryState) {
        const selected = zoomGallerySelectedItem(state);
        const display = zoomGalleryDisplayItem(state);
        const imgSrc = zoomPreviewImageSrc(display?.imgSrc);
        const regenerateState = state?.regenerateState || 'idle';
        const promptPanelHtml = state?.promptPanelOpen
            ? zoomPromptPanelHtml(zoomPromptPanelDataForDisplay(display, selected))
            : '';
        return zoomMainStageHtml(
            imgSrc,
            regenerateState === 'loading' ||
                Boolean(display?.meta?.loading || selected?.meta?.loading),
            display,
            selected,
            promptPanelHtml,
        );
    }

    function buildZoomGalleryRenderParts(state = naaZoomGalleryState) {
        const items = Array.isArray(state?.items) ? state.items : [];
        const selectedIndex = intBetween(state?.selectedIndex, 0, 0, Math.max(items.length - 1, 0));
        const selected = items[selectedIndex] || null;
        const history = zoomHistoryItemsForGalleryItem(selected);
        const display = zoomGalleryDisplayItem(state);
        const activeHistoryIndex = zoomPreviewHistoryIndexForState(state, history);
        const appliedHistoryIndex = zoomAppliedHistoryIndexForState(state, history);
        const imgSrc = zoomPreviewImageSrc(display?.imgSrc);
        const promptKey = zoomSeedPromptKeyForDisplay(display, selected);
        const seed = normalizeNovelAISeed(display?.seed || selected?.seed);
        const seedSetting = getPromptSeedSetting(promptKey);
        const seedFixedState = Boolean(
            seed && promptKey && seedSetting.fixed && seedSetting.seed === seed,
        );
        const canRegenerate = Boolean(
            selected?.assetName &&
                regenerationPlanFromDisplayMeta(zoomRegenerationMetaForDisplay(selected, display)),
        );
        const canShowPromptPanel = Boolean(
            regenerationPlanFromDisplayMeta(zoomRegenerationMetaForDisplay(selected, display)),
        );
        const developerModeEnabled = isDeveloperModeEnabled();
        const tagTesterTarget = zoomTagTesterTargetForState(state);
        const canOpenTagTester = Boolean(regenerationPlanFromDisplayMeta(tagTesterTarget?.meta));
        const regenerateState = state?.regenerateState || 'idle';
        const regenerateMessage = safeString(state?.regenerateMessage).trim();
        const latestGeneratedSizeItem = zoomLatestGeneratedHistoryItemWithSize(history);
        const regenerateSizePresetId = zoomRegenerateSizePresetIdForDisplay(
            latestGeneratedSizeItem || display,
            selected,
        );
        const selectedHistoryItem = zoomSelectedHistoryItemForState(state, history);
        const canDeleteHistoryAsset = selectedHistoryItem?.type === 'generated';
        const deletingHistoryAsset = state?.deleteHistoryAssetState === 'deleting';
        const canSaveHistoryToTagTester = Boolean(selectedHistoryItem && zoomHistoryItemHasReadableImageSource(selectedHistoryItem));
        const savingHistoryToTagTester = state?.tagTesterSaveState === 'saving';
        const tagTesterControlsHtml = developerModeEnabled
            ? zoomTagTesterHistorySaveControlHtml(canSaveHistoryToTagTester, savingHistoryToTagTester) +
              zoomTagTesterControlHtml(canOpenTagTester)
            : '';
        const controlsHtml =
            tagTesterControlsHtml +
            zoomDeleteHistoryAssetControlHtml(canDeleteHistoryAsset, deletingHistoryAsset) +
            zoomRegenerateControlHtmlV2(
                canRegenerate,
                regenerateState,
                regenerateMessage,
                regenerateSizePresetId,
            ) +
            zoomPromptControlHtml(canShowPromptPanel, Boolean(state?.promptPanelOpen)) +
            zoomSeedControlHtmlV2(seed, promptKey, seedFixedState);
        const generatedListHtml = zoomRailItemsHtml(items, 'select-gallery', selectedIndex);
        const historyListHtml = zoomRailItemsHtml(history, 'select-history', activeHistoryIndex, {
            fillWidth: true,
            showOriginalBadge: true,
            showSelectedBadge: true,
            selectedBadgeIndex: appliedHistoryIndex,
        });
        const mainStageHtml = zoomMainStageHtmlForState(state);
        const topBarHtml = zoomTopBarHtml(
            state,
            display,
            selected,
            selectedIndex,
            items.length,
            controlsHtml,
        );
        return {
            topBarHtml,
            generatedListHtml,
            historyListHtml,
            mainStageHtml,
        };
    }

    function buildZoomGalleryOverlayHtml(state = naaZoomGalleryState, parts = null) {
        const renderParts = parts || buildZoomGalleryRenderParts(state);
        const items = Array.isArray(state?.items) ? state.items : [];
        const selectedIndex = intBetween(state?.selectedIndex, 0, 0, Math.max(items.length - 1, 0));
        const selected = items[selectedIndex] || null;
        const history = zoomHistoryItemsForGalleryItem(selected);
        const display = zoomGalleryDisplayItem(state);
        const activeHistoryIndex = zoomPreviewHistoryIndexForState(state, history);
        return (
            '<div data-naa-zoom-layout style="position:fixed;inset:0;display:grid;grid-template-columns:178px minmax(0,1fr) 178px;grid-template-rows:auto minmax(0,1fr);gap:12px;padding:36px;box-sizing:border-box;cursor:default;background:radial-gradient(circle at 50% 30%,rgba(74,32,40,.18),transparent 38%),rgba(18,12,16,.94);overflow:hidden;">' +
            '<style>.naa-zoom-scroll-list{scrollbar-width:thin;scrollbar-color:rgba(215,184,111,.62) rgba(32,21,27,.72)}.naa-zoom-scroll-list::-webkit-scrollbar{width:10px;height:10px}.naa-zoom-scroll-list::-webkit-scrollbar-track{background:linear-gradient(180deg,rgba(234,215,173,.045),rgba(234,215,173,.015));border-radius:999px}.naa-zoom-scroll-list::-webkit-scrollbar-thumb{border:2px solid rgba(32,21,27,.9);border-radius:999px;background:linear-gradient(180deg,#d7b86f,#8a6a38);box-shadow:0 0 0 1px rgba(234,215,173,.12) inset}.naa-zoom-scroll-list::-webkit-scrollbar-thumb:hover{background:linear-gradient(180deg,#f0d68e,#a78242)}.naa-zoom-regenerate-size{color-scheme:dark}.naa-zoom-regenerate-size:focus{outline:none;border-color:#d7b86f!important;box-shadow:0 0 0 1px rgba(215,184,111,.22)}.naa-zoom-regenerate-size option{background:#1b1117;color:#f1e5cf}.naa-zoom-regenerate-size option:checked{background:#6d2d36;color:#fff2d5}</style>' +
            renderParts.topBarHtml +
            zoomRailHtml('Chat Images', items, 'select-gallery', selectedIndex, 'left', {
                width: 178,
                listAttr: 'data-naa-zoom-generated-list',
                listHtml: renderParts.generatedListHtml,
            }) +
            zoomHistoryPanelHtml(history, activeHistoryIndex, {
                listHtml: renderParts.historyListHtml,
            }) +
            renderParts.mainStageHtml +
            '</div>'
        );
    }

    function syncNaaZoomRegenerateContext() {
        const selected = zoomGallerySelectedItem();
        const display = zoomGalleryDisplayItem();
        naaZoomRegenerateContext = selected
            ? {
                  assetName: safeString(display?.assetName || selected.assetName).trim(),
                  assetMeta: zoomRegenerationMetaForDisplay(selected, display),
                  originalMarkup: selected.originalMarkup,
                  imgSrc: display?.imgSrc || selected.imgSrc,
              }
            : null;
    }

    function zoomTagTesterTargetForState(state = naaZoomGalleryState) {
        const selected = zoomGallerySelectedItem(state);
        const display = zoomGalleryDisplayItem(state);
        if (!selected || !display) return null;
        const assetName = safeString(display.assetName || selected.assetName).trim();
        let meta = (assetName && displayAssetMetaMap.get(assetName)) || display.meta || {};
        if (!regenerationPlanFromDisplayMeta(meta) && display.type === 'original') {
            meta = zoomMetaForTimelineSelection(
                display,
                selected,
                zoomHistoryItemsForGalleryItem(selected),
            );
        }
        if (!regenerationPlanFromDisplayMeta(meta)) {
            const selectedAssetName = safeString(selected.assetName).trim();
            meta =
                (selectedAssetName && displayAssetMetaMap.get(selectedAssetName)) ||
                selected.meta ||
                {};
        }
        return {
            selected,
            display,
            assetName: assetName || safeString(selected.assetName).trim(),
            meta,
        };
    }

    function tagTesterImageContextFromZoomTarget(target = null) {
        const selected = target?.selected || zoomGallerySelectedItem();
        const display = target?.display || selected || {};
        const currentImageSrc = zoomPreviewImageSrc(display?.imgSrc || selected?.imgSrc);
        const currentImage =
            currentImageSrc && currentImageSrc !== NAA_ZOOM_PLACEHOLDER_IMAGE
                ? normalizeTagTesterImageHistoryItem(
                      {
                          id:
                              display?.entryId ||
                              display?.assetName ||
                              target?.assetName ||
                              selected?.assetName ||
                              'current',
                          blobUrl: currentImageSrc,
                          fileName:
                              display?.label ||
                              display?.assetName ||
                              target?.assetName ||
                              selected?.assetName ||
                              'current-image.png',
                          seed: display?.seed || selected?.seed,
                          assetName: display?.assetName || selected?.assetName || target?.assetName,
                          type: display?.type || selected?.type,
                      },
                      -1,
                  )
                : null;
        let imageHistory = zoomHistoryItemsForGalleryItem(selected)
            .filter((entry) => entry?.type === 'generated')
            .map((entry, index) => {
                const historyImageSrc = zoomPreviewImageSrc(entry.imgSrc);
                if (!historyImageSrc || historyImageSrc === NAA_ZOOM_PLACEHOLDER_IMAGE) {
                    return null;
                }
                return normalizeTagTesterImageHistoryItem(
                    {
                        id: entry.entryId || entry.assetName || `history-${index + 1}`,
                        blobUrl: historyImageSrc,
                        fileName: entry.label || entry.assetName || `history-${index + 1}.png`,
                        seed: entry.seed,
                        assetName: entry.assetName,
                        type: entry.type,
                    },
                    index,
                );
            })
            .filter(Boolean);
        if (
            currentImage &&
            currentImage.type !== 'original' &&
            !imageHistory.some(
                (entry) =>
                    (currentImage.id && entry.id === currentImage.id) ||
                    (currentImage.assetName && entry.assetName === currentImage.assetName) ||
                    entry.blobUrl === currentImage.blobUrl,
            )
        ) {
            imageHistory = [currentImage, ...imageHistory].slice(0, 24);
        }
        return {
            currentImage,
            imageHistory,
        };
    }

    async function openTagTesterForZoomSelection(rootDoc = null) {
        const target = zoomTagTesterTargetForState();
        const context = tagTesterContextFromRegenerationPlan(target?.meta || {});
        if (!context) {
            if (naaZoomGalleryState) {
                naaZoomGalleryState.regenerateState = 'error';
                naaZoomGalleryState.regenerateMessage = 'Tag Tester context unavailable.';
                await renderNaaZoomOverlayContent();
            }
            return false;
        }
        setTagTesterLaunchContext({
            ...context,
            ...tagTesterImageContextFromZoomTarget(target),
        });
        lastNonTagTesterSettingsTab = 'character-prompts';
        activeSettingsTab = 'tag-tester';
        persistSettingsUiState({ activeSettingsTab });

        await closeNaaZoomOverlay(rootDoc);
        renderSettings();
        await Risu.showContainer('fullscreen');
        return true;
    }

    async function updateZoomOverlayPart(selector, html, cacheKey, mode = 'inner') {
        if (!naaZoomOverlayRef || !naaZoomRenderCache) return false;
        if (naaZoomRenderCache[cacheKey] === html) return true;
        const target = await naaZoomOverlayRef.querySelector(selector);
        if (!target) return false;
        if (mode === 'outer') {
            await target.setOuterHTML(html);
        } else {
            await target.setInnerHTML(html);
        }
        invalidateZoomOverlayHitTestCache();
        naaZoomRenderCache[cacheKey] = html;
        return true;
    }

    async function renderNaaZoomMainStageOnly() {
        if (!naaZoomOverlayRef || !naaZoomGalleryState) return false;
        if (!naaZoomRenderCache) {
            await renderNaaZoomOverlayContent();
            return true;
        }
        await prepareZoomDisplayImageForRender(naaZoomGalleryState);
        const mainStageHtml = zoomMainStageHtmlForState(naaZoomGalleryState);
        const updated = await updateZoomOverlayPart(
            '[data-naa-zoom-main-stage]',
            mainStageHtml,
            'mainStageHtml',
            'outer',
        );
        syncNaaZoomRegenerateContext();
        return updated;
    }

    function scheduleZoomOverlayContentRender(reason = 'deferred') {
        const state = naaZoomGalleryState;
        if (!state || !naaZoomOverlayRef) return;
        const render = () => {
            if (!naaZoomOverlayRef || naaZoomGalleryState !== state) return;
            renderNaaZoomOverlayContent().catch((error) => {

            });
        };
        if (typeof setTimeout === 'function') setTimeout(render, 0);
        else Promise.resolve().then(render);
    }

    async function renderNaaZoomOverlayContent() {
        if (!naaZoomOverlayRef || !naaZoomGalleryState) return;
        await prepareZoomDisplayImageForRender(naaZoomGalleryState);
        const parts = buildZoomGalleryRenderParts(naaZoomGalleryState);
        if (!naaZoomRenderCache) {
            const fullHtml = buildZoomGalleryOverlayHtml(naaZoomGalleryState, parts);
            await naaZoomOverlayRef.setInnerHTML(fullHtml);
            naaZoomRenderCache = parts;
            invalidateZoomOverlayHitTestCache();
            syncNaaZoomRegenerateContext();
            return;
        }
        const updated = [
            await updateZoomOverlayPart(
                '[data-naa-zoom-topbar]',
                parts.topBarHtml,
                'topBarHtml',
                'outer',
            ),
            await updateZoomOverlayPart(
                '[data-naa-zoom-generated-list]',
                parts.generatedListHtml,
                'generatedListHtml',
            ),
            await updateZoomOverlayPart(
                '[data-naa-zoom-history-list]',
                parts.historyListHtml,
                'historyListHtml',
            ),
            await updateZoomOverlayPart(
                '[data-naa-zoom-main-stage]',
                parts.mainStageHtml,
                'mainStageHtml',
                'outer',
            ),
        ];
        if (updated.some((ok) => !ok)) {
            const fullHtml = buildZoomGalleryOverlayHtml(naaZoomGalleryState, parts);
            await naaZoomOverlayRef.setInnerHTML(fullHtml);
            naaZoomRenderCache = parts;
            invalidateZoomOverlayHitTestCache();
        }
        syncNaaZoomRegenerateContext();
    }

    async function buildZoomGalleryState(clickedHtml, imgSrc, assetName) {
        const cleanAssetName = safeString(assetName).trim();
        const snapshot = await getCurrentChatForAssetReplacement().catch(() => null);
        const chatKey = currentChatKey(
            snapshot?.character,
            snapshot?.charIndex,
            snapshot?.chatIndex,
            snapshot?.chat,
        );
        const storedMeta = displayAssetMetaMap.get(cleanAssetName) || {};
        const loading = htmlHasClass(clickedHtml, 'naa-loading-image');
        const originalMarkup =
            htmlFirstAttributeValue(clickedHtml, ['x-risu-naa-original', 'data-naa-original']) ||
            safeString(storedMeta.sourceImageMarkup).trim() ||
            reverseAssetMap.get(cleanAssetName) ||
            '';
        const htmlSlotId = htmlFirstAttributeValue(clickedHtml, [
            'x-risu-naa-slot-id',
            'data-naa-slot-id',
        ]);
        const renderOnlyHistoryPreviewAttr =
            htmlFirstAttributeValue(clickedHtml, [
                'x-risu-naa-render-only-history-preview',
                'data-naa-render-only-history-preview',
            ]) === 'true';
        const renderedPersistentAssetName = htmlFirstAttributeValue(clickedHtml, [
            'x-risu-naa-persistent-asset',
            'data-naa-persistent-asset',
        ]);
        const renderedHistoryEntryId =
            htmlFirstAttributeValue(clickedHtml, [
                'x-risu-naa-rendered-history-entry-id',
                'data-naa-rendered-history-entry-id',
                'x-risu-naa-chat-history-entry-id',
                'data-naa-chat-history-entry-id',
            ]) ||
            (htmlFirstAttributeValue(clickedHtml, [
                'x-risu-naa-original-display',
                'data-naa-original-display',
            ]) === 'true'
                ? displayAssetSlotOriginalEntryId(htmlSlotId || storedMeta.slotId)
                : '');
        const meta = {
            ...storedMeta,
            chatKey: safeString(storedMeta.chatKey || chatKey).trim(),
        };
        meta.slotId = imageSlotIdFromParts({
            ...meta,
            slotId: htmlSlotId || meta.slotId,
            assetName: cleanAssetName,
            sourceImageMarkup: originalMarkup || meta.sourceImageMarkup,
        });
        const clickedImgSrc = safeString(imgSrc).trim();
        const safeClickedImgSrc = normalizeImageDataUrl(clickedImgSrc) ? '' : clickedImgSrc;
        const displayImgSrc =
            (safeClickedImgSrc && !isRawAssetImageSrc(safeClickedImgSrc)
                ? safeClickedImgSrc
                : '') ||
            safeClickedImgSrc ||
            imageSrcFromGeneratedBlock(clickedHtml, cleanAssetName, meta);
        let items = cleanAssetName
            ? [
                  {
                      type: 'current',
                      assetName: cleanAssetName,
                      html: clickedHtml,
                      messageIndex: -1,
                      order: 0,
                      imgSrc: displayImgSrc,
                      originalMarkup,
                      seed: normalizeNovelAISeed(meta.seed),
                      promptKey: meta.promptKey,
                      seedFixed: Boolean(meta.seedFixed),
                      width: meta.width,
                      height: meta.height,
                      meta: { ...meta, loading },
                  },
              ]
            : [];
        let selectedIndex = 0;
        let initialView = 'current';
        let initialHistoryIndex = -1;
        let refreshSelectedAssetName = cleanAssetName;
        let refreshSelectedImgSrc = displayImgSrc;
        const slot =
            displayAssetSlotForAsset('', meta.slotId) ||
            displayAssetSlotForAsset(cleanAssetName, meta.slotId);
        const appliedEntry = currentDisplayAssetSlotEntry(slot);
        const renderedEntry = renderedHistoryEntryId
            ? slot?.entries?.find(
                  (entry) => safeString(entry?.entryId).trim() === renderedHistoryEntryId,
              ) || null
            : null;
        const appliedEntryId = safeString(appliedEntry?.entryId).trim();
        const clickedRepresentsHistoryPreview = Boolean(
            slot &&
                renderedEntry &&
                renderedHistoryEntryId &&
                (renderOnlyHistoryPreviewAttr ||
                    (appliedEntryId && renderedHistoryEntryId !== appliedEntryId)),
        );
        const persistentSelectedAssetName = safeString(
            appliedEntry?.assetName || renderedPersistentAssetName,
        ).trim();
        if (clickedRepresentsHistoryPreview && persistentSelectedAssetName) {
            if (safeClickedImgSrc && !normalizeImageDataUrl(safeClickedImgSrc)) {
                renderedEntry.imgSrc = safeClickedImgSrc;
            }
            const chatItems = collectGeneratedImageItemsFromChat(snapshot?.chat, chatKey);
            const currentItemMeta = displayAssetMetaMap.get(persistentSelectedAssetName) || {};
            const fallbackCurrentItem = {
                type: 'current',
                assetName: persistentSelectedAssetName,
                html: '',
                messageIndex: nonNegativeIntegerOr(
                    currentItemMeta.messageIndex ?? slot?.messageIndex,
                    -1,
                ),
                order: 0,
                imgSrc:
                    runtimeDisplaySlotEntryImgSrc(appliedEntry) ||
                    currentItemMeta.displaySrc ||
                    rawAssetImageSrc(persistentSelectedAssetName),
                originalMarkup:
                    originalMarkup || slot?.sourceImageMarkup || currentItemMeta.sourceImageMarkup,
                seed: normalizeNovelAISeed(appliedEntry?.seed || currentItemMeta.seed),
                promptKey: appliedEntry?.promptKey || currentItemMeta.promptKey,
                seedFixed: Boolean(currentItemMeta.seedFixed),
                width: appliedEntry?.width || currentItemMeta.width,
                height: appliedEntry?.height || currentItemMeta.height,
                chatKey: slot?.chatKey || currentItemMeta.chatKey || chatKey,
                slotId: slot?.slotId || meta.slotId,
                meta: {
                    ...currentItemMeta,
                    slotId: slot?.slotId || meta.slotId,
                    chatKey: slot?.chatKey || currentItemMeta.chatKey || chatKey,
                    sourceImageMarkup:
                        originalMarkup ||
                        slot?.sourceImageMarkup ||
                        currentItemMeta.sourceImageMarkup,
                },
            };
            items = chatItems.length ? chatItems : [fallbackCurrentItem];
            let persistentSelectedIndex = slot?.slotId
                ? items.findIndex(
                      (item) =>
                          safeString(item?.slotId || item?.meta?.slotId).trim() ===
                              slot.slotId &&
                          safeString(item?.assetName).trim() === persistentSelectedAssetName,
                  )
                : -1;
            if (persistentSelectedIndex < 0 && slot?.slotId) {
                persistentSelectedIndex = items.findIndex(
                    (item) =>
                        safeString(item?.slotId || item?.meta?.slotId).trim() === slot.slotId,
                );
            }
            if (persistentSelectedIndex < 0) {
                persistentSelectedIndex = items.findIndex(
                    (item) => safeString(item?.assetName).trim() === persistentSelectedAssetName,
                );
            }
            if (persistentSelectedIndex >= 0) {
                selectedIndex = persistentSelectedIndex;
            } else {
                items = [...items, fallbackCurrentItem];
                selectedIndex = items.length - 1;
            }
            const selectedItem = items[selectedIndex] || fallbackCurrentItem;
            const history = zoomHistoryItemsForGalleryItem(selectedItem);
            const renderedIndex = history.findIndex(
                (entry) =>
                    safeString(entry?.entryId).trim() === renderedHistoryEntryId ||
                    (cleanAssetName &&
                        safeString(entry?.assetName).trim() === cleanAssetName),
            );
            const appliedIndex = zoomAppliedHistoryIndexForState(
                { items, selectedIndex, view: 'current' },
                history,
            );
            if (renderedIndex >= 0 && renderedIndex !== appliedIndex) {
                initialView = 'history';
                initialHistoryIndex = renderedIndex;
            }
            refreshSelectedAssetName = persistentSelectedAssetName;
            refreshSelectedImgSrc = initialView === 'current' ? displayImgSrc : '';
        }
        const initialPreviewItem = items[selectedIndex] || items[0];
        if (initialPreviewItem && !normalizeZoomAssetPreviewUrl(initialPreviewItem.imgSrc)) {
            const previewAssetName = safeString(
                initialPreviewItem?.assetName || cleanAssetName,
            ).trim();
            const previewUrl = await loadDecodedZoomImageTokenObjectUrl(previewAssetName, {
                forceAssetRead: true,
            }).catch(() => '');
            if (previewUrl) initialPreviewItem.imgSrc = previewUrl;
        }
        return {
            items,
            selectedIndex,
            view: initialView,
            historyIndex: initialHistoryIndex,
            renderOnlyHistoryPreview: clickedRepresentsHistoryPreview,
            renderedHistoryEntryId: clickedRepresentsHistoryPreview ? renderedHistoryEntryId : '',
            persistentSelectedAssetName: clickedRepresentsHistoryPreview
                ? persistentSelectedAssetName
                : '',
            persistentSlotId: clickedRepresentsHistoryPreview ? slot?.slotId || meta.slotId : '',
            regenerateState: loading ? 'loading' : 'idle',
            regenerateMessage: loading ? '재생성 중...' : '',
            needsChatItemRefresh: true,
            clickedAssetName: refreshSelectedAssetName,
            clickedImgSrc: refreshSelectedImgSrc,
        };
    }

    async function refreshZoomGalleryAfterRegeneration(assetName) {
        if (!naaZoomOverlayRef) return;
        invalidateZoomGeneratedItemsCache();
        const items = await collectCurrentChatGeneratedImageItems();
        const selectedIndex = Math.max(
            0,
            items.findIndex((item) => item.assetName === assetName),
        );
        if (items[selectedIndex]?.assetName === assetName) {
            const meta = displayAssetMetaMap.get(assetName) || items[selectedIndex].meta || {};
            const displaySrc = safeString(meta.displaySrc).trim();
            if (displaySrc && !normalizeImageDataUrl(displaySrc)) {
                items[selectedIndex] = { ...items[selectedIndex], imgSrc: displaySrc };
            }
        }
        naaZoomGalleryState = {
            items,
            selectedIndex,
            view: 'current',
            historyIndex: -1,
            regenerateState: 'done',
            regenerateMessage: '',
            promptPanelOpen: Boolean(naaZoomGalleryState?.promptPanelOpen),
        };
        await renderNaaZoomOverlayContent();
        scheduleZoomGalleryPreviewHydration();
    }

    async function handleZoomToggleSeed() {
        const selected = zoomGallerySelectedItem();
        const display = zoomGalleryDisplayItem();
        const promptKey = zoomSeedPromptKeyForDisplay(display, selected);
        const seed = normalizeNovelAISeed(display?.seed);
        if (!promptKey || !seed) return;
        const current = getPromptSeedSetting(promptKey);
        const currentMatchesImageSeed = Boolean(current.fixed && current.seed === seed);
        const nextFixed = !currentMatchesImageSeed;
        await setPromptSeedSetting(promptKey, seed, nextFixed);
        await renderNaaZoomOverlayContent();
    }

