    async function handleZoomRegenerateFromGallery(rootDoc) {
        if (naaZoomRegenerationInFlight) return;
        const selected = zoomGallerySelectedItem();
        if (!selected) return;
        const display = zoomGalleryDisplayItem();
        const assetName = safeString(display?.assetName || selected.assetName).trim();
        const oldMeta = zoomRegenerationMetaForDisplay(selected, display);
        if (!assetName || !regenerationPlanFromDisplayMeta(oldMeta)) {
            if (naaZoomGalleryState) {
                naaZoomGalleryState.regenerateState = 'error';
                naaZoomGalleryState.regenerateMessage =
                    'This image has no saved regeneration plan.';
                await renderNaaZoomOverlayContent();
            }
            return;
        }
        const liveSizePresetId = await selectedZoomSizePresetIdFromRoot(rootDoc);
        const sizePresetId = await persistZoomRegenerateSizeSelection(
            liveSizePresetId || selectedZoomRegenerateSizePresetId(),
        );
        const context = {
            rootDoc,
            assetName,
            assetMeta: oldMeta,
            originalMarkup: selected.originalMarkup || display?.sourceImageMarkup,
            imgSrc: display?.imgSrc || selected.imgSrc,
            sizePresetId,
        };
        naaZoomRegenerationInFlight = true;
        if (naaZoomGalleryState) {
            naaZoomGalleryState.regenerateState = 'loading';
            naaZoomGalleryState.regenerateMessage = '재생성 중...';
            await renderNaaZoomOverlayContent();
        }
        try {
            const result = await regenerateGeneratedAssetFromZoomContext(context);
            if (naaZoomOverlayRef) await refreshZoomGalleryAfterRegeneration(result.assetName);
        } catch (error) {
            const replacement = stableRegenerationChatHtml(
                assetName,
                selected.originalMarkup,
                oldMeta,
                selected.imgSrc,
            );
            if (rootDoc) {
                replaceFirstGeneratedAssetInRootDom(rootDoc, assetName, replacement).catch(
                    () => {},
                );
            }
            await replaceFirstGeneratedAssetInCurrentChat(
                assetName,
                () => replacement,
                'regenerate-error-restore',
                {
                    slotId: oldMeta.slotId,
                    messageIndex: oldMeta.messageIndex,
                    chatKey: oldMeta.chatKey,
                },
            ).catch(() => {});


            finishNovelAIQueueRuntimeToast('NAI image regeneration failed.', 'error');
            if (naaZoomOverlayRef && naaZoomGalleryState) {
                naaZoomGalleryState.regenerateState = 'error';
                naaZoomGalleryState.regenerateMessage = error?.message || String(error);
                await renderNaaZoomOverlayContent();
            }
        } finally {
            naaZoomRegenerationInFlight = false;
        }
    }

    function zoomMetaForTimelineSelection(item, selected, timeline) {
        const assetName = safeString(item?.assetName).trim();
        const selectedMeta = displayAssetMetaMap.get(selected?.assetName) || selected?.meta || {};
        const storedMeta = displayAssetMetaMap.get(assetName) || {};
        const sourceImageMarkup = safeString(
            item?.sourceImageMarkup ||
                selected?.originalMarkup ||
                selectedMeta.sourceImageMarkup ||
                reverseAssetMap.get(selected?.assetName) ||
                '',
        ).trim();
        const parsedSource = parseSupportedImageMarkup(sourceImageMarkup);
        const sourceImageToken = safeString(
            selectedMeta.sourceImageToken ||
                parsedSource?.tokenName ||
                rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(sourceImageMarkup)),
        ).trim();
        const rawDisplaySrc = safeString(item?.imgSrc || storedMeta.displaySrc).trim();
        const displaySrc = normalizeImageDataUrl(rawDisplaySrc) ? '' : rawDisplaySrc;
        const basePlan =
            regenerationPlanFromDisplayMeta(storedMeta) ||
            regenerationPlanFromDisplayMeta(selectedMeta) ||
            regenerationPlanFromDisplayMeta(
                displayMetaWithSlotRegenerationPlan(storedMeta, item?.slotId || selectedMeta.slotId),
            ) ||
            regenerationPlanFromDisplayMeta(
                displayMetaWithSlotRegenerationPlan(selectedMeta, item?.slotId || selectedMeta.slotId),
            );
        const regenerationPlan = basePlan
            ? normalizeDisplayRegenerationPlan({
                  ...basePlan,
                  assetName,
                  chatKey: storedMeta.chatKey || selectedMeta.chatKey || basePlan.chatKey,
                  sourceImageToken: sourceImageToken || basePlan.sourceImageToken,
                  sourceImageMarkup: sourceImageMarkup || basePlan.sourceImageMarkup,
                  seed: normalizeNovelAISeed(item?.seed) || basePlan.seed,
              })
            : null;
        const storedPlan = regenerationPlanFromDisplayMeta(storedMeta);
        const locationMeta = locationMetaFromParts({
            ...selectedMeta,
            ...storedMeta,
            ...item,
        });
        const itemIsOriginalDisplay = item?.type === 'original';
        const historyWidth = intBetween(
            (itemIsOriginalDisplay ? 0 : item?.width) || storedMeta.width || storedPlan?.width,
            0,
            0,
            8192,
        );
        const historyHeight = intBetween(
            (itemIsOriginalDisplay ? 0 : item?.height) || storedMeta.height || storedPlan?.height,
            0,
            0,
            8192,
        );
        return {
            ...storedMeta,
            seed:
                item?.type === 'original'
                    ? ''
                    : normalizeNovelAISeed(item?.seed || storedMeta.seed),
            seedFixed: Boolean(storedMeta.seedFixed),
            promptKey: safeString(
                item?.promptKey || storedMeta.promptKey || selected?.promptKey,
            ).trim(),
            width: historyWidth,
            height: historyHeight,
            dataUrl: '',
            displaySrc,
            originalDisplay: item?.type === 'original',
            originalDisplayNatural: itemIsOriginalDisplay || Boolean(storedMeta.originalDisplayNatural),
            sourceImageToken,
            sourceImageMarkup,
            chatKey: safeString(storedMeta.chatKey || selectedMeta.chatKey || item?.chatKey).trim(),
            ...locationMeta,
            sourceImageMarkerId: safeString(
                selectedMeta.sourceImageMarkerId ||
                    regenerationPlanFromDisplayMeta(selectedMeta)?.sourceImageMarkerId,
            ).trim(),
            slotId: imageSlotIdFromParts({
                ...selectedMeta,
                slotId: item?.slotId || selectedMeta.slotId,
                assetName,
                sourceImageToken,
                sourceImageMarkup,
                chatKey: storedMeta.chatKey || selectedMeta.chatKey || item?.chatKey,
            }),
            regenerationPlan,
        };
    }

    function chatHistoryEntriesForSlot(slot = {}) {
        const entries = Array.isArray(slot?.entries) ? slot.entries : [];
        const seen = new Set();
        const result = [];
        for (const [index, entry] of entries.entries()) {
            const assetName = safeString(entry?.assetName).trim();
            if (!assetName || seen.has(assetName)) continue;
            seen.add(assetName);
            result.push({
                ...entry,
                assetName,
                slotId: safeString(slot?.slotId || entry?.slotId).trim(),
                __naaOrderIndex: index,
            });
        }
        return result
            .sort((a, b) => {
                if (a.type === 'original' && b.type !== 'original') return -1;
                if (a.type !== 'original' && b.type === 'original') return 1;
                const aCreated = Number(a.createdAt) || 0;
                const bCreated = Number(b.createdAt) || 0;
                if (aCreated !== bCreated) return aCreated - bCreated;
                return (a.__naaOrderIndex || 0) - (b.__naaOrderIndex || 0);
            })
            .map(({ __naaOrderIndex, ...entry }) => entry);
    }

    function chatHistoryNextSlotEntry(
        slot = {},
        currentAssetName = '',
        currentEntryId = '',
        action = 'next',
    ) {
        const items = chatHistoryEntriesForSlot(slot);
        if (!items.length) return -1;
        const cleanAssetName = safeString(currentAssetName).trim();
        const cleanEntryId = safeString(currentEntryId).trim();
        let currentIndex = -1;
        if (cleanEntryId) {
            currentIndex = items.findIndex(
                (entry) => safeString(entry?.entryId).trim() === cleanEntryId,
            );
        }
        if (currentIndex < 0 && cleanAssetName) {
            currentIndex = items.findIndex(
                (entry) => safeString(entry?.assetName).trim() === cleanAssetName,
            );
        }
        if (currentIndex < 0) currentIndex = 0;
        const delta = action === 'prev' ? -1 : 1;
        return items[(currentIndex + delta + items.length) % items.length] || null;
    }

    function manualGenerationSlotIdsFromHtml(html = '') {
        const ids = [];
        const text = safeString(html);
        const regex =
            /<div\b(?=[^>]*(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["'])(?=[^>]*(?:data-naa-slot-id|x-risu-naa-slot-id)=["']([^"']+)["'])[^>]*>/giu;
        let match;
        while ((match = regex.exec(text))) {
            const tag = safeString(match[0]);
            if (
                /\b(?:data-naa-manual-generation-disabled|x-risu-naa-manual-generation-disabled)=["']true["']/.test(
                    tag,
                )
            ) {
                continue;
            }
            const slotId = safeString(match[1]).trim();
            if (slotId && !ids.includes(slotId)) ids.push(slotId);
        }
        return ids;
    }

    function manualGenerationMessageMatchesAction(html = '', actionInfo = {}) {
        const text = safeString(html);
        if (!text || !/\b(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["']/.test(text)) {
            return false;
        }
        const slotId = safeString(actionInfo?.slotId).trim();
        if (slotId && text.includes(slotId)) return true;
        const assetName = safeString(actionInfo?.assetName).trim();
        if (assetName && text.includes(assetName)) return true;
        const original = safeString(actionInfo?.originalMarkup).trim();
        if (original && text.includes(encodeNaaOriginal(original))) return true;
        return false;
    }

    function replaceManualImageCardsWithLoading(content, slotIds = []) {
        const selectedSlotIds = new Set(
            (Array.isArray(slotIds) ? slotIds : [])
                .map((slotId) => safeString(slotId).trim())
                .filter(Boolean),
        );
        if (!selectedSlotIds.size) return safeString(content);
        return safeString(content).replace(naaGeneratedImageBlockRegex(), (block) => {
            if (!/\b(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["']/.test(block)) {
                return block;
            }
            const slotId = slotIdFromGeneratedImageHtml(block);
            if (!selectedSlotIds.has(slotId)) return block;
            const assetName = assetNameFromGeneratedImageHtml(block);
            const originalMarkup =
                htmlFirstAttributeValue(block, ['x-risu-naa-original', 'data-naa-original']) ||
                reverseAssetMap.get(assetName) ||
                '';
            return generatedAssetLoadingHtmlTemplate(assetName, originalMarkup, {
                slotId,
                sourceImageMarkup: originalMarkup,
                sourceImageToken: assetName,
                originalDisplay: true,
                originalDisplayNatural: true,
                displaySrc: rawAssetImageSrc(assetName),
            });
        });
    }

    async function replaceManualImageCardsInRootDom(rootDoc, slotIds = [], messageHtml = '') {
        const selectedSlotIds = new Set(
            (Array.isArray(slotIds) ? slotIds : [])
                .map((slotId) => safeString(slotId).trim())
                .filter(Boolean),
        );
        if (!rootDoc || !selectedSlotIds.size) return false;
        try {
            const nodes = await rootDoc.querySelectorAll(
                '.naa-generated-image, .x-risu-naa-generated-image',
            );
            const len = await nodes.length();
            let replaced = false;
            for (let index = 0; index < len; index++) {
                const node = await nodes.at(index);
                const html = await node.getOuterHTML();
                if (!/\b(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["']/.test(html)) {
                    continue;
                }
                const slotId = slotIdFromGeneratedImageHtml(html);
                if (!selectedSlotIds.has(slotId)) continue;
                const loadingHtml = replaceManualImageCardsWithLoading(html, [slotId]);
                await node.setOuterHTML(loadingHtml);
                replaced = true;
            }
            if (replaced) invalidateZoomHitTestCache();
            return replaced;
        } catch (error) {

            return false;
        }
    }

    async function handleNaaManualGenerateAction(rootDoc, actionInfo) {
        const action = safeString(actionInfo?.action).trim();
        if (action !== 'all') return false;
        const actionSlotId = safeString(actionInfo?.slotId).trim();
        const inFlightKey = `all:${actionSlotId || safeString(actionInfo?.assetName).trim()}`;
        if (inFlightKey && naaManualGenerationInFlightSlots.has(inFlightKey)) return true;
        const snapshot = await getCurrentChatForAssetReplacement();
        if (!snapshot?.chat || !Array.isArray(snapshot.chat.message)) return false;
        let messageIndex = -1;
        let message = null;
        for (let index = snapshot.chat.message.length - 1; index >= 0; index--) {
            const candidate = snapshot.chat.message[index];
            if (!manualGenerationMessageMatchesAction(candidate?.data, actionInfo)) continue;
            messageIndex = index;
            message = candidate;
            break;
        }
        if (!message || messageIndex < 0) return false;
        const manualSlotIds = manualGenerationSlotIdsFromHtml(message.data);
        const targetSlotIds = manualSlotIds;
        if (!targetSlotIds.length) return false;
        naaManualGenerationInFlightSlots.add(inFlightKey);
        try {
            const loadingMessageData = replaceManualImageCardsWithLoading(
                message.data,
                targetSlotIds,
            );
            if (loadingMessageData !== message.data) {
                snapshot.chat.message[messageIndex] = { ...message, data: loadingMessageData };
                await writeCurrentChatForAssetReplacement(snapshot);
                await replaceManualImageCardsInRootDom(rootDoc, targetSlotIds, loadingMessageData);
            }
            const restoredText = normalizeNaaImageMarkupForModel(message.data);
            const latest = {
                ...snapshot,
                message: { ...message, data: restoredText },
                messageIndex,
                data: restoredText,
                pendingKey: snapshot.chatKey,
            };
            const output = await handleAfterResponseSkeleton(restoredText, 'manual-generation', latest, {
                forceImageGeneration: true,
                manualWrapRemaining: true,
                skipInitialLoadingState: true,
                targetSlotIds,
            });
            snapshot.chat.message[messageIndex] = { ...message, data: output };
            await writeCurrentChatForAssetReplacement(snapshot);
            invalidateZoomGeneratedItemsCache();
            scheduleGeneratedChatImageHydration('manual-generation-complete', 80);
            return true;
        } catch (error) {


            try {
                snapshot.chat.message[messageIndex] = { ...message, data: message.data };
                await writeCurrentChatForAssetReplacement(snapshot);
                scheduleGeneratedChatImageHydration('manual-generation-error-restore', 80);
            } catch (restoreError) {

            }
            await showAiAnalysisErrorModal('채팅 이미지 분석 실패', error, {
                scope: 'manual-generation-image-token-analyzer',
                force: true,
            });
            finishRuntimeOverlay('Manual image generation failed.', 'error');
            return false;
        } finally {
            naaManualGenerationInFlightSlots.delete(inFlightKey);
        }
    }

    async function handleNaaChatRegenerateAction(rootDoc, actionInfo) {
        const action = safeString(actionInfo?.action).trim();
        if (action !== 'regenerate') return false;
        const assetName = safeString(actionInfo?.assetName).trim();
        if (!assetName) return false;
        if (naaChatRegenerationInFlightAssets.has(assetName)) return true;
        const slot = displayAssetSlotForAsset(assetName, actionInfo?.slotId);
        const meta = displayMetaWithSlotRegenerationPlan(
            displayAssetMetaMap.get(assetName) || {},
            slot?.slotId,
        );
        if (!regenerationPlanFromDisplayMeta(meta)) return false;
        const originalMarkup = safeString(
            actionInfo.originalMarkup ||
                meta.sourceImageMarkup ||
                regenerationPlanFromDisplayMeta(meta)?.sourceImageMarkup ||
                reverseAssetMap.get(assetName) ||
                '',
        ).trim();
        const context = {
            rootDoc,
            assetName,
            assetMeta: meta,
            originalMarkup,
            imgSrc: safeString(meta.displaySrc).trim() || cachedImageTokenPreviewUrl(assetName),
        };
        naaChatRegenerationInFlightAssets.add(assetName);
        if (naaZoomOverlayRef && naaZoomGalleryState) {
            naaZoomGalleryState.regenerateState = 'loading';
            naaZoomGalleryState.regenerateMessage = '';
            await renderNaaZoomOverlayContent();
        }
        try {
            const result = await regenerateGeneratedAssetFromZoomContext(context);
            if (naaZoomOverlayRef) await refreshZoomGalleryAfterRegeneration(result.assetName);
        } catch (error) {
            await restoreRegenerationStableChatImage(
                rootDoc,
                assetName,
                originalMarkup,
                meta,
                context.imgSrc,
            );


            finishNovelAIQueueRuntimeToast('NAI image regeneration failed.', 'error');
            if (naaZoomOverlayRef && naaZoomGalleryState) {
                naaZoomGalleryState.regenerateState = 'error';
                naaZoomGalleryState.regenerateMessage = error?.message || String(error);
                await renderNaaZoomOverlayContent();
            }
        } finally {
            naaChatRegenerationInFlightAssets.delete(assetName);
        }
        return true;
    }

    async function handleNaaChatHistoryAction(rootDoc, actionInfo) {
        const recordDebug =
            typeof recordZoomDebugEntry === 'function' ? recordZoomDebugEntry : () => {};
        const htmlSummary =
            typeof zoomDebugHtmlImageSummary === 'function'
                ? zoomDebugHtmlImageSummary
                : () => null;
        const slotSummary =
            typeof zoomDebugSlotSummary === 'function' ? zoomDebugSlotSummary : () => null;
        const previewKind =
            typeof zoomPreviewSrcKind === 'function' ? zoomPreviewSrcKind : () => '';
        const action = safeString(actionInfo?.action).trim();
        const actionSlotId = safeString(actionInfo?.slotId).trim();
        const currentAssetName = safeString(actionInfo?.assetName).trim();
        const renderedEntryId = safeString(actionInfo?.entryId).trim();
        const actionHtml = safeString(actionInfo?.html).trim();
        const debugBase = {
            action,
            actionSlotId,
            currentAssetName,
            renderedEntryId,
            actionHtml: htmlSummary(actionHtml),
        };
        recordDebug('chat-history-action-start', 'Chat image history button clicked.', debugBase);
        const logBlocked = (reason, data = {}) => {
            recordDebug('chat-history-action-blocked', reason, {
                ...debugBase,
                ...data,
            });
            return false;
        };
        if (action !== 'prev' && action !== 'next') {
            return logBlocked('invalid-action');
        }

        if (!currentAssetName && !actionSlotId) return logBlocked('missing-target');
        const slotById = displayAssetSlotForAsset('', actionSlotId);
        const slotByAsset = slotById
            ? null
            : displayAssetSlotForAsset(currentAssetName, actionSlotId);
        const gallerySlot =
            slotById || slotByAsset || !currentAssetName
                ? null
                : displayAssetSlotForGalleryItem({
                      assetName: currentAssetName,
                      meta: displayAssetMetaMap.get(currentAssetName) || {},
                  });
        const slot = slotById || slotByAsset || gallerySlot;
        const slotSource = slotById ? 'slot-id' : slotByAsset ? 'asset-slot' : gallerySlot ? 'gallery' : 'none';
        const slotEntries = Array.isArray(slot?.entries) ? slot.entries : [];
        recordDebug('chat-history-slot-resolved', 'Resolved slot for chat history action.', {
            ...debugBase,
            slotSource,
            slot: slotSummary(slot),
        });

        if (!slot) {
            return logBlocked('slot-not-found', { slotSource });
        }
        if (slotEntries.length < 2) {
            return logBlocked('insufficient-slot-entries', {
                slotSource,
                slotId: slot.slotId || '',
                slotEntryCount: slotEntries.length,
                slotCurrentEntryId: slot.currentEntryId || '',
            });
        }
        const selectedAssetName = safeString(currentAssetName).trim();
        const selected = {
            type: 'current',
            assetName: selectedAssetName,
            originalMarkup: slot.sourceImageMarkup,
            slotId: slot.slotId,
            chatKey: slot.chatKey,
            meta: displayAssetMetaMap.get(selectedAssetName) || {},
        };
        const historyEntries = chatHistoryEntriesForSlot(slot);
        if (historyEntries.length < 2) {
            return logBlocked('insufficient-history', {
                slotSource,
                slotId: slot.slotId || '',
                slotEntryCount: slotEntries.length,
                historyCount: historyEntries.length,
                slotCurrentEntryId: slot.currentEntryId || '',
            });
        }
        const currentEntryId = renderedEntryId || safeString(slot.currentEntryId).trim();
        const item = chatHistoryNextSlotEntry(
            slot,
            currentAssetName,
            currentEntryId,
            action,
        );
        const nextAssetName = safeString(item?.assetName).trim();
        recordDebug('chat-history-next-entry', 'Selected next history entry.', {
            ...debugBase,
            currentEntryId,
            nextAssetName,
            nextEntry: {
                type: safeString(item?.type).trim(),
                entryId: safeString(item?.entryId).trim(),
                assetName: nextAssetName,
                imgSrcKind: previewKind(item?.imgSrc),
                charIndex: nonNegativeIntegerOr(item?.charIndex, -1),
            },
            historyCount: historyEntries.length,
        });
        if (!item || !nextAssetName) {
            return logBlocked('no-next-entry', {
                slotSource,
                slotId: slot.slotId || '',
                currentEntryId,
                historyCount: historyEntries.length,
                history: historyEntries.slice(0, 8).map((entry, index) => ({
                    index,
                    type: entry.type || '',
                    entryId: entry.entryId || '',
                    assetName: entry.assetName || '',
                    charIndex: nonNegativeIntegerOr(entry.charIndex, -1),
                })),
            });
        }
        const nextMeta = zoomMetaForTimelineSelection(
            { ...item, assetName: nextAssetName },
            selected,
            historyEntries,
        );
        const sourceImageMarkup = safeString(
            nextMeta.sourceImageMarkup || selected.originalMarkup || item.sourceImageMarkup,
        ).trim();
        const previewCharIndex = nonNegativeIntegerOr(
            nextMeta.charIndex ?? item.charIndex ?? selected.meta?.charIndex ?? slot.charIndex,
            -1,
        );
        const currentRootImageHtml = await findGeneratedAssetHtmlInRootDom(
            rootDoc,
            currentAssetName,
            { slotId: slot.slotId, actionHtml },
        );
        let previewUrl = '';
        try {
            previewUrl = await loadChatRootImageTokenObjectUrl(
                nextAssetName,
                {
                    ...(previewCharIndex >= 0 ? { charIndex: previewCharIndex } : {}),
                    ...(currentRootImageHtml ? { renderedHtml: currentRootImageHtml } : {}),
                },
            );
        } catch (error) {
            recordDebug('chat-history-preview-error', 'Failed to load next history preview.', {
                ...debugBase,
                nextAssetName,
                nextEntryId: item?.entryId || '',
                charIndex: previewCharIndex,
                error: error?.message || String(error),
            });
        }
        if (!previewUrl) {
            return logBlocked('preview-empty', {
                slotSource,
                slotId: slot.slotId || '',
                currentEntryId,
                nextEntryId: item.entryId || '',
                nextAssetName,
                charIndex: previewCharIndex,
            });
        }
        const stableReplacement = generatedAssetHtmlTemplate(nextAssetName, sourceImageMarkup, {
            ...nextMeta,
            displaySrc: previewUrl,
            preferDisplaySrc: true,
            renderedEntryId: item.entryId,
            renderOnlyHistoryPreview: true,
            persistentAssetName: currentDisplayAssetSlotEntry(slot)?.assetName || selectedAssetName,
            __naaSkipCurrentSlotRedirect: true,
        });
        recordDebug('chat-history-replacement-built', 'Built live replacement for chat history action.', {
            ...debugBase,
            nextAssetName,
            nextEntryId: item?.entryId || '',
            previewSrcKind: previewKind(previewUrl),
            previewUrlSource:
                typeof lastChatRootBlobUrlSource === 'string' ? lastChatRootBlobUrlSource : '',
            replacement: htmlSummary(stableReplacement),
        });
        try {
            const domReplaced = await replaceFirstGeneratedAssetInRootDom(
                rootDoc,
                currentAssetName,
                stableReplacement,
                { slotId: slot.slotId, actionHtml },
            );
            recordDebug('chat-history-dom-replace', 'Tried replacing chat image DOM for history action.', {
                ...debugBase,
                domReplaced,
                slotId: slot.slotId,
                currentAssetName,
                nextAssetName,
                replacement: htmlSummary(stableReplacement),
            });

            if (!domReplaced) {
                return logBlocked('dom-not-replaced', {
                    slotSource,
                    slotId: slot.slotId || '',
                    currentEntryId,
                    nextEntryId: item.entryId || '',
                    nextAssetName,
                    charIndex: previewCharIndex,
                    historyCount: historyEntries.length,
                });
            }
            const nextSlot = persistDisplayAssetSlotCurrentEntry(
                slot,
                item.entryId,
                'chat-history-current-preview',
            );

            if (nextSlot) {
                invalidateZoomGeneratedItemsCache();
                recordDebug('chat-history-current-persisted', 'Persisted selected history entry as slot current.', {
                    ...debugBase,
                    nextEntryId: item.entryId,
                    slot: slotSummary(nextSlot),
                });
            }
        } catch (error) {
            recordDebug('chat-history-action-error', 'Chat history action failed.', {
                ...debugBase,
                nextAssetName,
                error: error?.message || String(error),
            });
            return false;
        }
        return true;
    }

    async function selectZoomHistoryPreview(historyIndex) {
        const selected = zoomGallerySelectedItem();
        if (!selected) return false;
        const state = naaZoomGalleryState || {};
        const timeline = zoomHistoryItemsForGalleryItem(selected);
        const index = intBetween(historyIndex, 0, 0, Math.max(timeline.length - 1, 0));
        if (!timeline[index]) return false;
        naaZoomGalleryState = {
            ...state,
            view: 'history',
            historyIndex: index,
            regenerateState: 'idle',
            regenerateMessage: '',
        };
        await prepareZoomDisplayImageForRender(naaZoomGalleryState);
        await renderNaaZoomMainStageOnly();
        scheduleZoomOverlayContentRender('zoom-history-preview');
        return true;
    }

    async function cycleZoomHistoryPreview(action = 'next-history') {
        const selected = zoomGallerySelectedItem();
        if (!selected) return false;
        const history = zoomHistoryItemsForGalleryItem(selected);
        if (!history.length) return true;
        const currentIndex = Math.max(0, zoomPreviewHistoryIndexForState(naaZoomGalleryState, history));
        const delta = action === 'prev-history' ? -1 : 1;
        const nextIndex = (currentIndex + delta + history.length) % history.length;
        await selectZoomHistoryPreview(nextIndex);
        scheduleZoomGalleryPreviewHydration();
        return true;
    }

    async function zoomHistoryDeleteLiveReplacementHtml(
        fallbackAssetName = '',
        sourceImageMarkup = '',
        fallbackMeta = {},
        fallbackEntry = {},
    ) {
        const cleanAssetName = safeString(fallbackAssetName).trim();
        if (!cleanAssetName) return '';
        const cleanSourceMarkup = safeString(
            sourceImageMarkup ||
                fallbackEntry?.sourceImageMarkup ||
                fallbackMeta?.sourceImageMarkup,
        ).trim();
        const charIndex = nonNegativeIntegerOr(
            fallbackMeta?.charIndex ?? fallbackEntry?.charIndex,
            -1,
        );
        const readOptions = charIndex >= 0 ? { charIndex } : {};
        const storedPreview = safeString(
            fallbackEntry?.imgSrc || fallbackMeta?.displaySrc,
        ).trim();
        let previewUrl = isRenderableZoomHistoryPreviewSrc(storedPreview) ? storedPreview : '';
        if (!previewUrl && fallbackEntry?.type === 'original') {
            previewUrl = await resolveOriginalMarkupPreviewUrl(cleanSourceMarkup, readOptions).catch(
                () => '',
            );
        }
        if (!isRenderableZoomHistoryPreviewSrc(previewUrl)) {
            previewUrl = await loadZoomImageTokenObjectUrl(cleanAssetName, readOptions).catch(
                () => '',
            );
        }
        recordZoomDebugEntry('zoom-history-delete-live-preview', 'Resolved delete fallback live preview.', {
            fallbackAssetName: cleanAssetName,
            fallbackEntryType: safeString(fallbackEntry?.type).trim(),
            fallbackEntryId: safeString(fallbackEntry?.entryId).trim(),
            storedPreviewKind: zoomPreviewSrcKind(storedPreview),
            previewUrlKind: zoomPreviewSrcKind(previewUrl),
            charIndex,
        });
        if (!isRenderableZoomHistoryPreviewSrc(previewUrl)) return '';
        const html = generatedAssetHtmlTemplate(cleanAssetName, cleanSourceMarkup, {
            ...fallbackMeta,
            originalDisplay:
                fallbackEntry?.type === 'original' || Boolean(fallbackMeta?.originalDisplay),
            originalDisplayNatural:
                fallbackEntry?.type === 'original' ||
                Boolean(fallbackMeta?.originalDisplayNatural),
            displaySrc: previewUrl,
            preferDisplaySrc: true,
        });
        recordZoomDebugEntry('zoom-history-delete-live-html', 'Built delete fallback live HTML.', {
            fallbackAssetName: cleanAssetName,
            html: zoomDebugHtmlImageSummary(html),
        });
        return html;
    }

    async function deleteZoomHistoryAsset(rootDoc) {
        const selected = zoomGallerySelectedItem();
        if (!selected) return false;
        const state = naaZoomGalleryState || {};
        const timeline = zoomHistoryItemsForGalleryItem(selected);
        const item = zoomSelectedHistoryItemForState(state, timeline);
        if (!item || item.type !== 'generated') return false;
        const assetName = safeString(item.assetName).trim();
        if (!assetName) return false;
        const slot = displayAssetSlotForGalleryItem(selected);
        recordZoomDebugEntry('zoom-history-delete-start', 'Zoom history delete started.', {
            assetName,
            selectedIndex: state.selectedIndex,
            view: state.view,
            historyIndex: state.historyIndex,
            selected: {
                type: selected?.type || '',
                assetName: selected?.assetName || '',
                imgSrcKind: zoomPreviewSrcKind(selected?.imgSrc),
                slotId: selected?.slotId || selected?.meta?.slotId || '',
            },
            targetHistoryItem: {
                type: item.type,
                entryId: item.entryId,
                assetName: item.assetName,
                imgSrcKind: zoomPreviewSrcKind(item.imgSrc),
            },
            timeline: timeline.slice(0, 16).map((entry, index) => ({
                index,
                type: entry.type,
                entryId: entry.entryId,
                assetName: entry.assetName,
                imgSrcKind: zoomPreviewSrcKind(entry.imgSrc),
            })),
            slot: zoomDebugSlotSummary(slot),
        });
        const result = removeGeneratedAssetHistoryEntryFromSlot(slot, assetName, item.entryId);
        if (!result.removed || !result.slot) return false;
        const nextSlot = result.slot;
        recordZoomDebugEntry('zoom-history-delete-slot-result', 'Removed generated entry from slot.', {
            removedEntry: {
                type: result.removedEntry?.type || '',
                entryId: result.removedEntry?.entryId || '',
                assetName: result.removedEntry?.assetName || '',
            },
            fallbackEntry: {
                type: result.fallbackEntry?.type || '',
                entryId: result.fallbackEntry?.entryId || '',
                assetName: result.fallbackEntry?.assetName || '',
                imgSrcKind: zoomPreviewSrcKind(result.fallbackEntry?.imgSrc),
            },
            nextSlot: zoomDebugSlotSummary(nextSlot),
        });
        const deletedMeta = displayMetaWithSlotRegenerationPlan(
            displayAssetMetaMap.get(assetName) || item.meta || selected.meta || {},
            nextSlot.slotId,
        );
        displayAssetSlots.set(nextSlot.slotId, nextSlot);
        upsertDisplayAssetSlotRegenerationPlan(nextSlot.slotId, deletedMeta.regenerationPlan, {
            ...deletedMeta,
            assetName,
            lastAssetName: assetName,
        });
        displayAssetSlotMap.delete(assetName);
        displayAssetMetaMap.delete(assetName);
        reverseAssetMap.delete(assetName);
        for (const [key, value] of Array.from(displayAssetMap.entries())) {
            if (value === assetName) displayAssetMap.delete(key);
        }
        forgetImageTokenPreviewUrl(assetName);
        invalidateZoomGeneratedItemsCache();
        const assetRemoveResult = await removeGeneratedAssetFromCharacterAssets(assetName).catch((error) => {
            recordZoomDebugEntry('zoom-history-delete-asset-remove-error', 'Failed to remove generated asset from character assets.', {
                assetName,
                error: error?.message || String(error),
            });
            return null;
        });
        recordZoomDebugEntry('zoom-history-delete-asset-remove', 'Removed generated asset from character assets.', {
            assetName,
            result: assetRemoveResult,
        });

        const fallbackEntry = result.fallbackEntry;
        const fallbackAssetName = safeString(fallbackEntry?.assetName).trim();
        const selectedIndex = intBetween(
            state.selectedIndex,
            0,
            0,
            Math.max((Array.isArray(state.items) ? state.items.length : 1) - 1, 0),
        );
        const sourceImageMarkup = safeString(
            fallbackEntry?.sourceImageMarkup ||
                nextSlot.sourceImageMarkup ||
                selected.originalMarkup ||
                item.sourceImageMarkup,
        ).trim();
        let replacement = '';
        let fallbackMeta = {};
        if (fallbackAssetName) {
            const fallbackDisplaySrc = safeString(fallbackEntry?.imgSrc).trim();
            fallbackMeta = displayMetaWithSlotRegenerationPlan({
                ...(displayAssetMetaMap.get(fallbackAssetName) || {}),
                sourceImageMarkup,
                slotId: nextSlot.slotId,
                originalDisplay: fallbackEntry?.type === 'original',
                displaySrc: isRawAssetImageSrc(fallbackDisplaySrc) ? fallbackDisplaySrc : '',
                seed: fallbackEntry?.seed || displayAssetMetaMap.get(fallbackAssetName)?.seed,
                promptKey:
                    fallbackEntry?.promptKey || displayAssetMetaMap.get(fallbackAssetName)?.promptKey,
                width: fallbackEntry?.width || displayAssetMetaMap.get(fallbackAssetName)?.width,
                height: fallbackEntry?.height || displayAssetMetaMap.get(fallbackAssetName)?.height,
            }, nextSlot.slotId);
            displayAssetMetaMap.set(fallbackAssetName, fallbackMeta);
            displayAssetSlotMap.set(fallbackAssetName, nextSlot.slotId);
            if (sourceImageMarkup) reverseAssetMap.set(fallbackAssetName, sourceImageMarkup);
            replacement = generatedAssetHtmlTemplate(
                fallbackAssetName,
                sourceImageMarkup,
                fallbackMeta,
            );
            recordZoomDebugEntry('zoom-history-delete-replacement-built', 'Built persisted fallback replacement after delete.', {
                deletedAssetName: assetName,
                fallbackAssetName,
                fallbackEntryType: fallbackEntry?.type || '',
                fallbackMetaDisplaySrcKind: zoomPreviewSrcKind(fallbackMeta.displaySrc),
                replacement: zoomDebugHtmlImageSummary(replacement),
            });
        }
        scheduleDisplayAssetMapSave('zoom-history-delete');
        try {
            await saveDisplayAssetMap();
        } catch (error) {

        }
        if (replacement) {
            const chatReplaced = await replaceFirstGeneratedAssetInCurrentChat(
                assetName,
                () => replacement,
                'zoom-history-delete',
                {
                    slotId: nextSlot.slotId,
                    messageIndex:
                        fallbackMeta.messageIndex ??
                        deletedMeta.messageIndex ??
                        selected.meta?.messageIndex,
                    chatKey: fallbackMeta.chatKey || deletedMeta.chatKey || selected.meta?.chatKey,
                    replacementAssetName: fallbackAssetName,
                },
            ).catch((error) => {
                recordZoomDebugEntry('zoom-history-delete-chat-replace-error', 'Failed to replace persisted chat HTML after delete.', {
                    deletedAssetName: assetName,
                    fallbackAssetName,
                    error: error?.message || String(error),
                });
                return false;
            });
            recordZoomDebugEntry('zoom-history-delete-chat-replace', 'Tried replacing persisted chat HTML after delete.', {
                deletedAssetName: assetName,
                fallbackAssetName,
                chatReplaced,
                replacement: zoomDebugHtmlImageSummary(replacement),
            });
            const liveReplacement = await zoomHistoryDeleteLiveReplacementHtml(
                fallbackAssetName,
                sourceImageMarkup,
                fallbackMeta,
                fallbackEntry,
            ).catch(() => '');
            recordZoomDebugEntry('zoom-history-delete-live-replacement', 'Resolved live DOM replacement after delete.', {
                deletedAssetName: assetName,
                fallbackAssetName,
                hasLiveReplacement: Boolean(liveReplacement),
                liveReplacement: zoomDebugHtmlImageSummary(liveReplacement),
            });
            if (liveReplacement) {
                const liveDomReplaced = await replaceFirstGeneratedAssetInRootDom(
                    rootDoc,
                    assetName,
                    liveReplacement,
                ).catch((error) => {
                    recordZoomDebugEntry('zoom-history-delete-live-dom-error', 'Failed to replace live DOM after delete.', {
                        deletedAssetName: assetName,
                        fallbackAssetName,
                        error: error?.message || String(error),
                    });
                    return false;
                });
                recordZoomDebugEntry('zoom-history-delete-live-dom', 'Tried replacing live DOM after delete.', {
                    deletedAssetName: assetName,
                    fallbackAssetName,
                    liveDomReplaced,
                    liveReplacement: zoomDebugHtmlImageSummary(liveReplacement),
                });
            }
            scheduleGeneratedChatImageHydration('zoom-history-delete', 0);
        }

        const items = [...(Array.isArray(state.items) ? state.items : [])];
        if (items.length && fallbackAssetName) {
            items[selectedIndex] = {
                ...selected,
                type: 'current',
                assetName: fallbackAssetName,
                imgSrc:
                    safeString(fallbackMeta.displaySrc).trim() ||
                    safeString(fallbackEntry?.imgSrc).trim() ||
                    selected.imgSrc,
                originalMarkup: sourceImageMarkup,
                originalImgSrc:
                    fallbackEntry?.type === 'original' ? fallbackEntry.imgSrc : selected.originalImgSrc,
                seed: fallbackMeta.seed,
                promptKey: fallbackMeta.promptKey,
                width: fallbackMeta.width || fallbackEntry?.width || 0,
                height: fallbackMeta.height || fallbackEntry?.height || 0,
                meta: fallbackMeta,
            };
        }
        const nextHistory = zoomHistoryItemsForGalleryItem(items[selectedIndex] || selected);
        const fallbackHistoryIndex = fallbackEntry
            ? nextHistory.findIndex((entry) => entry.entryId === fallbackEntry.entryId)
            : -1;
        naaZoomGalleryState = {
            ...state,
            items,
            selectedIndex,
            view: fallbackHistoryIndex >= 0 ? 'history' : 'current',
            historyIndex: fallbackHistoryIndex,
            regenerateState: 'idle',
            regenerateMessage: '',
            deleteHistoryAssetState: '',
        };
        recordZoomDebugEntry('zoom-history-delete-state-updated', 'Zoom gallery state updated after delete.', {
            fallbackAssetName,
            fallbackHistoryIndex,
            nextView: naaZoomGalleryState.view,
            nextHistoryIndex: naaZoomGalleryState.historyIndex,
            nextSelected: {
                assetName: items[selectedIndex]?.assetName || '',
                imgSrcKind: zoomPreviewSrcKind(items[selectedIndex]?.imgSrc),
            },
            nextHistory: nextHistory.slice(0, 16).map((entry, index) => ({
                index,
                type: entry.type,
                entryId: entry.entryId,
                assetName: entry.assetName,
                imgSrcKind: zoomPreviewSrcKind(entry.imgSrc),
            })),
        });
        await prepareZoomDisplayImageForRender(naaZoomGalleryState);
        await renderNaaZoomOverlayContent();
        scheduleZoomGalleryPreviewHydration();

        return true;
    }

    async function handleNaaZoomAction(rootDoc, actionInfo) {
        const action = safeString(actionInfo?.action).trim();
        if (!action || !naaZoomGalleryState) return false;
        const items = Array.isArray(naaZoomGalleryState.items) ? naaZoomGalleryState.items : [];
        if (action === 'regenerate') {
            const liveSizeId = await selectedZoomSizePresetIdFromRoot(rootDoc);
            const persistedSizeId = await persistZoomRegenerateSizeSelection(liveSizeId).catch((error) => {

                return '';
            });

        }
        if (action === 'close') {
            await closeNaaZoomOverlay(rootDoc);
            return true;
        }
        if (action === 'regenerate') {
            await handleZoomRegenerateFromGallery(rootDoc);
            return true;
        }
        if (action === 'set-size') {
            const sizePresetId = normalizeZoomRegenerateSizePresetId(
                actionInfo?.sizePresetId ||
                    htmlFirstAttributeValue(actionInfo?.html, [
                        'x-risu-naa-zoom-size-preset-id',
                        'data-naa-zoom-size-preset-id',
                    ]),
            );
            if (sizePresetId) {
                await persistZoomRegenerateSizeSelection(sizePresetId);
                await renderNaaZoomOverlayContent();
            }
            return true;
        }
        if (action === 'toggle-seed') {
            await handleZoomToggleSeed();
            return true;
        }
        if (action === 'open-tag-tester') {
            await openTagTesterForZoomSelection(rootDoc);
            return true;
        }
        if (action === 'save-history-to-tag-tester') {
            if (naaZoomGalleryState.tagTesterSaveState === 'saving') return true;
            naaZoomGalleryState = {
                ...naaZoomGalleryState,
                tagTesterSaveState: 'saving',
                tagTesterSaveMessage: '',
            };
            await renderNaaZoomOverlayContent();
            try {
                const saved = await saveSelectedZoomHistoryImageToTagTesterFolder();
                if (naaZoomGalleryState) {
                    naaZoomGalleryState = {
                        ...naaZoomGalleryState,
                        tagTesterSaveState: 'done',
                        tagTesterSaveMessage: `Tag saved: ${safeString(saved?.fileName || saved?.path || '').trim()}`,
                    };
                    await renderNaaZoomOverlayContent();
                }
            } catch (error) {
                const message = error?.message || String(error);

                if (naaZoomGalleryState) {
                    naaZoomGalleryState = {
                        ...naaZoomGalleryState,
                        tagTesterSaveState: 'error',
                        tagTesterSaveMessage: `Tag save failed: ${message}`,
                    };
                    await renderNaaZoomOverlayContent();
                }
            }
            return true;
        }
        if (action === 'toggle-prompt-panel') {
            naaZoomGalleryState.promptPanelOpen = !Boolean(naaZoomGalleryState.promptPanelOpen);
            await renderNaaZoomOverlayContent();
            return true;
        }
        if (action === 'delete-history-asset') {
            if (naaZoomGalleryState.deleteHistoryAssetState === 'deleting') return true;
            naaZoomGalleryState = {
                ...naaZoomGalleryState,
                deleteHistoryAssetState: 'deleting',
            };
            await renderNaaZoomOverlayContent();
            try {
                const deleted = await deleteZoomHistoryAsset(rootDoc);
                if (!deleted && naaZoomGalleryState) {
                    naaZoomGalleryState = {
                        ...naaZoomGalleryState,
                        deleteHistoryAssetState: '',
                    };
                    await renderNaaZoomOverlayContent();
                }
            } catch (error) {

            } finally {
                if (naaZoomGalleryState?.deleteHistoryAssetState === 'deleting') {
                    naaZoomGalleryState = {
                        ...naaZoomGalleryState,
                        deleteHistoryAssetState: '',
                    };
                    await renderNaaZoomOverlayContent();
                }
            }
            return true;
        }
        if (action === 'prev-history' || action === 'next-history') {
            await cycleZoomHistoryPreview(action);
            return true;
        }
        if (action === 'prev' || action === 'next') {
            if (!items.length) return true;
            const delta = action === 'next' ? 1 : -1;
            naaZoomGalleryState.selectedIndex =
                (intBetween(naaZoomGalleryState.selectedIndex, 0, 0, items.length - 1) +
                    delta +
                    items.length) %
                items.length;
            naaZoomGalleryState.view = 'current';
            naaZoomGalleryState.historyIndex = -1;
            naaZoomGalleryState.renderOnlyHistoryPreview = false;
            naaZoomGalleryState.renderedHistoryEntryId = '';
            naaZoomGalleryState.persistentSelectedAssetName = '';
            naaZoomGalleryState.persistentSlotId = '';
            naaZoomGalleryState.regenerateState = 'idle';
            naaZoomGalleryState.regenerateMessage = '';
            await prepareZoomDisplayImageForRender(naaZoomGalleryState);
            await renderNaaZoomOverlayContent();
            scheduleZoomGalleryPreviewHydration();
            return true;
        }
        if (action === 'select-gallery') {
            const index = intBetween(actionInfo.index, 0, 0, Math.max(items.length - 1, 0));
            naaZoomGalleryState.selectedIndex = index;
            naaZoomGalleryState.view = 'current';
            naaZoomGalleryState.historyIndex = -1;
            naaZoomGalleryState.renderOnlyHistoryPreview = false;
            naaZoomGalleryState.renderedHistoryEntryId = '';
            naaZoomGalleryState.persistentSelectedAssetName = '';
            naaZoomGalleryState.persistentSlotId = '';
            naaZoomGalleryState.regenerateState = 'idle';
            naaZoomGalleryState.regenerateMessage = '';
            await prepareZoomDisplayImageForRender(naaZoomGalleryState);
            await renderNaaZoomOverlayContent();
            scheduleZoomGalleryPreviewHydration();
            return true;
        }
        if (action === 'select-history') {
            await selectZoomHistoryPreview(actionInfo.index);
            scheduleZoomGalleryPreviewHydration();
            return true;
        }
        return false;
    }

    async function hasGlobalAssetsMarker(rootDoc) {
        try {
            return Boolean(
                await rootDoc.querySelector(
                    `[x-naa-global-assets="${NAA_GLOBAL_ASSETS_MARKER_VALUE}"]`,
                ),
            );
        } catch (_) {
            return false;
        }
    }

    async function markGlobalAssetsInjected(rootDoc, body) {
        try {
            const marker = await rootDoc.createElement('span');
            await marker.setAttribute('x-naa-global-assets', NAA_GLOBAL_ASSETS_MARKER_VALUE);
            await marker.setStyleAttribute('display:none!important');
            await body.appendChild(marker);
        } catch (error) {

        }
    }

    async function migrateLegacyChatRegenerateClasses(rootDoc) {
        try {
            const controls = await rootDoc.querySelectorAll(
                '.naa-chat-regenerate-action, .x-risu-naa-chat-regenerate-action',
            );
            const len = await controls.length();
            for (let i = 0; i < len; i++) {
                const control = await controls.at(i);
                const html = await control.getOuterHTML();
                const isRegenerate =
                    /\bnaa-chat-regenerate-action\b/.test(html) ||
                    /\bx-risu-naa-chat-regenerate-action\b/.test(html);
                await control.removeClass('naa-chat-regenerate-action');
                await control.removeClass('x-risu-naa-chat-regenerate-action');
                if (isRegenerate) {
                    await control.addClass('naa-chat-regenerate-button');
                    await control.addClass('x-risu-naa-chat-regenerate-button');
                }
            }
        } catch (error) {

        }
    }

    async function bindZoomRegenerateSizeChangeListener(rootDoc) {
        try {
            await rootDoc.addEventListener('change', async function (event) {
                if (!isActivePluginInstance() || !naaZoomOverlayRef) return;
                try {
                    const target = event?.target;
                    const select = target?.closest?.('[data-naa-zoom-regenerate-size]');
                    if (!select) return;
                    const selectedSizeId = selectedZoomSizePresetIdFromSelectElement(select);
                    const persistedSizeId = await persistZoomRegenerateSizeSelection(selectedSizeId);

                } catch (error) {

                }
            });
        } catch (error) {

        }
    }

    function pluginEntryButtonName() {
        return IS_DEV_LOADER_INSTANCE ? 'Asset Mommy (Dev)' : 'Asset Mommy';
    }

    async function patchRisuRootEntryIconNode(rootDoc, node, reason = '') {
        if (!rootDoc || !node) return false;
        try {
            const html = safeString(await node.getOuterHTML());
            if (!html || html.includes('data-naa-root-entry-icon')) return false;
            if (html.includes('x-naa-root-entry-icon')) return false;
            if (!html.includes('Asset Mommy')) return false;
            const icon = await rootDoc.createElement('span');
            await icon.setAttribute('x-naa-root-entry-icon', reason || 'plugin-list');
            await icon.setStyleAttribute(
                'display:inline-grid;place-items:center;width:1.25em;height:1.25em;flex:0 0 auto;margin-right:2px;align-self:center;line-height:0;',
            );
            await icon.setInnerHTML(ROOT_ENTRY_ICON_HTML);
            await node.prepend(icon);
            return true;
        } catch (_) {
            return false;
        }
    }

    async function patchRisuRootEntryIcons(reason = '') {
        if (typeof Risu.getRootDocument !== 'function') return 0;
        try {
            const rootDoc = await Risu.getRootDocument();
            const pluginListSelector = '[aria-labelledby="show-params"][role="button"]';
            const nodes = await rootDoc.querySelectorAll(pluginListSelector);
            const len = await nodes.length();
            let patched = 0;
            for (let i = 0; i < len; i++) {
                const node = await nodes.at(i);
                if (await patchRisuRootEntryIconNode(rootDoc, node, 'plugin-list')) patched += 1;
            }
            return patched;
        } catch (_) {
            return 0;
        }
    }

    function scheduleRisuRootEntryIconPatch(reason = '', delay = 80, retries = 4) {
        if (risuRootEntryIconPatchTimer) clearTimeout(risuRootEntryIconPatchTimer);
        risuRootEntryIconPatchTimer = setTimeout(() => {
            risuRootEntryIconPatchTimer = null;
            void (async () => {
                await patchRisuRootEntryIcons(reason);
                if (retries > 0 && isActivePluginInstance()) {
                    scheduleRisuRootEntryIconPatch(
                        reason,
                        Math.min(Math.max(delay, 40) * 2, 500),
                        retries - 1,
                    );
                }
            })();
        }, Math.max(0, delay));
    }

    async function ensureGlobalAssets() {
        if (typeof Risu.getRootDocument !== 'function') {

            return;
        }
        try {
            const rootDoc = await Risu.getRootDocument();
            if (naaGlobalAssetsInjected && (await hasGlobalAssetsMarker(rootDoc))) {
                scheduleRisuRootEntryIconPatch('global-assets');
                startGeneratedChatImageHydrationLoop();
                scheduleGeneratedChatImageHydration('global-assets-existing', 30);
                return;
            }
            naaGlobalAssetsInjected = false;
            const body = await rootDoc.querySelector('body');
            if (!body) {

                return;
            }
            const style = await rootDoc.createElement('style');
            await style.setTextContent(NAA_GLOBAL_CSS);
            await body.appendChild(style);

            await migrateLegacyChatRegenerateClasses(rootDoc);
            try {
                await rootDoc.addEventListener('mousedown', async function (event) {
                    if (!isActivePluginInstance()) return;
                    try {
                        const x = Number(event.clientX);
                        const y = Number(event.clientY);
                        if (
                            (await eventHasNaaZoomSuppressedTarget(event)) ||
                            (await hasNaaZoomSuppressedHitTargetAtPoint(rootDoc, x, y))
                        ) {
                            naaZoomPointerDown = null;
                            rememberNaaZoomSuppressedPointerDown(x, y);
                            return;
                        }
                        naaZoomSuppressedPointerDown = null;
                        const clickedHtml = await findNaaZoomableHtmlAtPoint(rootDoc, x, y);
                        naaZoomPointerDown = clickedHtml
                            ? { x, y, at: Date.now(), html: clickedHtml }
                            : null;
                    } catch (_) {
                        naaZoomPointerDown = null;
                    }
                });
                await rootDoc.addEventListener('scroll', function () {
                    if (!isActivePluginInstance()) return;
                    invalidateZoomHitTestCache();
                    scheduleGeneratedChatImageHydration('scroll', 80);
                    scheduleRisuRootEntryIconPatch('root-scroll', 120);
                });
                await bindZoomRegenerateSizeChangeListener(rootDoc);
                await rootDoc.addEventListener('click', async function (event) {
                    if (!isActivePluginInstance()) return;
                    scheduleRisuRootEntryIconPatch('root-click');
                    try {
                        const x = Number(event.clientX);
                        const y = Number(event.clientY);
                        if (naaZoomOverlayRef) {
                            const zoomCloseAction = await findNaaZoomCloseActionAtPoint(
                                rootDoc,
                                x,
                                y,
                            );
                            if (zoomCloseAction) {
                                await closeNaaZoomOverlay(rootDoc);
                                return;
                            }
                            const zoomAction = await findNaaZoomActionAtPoint(rootDoc, x, y);
                            if (zoomAction) {
                                await handleNaaZoomAction(rootDoc, zoomAction);
                                return;
                            }
                            if (await hasNaaZoomControlAtPoint(rootDoc, x, y)) {
                                invalidateZoomOverlayHitTestCache();
                                return;
                            }
                            return;
                        }
                        const manualGenerateAction = await findNaaManualGenerateActionAtPoint(
                            rootDoc,
                            x,
                            y,
                        );
                        if (manualGenerateAction) {
                            naaZoomPointerDown = null;
                            event.preventDefault?.();
                            event.stopPropagation?.();
                            event.stopImmediatePropagation?.();
                            await handleNaaManualGenerateAction(rootDoc, manualGenerateAction);
                            return;
                        }
                        const chatHistoryAction = await findNaaChatHistoryActionAtPoint(
                            rootDoc,
                            x,
                            y,
                        );
                        if (chatHistoryAction) {
                            naaZoomPointerDown = null;
                            event.preventDefault?.();
                            event.stopPropagation?.();
                            event.stopImmediatePropagation?.();
                            recordZoomDebugEntry(
                                'chat-history-dispatch',
                                'Chat history button hit-test matched.',
                                {
                                    action: chatHistoryAction.action,
                                    assetName: chatHistoryAction.assetName,
                                    slotId: chatHistoryAction.slotId,
                                    entryId: chatHistoryAction.entryId,
                                    html: zoomDebugHtmlImageSummary(chatHistoryAction.html),
                                },
                            );
                            const handled = await handleNaaChatHistoryAction(
                                rootDoc,
                                chatHistoryAction,
                            );
                            recordZoomDebugEntry(
                                'chat-history-dispatch-result',
                                'Chat history button handler returned.',
                                {
                                    handled,
                                    action: chatHistoryAction.action,
                                    assetName: chatHistoryAction.assetName,
                                    slotId: chatHistoryAction.slotId,
                                    entryId: chatHistoryAction.entryId,
                                },
                            );
                            return;
                        }
                        const chatRegenerateAction = await findNaaChatRegenerateActionAtPoint(
                            rootDoc,
                            x,
                            y,
                        );
                        if (chatRegenerateAction) {
                            naaZoomPointerDown = null;
                            event.preventDefault?.();
                            event.stopPropagation?.();
                            event.stopImmediatePropagation?.();
                            await handleNaaChatRegenerateAction(rootDoc, chatRegenerateAction);
                            return;
                        }
                        if (consumeNaaZoomSuppressedPointerClick(x, y)) {
                            naaZoomPointerDown = null;
                            return;
                        }
                        if (
                            (await eventHasNaaZoomSuppressedTarget(event)) ||
                            (await hasNaaZoomSuppressedHitTargetAtPoint(rootDoc, x, y))
                        ) {
                            naaZoomPointerDown = null;
                            return;
                        }
                        const pointerDown = naaZoomPointerDown;
                        naaZoomPointerDown = null;
                        if (
                            !pointerDown ||
                            Date.now() - pointerDown.at > 800 ||
                            Math.abs(pointerDown.x - x) > 8 ||
                            Math.abs(pointerDown.y - y) > 8
                        ) {
                            return;
                        }
                        const clickedHtml = pointerDown.html;
                        if (!clickedHtml) return;
                        const srcMatch = /src\s*=\s*"([^"]+)"/.exec(clickedHtml);
                        if (!srcMatch || !srcMatch[1]) return;
                        const imgSrc = srcMatch[1];
                        const assetName =
                            htmlFirstAttributeValue(clickedHtml, [
                                'x-risu-naa-asset',
                                'data-naa-asset',
                            ]) || rawAssetNameFromImageSrc(imgSrc);
                        if (!assetName) return;
                        await openNaaZoomOverlayInPluginContainer(
                            rootDoc,
                            clickedHtml,
                            imgSrc,
                            assetName,
                        );
                    } catch (zoomErr) {

                    }
                });

                await markGlobalAssetsInjected(rootDoc, body);
                naaGlobalAssetsInjected = true;
                scheduleRisuRootEntryIconPatch('global-assets');
                startGeneratedChatImageHydrationLoop();
                scheduleGeneratedChatImageHydration('global-assets-injected', 30);
            } catch (evErr) {

            }
        } catch (err) {

        }
    }

    async function ensureStreamImageGuardStyle() {
        if (streamImageGuardStyleElement && streamImageGuardBodyElement) return true;
        if (typeof Risu.getRootDocument !== 'function') return false;
        const rootDoc = await Risu.getRootDocument();
        const body = await rootDoc.querySelector('body');
        if (!body) return false;
        const style = await rootDoc.createElement('style');
        await style.setTextContent(STREAM_IMAGE_GUARD_STYLE);
        await body.appendChild(style);
        streamImageGuardStyleElement = style;
        streamImageGuardBodyElement = body;
        return true;
    }

    async function setStreamImageGuardActive(active) {
        if (!(await ensureStreamImageGuardStyle())) return;
        if (streamImageGuardActive === active) return;
        streamImageGuardActive = active;
        try {
            if (active) await streamImageGuardBodyElement.addClass('naa-stream-image-guard-active');
            else await streamImageGuardBodyElement.removeClass('naa-stream-image-guard-active');
        } catch (_) {}
    }

    async function cleanupStreamImageGuard() {
        streamImageGuardActive = false;
        try {
            if (streamImageGuardBodyElement)
                await streamImageGuardBodyElement.removeClass('naa-stream-image-guard-active');
        } catch (_) {}
        try {
            if (streamImageGuardStyleElement) await streamImageGuardStyleElement.remove();
        } catch (_) {}
        streamImageGuardStyleElement = null;
        streamImageGuardBodyElement = null;
    }

    async function pollStreamStateOnce() {
        if (!isPluginRuntimeEnabled()) {
            await setStreamImageGuardActive(false);
            return;
        }
        const latest = await getLatestCurrentCharacterMessage();
        if (!latest) {
            await setStreamImageGuardActive(false);
            lastStreamPollWasStreaming = false;
            lastStreamPollKey = '';
            return;
        }
        const key = `${latest.charIndex}:${latest.chatIndex}`;
        const isStreaming = Boolean(latest.chat?.isStreaming);
        const hasPendingImageTokens = pendingOutputImageTokens.has(key);
        await setStreamImageGuardActive(isStreaming || hasPendingImageTokens);
        if (!isStreaming && lastStreamPollWasStreaming && key === lastStreamPollKey) {
            scheduleOutputFinalProcessing('stream-poll-finished');
        }
        lastStreamPollWasStreaming = isStreaming;
        lastStreamPollKey = key;
    }

    function startStreamStateMonitor() {
        if (streamStatePollTimer) return;
        streamStatePollTimer = setInterval(() => {
            void pollStreamStateOnce().catch((error) => {
                if (isCurrentChatUnavailableError(error)) return;
                const now = Date.now();
                if (now - lastStreamGuardErrorAt < 10000) return;
                lastStreamGuardErrorAt = now;

            });
        }, 400);
        void pollStreamStateOnce().catch(() => {});
    }

    async function stopStreamStateMonitor() {
        if (streamStatePollTimer) {
            clearInterval(streamStatePollTimer);
            streamStatePollTimer = null;
        }
        await cleanupStreamImageGuard();
    }

    function findLatestRuntimeMessage(chat) {
        const messages = Array.isArray(chat?.message) ? chat.message : [];
        for (let index = messages.length - 1; index >= 0; index--) {
            const message = messages[index];
            if (safeString(message?.role).toLowerCase() === 'char') return message;
        }
        return null;
    }

    async function buildCurrentContext(responseText, modelType, latest = null) {
        const markerStrippedResponseText = stripImageTokenMarkers(responseText);
        const charIndex = Number.isInteger(latest?.charIndex)
            ? latest.charIndex
            : await getSafeCurrentCharacterIndex();
        const chatIndex = Number.isInteger(latest?.chatIndex)
            ? latest.chatIndex
            : await getSafeCurrentChatIndex();
        const messageIndex = Number.isInteger(latest?.messageIndex) ? latest.messageIndex : -1;
        const character =
            latest?.character ||
            (charIndex >= 0 && typeof Risu.getCharacterFromIndex === 'function'
                ? await Risu.getCharacterFromIndex(charIndex)
                : typeof Risu.getCharacter === 'function'
                  ? await Risu.getCharacter()
                  : null);
        const chat =
            latest?.chat ||
            (charIndex >= 0 && chatIndex >= 0 && typeof Risu.getChatFromIndex === 'function'
                ? await Risu.getChatFromIndex(charIndex, chatIndex)
                : null);
        const runtimeMessage = latest?.message || findLatestRuntimeMessage(chat);
        const chatroomId = getCharacterId(character, charIndex);
        const chatroomName = getCharacterName(character, '');
        const chatroomType = safeString(character?.type || 'character') || 'character';
        const speakerId = safeString(
            runtimeMessage?.saying || (chatroomType !== 'group' ? chatroomId : ''),
        ).trim();
        const assets = Array.isArray(character?.additionalAssets)
            ? character.additionalAssets
                  .map((asset) => ({
                      name: safeString(asset?.[0]),
                      ext: safeString(asset?.[2] || safeString(asset?.[1]).split('.').pop()),
                  }))
                  .filter((asset) => asset.name)
            : [];
        const customImageTokenDetectors = buildCharxRegexImageTokenDetectors(
            character,
            getCharacterPromptConfig().charxAssetRegexAnalysis,
        );
        const splitResponse = splitPreCheckBlock(markerStrippedResponseText);
        const latestAssistantResponse = splitResponse.displayText || safeString(markerStrippedResponseText);
        const focusedTurnMessages = focusedTurnMessagesForAnalyzer(
            chat?.message || [],
            messageIndex,
            latestAssistantResponse,
        );
        const allImageTokens = extractImageTokens(responseText, { customImageTokenDetectors });
        const activeModuleAssetTokens = await loadActiveModuleAssetTokenSet();
        const moduleImageTokens = allImageTokens
            .filter(isProcessableImageToken)
            .filter((token) => imageTokenMatchesActiveModuleAsset(token, activeModuleAssetTokens));
        const imageTokens = filterPluginProcessableImageTokens(
            allImageTokens,
            activeModuleAssetTokens,
        );
        return {
            responseText: latestAssistantResponse,
            rawResponseText: safeString(markerStrippedResponseText),
            preCheck: splitResponse.preCheck,
            modelType: safeString(modelType),
            chatKey: currentChatKey(character, charIndex, chatIndex, chat),
            charIndex,
            chatIndex,
            messageIndex,
            characterId: chatroomId,
            characterName: chatroomName,
            chatroomId,
            chatroomName,
            chatroomType,
            speakerId,
            speakerName: '',
            characterDescription: safeString(
                character?.description || character?.desc || character?.data?.description || '',
            ).slice(0, 2000),
            previousAssistantResponse: focusedTurnMessages.previousAssistantResponse,
            currentUserInput: focusedTurnMessages.currentUserInput,
            characterIdentityPrompts: getActiveIdentityPrompts().map((item) => item.prompt),
            selectedLorebookPrompts: getActiveIdentityPrompts(),
            imageTokens,
            moduleImageTokens,
            activeModuleAssetTokens,
            customImageTokenDetectors,
            assets,
        };
    }

