    function encodeNaaOriginal(markup) {
        const text = safeString(markup);
        if (!text) return '';
        try {
            if (typeof btoa === 'function') {
                return `naa-b64:${btoa(encodeURIComponent(text))
                    .replace(/\+/g, '-')
                    .replace(/\//g, '_')
                    .replace(/=+$/g, '')}`;
            }
        } catch (_) {}
        return text
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function decodeNaaOriginal(encoded) {
        const text = safeString(encoded);
        if (text.startsWith('naa-b64:')) {
            try {
                const body = text
                    .slice('naa-b64:'.length)
                    .replace(/-/g, '+')
                    .replace(/_/g, '/');
                const padded = `${body}${'='.repeat((4 - (body.length % 4)) % 4)}`;
                if (typeof atob === 'function') return decodeURIComponent(atob(padded));
            } catch (_) {}
        }
        return text
            .replace(/&quot;/g, '"')
            .replace(/&gt;/g, '>')
            .replace(/&lt;/g, '<')
            .replace(/&amp;/g, '&');
    }

    function imageTokenSlotIdForContext(token = {}, context = {}) {
        const tokenMarkup = safeString(token.full || token.sourceImageMarkup).trim();
        return imageSlotIdFromParts({
            chatKey: context.chatKey,
            sourceImageToken: safeString(token.tokenName || token.sourceImageToken).trim(),
            sourceImageMarkup: tokenMarkup,
            sourceImageMarkerId: imageTokenOccurrenceId(token, token.index),
        });
    }

    function imageTokenStableSourceSlotIdForContext(token = {}, context = {}) {
        const tokenMarkup = safeString(token.full || token.sourceImageMarkup).trim();
        return imageSlotIdFromParts({
            chatKey: context.chatKey,
            sourceImageToken: safeString(token.tokenName || token.sourceImageToken).trim(),
            sourceImageMarkup: tokenMarkup,
        });
    }

    function manualGenerationTargetSlotMatchesToken(token = {}, context = {}, targetSlotIds = new Set()) {
        if (!(targetSlotIds instanceof Set) || !targetSlotIds.size) return true;
        const tokenMarkup = safeString(token.full || token.sourceImageMarkup).trim();
        const tokenName = safeString(token.tokenName || token.sourceImageToken).trim();
        const candidateSlotIds = [
            imageTokenSlotIdForContext(token, context),
            imageTokenStableSourceSlotIdForContext(token, context),
            imageSlotIdFromParts({
                sourceImageToken: tokenName,
                sourceImageMarkup: tokenMarkup,
            }),
            imageSlotIdFromParts({
                sourceImageToken: tokenName,
            }),
            imageSlotIdFromParts({
                assetName: tokenName,
            }),
        ].filter(Boolean);
        return candidateSlotIds.some((slotId) => targetSlotIds.has(slotId));
    }

    function imageDecisionSlotIdForContext(decision = {}, context = {}) {
        const sourceImageMarkup = safeString(
            decision.source_image_markup || decision.sourceImageMarkup,
        ).trim();
        return imageSlotIdFromParts({
            chatKey: context.chatKey,
            sourceImageToken: safeString(
                decision.source_image_token ||
                    decision.sourceImageToken ||
                    decision.asset_name ||
                    decision.assetName,
            ).trim(),
            sourceImageMarkup,
            sourceImageMarkerId: safeString(
                decision.source_image_marker_id || decision.sourceImageMarkerId,
            ).trim(),
        });
    }

    function imageDecisionStableSourceSlotIdForContext(decision = {}, context = {}) {
        const sourceImageMarkup = safeString(
            decision.source_image_markup || decision.sourceImageMarkup,
        ).trim();
        return imageSlotIdFromParts({
            chatKey: context.chatKey,
            sourceImageToken: safeString(
                decision.source_image_token ||
                    decision.sourceImageToken ||
                    decision.asset_name ||
                    decision.assetName,
            ).trim(),
            sourceImageMarkup,
        });
    }

    function wrapRemainingCharxTokens(content, onWrap, useLoading, options = {}) {
        const text = safeString(content);
        const matches = extractImageTokens(text, options)
            .filter(isProcessableImageToken)
            .filter((token) => !imageTokenMatchesActiveModuleAsset(token, options.moduleAssetTokens));
        if (!matches.length) return text;
        const manualGenerationDisabledSlotIds =
            options.manualGenerationDisabledSlotIds instanceof Set
                ? options.manualGenerationDisabledSlotIds
                : new Set(
                      (Array.isArray(options.manualGenerationDisabledSlotIds)
                          ? options.manualGenerationDisabledSlotIds
                          : []
                      )
                          .map((slotId) => safeString(slotId).trim())
                          .filter(Boolean),
                  );
        let output = '';
        let lastIndex = 0;
        for (const token of matches) {
            if (token.offset < lastIndex) continue;
            const full = safeString(token.full);
            const tokenName = safeString(token.tokenName).trim();
            if (!tokenName) continue;
            const slotId = imageTokenSlotIdForContext(token, options);
            const stableSourceSlotId = imageTokenStableSourceSlotIdForContext(token, options);
            const shouldApplyLorebookImageFilter =
                Boolean(options.manualGeneration) ||
                Boolean(options.skipExcludedLorebookImageTokens);
            const lorebookImageFilterDecision = shouldApplyLorebookImageFilter
                ? lorebookImageFilterDecisionForAsset(tokenName, options.lorebookImageFilter)
                : 'unknown';
            const skipExcludedLorebookImageToken =
                Boolean(options.skipExcludedLorebookImageTokens) &&
                lorebookImageFilterDecision === 'excluded';
            output += text.slice(lastIndex, token.offset);
            const manualGenerationDisabled =
                (Boolean(slotId) && manualGenerationDisabledSlotIds.has(slotId)) ||
                (Boolean(stableSourceSlotId) &&
                    manualGenerationDisabledSlotIds.has(stableSourceSlotId)) ||
                lorebookImageFilterDecision === 'excluded';
            const originalForToken = reverseAssetMap.get(tokenName);
            const effectiveOriginal = originalForToken || full;
            if (typeof onWrap === 'function') onWrap(tokenName, effectiveOriginal);
            output += skipExcludedLorebookImageToken
                ? originalDisplayAssetHtmlTemplate(tokenName, effectiveOriginal, {
                      chatKey: options.chatKey,
                      sourceImageToken: tokenName,
                      sourceImageMarkup: effectiveOriginal,
                      sourceImageMarkerId: imageTokenOccurrenceId(token, token.index),
                      suppressChatControls: true,
                  })
                : options.manualGeneration
                ? manualOriginalAssetHtmlTemplate(tokenName, effectiveOriginal, {
                      ...options.manualMeta,
                      slotId,
                      chatKey: options.chatKey,
                      sourceImageToken: tokenName,
                      sourceImageMarkup: effectiveOriginal,
                      sourceImageMarkerId: imageTokenOccurrenceId(token, token.index),
                      manualGenerationDisabled,
                      lorebookImageFilterDecision,
                      manualImageCount: matches.length,
                  })
                : useLoading
                  ? originalAssetHtmlTemplate(tokenName, effectiveOriginal)
                  : generatedAssetHtmlTemplate(tokenName, effectiveOriginal);
            lastIndex = token.offset + full.length;
        }
        output += text.slice(lastIndex);
        return output;
    }

    function chatImageFrameStyle(ratioWidth, ratioHeight) {
        const width = intBetween(ratioWidth, DEFAULT_CONFIG.novelai.width, 1, 8192);
        const height = intBetween(ratioHeight, DEFAULT_CONFIG.novelai.height, 1, 8192);
        const longSide = Math.max(width, height);
        const frameBaseSize = height > width ? 680 : 760;
        const frameWidth = Math.round((frameBaseSize * longSide) / height);
        const frameMaxHeight = Math.round((frameBaseSize * longSide) / width);
        return `display:grid;place-items:center;position:relative;width:${frameWidth}px;aspect-ratio:${width}/${height};max-width:100%;max-height:${frameMaxHeight}px;overflow:visible;vertical-align:top;line-height:0;`;
    }

    function generatedImageFrameStyle(ratioWidth, ratioHeight) {
        return chatImageFrameStyle(ratioWidth, ratioHeight);
    }

    function generatedImageElementStyle() {
        return 'display:block;width:100%;height:100%;max-width:100%;max-height:100%;object-fit:contain;margin:0;padding:0;border:0;border-radius:8px;vertical-align:top;background:transparent;';
    }

    function originalImageFrameStyle(ratioWidth, ratioHeight) {
        return chatImageFrameStyle(ratioWidth, ratioHeight);
    }

    function originalNaturalImageFrameStyle() {
        return 'display:inline-grid;place-items:center;position:relative;width:auto;max-width:100%;max-height:min(980px,80vh);overflow:visible;vertical-align:top;line-height:0;';
    }

    function originalImageElementStyle(options = {}) {
        if (options?.natural) {
            return 'display:block;width:auto;height:auto;max-width:100%;max-height:min(980px,80vh);object-fit:contain;margin:0;padding:0;border:0;border-radius:8px;vertical-align:top;background:transparent;';
        }
        return 'display:block;width:100%;height:100%;max-width:100%;max-height:100%;object-fit:contain;margin:0;padding:0;border:0;border-radius:8px;vertical-align:top;background:transparent;';
    }

    function originalAssetHtmlTemplate(assetName, originalMarkup) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        const origAttr = originalMarkup
            ? ` data-naa-original="${encodeNaaOriginal(originalMarkup)}"`
            : '';
        const ratioWidth = DEFAULT_CONFIG.novelai.width;
        const ratioHeight = DEFAULT_CONFIG.novelai.height;
        const frameStyle = generatedImageFrameStyle(ratioWidth, ratioHeight);
        const imageStyle = generatedImageElementStyle();
        const inlineSpinner = `<svg class="naa-loading-spinner" style="position:absolute;right:-46px;top:0;display:block;width:34px;height:34px;pointer-events:none;filter:drop-shadow(0 8px 18px rgba(0,0,0,.45));" width="34" height="34" viewBox="0 0 44 44" xmlns="http://www.w3.org/2000/svg" aria-label="Generating image"><circle cx="22" cy="22" r="18" fill="none" stroke="rgba(255,255,255,0.22)" stroke-width="4"/><circle cx="22" cy="22" r="18" fill="none" stroke="#fff" stroke-width="4" stroke-dasharray="28 85" stroke-linecap="round"/></svg>`;
        return `<div class="naa-generated-image naa-loading-image" style="display:flex;justify-content:center;align-items:center;margin:14px auto;width:70%;max-width:70%;box-sizing:border-box;overflow:visible;border-radius:8px;background:transparent;"${origAttr}><span class="naa-generated-image-frame naa-loading-image-frame" style="${frameStyle}"><img class="naa-generated-image__img" alt="" loading="lazy" decoding="async" src="${escapeHtml(rawAssetImageSrc(cleanAssetName))}" width="${ratioWidth}" height="${ratioHeight}" style="${imageStyle}">${inlineSpinner}</span></div>`;
    }

    function loadingSpinnerHtml() {
        return `<svg class="naa-loading-spinner" style="position:absolute;right:-46px;top:0;display:block;width:34px;height:34px;pointer-events:none;filter:drop-shadow(0 8px 18px rgba(0,0,0,.45));" width="34" height="34" viewBox="0 0 44 44" xmlns="http://www.w3.org/2000/svg" aria-label="Generating image"><circle cx="22" cy="22" r="18" fill="none" stroke="rgba(255,255,255,0.22)" stroke-width="4"/><g><animateTransform attributeName="transform" type="rotate" from="0 22 22" to="360 22 22" dur="0.75s" repeatCount="indefinite"/><circle cx="22" cy="22" r="18" fill="none" stroke="#fff" stroke-width="4" stroke-dasharray="28 85" stroke-linecap="round"/></g></svg>`;
    }
    function chatRegenerateControlHtmlForGeneratedAsset(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName).trim();
        if (!cleanAssetName || !regenerationPlanFromDisplayMeta(meta)) {
            return '';
        }
        const originalAttr = originalMarkup
            ? ` data-naa-chat-regenerate-original="${encodeNaaOriginal(originalMarkup)}" x-risu-naa-chat-regenerate-original="${encodeNaaOriginal(originalMarkup)}"`
            : '';
        return `<button class="naa-chat-regenerate-button x-risu-naa-chat-regenerate-button" type="button" data-naa-chat-regenerate-action="regenerate" x-risu-naa-chat-regenerate-action="regenerate" data-naa-chat-regenerate-asset="${escapeHtml(cleanAssetName)}" x-risu-naa-chat-regenerate-asset="${escapeHtml(cleanAssetName)}"${originalAttr} aria-label="다른 시드로 재생성" title="다른 시드로 재생성">&#10227;</button>`;
    }

    function chatHistoryNavControlsHtml(assetName = '', slotId = '', renderedEntryId = '') {
        const cleanAssetName = safeString(assetName).trim();
        const cleanSlotId = safeString(slotId).trim();
        const cleanRenderedEntryId = safeString(renderedEntryId).trim();
        const slot = displayAssetSlotForAsset(cleanAssetName, cleanSlotId);
        const items = chatHistoryEntriesForSlot(slot);
        if (!cleanAssetName || !slot || items.length < 2) return '';
        const currentEntry = currentDisplayAssetSlotEntry(slot);
        const currentEntryId = safeString(
            cleanRenderedEntryId || currentEntry?.entryId || slot.currentEntryId,
        ).trim();
        let currentIndex = currentEntryId
            ? items.findIndex((entry) => safeString(entry?.entryId).trim() === currentEntryId)
            : -1;
        if (currentIndex < 0) {
            currentIndex = items.findIndex(
                (entry) => safeString(entry?.assetName).trim() === cleanAssetName,
            );
        }
        if (currentIndex < 0) currentIndex = 0;
        const commonAttrs =
            ` data-naa-chat-history-asset="${escapeHtml(cleanAssetName)}"` +
            ` x-risu-naa-chat-history-asset="${escapeHtml(cleanAssetName)}"` +
            ` data-naa-chat-history-slot-id="${escapeHtml(slot.slotId)}"` +
            ` x-risu-naa-chat-history-slot-id="${escapeHtml(slot.slotId)}"` +
            ` data-naa-chat-history-entry-id="${escapeHtml(currentEntryId)}"` +
            ` x-risu-naa-chat-history-entry-id="${escapeHtml(currentEntryId)}"`;
        return (
            `<span class="naa-chat-history-control-group x-risu-naa-chat-history-control-group" aria-label="image history ${currentIndex + 1}/${items.length}">` +
            `<button class="naa-chat-history-button x-risu-naa-chat-history-button" type="button" data-naa-chat-history-action="prev" x-risu-naa-chat-history-action="prev"${commonAttrs} aria-label="previous image" title="previous image">&#10094;</button>` +
            `<span class="naa-chat-history-count x-risu-naa-chat-history-count">${currentIndex + 1}/${items.length}</span>` +
            `<button class="naa-chat-history-button x-risu-naa-chat-history-button" type="button" data-naa-chat-history-action="next" x-risu-naa-chat-history-action="next"${commonAttrs} aria-label="next image" title="next image">&#10095;</button>` +
            `</span>`
        );
    }

    function chatImageControlsHtml(regenerateControlHtml = '', historyControlsHtml = '') {
        const regenerateHtml = safeString(regenerateControlHtml).trim();
        const historyHtml = safeString(historyControlsHtml).trim();
        if (!regenerateHtml && !historyHtml) return '';
        return (
            `<span class="naa-chat-image-controls x-risu-naa-chat-image-controls">` +
            `${regenerateHtml}${historyHtml}` +
            `</span>`
        );
    }

    function manualImageGenerationControlsHtml(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName).trim();
        const cleanSlotId = safeString(meta.slotId).trim();
        const encodedOriginal = encodeNaaOriginal(originalMarkup);
        const commonAttrs =
            ` data-naa-manual-generate-asset="${escapeHtml(cleanAssetName)}"` +
            ` x-risu-naa-manual-generate-asset="${escapeHtml(cleanAssetName)}"` +
            ` data-naa-manual-generate-slot-id="${escapeHtml(cleanSlotId)}"` +
            ` x-risu-naa-manual-generate-slot-id="${escapeHtml(cleanSlotId)}"` +
            ` data-naa-manual-generate-original="${escapeHtml(encodedOriginal)}"` +
            ` x-risu-naa-manual-generate-original="${escapeHtml(encodedOriginal)}"`;
        return (
            `<span class="naa-manual-generation-controls x-risu-naa-manual-generation-controls">` +
            `<button class="naa-manual-generate-button x-risu-naa-manual-generate-button" type="button" data-naa-manual-generate-action="all" x-risu-naa-manual-generate-action="all"${commonAttrs} aria-label="${escapeHtml(t('manualGenerateAllImages'))}" title="${escapeHtml(t('manualGenerateAllImages'))}">&#10022;</button>` +
            `</span>`
        );
    }

    function manualOriginalAssetHtmlTemplate(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        const effectiveOriginalMarkup = safeString(originalMarkup || meta.sourceImageMarkup).trim();
        const sourceImageToken = safeString(meta.sourceImageToken || cleanAssetName).trim();
        const slotId = imageSlotIdFromParts({
            ...meta,
            assetName: cleanAssetName,
            sourceImageToken,
            sourceImageMarkup: effectiveOriginalMarkup,
        });
        const displayMeta = {
            ...(displayAssetMetaMap.get(cleanAssetName) || {}),
            ...meta,
            assetName: cleanAssetName,
            originalDisplay: true,
            originalDisplayNatural: true,
            sourceImageToken,
            sourceImageMarkup: effectiveOriginalMarkup,
            slotId,
        };
        const originalImgSrc = rawAssetImageSrc(cleanAssetName) || NAA_ZOOM_PLACEHOLDER_IMAGE;
        if (cleanAssetName) {
            displayAssetMetaMap.set(cleanAssetName, displayMeta);
            reverseAssetMap.set(cleanAssetName, effectiveOriginalMarkup);
        }
        ensureDisplayAssetSlotBase(
            {
                ...displayMeta,
                meta: displayMeta,
            },
            {
                currentOriginal: true,
                originalImgSrc,
            },
        );
        const origAttr = effectiveOriginalMarkup
            ? ` data-naa-original="${encodeNaaOriginal(effectiveOriginalMarkup)}"`
            : '';
        const imgMetaAttrs = [
            cleanAssetName
                ? `data-naa-asset="${escapeHtml(cleanAssetName)}" x-risu-naa-asset="${escapeHtml(cleanAssetName)}"`
                : '',
            slotId
                ? `data-naa-slot-id="${escapeHtml(slotId)}" x-risu-naa-slot-id="${escapeHtml(slotId)}"`
                : '',
            'data-naa-original-display="true" x-risu-naa-original-display="true"',
        ]
            .filter(Boolean)
            .join(' ');
        const containerAttrs = [
            imgMetaAttrs,
            'data-naa-manual-image="true" x-risu-naa-manual-image="true"',
            meta.manualGenerationDisabled
                ? 'data-naa-manual-generation-disabled="true" x-risu-naa-manual-generation-disabled="true"'
                : '',
        ]
            .filter(Boolean)
            .join(' ');
        const controlsHtml = meta.manualGenerationDisabled ? '' : manualImageGenerationControlsHtml(
                cleanAssetName,
                effectiveOriginalMarkup,
                {
                    ...displayMeta,
                    manualImageCount: meta.manualImageCount,
                },
            );
        const ratioWidth = DEFAULT_CONFIG.novelai.width;
        const ratioHeight = DEFAULT_CONFIG.novelai.height;
        const frameStyle = generatedImageFrameStyle(ratioWidth, ratioHeight);
        const imageStyle = generatedImageElementStyle();
        return `<div class="naa-generated-image naa-manual-image naa-zoomable" style="display:flex;justify-content:center;align-items:center;margin:14px auto;width:70%;max-width:70%;box-sizing:border-box;overflow:visible;overflow-anchor:none;contain:layout;border-radius:8px;background:transparent;cursor:pointer;"${origAttr} ${containerAttrs}><span class="naa-generated-image-frame naa-manual-image-frame" style="${frameStyle}"><img class="naa-generated-image__img" alt="" loading="lazy" decoding="async" src="${escapeHtml(rawAssetImageSrc(cleanAssetName))}" ${imgMetaAttrs} width="${ratioWidth}" height="${ratioHeight}" style="${imageStyle}">${controlsHtml}</span></div>`;
    }

    function originalDisplayAssetHtmlTemplate(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        const effectiveOriginalMarkup = safeString(originalMarkup || meta.sourceImageMarkup).trim();
        const sourceImageToken = safeString(meta.sourceImageToken || cleanAssetName).trim();
        const slotId = imageSlotIdFromParts({
            ...meta,
            assetName: cleanAssetName,
            sourceImageToken,
            sourceImageMarkup: effectiveOriginalMarkup,
        });
        const originalImgSrc =
            safeString(meta.displaySrc).trim() ||
            rawAssetImageSrc(cleanAssetName) ||
            NAA_ZOOM_PLACEHOLDER_IMAGE;
        const displayMeta = {
            ...(displayAssetMetaMap.get(cleanAssetName) || {}),
            ...meta,
            assetName: cleanAssetName,
            seed: '',
            width: 0,
            height: 0,
            originalDisplay: true,
            originalDisplayNatural: true,
            sourceImageToken,
            sourceImageMarkup: effectiveOriginalMarkup,
            slotId,
            displaySrc: originalImgSrc,
            suppressChatControls: true,
        };
        if (cleanAssetName) {
            displayAssetMetaMap.set(cleanAssetName, displayMeta);
            reverseAssetMap.set(cleanAssetName, effectiveOriginalMarkup);
        }
        ensureDisplayAssetSlotBase(
            {
                ...displayMeta,
                meta: displayMeta,
            },
            {
                currentOriginal: true,
                originalImgSrc,
            },
        );
        return generatedAssetHtmlTemplate(cleanAssetName, effectiveOriginalMarkup, {
            ...displayMeta,
            __naaSkipCurrentSlotRedirect: true,
        });
    }

    function generatedAssetHtmlTemplate(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        const storedMeta = displayAssetMetaMap.get(cleanAssetName) || {};
        let mergedMeta = { ...storedMeta, ...meta };
        let mergedPlan = regenerationPlanFromDisplayMeta(mergedMeta);
        const initialOriginalMarkup = safeString(
            originalMarkup ||
                mergedMeta.sourceImageMarkup ||
                mergedPlan?.sourceImageMarkup ||
                reverseAssetMap.get(cleanAssetName) ||
                '',
        ).trim();
        const slotId = imageSlotIdFromParts({
            ...mergedMeta,
            assetName: cleanAssetName,
            chatKey: mergedMeta.chatKey || mergedPlan?.chatKey,
            sourceImageToken: mergedMeta.sourceImageToken || mergedPlan?.sourceImageToken,
            sourceImageMarkerId: mergedMeta.sourceImageMarkerId || mergedPlan?.sourceImageMarkerId,
            sourceImageMarkup: initialOriginalMarkup,
        });
        mergedMeta = displayMetaWithSlotRegenerationPlan(mergedMeta, slotId);
        mergedPlan = regenerationPlanFromDisplayMeta(mergedMeta);
        const effectiveOriginalMarkup = safeString(
            initialOriginalMarkup ||
                mergedMeta.sourceImageMarkup ||
                mergedPlan?.sourceImageMarkup ||
                '',
        ).trim();
        const slot = displayAssetSlotForAsset(cleanAssetName, slotId);
        const currentEntry = currentDisplayAssetSlotEntry(slot);
        if (
            currentEntry?.assetName &&
            currentEntry.assetName !== cleanAssetName &&
            !mergedMeta.__naaSkipCurrentSlotRedirect
        ) {
            const currentMeta = displayAssetMetaMap.get(currentEntry.assetName) || {};
            return generatedAssetHtmlTemplate(currentEntry.assetName, effectiveOriginalMarkup, {
                ...mergedMeta,
                ...currentMeta,
                assetName: currentEntry.assetName,
                originalDisplay: currentEntry.type === 'original',
                originalDisplayNatural:
                    currentEntry.type === 'original' || Boolean(currentMeta.originalDisplayNatural),
                displaySrc: currentEntry.imgSrc || currentMeta.displaySrc,
                width: currentEntry.type === 'original' ? currentMeta.width : currentEntry.width || currentMeta.width,
                height: currentEntry.type === 'original' ? currentMeta.height : currentEntry.height || currentMeta.height,
                sourceImageMarkup: effectiveOriginalMarkup || slot?.sourceImageMarkup,
                slotId: slot?.slotId || slotId,
                __naaSkipCurrentSlotRedirect: true,
            });
        }
        const origAttr = effectiveOriginalMarkup
            ? ` data-naa-original="${encodeNaaOriginal(effectiveOriginalMarkup)}"`
            : '';
        const cleanSeed = normalizeNovelAISeed(mergedMeta.seed);
        const cleanPromptKey = safeString(
            mergedMeta.promptKey || mergedMeta.lorebookPromptKey,
        ).trim();
        const hasExplicitImageSize =
            Number.isFinite(Number(mergedMeta.width)) &&
            Number(mergedMeta.width) > 0 &&
            Number.isFinite(Number(mergedMeta.height)) &&
            Number(mergedMeta.height) > 0;
        const ratioWidth = intBetween(mergedMeta.width, DEFAULT_CONFIG.novelai.width, 1, 8192);
        const ratioHeight = intBetween(mergedMeta.height, DEFAULT_CONFIG.novelai.height, 1, 8192);
        const originalSourceTokenMatchesAsset =
            safeString(mergedMeta.sourceImageToken).trim() === cleanAssetName;
        const useNaturalOriginalLayout = Boolean(
            mergedMeta.originalDisplay &&
                (mergedMeta.originalDisplayNatural ||
                    originalSourceTokenMatchesAsset ||
                    !hasExplicitImageSize),
        );
        const frameStyle = mergedMeta.originalDisplay
            ? useNaturalOriginalLayout
                ? originalNaturalImageFrameStyle()
                : originalImageFrameStyle(ratioWidth, ratioHeight)
            : generatedImageFrameStyle(ratioWidth, ratioHeight);
        const imageStyle = mergedMeta.originalDisplay
            ? originalImageElementStyle({ natural: useNaturalOriginalLayout })
            : generatedImageElementStyle();
        const originalImgSrc = imageSrcFromOriginalMarkup(effectiveOriginalMarkup);
        const displaySrc = safeString(mergedMeta.displaySrc).trim();
        const renderableDisplaySrc = isRenderableZoomHistoryPreviewSrc(displaySrc)
            ? displaySrc
            : '';
        const rawDisplaySrc = isRawAssetImageSrc(displaySrc) ? displaySrc : '';
        const rawOriginalDisplaySrc =
            mergedMeta.originalDisplay && isRawAssetImageSrc(displaySrc) ? displaySrc : '';
        const renderableOriginalImgSrc = isRenderableZoomHistoryPreviewSrc(originalImgSrc)
            ? originalImgSrc
            : '';
        const rawOriginalImgSrc = isRawAssetImageSrc(originalImgSrc) ? originalImgSrc : '';
        const generatedAssetSrc = chatGeneratedAssetImageSrc(cleanAssetName);
        const originalAssetFallbackSrc =
            mergedMeta.originalDisplay && cleanAssetName ? rawAssetImageSrc(cleanAssetName) : '';
        const preferredDisplaySrc =
            mergedMeta.preferDisplaySrc && renderableDisplaySrc ? renderableDisplaySrc : '';
        const imgSrc =
            (mergedMeta.originalDisplay
                ? preferredDisplaySrc ||
                  rawDisplaySrc ||
                  renderableDisplaySrc ||
                  rawOriginalImgSrc ||
                  rawOriginalDisplaySrc ||
                  renderableOriginalImgSrc ||
                  originalAssetFallbackSrc
                : preferredDisplaySrc || generatedAssetSrc || rawDisplaySrc) ||
            NAA_ZOOM_PLACEHOLDER_IMAGE;
        const regenerateControlHtml = chatRegenerateControlHtmlForGeneratedAsset(
            cleanAssetName,
            effectiveOriginalMarkup,
            mergedMeta,
        );
        const chatHistoryControlsHtml = chatHistoryNavControlsHtml(
            cleanAssetName,
            slotId,
            mergedMeta.renderedEntryId,
        );
        const chatControlsHtml = mergedMeta.suppressChatControls
            ? ''
            : chatImageControlsHtml(regenerateControlHtml, chatHistoryControlsHtml);
        const imgMetaAttrs = [
            cleanAssetName
                ? `data-naa-asset="${escapeHtml(cleanAssetName)}" x-risu-naa-asset="${escapeHtml(cleanAssetName)}"`
                : '',
            cleanSeed
                ? `data-naa-seed="${escapeHtml(cleanSeed)}" x-risu-naa-seed="${escapeHtml(cleanSeed)}"`
                : '',
            cleanPromptKey
                ? `data-naa-prompt-key="${escapeHtml(cleanPromptKey)}" x-risu-naa-prompt-key="${escapeHtml(cleanPromptKey)}"`
                : '',
            mergedMeta.seedFixed ? 'data-naa-seed-fixed="true" x-risu-naa-seed-fixed="true"' : '',
            slotId
                ? `data-naa-slot-id="${escapeHtml(slotId)}" x-risu-naa-slot-id="${escapeHtml(slotId)}"`
                : '',
            locationMetaAttrs(mergedMeta),
        ]
            .filter(Boolean)
            .join(' ');
        const originalDisplayAttr = mergedMeta.originalDisplay
            ? 'data-naa-original-display="true" x-risu-naa-original-display="true"'
            : '';
        const cleanRenderedHistoryEntryId = safeString(mergedMeta.renderedEntryId).trim();
        const cleanPersistentAssetName = safeString(mergedMeta.persistentAssetName).trim();
        const renderedHistoryEntryIdAttr = cleanRenderedHistoryEntryId
            ? `data-naa-rendered-history-entry-id="${escapeHtml(cleanRenderedHistoryEntryId)}" x-risu-naa-rendered-history-entry-id="${escapeHtml(cleanRenderedHistoryEntryId)}"`
            : '';
        const renderOnlyHistoryPreviewAttr = mergedMeta.renderOnlyHistoryPreview
            ? 'data-naa-render-only-history-preview="true" x-risu-naa-render-only-history-preview="true"'
            : '';
        const persistentAssetAttr = cleanPersistentAssetName
            ? `data-naa-persistent-asset="${escapeHtml(cleanPersistentAssetName)}" x-risu-naa-persistent-asset="${escapeHtml(cleanPersistentAssetName)}"`
            : '';
        const containerMetaAttrs = [
            imgMetaAttrs,
            originalDisplayAttr,
            renderedHistoryEntryIdAttr,
            renderOnlyHistoryPreviewAttr,
            persistentAssetAttr,
        ]
            .filter(Boolean)
            .join(' ');
        const containerMetaAttrText = containerMetaAttrs ? ` ${containerMetaAttrs}` : '';
        const imageDimensionAttrs = useNaturalOriginalLayout
            ? ''
            : ` width="${ratioWidth}" height="${ratioHeight}"`;
        if (mergedMeta.originalDisplay) {
            return `<div class="naa-generated-image naa-zoomable" style="display:flex;justify-content:center;align-items:center;margin:14px auto;width:70%;max-width:70%;box-sizing:border-box;overflow:visible;overflow-anchor:none;contain:layout;border-radius:8px;background:transparent;cursor:pointer;"${origAttr}${containerMetaAttrText}><span class="naa-generated-image-frame" style="${frameStyle}"><img class="naa-generated-image__img" alt="" loading="lazy" decoding="async" src="${escapeHtml(imgSrc)}" ${imgMetaAttrs}${imageDimensionAttrs} style="${imageStyle}">${chatControlsHtml}</span></div>`;
        }
        return `<div class="naa-generated-image naa-zoomable" style="display:flex;justify-content:center;align-items:center;margin:14px auto;width:70%;max-width:70%;box-sizing:border-box;overflow:visible;overflow-anchor:none;contain:layout;border-radius:8px;background:transparent;cursor:pointer;"${origAttr}${containerMetaAttrText}><span class="naa-generated-image-frame" style="${frameStyle}"><img class="naa-generated-image__img" alt="" loading="lazy" decoding="async" src="${escapeHtml(imgSrc)}" ${imgMetaAttrs}${imageDimensionAttrs} style="${imageStyle}">${chatControlsHtml}</span></div>`;
    }

    function generatedAssetLoadingHtmlTemplate(assetName, originalMarkup, meta = {}) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        const origAttr = originalMarkup
            ? ` data-naa-original="${encodeNaaOriginal(originalMarkup)}"`
            : '';
        const storedMeta = displayAssetMetaMap.get(cleanAssetName) || {};
        const mergedMeta = { ...storedMeta, ...meta };
        const cleanSeed = normalizeNovelAISeed(mergedMeta.seed);
        const cleanPromptKey = safeString(
            mergedMeta.promptKey || mergedMeta.lorebookPromptKey,
        ).trim();
        const slotId = imageSlotIdFromParts({
            ...mergedMeta,
            assetName: cleanAssetName,
            chatKey: mergedMeta.chatKey || regenerationPlanFromDisplayMeta(mergedMeta)?.chatKey,
            sourceImageMarkup: originalMarkup || mergedMeta.sourceImageMarkup,
        });
        const ratioWidth = intBetween(mergedMeta.width, DEFAULT_CONFIG.novelai.width, 1, 8192);
        const ratioHeight = intBetween(mergedMeta.height, DEFAULT_CONFIG.novelai.height, 1, 8192);
        const useNaturalOriginalLayout = Boolean(mergedMeta.originalDisplayNatural);
        const frameStyle = useNaturalOriginalLayout
            ? originalNaturalImageFrameStyle()
            : generatedImageFrameStyle(ratioWidth, ratioHeight);
        const imageStyle = useNaturalOriginalLayout
            ? originalImageElementStyle({ natural: true })
            : generatedImageElementStyle();
        const imageDimensionAttrs = useNaturalOriginalLayout
            ? ''
            : ` width="${ratioWidth}" height="${ratioHeight}"`;
        const displaySrc = safeString(mergedMeta.displaySrc).trim();
        const imgSrc =
            chatGeneratedAssetImageSrc(cleanAssetName) ||
            (isRawAssetImageSrc(displaySrc) ? displaySrc : '') ||
            NAA_ZOOM_PLACEHOLDER_IMAGE;
        const imgMetaAttrs = [
            cleanAssetName
                ? `data-naa-asset="${escapeHtml(cleanAssetName)}" x-risu-naa-asset="${escapeHtml(cleanAssetName)}"`
                : '',
            cleanSeed
                ? `data-naa-seed="${escapeHtml(cleanSeed)}" x-risu-naa-seed="${escapeHtml(cleanSeed)}"`
                : '',
            cleanPromptKey
                ? `data-naa-prompt-key="${escapeHtml(cleanPromptKey)}" x-risu-naa-prompt-key="${escapeHtml(cleanPromptKey)}"`
                : '',
            mergedMeta.seedFixed ? 'data-naa-seed-fixed="true" x-risu-naa-seed-fixed="true"' : '',
            slotId
                ? `data-naa-slot-id="${escapeHtml(slotId)}" x-risu-naa-slot-id="${escapeHtml(slotId)}"`
                : '',
            locationMetaAttrs(mergedMeta),
        ]
            .filter(Boolean)
            .join(' ');
        const containerMetaAttrs = imgMetaAttrs ? ` ${imgMetaAttrs}` : '';
        return `<div class="naa-generated-image naa-loading-image naa-zoomable" style="display:flex;justify-content:center;align-items:center;margin:14px auto;width:70%;max-width:70%;box-sizing:border-box;overflow:visible;overflow-anchor:none;contain:layout;border-radius:8px;background:transparent;cursor:pointer;"${origAttr}${containerMetaAttrs}><span class="naa-generated-image-frame naa-loading-image-frame" style="${frameStyle}"><img class="naa-generated-image__img" alt="" loading="lazy" decoding="async" src="${escapeHtml(imgSrc)}" ${imgMetaAttrs}${imageDimensionAttrs} style="${imageStyle}">${loadingSpinnerHtml()}</span></div>`;
    }

    function naaGeneratedImageBlockRegex() {
        return /<div\b(?=[^>]*\bclass\s*=\s*(?:"[^"]*(?:x-risu-)?naa-generated-image\b[^"]*"|'[^']*(?:x-risu-)?naa-generated-image\b[^']*'))[\s\S]*?<\/div>/giu;
    }

    function naaLoadingGeneratedImageBlockRegex() {
        return /<div\b(?=[^>]*\bclass\s*=\s*(?:"[^"]*(?:x-risu-)?naa-generated-image\b[^"]*"|'[^']*(?:x-risu-)?naa-generated-image\b[^']*'))(?=[^>]*\bclass\s*=\s*(?:"[^"]*(?:x-risu-)?naa-loading-image\b[^"]*"|'[^']*(?:x-risu-)?naa-loading-image\b[^']*'))[\s\S]*?<\/div>/giu;
    }

    function assetNameFromGeneratedImageHtml(html) {
        const assetName = htmlFirstAttributeValue(html, ['x-risu-naa-asset', 'data-naa-asset']);
        if (assetName) return assetName;
        return rawAssetNameFromImageSrc(htmlFirstAttributeValue(html, ['src']));
    }

    function generatedAssetParserSrcNeedsRepair(src = '') {
        const cleanSrc = safeString(src).trim();
        if (!cleanSrc) return true;
        if (isRawAssetImageSrc(cleanSrc)) return false;
        if (decodeSwImagePathForParser(cleanSrc)) return false;
        return true;
    }

    function repairGeneratedAssetParserSourcesInBlock(block) {
        const cleanBlock = safeString(block);
        const assetName = assetNameFromGeneratedImageHtml(cleanBlock);
        if (!assetName) return cleanBlock;
        const currentSrc = htmlFirstAttributeValue(cleanBlock, ['src']);
        if (!generatedAssetParserSrcNeedsRepair(currentSrc)) return cleanBlock;
        const parserSrc = rawAssetImageSrc(assetName);
        if (!parserSrc) return cleanBlock;
        const imgMatch = /<img\b[^>]*>/i.exec(cleanBlock);
        if (!imgMatch) return cleanBlock;
        const imgTag = imgMatch[0];
        let nextImgTag = /\ssrc\s*=/i.test(imgTag)
            ? imgTag.replace(
                  /\ssrc\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/i,
                  ` src="${escapeHtml(parserSrc)}"`,
              )
            : imgTag.replace(/^<img\b/i, `<img src="${escapeHtml(parserSrc)}"`);
        nextImgTag = nextImgTag.replace(
            /\snoimage(?:\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+))?(?=\s|\/?>)/gi,
            '',
        );
        if (nextImgTag === imgTag) return cleanBlock;
        return `${cleanBlock.slice(0, imgMatch.index)}${nextImgTag}${cleanBlock.slice(
            imgMatch.index + imgTag.length,
        )}`;
    }

    function repairGeneratedAssetParserSourcesInContent(content) {
        return safeString(content).replace(naaGeneratedImageBlockRegex(), (block) =>
            repairGeneratedAssetParserSourcesInBlock(block),
        );
    }

    function slotIdFromGeneratedImageHtml(html) {
        return htmlFirstAttributeValue(html, ['x-risu-naa-slot-id', 'data-naa-slot-id']);
    }

    function stableGeneratedAssetHtmlFromLoadingBlock(block) {
        const originalMarkup = htmlFirstAttributeValue(block, [
            'x-risu-naa-original',
            'data-naa-original',
        ]);
        const assetName = assetNameFromGeneratedImageHtml(block);
        const fallbackOriginal = assetName ? reverseAssetMap.get(assetName) : '';
        if (!assetName) return originalMarkup || '';
        return generatedAssetHtmlTemplate(assetName, originalMarkup || fallbackOriginal);
    }

    function manualGeneratedAssetHtmlFromLoadingBlock(block, meta = {}) {
        const originalMarkup = htmlFirstAttributeValue(block, [
            'x-risu-naa-original',
            'data-naa-original',
        ]);
        const assetName = assetNameFromGeneratedImageHtml(block);
        const fallbackOriginal = assetName ? reverseAssetMap.get(assetName) : '';
        const effectiveOriginal = originalMarkup || fallbackOriginal;
        if (!assetName) return effectiveOriginal || '';
        const slotId = slotIdFromGeneratedImageHtml(block);
        return manualOriginalAssetHtmlTemplate(assetName, effectiveOriginal, {
            ...meta,
            slotId,
            sourceImageToken: assetName,
            sourceImageMarkup: effectiveOriginal,
            manualImageCount: meta.manualImageCount,
        });
    }

    function replaceLoadingGeneratedImagesWithStableAssets(content) {
        return safeString(content).replace(naaLoadingGeneratedImageBlockRegex(), (block) =>
            stableGeneratedAssetHtmlFromLoadingBlock(block),
        );
    }

    function replaceLoadingGeneratedImagesWithManualAssets(content, options = {}) {
        const text = safeString(content);
        const loadingBlocks = text.match(naaLoadingGeneratedImageBlockRegex()) || [];
        return text.replace(naaLoadingGeneratedImageBlockRegex(), (block) =>
            manualGeneratedAssetHtmlFromLoadingBlock(block, {
                ...options,
                manualImageCount: loadingBlocks.length || 1,
            }),
        );
    }

    function rehydrateGeneratedAssetHtmlBlocks(content) {
        const stableContent = replaceLoadingGeneratedImagesWithStableAssets(content);
        return safeString(stableContent).replace(naaGeneratedImageBlockRegex(), (block) => {
            if (/\b(?:data-naa-manual-image|x-risu-naa-manual-image)=["']true["']/.test(block)) {
                return block;
            }
            const assetName = assetNameFromGeneratedImageHtml(block);
            if (!assetName) return block;
            const originalMarkup =
                htmlFirstAttributeValue(block, ['x-risu-naa-original', 'data-naa-original']) ||
                reverseAssetMap.get(assetName) ||
                '';
            const parsedSource = parseSupportedImageMarkup(originalMarkup);
            const storedMeta = displayAssetMetaMap.get(assetName) || {};
            const seed = htmlFirstAttributeValue(block, ['x-risu-naa-seed', 'data-naa-seed']);
            const promptKey = htmlFirstAttributeValue(block, [
                'x-risu-naa-prompt-key',
                'data-naa-prompt-key',
            ]);
            const htmlSlotId = htmlFirstAttributeValue(block, [
                'x-risu-naa-slot-id',
                'data-naa-slot-id',
            ]);
            const htmlLocationMeta = locationMetaFromParts({
                charIndex: htmlIndexAttributeValue(block, [
                    'x-risu-naa-char-index',
                    'data-naa-char-index',
                ]),
                chatIndex: htmlIndexAttributeValue(block, [
                    'x-risu-naa-chat-index',
                    'data-naa-chat-index',
                ]),
                messageIndex: htmlIndexAttributeValue(block, [
                    'x-risu-naa-message-index',
                    'data-naa-message-index',
                ]),
            });
            const sourceImageToken = safeString(
                storedMeta.sourceImageToken ||
                    parsedSource?.tokenName ||
                    rawAssetNameFromImageSrc(imageSrcFromOriginalMarkup(originalMarkup)),
            ).trim();
            const originalDisplayAttr =
                htmlFirstAttributeValue(block, [
                    'x-risu-naa-original-display',
                    'data-naa-original-display',
                ]) === 'true';
            const sourceTokenIsOriginalAsset = Boolean(
                sourceImageToken && sourceImageToken === assetName && !seed,
            );
            const shouldRenderOriginalDisplay =
                originalDisplayAttr || sourceTokenIsOriginalAsset;
            const meta = {
                ...storedMeta,
                seed: normalizeNovelAISeed(seed || storedMeta.seed),
                promptKey: safeString(promptKey || storedMeta.promptKey).trim(),
                originalDisplay: shouldRenderOriginalDisplay,
                originalDisplayNatural: shouldRenderOriginalDisplay,
                sourceImageToken,
                sourceImageMarkup: safeString(
                    storedMeta.sourceImageMarkup || originalMarkup,
                ).trim(),
                ...htmlLocationMeta,
                slotId: imageSlotIdFromParts({
                    ...storedMeta,
                    slotId: htmlSlotId,
                    assetName,
                    sourceImageToken,
                    sourceImageMarkup: storedMeta.sourceImageMarkup || originalMarkup,
                }),
            };
            const slot = meta.originalDisplay
                ? ensureDisplayAssetSlotBase(
                      { ...meta, assetName, sourceImageMarkup: meta.sourceImageMarkup, meta },
                      { currentOriginal: false },
                  )
                : recordGeneratedAssetSlot(assetName, meta, meta.sourceImageMarkup, {
                      current: false,
                      imgSrc: cachedImageTokenPreviewUrl(assetName) || rawAssetImageSrc(assetName),
                  });
            const currentEntry = slot?.entries.find(
                (entry) => entry.entryId === slot.currentEntryId,
            );
            const anchorEntryId = shouldRenderOriginalDisplay
                ? displayAssetSlotOriginalEntryId(slot?.slotId || meta.slotId)
                : displayAssetSlotGeneratedEntryId(assetName);

            if (
                meta.sourceImageMarkup ||
                meta.sourceImageToken ||
                meta.regenerationPlan ||
                meta.slotId ||
                meta.originalDisplay
            ) {
                displayAssetMetaMap.set(assetName, meta);
            }
            return generatedAssetHtmlTemplate(assetName, originalMarkup, meta);
        });
    }

    async function repairLegacyGeneratedChatParserSources(reason = '', probeItems = []) {
        if (
            typeof Risu.getChatFromIndex !== 'function' ||
            typeof Risu.setChatToIndex !== 'function'
        ) {
            return;
        }
        const targets = [];
        const seen = new Set();
        for (const item of Array.isArray(probeItems) ? probeItems : []) {
            const assetName = safeString(item?.assetName).trim();
            const charIndex = nonNegativeIntegerOr(item?.charIndex, -1);
            const chatIndex = nonNegativeIntegerOr(item?.chatIndex, -1);
            const messageIndex = nonNegativeIntegerOr(item?.messageIndex, -1);
            if (!assetName || charIndex < 0 || chatIndex < 0 || messageIndex < 0) continue;
            if (!generatedAssetParserSrcNeedsRepair(item?.srcValue || item?.srcPrefix)) continue;
            const key = `${charIndex}:${chatIndex}:${messageIndex}`;
            if (seen.has(key)) continue;
            seen.add(key);
            targets.push({ charIndex, chatIndex, messageIndex, assetName });
        }
        if (!targets.length) return;
        const signature = JSON.stringify(
            targets.map((target) => [
                target.charIndex,
                target.chatIndex,
                target.messageIndex,
                target.assetName,
            ]),
        );
        if (signature === generatedChatImageParserRepairSignature) return;
        generatedChatImageParserRepairSignature = signature;

        const groups = new Map();
        for (const target of targets) {
            const key = `${target.charIndex}:${target.chatIndex}`;
            if (!groups.has(key)) {
                groups.set(key, {
                    charIndex: target.charIndex,
                    chatIndex: target.chatIndex,
                    targets: [],
                });
            }
            groups.get(key).targets.push(target);
        }

        for (const group of groups.values()) {
            let chat = null;
            try {
                chat = await Risu.getChatFromIndex(group.charIndex, group.chatIndex);
            } catch (_) {
                continue;
            }
            if (!chat || !Array.isArray(chat.message)) continue;
            const repairedMessages = [];
            for (const target of group.targets) {
                const message = chat.message[target.messageIndex];
                if (!message) continue;
                const before = safeString(message.data);
                if (!before || !/\b(?:x-risu-)?naa-generated-image\b/i.test(before)) continue;
                const after = repairGeneratedAssetParserSourcesInContent(before);
                if (after === before) continue;
                chat.message[target.messageIndex] = { ...message, data: after };
                repairedMessages.push({
                    messageIndex: target.messageIndex,
                    assetName: target.assetName,
                    beforeHasRawToken: imageTokenNamesForParserPreview(before).length > 0,
                    afterHasRawToken: imageTokenNamesForParserPreview(after).length > 0,
                });
            }
            if (!repairedMessages.length) continue;
            try {
                await Risu.setChatToIndex(group.charIndex, group.chatIndex, chat);
                invalidateZoomGeneratedItemsCache();
            } catch (_) {}
        }
    }

    function replaceFirstGeneratedAssetHtml(content, assetName, replacementFactory, options = {}) {
        const cleanAssetName = safeString(assetName).trim();
        const cleanSlotId = safeString(options?.slotId).trim();
        if (!cleanAssetName && !cleanSlotId) return safeString(content);
        let replaced = false;
        return safeString(content).replace(naaGeneratedImageBlockRegex(), (block) => {
            if (replaced) return block;
            const blockSlotId = slotIdFromGeneratedImageHtml(block);
            const blockAssetName = assetNameFromGeneratedImageHtml(block);
            const matches = cleanSlotId ? blockSlotId === cleanSlotId : blockAssetName === cleanAssetName;
            if (!matches) return block;
            replaced = true;
            return typeof replacementFactory === 'function'
                ? replacementFactory(block)
                : safeString(replacementFactory);
        });
    }

    function originalImageTokenTemplateForAsset(tokenMarkup, assetName) {
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        return generatedAssetHtmlTemplate(cleanAssetName, tokenMarkup);
    }

    function renderDisplayImageTokenBlocks(content, options = {}) {
        const disableGeneratedAssets = Boolean(options.disableGeneratedAssets);
        return safeString(content).replace(
            imageTokenMarkerBlockRegex(),
            (_full, rawMeta, inner) => {
                const meta = parseImageTokenMarkerMeta(rawMeta);
                const generatedAssetName = safeString(meta.asset).trim();
                if (generatedAssetName && !disableGeneratedAssets) {
                    return generatedAssetHtmlTemplate(generatedAssetName, safeString(inner));
                }
                return safeString(inner);
            },
        );
    }

    function streamingImageDisplayPlaceholder(markup) {
        return streamImageTokenPlaceholderOpen({
            id: stableStreamImagePlaceholderId(markup, 0),
            markup,
        });
    }

    function hideDisplayImageTokens(content) {
        const text = safeString(content);
        const regex = supportedImageMarkupRegex();
        let output = '';
        let lastIndex = 0;
        let changed = false;
        let match;
        while ((match = regex.exec(text))) {
            const offset = match.index;
            const end = offset + match[0].length;
            const parsed = parseSupportedImageMarkup(match[0]);
            if (!parsed) continue;
            output += text.slice(lastIndex, offset);
            output += streamingImageDisplayPlaceholder(match[0]);
            lastIndex = end;
            changed = true;
        }
        output += text.slice(lastIndex);
        return changed ? output : text;
    }

    const STREAM_IMAGE_LAYOUT_STABILIZER_STYLE = `
<style data-naa-stream-image-layout-stabilizer>
.default-chat-screen,
.default-chat-screen *,
.han-image-container,
.regex-modern-stylish-white,
.naa-generated-image{
  overflow-anchor:none !important;
}
.han-image-container,
.regex-modern-stylish-white,
.naa-generated-image{
  contain:layout paint !important;
}
.han-rounded-image-wrapper,
.regex-modern-stylish-white .image-container,
.naa-generated-image{
  aspect-ratio:832 / 1216 !important;
  min-height:0 !important;
}
.han-rounded-image,
.regex-modern-stylish-white .image-container img,
.naa-generated-image__img{
  display:block !important;
  width:100% !important;
  height:100% !important;
  object-fit:contain !important;
}
</style>
`;

    function addStreamImageLayoutStabilizer(content) {
        const text = safeString(content);
        if (text.includes('data-naa-stream-image-layout-stabilizer')) return text;
        return `${STREAM_IMAGE_LAYOUT_STABILIZER_STYLE}${text}`;
    }

    function replaceNaaGeneratedHtmlWithImageToken(content) {
        return safeString(content).replace(
            /<div\b(?=[^>]*\bclass\s*=\s*(?:"[^"]*\bnaa-generated-image\b[^"]*"|'[^']*\bnaa-generated-image\b[^']*'))[\s\S]*?<img\b[^>]*>[\s\S]*?<\/div>/giu,
            (_full) => {
                const origMatch = /data-naa-original="([^"]*)"/.exec(_full);
                if (origMatch) return decodeNaaOriginal(origMatch[1]);
                const assetAttrMatch = /(?:data-naa-asset|x-risu-naa-asset)="([^"]+)"/.exec(_full);
                const rawSrcMatch =
                    /src\s*=\s*(?:"\{\{raw::([^}]+)\}\}"|'\{\{raw::([^}]+)\}\}'|\{\{raw::([^}\s]+)\}\})/iu.exec(
                        _full,
                    );
                const assetName = safeString(
                    assetAttrMatch?.[1] || rawSrcMatch?.[1] || rawSrcMatch?.[2] || rawSrcMatch?.[3],
                ).trim();
                const originalMarkup = reverseAssetMap.get(assetName);
                if (originalMarkup) return originalMarkup;
                return assetName ? `{{image::${assetName}}}` : '';
            },
        );
    }

    function replaceGeneratedAssetTokensWithOriginal(content) {
        if (!reverseAssetMap.size) return safeString(content);
        return safeString(content).replace(originalImageMarkupRegex(), (_full) => {
            const parsed = parseSupportedImageMarkup(_full);
            const originalMarkup = reverseAssetMap.get(safeString(parsed?.tokenName).trim());
            if (originalMarkup) return originalMarkup;
            return _full;
        });
    }

    function shouldNormalizeNaaImageMarkupForModel(content) {
        const text = safeString(content);
        if (!text) return false;
        return (
            text.includes('naa-generated-image') ||
            text.includes('data-naa-original=') ||
            text.includes('x-risu-naa-asset=') ||
            text.includes(NAA_IMAGE_TOKEN_MARKER_PREFIX) ||
            text.includes('{{image::') ||
            text.includes('{{asset::') ||
            text.includes('{{img::') ||
            text.includes('<img') ||
            text.includes('<IMG') ||
            text.includes('<Img')
        );
    }

    function normalizeNaaImageMarkupForModel(content) {
        const text = safeString(content);
        if (!shouldNormalizeNaaImageMarkupForModel(text)) return text;
        let result = replaceNaaGeneratedHtmlWithImageToken(stripImageTokenMarkers(text));
        result = replaceGeneratedAssetTokensWithOriginal(result);
        return result;
    }

    function setImageTokenMarkerAsset(content, markerId, sourceMarkup, assetName) {
        const cleanMarkerId = safeString(markerId).trim();
        const cleanAssetName = safeString(assetName)
            .trim()
            .replace(/[<>"']/g, '');
        if (!cleanAssetName) return safeString(content);
        let changed = false;
        let fallbackDone = false;
        const output = safeString(content).replace(
            imageTokenMarkerBlockRegex(),
            (full, rawMeta, inner) => {
                const meta = parseImageTokenMarkerMeta(rawMeta);
                const currentMarkerId = safeString(meta.id).trim();
                const isTarget =
                    (cleanMarkerId && currentMarkerId === cleanMarkerId) ||
                    (!cleanMarkerId && !fallbackDone && full === sourceMarkup);
                if (!isTarget) return full;
                changed = true;
                fallbackDone = true;
                const nextMeta = {
                    ...meta,
                    id: currentMarkerId || cleanMarkerId || createImageTokenMarkerId(),
                    asset: cleanAssetName,
                };
                return `${imageTokenMarkerOpen(nextMeta)}${safeString(inner)}<!--/${NAA_IMAGE_TOKEN_MARKER_PREFIX}-->`;
            },
        );
        if (changed) return output;
        const source = safeString(sourceMarkup);
        const index = output.indexOf(source);
        if (index < 0) return output;
        const markerIdForSource = cleanMarkerId || createImageTokenMarkerId();
        const wrapped = `${imageTokenMarkerOpen({
            id: markerIdForSource,
            asset: cleanAssetName,
        })}${source}<!--/${NAA_IMAGE_TOKEN_MARKER_PREFIX}-->`;
        return `${output.slice(0, index)}${wrapped}${output.slice(index + source.length)}`;
    }

    function replaceFirstImageToken(content, tokenMarkup, assetName) {
        const sourceMarkup = safeString(tokenMarkup);
        const replacement = originalImageTokenTemplateForAsset(sourceMarkup, assetName);
        const index = safeString(content).indexOf(sourceMarkup);
        if (index < 0) return safeString(content);
        return `${content.slice(0, index)}${replacement}${content.slice(index + sourceMarkup.length)}`;
    }

    function responseUnitSeedKeyForPlan(plan = {}) {
        return promptSeedKeyFromParts(plan);
    }

    function applyResponseUnitSeedToPlan(plan, seedByCharacterKey = new Map()) {
        if (!plan || (plan.seedFixed && normalizeNovelAISeed(plan.seed))) return plan;
        if (plan.seedFixed && !normalizeNovelAISeed(plan.seed)) plan.seedFixed = false;
        const characterKey = responseUnitSeedKeyForPlan(plan);
        if (!characterKey) return plan;
        let responseSeed = seedByCharacterKey.get(characterKey);
        if (!responseSeed) {
            responseSeed = normalizeNovelAISeed(createNovelAIRandomSeed());
            seedByCharacterKey.set(characterKey, responseSeed);
        }
        plan.seed = responseSeed;
        plan.responseUnitSeedKey = characterKey;
        return plan;
    }

    function applyPromptSeedSettingToPlan(plan) {
        if (!plan || typeof plan !== 'object') return plan;
        const promptKey = promptSeedKeyFromParts(plan);
        const seedSetting = getPromptSeedSetting(promptKey);
        if (!seedSetting.fixed || !seedSetting.seed) return plan;
        plan.seed = seedSetting.seed;
        plan.seedFixed = true;
        return plan;
    }

    async function generateNovelAIForPlan(plan, index, total, mode, staggerMs = 0) {
        if (staggerMs > 0) await sleepMs(staggerMs);
        if (!isNovelAIQueueOnlyRuntimeMode(mode)) {
            plan = applyPromptSeedSettingToPlan(plan);
        }
        setRuntimeNovelAIProgress(index, total, false, mode);

        const effectiveNovelAIConfig = getEffectiveNovelAIConfig({
            ...config.novelai,
            seed: normalizeNovelAISeed(plan.seed),
            width: plan.width,
            height: plan.height,
            negativePrompt: plan.negativePrompt,
            characterPrompts: plan.characters,
            characterReferences: plan.characterReferences,
        });
        const result = await callNovelAIWithRetry(plan.globalPositive, effectiveNovelAIConfig, 3, {
            source: 'chat',
            mode,
            assetName: plan.assetName,
            sourceImageToken: plan.sourceImageToken,
            index: index + 1,
            total,
        });
        setRuntimeNovelAIProgress(index, total, true, mode);
        return {
            plan: {
                ...plan,
                seed: normalizeNovelAISeed(result?.seed || plan.seed),
                seedFixed: Boolean(plan.seedFixed),
            },
            dataUrl: result?.dataUrl || result,
            seed: result?.seed,
            extraNoiseSeed: result?.extraNoiseSeed,
        };
    }

    function makeRegeneratedAssetName(assetName) {
        const base = sanitizeAssetNamePart(
            safeString(assetName).replace(/\.(?:png|jpe?g|webp)$/i, ''),
            'nai_regen',
        ).slice(0, 72);
        generatedAssetNameCounter = (generatedAssetNameCounter + 1) % 1000000;
        return `${base || 'nai_regen'}_regen_${generatedAssetNameCounter}_${createNovelAIRandomSeed().toString(36).slice(0, 5)}`;
    }

    function regenerationPlanFromDisplayMeta(meta = {}) {
        return normalizeDisplayRegenerationPlan(meta?.regenerationPlan || meta?.plan);
    }

    function displayMetaForGeneratedPlan(plan, dataUrl, savedAssetName, sourceMarkup = '') {
        const sourceToken = safeString(plan?.sourceImageToken).trim();
        const resolvedSourceMarkup =
            safeString(sourceMarkup).trim() || safeString(plan?.sourceImageMarkup).trim();
        rememberImageTokenPreviewUrl(savedAssetName, dataUrl);
        const promptKey = safeString(
            plan?.matchedIdentityKey || plan?.selectedLorebookPromptKey,
        ).trim();
        const locationMeta = locationMetaFromParts(plan);
        const regenerationPlan = normalizeDisplayRegenerationPlan({
            ...plan,
            ...locationMeta,
            assetName: savedAssetName,
            chatKey: safeString(plan?.chatKey).trim(),
            sourceImageToken: sourceToken,
            sourceImageMarkup: resolvedSourceMarkup,
            seed: '',
            seedFixed: false,
        });
        const slotId = imageSlotIdFromParts({
            ...plan,
            chatKey: safeString(plan?.chatKey).trim(),
            sourceImageToken: sourceToken,
            sourceImageMarkup: resolvedSourceMarkup,
        });
        const meta = {
            seed: plan?.seed,
            seedFixed: Boolean(plan?.seedFixed),
            promptKey,
            width: plan?.width,
            height: plan?.height,
            sizeId: plan?.sizeId,
            sourceImageToken: sourceToken,
            sourceImageMarkup: resolvedSourceMarkup,
            sourceImageMarkerId: safeString(plan?.sourceImageMarkerId).trim(),
            chatKey: safeString(plan?.chatKey).trim(),
            ...locationMeta,
            slotId,
            regenerationPlan,
            analyzerDecision: normalizeAnalyzerDecisionForPromptPanel(
                plan?.analyzerDecision || regenerationPlan?.analyzerDecision,
                {
                    ...plan,
                    ...regenerationPlan,
                    sourceImageToken: sourceToken || regenerationPlan?.sourceImageToken,
                    sourceImageMarkup: resolvedSourceMarkup || regenerationPlan?.sourceImageMarkup,
                    sourceImageMarkerId:
                        safeString(plan?.sourceImageMarkerId).trim() ||
                        regenerationPlan?.sourceImageMarkerId,
                },
            ),
        };
        upsertDisplayAssetSlotRegenerationPlan(slotId, regenerationPlan, {
            ...meta,
            assetName: savedAssetName,
            lastAssetName: savedAssetName,
        });
        return meta;
    }

    async function regenerateGeneratedAssetFromZoomContext(context) {
        const oldAssetName = safeString(context?.assetName).trim();
        if (!oldAssetName) throw new Error('Regeneration target asset is empty.');
        const oldMeta = displayMetaWithSlotRegenerationPlan(
            displayAssetMetaMap.get(oldAssetName) || context?.assetMeta || {},
            context?.assetMeta?.slotId,
        );
        const basePlan = regenerationPlanFromDisplayMeta(oldMeta);
        if (!basePlan) throw new Error('This generated image has no saved regeneration plan.');
        const sourceMarkup =
            safeString(context?.originalMarkup).trim() ||
            safeString(basePlan.sourceImageMarkup).trim() ||
            reverseAssetMap.get(oldAssetName) ||
            '';
        const oldPreviewUrl = await loadZoomImageTokenObjectUrl(oldAssetName).catch(() => '');
        if (oldPreviewUrl) rememberImageTokenPreviewUrl(oldAssetName, oldPreviewUrl);
        const oldSlot = recordGeneratedAssetSlot(oldAssetName, oldMeta, sourceMarkup, {
            current: false,
            imgSrc: oldPreviewUrl,
        });
        await showRegenerationLoadingStateForAsset(
            context.rootDoc,
            oldAssetName,
            sourceMarkup,
            oldMeta,
            'regenerate-loading',
        );
        beginRuntimeQueueOnlyRun();

        const sizePromptKey = promptSeedKeyFromParts({
            ...oldMeta,
            ...basePlan,
            promptKey:
                basePlan.matchedIdentityKey ||
                basePlan.selectedLorebookPromptKey ||
                oldMeta.promptKey,
        });
        const requestedSizePresetId = normalizeZoomRegenerateSizePresetId(context?.sizePresetId);
        if (sizePromptKey && requestedSizePresetId) {
            await setPromptRegenerateSizePresetId(sizePromptKey, requestedSizePresetId);
        }
        const savedSizePresetId = getPromptRegenerateSizePresetId(sizePromptKey);
        const regenerateSizePreset = getImageSizePreset(
            requestedSizePresetId || savedSizePresetId || basePlan.sizeId,
        );

        const nextPlan = {
            ...cloneJson(basePlan),
            assetName: makeRegeneratedAssetName(oldAssetName),
            sizeId: regenerateSizePreset.id,
            width: regenerateSizePreset.width,
            height: regenerateSizePreset.height,
            seed: '',
            seedFixed: false,
            analyzerDecision: normalizeAnalyzerDecisionForPromptPanel(
                basePlan.analyzerDecision || oldMeta.analyzerDecision,
                {
                    ...oldMeta,
                    ...basePlan,
                },
            ),
        };
        const result = await generateNovelAIForPlan(nextPlan, 0, 1, 'regenerate', 0);
        const generatedPlan = {
            ...result.plan,
            seedFixed: false,
        };
        const saved = await saveGeneratedImageAsAdditionalAsset(
            result.dataUrl,
            generatedPlan,
            generatedPlan.assetName,
            {
                targetCharacterIndex: nonNegativeIntegerOr(
                    oldMeta.charIndex ?? basePlan.charIndex,
                    -1,
                ),
            },
        );
        const finalPlan = {
            ...generatedPlan,
            assetName: saved.assetName,
            chatKey: basePlan.chatKey,
            ...locationMetaFromParts({
                ...oldMeta,
                ...basePlan,
                ...generatedPlan,
            }),
            sourceImageToken: basePlan.sourceImageToken,
            sourceImageMarkup: sourceMarkup,
            sourceImageMarkerId: basePlan.sourceImageMarkerId,
            slotId: oldSlot?.slotId || basePlan.slotId,
        };
        const newMeta = displayMetaForGeneratedPlan(
            finalPlan,
            result.dataUrl,
            saved.assetName,
            sourceMarkup,
        );
        setDisplayAssetMapping(basePlan.sourceImageToken, saved.assetName, basePlan.chatKey);
        if (sourceMarkup) reverseAssetMap.set(saved.assetName, sourceMarkup);
        displayAssetMetaMap.set(saved.assetName, newMeta);
        upsertDisplayAssetSlotRegenerationPlan(newMeta.slotId || finalPlan.slotId, newMeta.regenerationPlan, {
            ...newMeta,
            assetName: saved.assetName,
            lastAssetName: saved.assetName,
        });
        recordGeneratedAssetSlot(saved.assetName, newMeta, sourceMarkup, {
            current: true,
            imgSrc: rawAssetImageSrc(saved.assetName),
        });
        await saveDisplayAssetMap().catch(() => {});
        const replacement = generatedAssetHtmlTemplate(saved.assetName, sourceMarkup, newMeta);
        if (context.rootDoc) {
            replaceFirstGeneratedAssetInRootDom(context.rootDoc, oldAssetName, replacement)
                .then((domReplaced) => {

                })
                .catch((error) => {

                });
        }
        const replaced = await replaceFirstGeneratedAssetInCurrentChat(
            oldAssetName,
            () => replacement,
            'regenerate-complete',
            {
                slotId: newMeta.slotId || oldMeta.slotId || basePlan.slotId,
                messageIndex: newMeta.messageIndex ?? oldMeta.messageIndex ?? basePlan.messageIndex,
                chatKey: newMeta.chatKey || oldMeta.chatKey || basePlan.chatKey,
                replacementAssetName: saved.assetName,
            },
        );

        return {
            assetName: saved.assetName,
            meta: newMeta,
            sourceMarkup,
            dataUrl: result.dataUrl,
        };
    }

    async function runNovelAIGenerationPlans(generationPlans) {
        const intervalSec = clampNovelAIParallelIntervalSec(
            config.runtime?.novelaiParallelIntervalSec,
            DEFAULT_CONFIG.runtime.novelaiParallelIntervalSec,
        );

        const results = [];
        for (let index = 0; index < generationPlans.length; index++) {
            const plan = generationPlans[index];
            try {
                const value = await generateNovelAIForPlan(
                    plan,
                    index,
                    generationPlans.length,
                    'sequential',
                    index > 0 ? intervalSec * 1000 : 0,
                );
                results.push({ status: 'fulfilled', value });
            } catch (error) {
                setRuntimeNovelAIProgress(index, generationPlans.length, true, 'sequential');
                results.push({ status: 'rejected', reason: { plan, error } });
            }
        }
        return results;
    }

    function generatedAssetReplacementHtmlForToken(savedAssetName, plan = {}, match = null) {
        const cleanAssetName = safeString(savedAssetName).trim();
        const existingMeta = displayAssetMetaMap.get(cleanAssetName) || {};
        const sourceImageMarkup = safeString(
            match?.inner || match?.full || plan.sourceImageMarkup,
        ).trim();
        const sourceImageToken = safeString(match?.tokenName || plan.sourceImageToken).trim();
        const sourceImageMarkerId = match
            ? imageTokenOccurrenceId(match, match.index)
            : safeString(plan.sourceImageMarkerId).trim();
        const slotId = match
            ? imageTokenSlotIdForContext(match, {
                  chatKey: plan.chatKey,
              })
            : safeString(plan.slotId || plan.imageSlotId).trim();
        const meta = {
            ...existingMeta,
            sourceImageToken: sourceImageToken || existingMeta.sourceImageToken,
            sourceImageMarkerId: sourceImageMarkerId || existingMeta.sourceImageMarkerId,
            sourceImageMarkup: sourceImageMarkup || existingMeta.sourceImageMarkup,
            chatKey: safeString(plan.chatKey || existingMeta.chatKey).trim(),
            ...locationMetaFromParts({ ...existingMeta, ...plan }),
            slotId: slotId || existingMeta.slotId,
        };
        if (cleanAssetName) displayAssetMetaMap.set(cleanAssetName, meta);
        return generatedAssetHtmlTemplate(cleanAssetName, sourceImageMarkup, meta);
    }

    function imageTokenMatchesGenerationPlan(token = {}, plan = {}, context = {}) {
        const sourceImageToken = safeString(plan.sourceImageToken).trim();
        const sourceImageMarkup = safeString(plan.sourceImageMarkup).trim();
        const sourceImageMarkerId = safeString(plan.sourceImageMarkerId).trim();
        const expectedSlotId = imageSlotIdFromParts({
            ...plan,
            chatKey: plan.chatKey || context.chatKey,
            sourceImageToken,
            sourceImageMarkerId,
            sourceImageMarkup,
        });
        const tokenSlotId = imageTokenSlotIdForContext(token, context);
        if (expectedSlotId && tokenSlotId && expectedSlotId === tokenSlotId) return true;
        const tokenMarkerId = imageTokenOccurrenceId(token, token.index);
        if (sourceImageMarkerId && tokenMarkerId === sourceImageMarkerId) return true;
        const tokenMarkup = safeString(token.inner || token.full).trim();
        if (sourceImageMarkup && tokenMarkup === sourceImageMarkup) return true;
        const tokenName = safeString(token.tokenName).trim();
        return Boolean(sourceImageToken && tokenName === sourceImageToken);
    }

    function replaceGeneratedAssetTokenInOutput(output, plan = {}, savedAssetName = '', context = {}) {
        const text = safeString(output);
        const tokenOptions = {
            moduleAssetTokens: context.activeModuleAssetTokens,
            customImageTokenDetectors: context.customImageTokenDetectors,
        };
        const match = extractImageTokens(text, tokenOptions)
            .filter(isProcessableImageToken)
            .filter((token) => !imageTokenMatchesActiveModuleAsset(token, context.activeModuleAssetTokens))
            .find((token) => imageTokenMatchesGenerationPlan(token, plan, context));
        if (match && Number.isFinite(Number(match.offset))) {
            const offset = Number(match.offset);
            const full = safeString(match.full);
            const slotId = imageTokenSlotIdForContext(match, context);
            const replacement = generatedAssetReplacementHtmlForToken(
                savedAssetName,
                {
                    ...plan,
                    slotId: slotId || plan.slotId,
                },
                match,
            );
            return {
                output: text.slice(0, offset) + replacement + text.slice(offset + full.length),
                replaced: true,
                reason: 'token-match',
                offset,
                slotId,
                sourceImageToken: match.tokenName,
            };
        }
        const sourceMarkup = safeString(plan.sourceImageMarkup);
        const sourceIdx = sourceMarkup ? text.indexOf(sourceMarkup) : -1;
        if (sourceIdx >= 0) {
            const replacement = generatedAssetReplacementHtmlForToken(savedAssetName, plan, null);
            return {
                output:
                    text.slice(0, sourceIdx) +
                    replacement +
                    text.slice(sourceIdx + sourceMarkup.length),
                replaced: true,
                reason: 'source-markup',
                offset: sourceIdx,
                sourceImageToken: plan.sourceImageToken,
            };
        }
        return {
            output: text,
            replaced: false,
            reason: 'not-found',
            offset: -1,
            sourceImageToken: plan.sourceImageToken,
        };
    }

