    function createNovelAIRandomSeed() {
        const max = 4294967295;
        const cryptoObj =
            globalThis.crypto || (typeof window !== 'undefined' ? window.crypto : null);
        if (cryptoObj?.getRandomValues) {
            const values = new Uint32Array(1);
            cryptoObj.getRandomValues(values);
            return Math.min(max, Math.max(0, Number(values[0])));
        }
        return Math.floor(Math.random() * (max + 1));
    }

