    function syncOutfitGenerateReferenceRangeOutput(input) {
        const rangeInput = input?.matches?.(
            '[data-naa-outfit-generate-reference-strength],[data-naa-outfit-generate-reference-fidelity]',
        )
            ? input
            : null;
        if (!rangeInput) return;
        const output = rangeInput
            .closest?.('.naa-range-row')
            ?.querySelector?.('[data-naa-outfit-generate-reference-range-output]');
        if (!output) return;
        const value = clampUnitFloat(rangeInput.value, 0);
        output.textContent = String(Math.round(value * 100) / 100);
    }

