    function outfitReferenceGenerateAssetName(promptRow, outfitRow, outfitOverride = null) {
        const promptKey = promptKeyForAssetRow(promptRow);
        const outfit = outfitOverride || outfitValuesFromDomRow(outfitRow);
        const characterName =
            promptRow?.querySelector?.('.naa-character-head strong')?.textContent ||
            promptRow?.getAttribute?.('data-lorebook-title') ||
            promptKey ||
            'character';
        const outfitName = outfit.label || outfit.id || 'outfit';
        const matchingTerms = uniqueStringList([
            ...lorebookKeysFromAssetRow(promptRow, {
                includeCustom: true,
                includeTitle: true,
            }),
            characterName,
        ])
            .map((term) => sanitizeAssetNamePart(term, ''))
            .filter(Boolean)
            .slice(0, 4);
        const matchingPart = sanitizeAssetNamePart(
            matchingTerms.join('_') || characterName,
            'character',
        )
            .slice(0, 120)
            .replace(/_+$/g, '');
        const outfitPart = sanitizeAssetNamePart(outfitName, 'outfit')
            .slice(0, 72)
            .replace(/_+$/g, '');
        generatedAssetNameCounter = (generatedAssetNameCounter + 1) % 1000000;
        return sanitizeAssetNamePart(
            `outfit_ref_${matchingPart || 'character'}_${outfitPart || 'outfit'}_${generatedAssetNameCounter}`,
            'outfit_ref',
        );
    }

    function outfitReferenceGenerateStateForModal(modal) {
        if (!modal) return { history: [], selectedHistoryIndex: -1 };
        const state =
            modal.__naaOutfitReferenceGenerateState &&
            typeof modal.__naaOutfitReferenceGenerateState === 'object'
                ? modal.__naaOutfitReferenceGenerateState
                : {};
        state.history = Array.isArray(state.history) ? state.history : [];
        if (!Number.isInteger(state.selectedHistoryIndex)) {
            state.selectedHistoryIndex = state.history.length ? 0 : -1;
        }
        modal.__naaOutfitReferenceGenerateState = state;
        return state;
    }

    function selectedOutfitReferenceGenerateState(modal) {
        const state = outfitReferenceGenerateStateForModal(modal);
        return state.history[state.selectedHistoryIndex] || state;
    }

    function renderOutfitReferenceGenerateHistory(modal) {
        const state = outfitReferenceGenerateStateForModal(modal);
        const root = modal?.querySelector?.('[data-naa-outfit-generate-history]');
        const list = modal?.querySelector?.('[data-naa-outfit-generate-history-list]');
        if (!root || !list) return;
        root.hidden = state.history.length === 0;
        list.innerHTML = state.history
            .map(
                (item, index) => `
                    <button class="naa-outfit-generate-history-item ${index === state.selectedHistoryIndex ? 'active' : ''}" type="button" data-naa-outfit-generate-history-index="${escapeHtml(index)}">
                        <img alt="" src="${escapeHtml(item.dataUrl)}">
                        <span>${escapeHtml(`#${state.history.length - index}`)}</span>
                    </button>
                `,
            )
            .join('');
    }

    function selectOutfitReferenceGenerateHistoryItem(modal, index = 0) {
        const state = outfitReferenceGenerateStateForModal(modal);
        const item = state.history[index];
        if (!item) return null;
        state.selectedHistoryIndex = index;
        Object.assign(state, item);
        const img = modal?.querySelector?.('[data-naa-outfit-generate-preview-img]');
        const placeholder = modal?.querySelector?.('[data-naa-outfit-generate-empty]');
        const saveButton = modal?.querySelector?.('[data-naa-outfit-generate-save]');
        if (img) {
            img.src = item.dataUrl;
            img.removeAttribute('hidden');
        }
        if (placeholder) placeholder.setAttribute('hidden', '');
        if (saveButton) saveButton.disabled = false;
        renderOutfitReferenceGenerateHistory(modal);
        return item;
    }

    function pushOutfitReferenceGenerateHistoryItem(modal, item = {}) {
        const state = outfitReferenceGenerateStateForModal(modal);
        const historyItem = {
            ...item,
            id:
                item.id ||
                `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
            createdAt: Number(item.createdAt) || Date.now(),
        };
        state.history = [historyItem, ...state.history].slice(
            0,
            OUTFIT_REFERENCE_GENERATE_HISTORY_LIMIT,
        );
        state.selectedHistoryIndex = 0;
        return selectOutfitReferenceGenerateHistoryItem(modal, 0);
    }

    async function generateOutfitReferenceImageFromModal(promptRow, outfitRow, modal) {
        const runButton = modal?.querySelector?.('[data-naa-outfit-generate-run]');
        const saveButton = modal?.querySelector?.('[data-naa-outfit-generate-save]');
        const status = modal?.querySelector?.('[data-naa-outfit-generate-status]');
        const img = modal?.querySelector?.('[data-naa-outfit-generate-preview-img]');
        const placeholder = modal?.querySelector?.('[data-naa-outfit-generate-empty]');
        const promptKey = promptKeyForAssetRow(promptRow);
        const defaultReferenceAsset = currentCharacterReferenceAssetFromRow(promptRow);
        const presetContext = outfitReferenceGeneratePresetContext();
        const useReference =
            modal?.querySelector?.('[data-naa-outfit-generate-reference-enabled]')?.checked ===
            true;
        const referenceSettings = outfitGenerateReferenceSettingsFromModal(modal);
        const positivePrompt = outfitReferenceGeneratePromptFromModal(
            promptRow,
            outfitRow,
            modal,
            presetContext,
        );
        if (!positivePrompt) {
            if (status) status.textContent = t('emptyPrompt');
            return;
        }
        const negativePrompt =
            safeString(promptRow?.querySelector?.('[data-naa-lorebook-negative-prompt]')?.value).trim() ||
            safeString(config.novelai?.negativePrompt || DEFAULT_CONFIG.novelai.negativePrompt);
        const characterPrompt = outfitReferenceGenerateCharacterPrompt(promptRow);
        const characterNegativePrompt = outfitReferenceGenerateCharacterNegativePrompt(promptRow);
        const novelaiConfig = getEffectiveNovelAIConfig({
            ...config.novelai,
            width: presetContext.width,
            height: presetContext.height,
            negativePrompt,
            characterPrompts: [{ prompt: characterPrompt, uc: characterNegativePrompt }],
            useCoords: false,
            characterReferenceEnabled: Boolean(useReference),
            characterReferenceType: referenceSettings.type,
            characterReferenceStrength: referenceSettings.strength,
            characterReferenceFidelity: referenceSettings.fidelity,
            characterReferences: useReference && defaultReferenceAsset?.key
                ? [{ promptKey, asset: defaultReferenceAsset, ...referenceSettings }]
                : [],
        });
        const originalRunText = runButton?.textContent || t('generateOutfitReference');
        if (runButton) {
            runButton.disabled = true;
            runButton.textContent = t('outfitReferenceGenerateRunning');
        }
        if (saveButton) saveButton.disabled = true;
        if (status) status.textContent = t('outfitReferenceGenerateRunning');
        try {
            const result = await callNovelAIWithRetry(positivePrompt, novelaiConfig, 3, {
                source: 'outfit-reference',
                mode: 'outfit-reference',
                promptKey,
            });
            const dataUrl = result?.dataUrl || result;
            if (!normalizeImageDataUrl(dataUrl)) throw new Error('NovelAI image data is empty.');
            pushOutfitReferenceGenerateHistoryItem(modal, {
                dataUrl,
                prompt: positivePrompt,
                negativePrompt,
                seed: normalizeNovelAISeed(result?.seed),
                promptKey,
                defaultReferenceUsed: Boolean(useReference && defaultReferenceAsset?.key),
                referenceSettings,
                presetPath: presetContext.presetPath,
                sizeId: presetContext.sizeId,
                width: presetContext.width,
                height: presetContext.height,
                selectedArtistId: presetContext.selectedArtistId,
            });
            if (img) {
                img.src = dataUrl;
                img.removeAttribute('hidden');
            }
            if (placeholder) placeholder.setAttribute('hidden', '');
            if (status) status.textContent = t('outfitReferenceGenerateReady');
            if (saveButton) saveButton.disabled = false;
        } catch (error) {
            if (status)
                status.textContent = `${t('outfitReferenceGenerateFailed')}: ${error?.message || error}`;

        } finally {
            if (runButton) {
                runButton.disabled = false;
                runButton.textContent = originalRunText;
            }
        }
    }

    async function saveOutfitReferenceGeneratedImageFromModal(promptRow, outfitRow, modal) {
        const saveButton = modal?.querySelector?.('[data-naa-outfit-generate-save]');
        const status = modal?.querySelector?.('[data-naa-outfit-generate-status]');
        const state = selectedOutfitReferenceGenerateState(modal);
        if (!normalizeImageDataUrl(state.dataUrl)) {
            if (status) status.textContent = t('outfitReferenceGenerateNoImage');
            return;
        }
        const originalText = saveButton?.textContent || t('save');
        if (saveButton) {
            saveButton.disabled = true;
            saveButton.textContent = t('saving');
        }
        try {
            const promptKey = promptKeyForAssetRow(promptRow);
            const outfit = normalizeOutfitPromptEntry({
                ...outfitValuesFromDomRow(outfitRow),
                ...outfitReferenceGenerateFieldsFromModal(modal),
            });
            const assetName = outfitReferenceGenerateAssetName(promptRow, outfitRow, outfit);
            state.assetName = assetName;
            const plan = {
                assetName,
                globalPositive: state.prompt,
                negativePrompt: state.negativePrompt,
                seed: state.seed,
                width: state.width,
                height: state.height,
                sizeId: state.sizeId,
                selectedLorebookPromptKey: promptKey,
                matchedIdentityKey: promptKey,
                selectedOutfitId: outfit.id,
                selectedArtistId: state.selectedArtistId,
                presetPath: state.presetPath,
                characterReferences: state.defaultReferenceUsed
                    ? [
                          {
                              promptKey,
                              asset: currentCharacterReferenceAssetFromRow(promptRow),
                              ...normalizeCharacterReferenceModelSettings(state.referenceSettings),
                          },
                      ].filter((reference) => reference.asset?.key)
                    : [],
            };
            const saveTarget = additionalAssetSaveTargetFromPromptRow(promptRow);
            const saved = await saveGeneratedImageAsAdditionalAsset(
                state.dataUrl,
                plan,
                assetName,
                {
                    targetCharacter: saveTarget?.character,
                    targetCharacterIndex: saveTarget?.characterIndex,
                    memberKey: saveTarget?.memberKey,
                },
            );
            const savedAsset = normalizeCharacterReferenceAsset({
                name: saved.assetName,
                key: saved.savedPath,
                ext: saved.extension,
            });
            setOutfitRowTextareaValues(outfitRow, {
                ...outfit,
                sourceAssetName: saved.assetName,
                referenceAsset: savedAsset,
            });
            setRowReferenceAssetAttrs(outfitRow, savedAsset);
            setRowMetadataReferenceAssetAttrs(outfitRow, savedAsset);
            renderOutfitReferencePreview(outfitRow, savedAsset);
            syncReferenceAnalysisBulkToggleStates();
            collectCharacterIdentityPromptsFromForm();
            await saveConfig();
            void loadCharacterPromptReferenceThumbnails(outfitRow);
            if (status) status.textContent = t('outfitReferenceGenerateSaved');
            closeOutfitReferenceGenerateModal();
            await renderCharacterPromptTab();
        } catch (error) {
            if (status)
                status.textContent = `${t('outfitReferenceGenerateFailed')}: ${error?.message || error}`;

            if (saveButton) {
                saveButton.disabled = false;
                saveButton.textContent = originalText;
            }
        }
    }

    function renderOutfitReferenceGenerateModal(promptRow, outfitRow) {
        closeOutfitReferenceGenerateModal();
        const outfit = outfitValuesFromDomRow(outfitRow);
        const defaultReferenceAsset = currentCharacterReferenceAssetFromRow(promptRow);
        const hasDefaultReference = Boolean(defaultReferenceAsset?.key);
        const title =
            promptRow?.querySelector?.('.naa-character-head strong')?.textContent ||
            promptRow?.getAttribute?.('data-lorebook-title') ||
            t('outfitReferenceGenerateTitle');
        const memberKey = safeString(promptRow?.getAttribute?.('data-member-key')).trim();
        const promptFieldHtml = (part) =>
            `<label class="naa-field naa-outfit-generate-${escapeHtml(part)}-field"><span>${escapeHtml(t(part))}</span><textarea data-naa-outfit-generate-${escapeHtml(part)} spellcheck="false" autocorrect="off" autocapitalize="off">${escapeHtml(outfit[part])}</textarea></label>`;
        document.body.insertAdjacentHTML(
            'beforeend',
            `
            <div class="naa-asset-picker-backdrop naa-outfit-generate-backdrop" data-naa-outfit-generate-modal>
                <section class="naa-asset-picker-modal naa-outfit-generate-modal" role="dialog" aria-modal="true" aria-label="${escapeHtml(t('outfitReferenceGenerateTitle'))}">
                    <header class="naa-asset-picker-head">
                        <div class="naa-outfit-generate-titlebar">
                            <strong>${escapeHtml(title)} - ${escapeHtml(t('outfitReferenceGenerateTitle'))}</strong>
                            <span class="naa-outfit-generate-title-status" data-naa-outfit-generate-status></span>
                        </div>
                        <div class="naa-inline compact">
                            <label class="naa-check naa-check-control naa-outfit-generate-reference-toggle">
                                <input type="checkbox" data-naa-outfit-generate-reference-enabled ${hasDefaultReference ? 'checked' : ''} ${hasDefaultReference ? '' : 'disabled'}>
                                <span>${escapeHtml(t('outfitReferenceGenerateUseDefaultReference'))}</span>
                            </label>
                            <button class="naa-btn primary naa-action-control" type="button" data-naa-outfit-generate-run>${escapeHtml(t('generateOutfitReference'))}</button>
                            <button class="naa-btn naa-action-control" type="button" data-naa-outfit-generate-save disabled>${escapeHtml(t('save'))}</button>
                            <button class="naa-btn naa-action-control" type="button" data-naa-outfit-generate-cancel>${escapeHtml(t('cancel'))}</button>
                        </div>
                    </header>
                    <div class="naa-outfit-generate-body">
                        <div class="naa-outfit-generate-preview">
                            <div class="naa-outfit-generate-image-frame naa-media-frame naa-media-frame--portrait naa-media-frame--contain">
                                <img data-naa-outfit-generate-preview-img alt="" hidden>
                                <em data-naa-outfit-generate-empty>${escapeHtml(t('outfitReferenceGenerateEmptyPreview'))}</em>
                                <div class="naa-outfit-generate-history" data-naa-outfit-generate-history hidden>
                                    <div class="naa-outfit-generate-history-list" data-naa-outfit-generate-history-list></div>
                                </div>
                            </div>
                        </div>
                        <div class="naa-outfit-generate-prompts">
                            <section class="naa-outfit-generate-group naa-outfit-generate-info">
                                <div class="naa-outfit-generate-overview-grid">
                                    <div class="naa-outfit-generate-default-reference">
                                        ${characterReferencePreviewHtml(defaultReferenceAsset, 'data-naa-outfit-generate-default-reference', t('defaultCharacterReference'), memberKey)}
                                    </div>
                                    <div class="naa-outfit-generate-reference-type-slot">
                                        ${outfitGenerateReferenceSettingsHtml()}
                                    </div>
                                </div>
                            </section>
                            <section class="naa-outfit-generate-group naa-outfit-generate-info-stack">
                                <label class="naa-field naa-outfit-generate-label-field">
                                    <span>${escapeHtml(t('outfitLabel'))}</span>
                                    <input data-naa-outfit-generate-label type="text" value="${escapeHtml(outfit.label)}" placeholder="homewear" spellcheck="false" autocorrect="off" autocapitalize="off">
                                </label>
                                <label class="naa-field naa-outfit-generate-description-field">
                                    <span>${escapeHtml(t('outfitDescription'))}</span>
                                    <textarea data-naa-outfit-generate-description placeholder="school uniform, white blouse, pleated skirt" spellcheck="false" autocorrect="off" autocapitalize="off">${escapeHtml(outfit.description)}</textarea>
                                </label>
                                ${promptFieldHtml('head')}
                            </section>
                            <section class="naa-outfit-generate-group naa-outfit-generate-prompt-fields">
                                <div class="naa-outfit-generate-part-grid">
                                    ${promptFieldHtml('top')}
                                    ${promptFieldHtml('bottom')}
                                    ${promptFieldHtml('legs')}
                                    ${promptFieldHtml('feet')}
                                </div>
                            </section>
                        </div>
                    </div>
                </section>
            </div>
        `,
        );
        const modal = document.querySelector('[data-naa-outfit-generate-modal]');
        modal
            ?.querySelectorAll(
                '[data-naa-outfit-generate-reference-strength],[data-naa-outfit-generate-reference-fidelity]',
            )
            .forEach(syncOutfitGenerateReferenceRangeOutput);
        modal?.addEventListener('input', (event) => {
            syncOutfitGenerateReferenceRangeOutput(event.target);
        });
        void loadCharacterPromptReferenceThumbnails(modal);
        modal?.addEventListener('click', async (event) => {
            if (
                event.target === modal ||
                event.target?.closest?.('[data-naa-outfit-generate-cancel]')
            ) {
                closeOutfitReferenceGenerateModal();
                return;
            }
            if (handleReferencePreviewZoomClick(event)) return;
            if (event.target?.closest?.('[data-naa-outfit-generate-default-reference]')) {
                collectCharacterIdentityPromptsFromForm();
                await renderCharacterReferencePickerModal(promptRow);
                return;
            }
            if (event.target?.closest?.('[data-naa-outfit-generate-run]')) {
                await generateOutfitReferenceImageFromModal(promptRow, outfitRow, modal);
                return;
            }
            const historyItem = event.target?.closest?.('[data-naa-outfit-generate-history-index]');
            if (historyItem) {
                const index = Number(historyItem.getAttribute('data-naa-outfit-generate-history-index'));
                selectOutfitReferenceGenerateHistoryItem(modal, index);
                return;
            }
            if (event.target?.closest?.('[data-naa-outfit-generate-save]')) {
                await saveOutfitReferenceGeneratedImageFromModal(promptRow, outfitRow, modal);
            }
        });
    }

    async function applyCharacterReferencePickerSelection(promptRow, modal, targetRow = promptRow) {
        const previousAsset = rowReferenceAssetFromAttrs(targetRow);
        const selectedAsset = selectedCharacterReferencePickerAsset(modal);
        if (selectedAsset) {
            setRowReferenceAssetAttrs(targetRow, selectedAsset);
            if (targetRow === promptRow) {
                const defaultOutfitRow = promptRow.querySelector?.(
                    '[data-naa-outfit-list] [data-naa-outfit-row]',
                );
                if (defaultOutfitRow) setRowMetadataReferenceAssetAttrs(defaultOutfitRow, selectedAsset);
            }
            const enabled = promptRow.querySelector('[data-naa-character-reference-enabled]');
            if (enabled) enabled.checked = true;
            if (targetRow === promptRow) {
                refreshOutfitGenerateDefaultReferencePreview(promptRow, selectedAsset);
            }
        }
        syncReferenceAnalysisBulkToggleStates();
        collectCharacterIdentityPromptsFromForm();
        await saveConfig();
        await deleteStaleCharacterReferenceCrop(previousAsset, selectedAsset);
    }

    async function renderCharacterReferencePickerModal(promptRow, outfitRow = null) {
        closeAssetPickerModal();
        const memberKey = safeString(promptRow?.getAttribute?.('data-member-key')).trim();
        const promptKey = promptKeyForAssetRow(promptRow);
        const baseNeedles = loreKeyNeedlesFromAssetRow(promptRow, { includeCustom: false });
        const manualSearchTerms = manualAssetSearchTermsForPromptKey(promptKey);
        const needles = loreKeyNeedlesFromAssetRow(promptRow);
        const selectedReference = outfitRow
            ? currentOutfitReferenceAssetFromRow(outfitRow)
            : currentCharacterReferenceAssetFromRow(promptRow);
        const selectedKey = safeString(selectedReference?.key).trim();
        const candidateCount = 0;
        const metadataCount = 0;
        const defaultFilter = 'all';
        const title =
            promptRow.querySelector('.naa-character-head strong')?.textContent ||
            promptRow.getAttribute('data-member-key') ||
            t('characterReference');
        const targetLabel = outfitRow ? t('outfitReference') : t('defaultCharacterReference');
        const candidateEmpty =
            '<div class="naa-empty wide" data-naa-candidate-empty hidden></div>';
        const emptyGridHtml = `<div class="naa-empty wide">${escapeHtml(t('noImageAssets'))}</div>`;
        const initialGridHtml = assetPickerLoadingHtml();
        document.body.insertAdjacentHTML(
            'beforeend',
            `
            <div class="naa-asset-picker-backdrop" data-naa-asset-picker-modal data-member-key="${escapeHtml(memberKey)}" data-prompt-key="${escapeHtml(promptKey)}" data-custom-lorebook-keys="${escapeHtml(JSON.stringify(manualSearchTerms))}" data-naa-asset-filter="${escapeHtml(defaultFilter)}" data-naa-metadata-filter="all" data-naa-generated-candidate-filter="all">
                <section class="naa-asset-picker-modal" role="dialog" aria-modal="true" aria-label="${escapeHtml(t('referenceSelection'))}">
                    <header class="naa-asset-picker-head">
                        <strong>${escapeHtml(title)} - ${escapeHtml(t('selectSuffix', { label: targetLabel }))}</strong>
                        <div class="naa-inline compact">
                ${!outfitRow ? `<button class="naa-btn naa-action-control" type="button" data-naa-character-reference-crop disabled>${escapeHtml(t('cropReferenceImage'))}</button>` : ''}
                <button class="naa-btn primary naa-action-control" type="button" data-naa-character-reference-apply>${escapeHtml(t('save'))}</button>
                <button class="naa-btn naa-action-control" type="button" data-naa-asset-picker-close>${escapeHtml(t('cancel'))}</button>
                        </div>
                    </header>
                    <div class="naa-asset-picker-body">
                        <div data-naa-asset-filter-controls>${assetPickerFilterControlsHtml(candidateCount, 0, metadataCount, defaultFilter, manualSearchTerms, {
                            showOutfitGeneratedFilter: true,
                            showChatGeneratedFilter: true,
                        })}</div>
                        <p class="naa-help">${escapeHtml(outfitRow ? t('outfitReferenceHelp') : t('defaultReferenceHelp'))}</p>
                        ${candidateEmpty}
                        <div class="naa-asset-picker-grid" data-naa-asset-picker-grid>${initialGridHtml}</div>
                    </div>
                </section>
            </div>
        `,
        );
        const modal = document.querySelector('[data-naa-asset-picker-modal]');
        modal?.addEventListener('click', async (event) => {
            if (await handleAssetPickerFilterControls(event, modal)) return;
            if (handleAssetPickerZoomClick(event)) return;
            if (
                event.target === modal ||
                event.target?.closest?.('[data-naa-asset-picker-close]')
            ) {
                closeAssetPickerModal();
                return;
            }
            if (!outfitRow && event.target?.closest?.('[data-naa-character-reference-crop]')) {
                const cropAsset = selectedCharacterReferencePickerAsset(modal);
                if (cropAsset?.key) await renderCharacterReferenceCropModal(promptRow, modal, cropAsset);
                syncCharacterReferencePickerCropButton(modal);
                return;
            }
            if (event.target?.closest?.('[data-naa-character-reference-apply]')) {
                const applyButton = event.target.closest('[data-naa-character-reference-apply]');
                if (applyButton) {
                    applyButton.disabled = true;
                    applyButton.textContent = t('saving');
                }
                await applyCharacterReferencePickerSelection(
                    promptRow,
                    modal,
                    outfitRow || promptRow,
                );
                closeAssetPickerModal();
                await renderCharacterPromptTab();
                return;
            }
            const card = event.target?.closest?.('[data-naa-picker-card]');
            if (card && !event.target?.closest?.('button,a,select,textarea')) {
                const input = card.querySelector('[data-naa-character-reference-radio]');
                if (input) {
                    input.checked = true;
                    modal.querySelectorAll('[data-naa-picker-card]').forEach((item) => {
                        item.classList.toggle('selected', item === card);
                    });
                    syncAssetPickerRenderedSelectionState(modal);
                    syncCharacterReferencePickerCropButton(modal);
                }
            }
        });
        modal?.addEventListener('change', (event) => {
            if (!event.target?.matches?.('[data-naa-character-reference-radio]')) return;
            syncAssetPickerRenderedSelectionState(modal);
            syncCharacterReferencePickerCropButton(modal);
            const selectedCard = event.target.closest('[data-naa-picker-card]');
            modal.querySelectorAll('[data-naa-picker-card]').forEach((item) => {
                item.classList.toggle('selected', item === selectedCard);
            });
        });
        if (modal) {
            bindAssetPickerFilterKeyboard(modal);
            scheduleAssetPickerModalHydration(modal, async () => {
                const sourceItems = (await promptRowReferencePickerItems(promptRow)).map(
                    (asset, index) => ({
                        ...asset,
                        index,
                        checked: selectedKey ? asset.key === selectedKey : false,
                    }),
                );
                const prepared = prepareAssetPickerItems(
                    sourceItems,
                    memberKey,
                    baseNeedles,
                    needles,
                    { deferMatching: true },
                );
                const preparedItems = sortAssetPickerItemsForInitialRender(prepared.items, {
                    keepCheckedVisible: true,
                });
                const prime = primeAssetPickerInitialCandidates(
                    preparedItems,
                    baseNeedles,
                    needles,
                );
                applyPreparedAssetPickerItemsToModal(modal, {
                    items: preparedItems,
                    candidateCount: prime.candidateCount,
                    metadataCount: prepared.metadataCount,
                    memberKey,
                    mode: 'reference',
                    customKeys: manualSearchTerms,
                    emptyGridHtml,
                    defaultFilter: prime.defaultFilter,
                    showOutfitGeneratedFilter: true,
                    showChatGeneratedFilter: true,
                    baseNeedles,
                    candidateNeedles: needles,
                });
                syncCharacterReferencePickerCropButton(modal);
                scheduleAssetPickerCandidateClassification(modal, baseNeedles, needles);
            });
        }
    }

    function openCharacterReferencePickerModal(promptRow) {
        if (!promptRow) return;
        void renderCharacterReferencePickerModal(promptRow);
    }

    function openOutfitReferencePickerModal(promptRow, outfitRow) {
        if (!promptRow || !outfitRow) return;
        void renderCharacterReferencePickerModal(promptRow, outfitRow);
    }

    function normalizeArtistExtractionAssetSelection(selection = {}) {
        const asset = normalizeAssetEntry(selection);
        return {
            memberKey: safeString(selection?.memberKey || selection?.member_key).trim(),
            ...asset,
        };
    }

    function artistExtractionAssetForSource(source = null) {
        const sourceId = safeString(source?.id).trim();
        if (!sourceId) return null;
        const promptConfig = getCharacterPromptConfig();
        const saved = normalizeArtistExtractionAssetSelection(
            promptConfig.artistExtractionAssetBySourceId?.[sourceId] || {},
        );
        if (!saved.memberKey || !saved.key) return null;
        const member = (Array.isArray(source?.members) ? source.members : []).find(
            (item) => safeString(item?.key).trim() === saved.memberKey,
        );
        if (!member) return null;
        const asset = uniqueAssetEntries(member.assets).find((item) =>
            assetEntryMatchesAsset(item, saved),
        );
        if (!asset) return null;
        return {
            member,
            asset: {
                ...asset,
                memberKey: saved.memberKey,
            },
        };
    }

    async function ensureArtistExtractionAssetForSource(source = null) {
        const current = artistExtractionAssetForSource(source);
        if (current?.asset?.key) return current;
        const fallback = artistExtractionMetadataPickerItemsForSource(source)[0];
        if (!fallback?.key) return null;
        setArtistExtractionAssetForSource(source, fallback);
        await saveConfig();
        return artistExtractionAssetForSource(source);
    }

    function setArtistExtractionAssetForSource(source = null, selection = null) {
        const sourceId = safeString(source?.id).trim();
        if (!sourceId) return false;
        const normalized = normalizeArtistExtractionAssetSelection(selection || {});
        const promptConfig = getCharacterPromptConfig();
        promptConfig.artistExtractionAssetBySourceId ||= {};
        if (!normalized.memberKey || !normalized.key) {
            delete promptConfig.artistExtractionAssetBySourceId[sourceId];
            return true;
        }
        promptConfig.artistExtractionAssetBySourceId[sourceId] = {
            memberKey: normalized.memberKey,
            name: normalized.name,
            key: normalized.key,
            ext: normalized.ext,
            sourceType: normalized.sourceType,
            moduleId: normalized.moduleId,
            moduleName: normalized.moduleName,
        };
        return true;
    }

    function artistExtractionAssetPreviewHtml(source = null) {
        const selection = artistExtractionAssetForSource(source);
        const asset = selection?.asset || null;
        const previewUrl = asset ? cachedSettingsPreviewBlobUrl(asset) : '';
        const hasAsset = Boolean(asset?.key);
        const label = asset?.name || t('artistExtractionSelectImageShort');
        return `
                <button class="naa-artist-extraction-preview naa-media-frame naa-media-frame--portrait naa-media-frame--contain" type="button" data-naa-artist-extraction-pick data-member-key="${escapeHtml(asset?.memberKey || '')}" data-asset-name="${escapeHtml(asset?.name || '')}" data-asset-key="${escapeHtml(asset?.key || '')}" data-asset-ext="${escapeHtml(asset?.ext || '')}" data-asset-source-type="${escapeHtml(asset?.sourceType || '')}" data-asset-module-id="${escapeHtml(asset?.moduleId || '')}" data-asset-module-name="${escapeHtml(asset?.moduleName || '')}" title="${escapeHtml(t('artistExtractionSelectImage'))}">
                ${hasAsset ? `<img data-naa-artist-extraction-img alt="${escapeHtml(label)}" src="${escapeHtml(previewUrl)}" ${previewUrl ? '' : 'hidden'}>` : `<span class="naa-artist-extraction-empty naa-empty-media-label">${escapeHtml(t('artistExtractionSelectImageShort'))}</span>`}
                <em data-naa-artist-extraction-status ${previewUrl || !hasAsset ? 'hidden' : ''}>${previewUrl || !hasAsset ? '' : t('loading')}</em>
            </button>
        `;
    }

    function artistExtractionAssetActionsHtml() {
        return `
            <div class="naa-artist-extraction-actions">
            <button class="naa-btn primary naa-action-control" id="naa-extract-artist-tags" type="button" data-naa-extract-artist-tags>${escapeHtml(t('artistTagExtraction'))}</button>
            </div>
        `;
    }

    async function loadArtistExtractionAssetThumbnail(root = document) {
        const card = root?.querySelector?.('[data-naa-artist-extraction-pick]');
        if (!card) return;
        const asset = {
            name: safeString(card.getAttribute('data-asset-name')).trim(),
            key: safeString(card.getAttribute('data-asset-key')).trim(),
            ext: safeString(card.getAttribute('data-asset-ext')).trim(),
            sourceType: safeString(card.getAttribute('data-asset-source-type')).trim(),
            moduleId: safeString(card.getAttribute('data-asset-module-id')).trim(),
            moduleName: safeString(card.getAttribute('data-asset-module-name')).trim(),
        };
        if (!asset.key) return;
        const img = card.querySelector('[data-naa-artist-extraction-img]');
        const status = card.querySelector('[data-naa-artist-extraction-status]');
        try {
            const previewUrl = await loadSettingsPreviewBlobUrlCached(asset);
            if (img) {
                if (img.getAttribute('src') !== previewUrl) img.src = previewUrl;
                img.removeAttribute('hidden');
            }
            if (status) {
                status.textContent = '';
                status.setAttribute('hidden', '');
            }
        } catch (error) {
            if (status) {
                status.removeAttribute('hidden');
                status.textContent = t('failed');
            }

        }
    }

    async function syncArtistExtractionPreviewElement(selection = null) {
        const card = document.querySelector('[data-naa-artist-extraction-pick]');
        const asset = selection?.asset || null;
        if (!card || !asset?.key) return;
        card.setAttribute('data-member-key', safeString(asset.memberKey).trim());
        card.setAttribute('data-asset-name', safeString(asset.name).trim());
        card.setAttribute('data-asset-key', safeString(asset.key).trim());
        card.setAttribute('data-asset-ext', safeString(asset.ext).trim());
        card.setAttribute('data-asset-source-type', safeString(asset.sourceType).trim());
        card.setAttribute('data-asset-module-id', safeString(asset.moduleId).trim());
        card.setAttribute('data-asset-module-name', safeString(asset.moduleName).trim());
        card.querySelector('.naa-artist-extraction-empty')?.remove();
        if (!card.querySelector('[data-naa-artist-extraction-img]')) {
            card.insertAdjacentHTML(
                'afterbegin',
                `<img data-naa-artist-extraction-img alt="${escapeHtml(asset.name || t('artistExtractionSelectImageShort'))}" hidden>`,
            );
        }
        await loadArtistExtractionAssetThumbnail(document);
    }

    function artistExtractionMetadataPickerItemsForSource(source = null) {
        const items = [];
        (Array.isArray(source?.members) ? source.members : []).forEach((member) => {
            const memberKey = safeString(member?.key).trim();
            const assets = uniqueAssetEntries(member?.assets);
            const metadataIndex = assetMetadataAvailabilityIndexForMemberAssets(
                getCharacterPromptConfig(),
                memberKey,
                assets,
            );
            assets
                .filter(
                    (asset) =>
                        isGeneratedAssetPickerAsset(asset) ||
                        assetMetadataAvailabilityStateFromIndex(metadataIndex, memberKey, asset) ===
                            'with',
                )
                .forEach((asset) => {
                    items.push({
                        ...asset,
                        memberKey,
                        memberName: safeString(member?.name).trim(),
                        hasMetadata: true,
                        candidate: false,
                        baseCandidate: false,
                    });
                });
        });
        return items.map((asset, index) => ({ ...asset, index }));
    }

    async function collectArtistExtractionMetadataPickerItemsForSource(
        source = null,
        options = {},
    ) {
        const promptConfig = getCharacterPromptConfig();
        const batchSize = Math.max(
            1,
            Number(options.batchSize) || ASSET_PICKER_CARD_BATCH_SIZE,
        );
        const onBatch = typeof options.onBatch === 'function' ? options.onBatch : null;
        const selectedMemberKey = safeString(options.selectedMemberKey).trim();
        const selectedKey = safeString(options.selectedKey).trim();
        const items = [];
        let batch = [];
        let index = 0;
        const flushBatch = async () => {
            if (!batch.length) return;
            if (onBatch) await onBatch(batch, items);
            items.push(...batch);
            batch = [];
            await sleepMs(0);
        };
        for (const member of Array.isArray(source?.members) ? source.members : []) {
            const memberKey = safeString(member?.key).trim();
            const assets = uniqueAssetEntries(member?.assets);
            const metadataIndex = assetMetadataAvailabilityIndexForMemberAssets(
                promptConfig,
                memberKey,
                assets,
            );
            for (const asset of assets) {
                const hasMetadata =
                    isGeneratedAssetPickerAsset(asset) ||
                    assetMetadataAvailabilityStateFromIndex(metadataIndex, memberKey, asset) ===
                        'with';
                if (!hasMetadata) continue;
                const item = {
                    ...asset,
                    memberKey,
                    memberName: safeString(member?.name).trim(),
                    hasMetadata: true,
                    candidate: false,
                    baseCandidate: false,
                    index: index++,
                };
                if (
                    selectedKey &&
                    selectedMemberKey === memberKey &&
                    selectedKey === assetEntryDedupKey(asset)
                ) {
                    item.checked = true;
                }
                batch.push(item);
                if (batch.length >= batchSize) await flushBatch();
            }
            await sleepMs(0);
        }
        await flushBatch();
        return items;
    }

    async function applyArtistExtractionAssetPickerSelection(source = null, modal = null) {
        syncAssetPickerRenderedSelectionState(modal);
        const state = assetPickerStateForModal(modal);
        const selectedInput = modal?.querySelector?.('[data-naa-character-reference-radio]:checked');
        const selectedIndex = Number(selectedInput?.getAttribute?.('data-asset-index'));
        const selectedAsset = state?.items?.find?.((asset) => Number(asset.index) === selectedIndex);
        if (!selectedAsset) return;
        setArtistExtractionAssetForSource(source, selectedAsset);
        await saveConfig();
    }

    async function renderArtistExtractionAssetPickerModal(source = null) {
        closeAssetPickerModal();
        if (!source) return;
        const selected = artistExtractionAssetForSource(source);
        const selectedAsset = selected?.asset || null;
        const selectedMemberKey = safeString(selectedAsset?.memberKey).trim();
        const selectedKey = assetEntryDedupKey(selectedAsset || {});
        const title = source?.name || t('artistsPrompt');
        const emptyGridHtml = `<div class="naa-empty wide">${escapeHtml(t('artistTagExtractionNoMetadata'))}</div>`;
        document.body.insertAdjacentHTML(
            'beforeend',
            `
            <div class="naa-asset-picker-backdrop" data-naa-asset-picker-modal data-naa-asset-filter="all" data-naa-metadata-filter="all" data-naa-include-generated-in-all="false">
                <section class="naa-asset-picker-modal" role="dialog" aria-modal="true" aria-label="${escapeHtml(t('artistExtractionImage'))}">
                    <header class="naa-asset-picker-head">
                        <strong>${escapeHtml(title)} - ${escapeHtml(t('artistExtractionImage'))}</strong>
                        <div class="naa-inline compact">
                <button class="naa-btn primary naa-action-control" type="button" data-naa-artist-extraction-apply>${escapeHtml(t('save'))}</button>
                <button class="naa-btn naa-action-control" type="button" data-naa-asset-picker-close>${escapeHtml(t('cancel'))}</button>
                        </div>
                    </header>
                    <div class="naa-asset-picker-body">
                        <p class="naa-help">${escapeHtml(t('artistExtractionSelectImage'))}</p>
                        ${artistExtractionFilterTabsHtml(0, 0, 'all')}
                        <div class="naa-asset-picker-grid" data-naa-asset-picker-grid>${assetPickerLoadingHtml()}</div>
                    </div>
                </section>
            </div>
        `,
        );
        const modal = document.querySelector('[data-naa-asset-picker-modal]');
        modal?.addEventListener('click', async (event) => {
            if (handleAssetPickerZoomClick(event)) return;
            if (
                event.target === modal ||
                event.target?.closest?.('[data-naa-asset-picker-close]')
            ) {
                closeAssetPickerModal();
                return;
            }
            const filterTab = event.target?.closest?.('[data-naa-asset-filter-tab]');
            if (filterTab) {
                event.preventDefault();
                const filter = filterTab.getAttribute('data-naa-asset-filter-tab') || 'all';
                setAssetPickerFilterTab(modal, filter);
                renderAssetPickerNextBatch(modal, { reset: true });
                return;
            }
            if (event.target?.closest?.('[data-naa-artist-extraction-apply]')) {
                const applyButton = event.target.closest('[data-naa-artist-extraction-apply]');
                if (applyButton) {
                    applyButton.disabled = true;
                    applyButton.textContent = t('saving');
                }
                await applyArtistExtractionAssetPickerSelection(source, modal);
                closeAssetPickerModal();
                await renderCharacterPromptTab();
                return;
            }
            const card = event.target?.closest?.('[data-naa-picker-card]');
            if (card && !event.target?.closest?.('button,a,select,textarea')) {
                const input = card.querySelector('[data-naa-character-reference-radio]');
                if (input) {
                    input.checked = true;
                    modal.querySelectorAll('[data-naa-picker-card]').forEach((item) => {
                        item.classList.toggle('selected', item === card);
                    });
                    syncAssetPickerRenderedSelectionState(modal);
                }
            }
        });
        modal?.addEventListener('change', (event) => {
            if (!event.target?.matches?.('[data-naa-character-reference-radio]')) return;
            syncAssetPickerRenderedSelectionState(modal);
            const selectedCard = event.target.closest('[data-naa-picker-card]');
            modal.querySelectorAll('[data-naa-picker-card]').forEach((item) => {
                item.classList.toggle('selected', item === selectedCard);
            });
        });
        if (modal) {
            initializeAssetPickerLazyGrid(modal, [], '', 'reference', {
                emptyHtml: emptyGridHtml,
                deferEmpty: true,
            });
            scheduleAssetPickerModalHydration(modal, async () => {
                await collectArtistExtractionMetadataPickerItemsForSource(source, {
                    selectedMemberKey,
                    selectedKey,
                    onBatch: async (batch) => {
                        appendAssetPickerLazyItems(modal, batch, {
                            updateArtistCounts: true,
                        });
                    },
                });
                const state = assetPickerStateForModal(modal);
                if (!state) return;
                state.deferEmpty = false;
                updateArtistExtractionFilterCountsUi(modal);
                if (!state.items.length) renderAssetPickerNextBatch(modal, { reset: true });
            });
        }
    }

    function openArtistExtractionAssetPickerModal(source = null) {
        void renderArtistExtractionAssetPickerModal(source);
    }

    function renderAssetPickerModal(row) {
        closeAssetPickerModal();
        const memberKey = safeString(row?.getAttribute?.('data-member-key')).trim();
        const promptKey = promptKeyForAssetRow(row);
        const baseNeedles = loreKeyNeedlesFromAssetRow(row, { includeCustom: false });
        const manualSearchTerms = manualAssetSearchTermsForPromptKey(promptKey);
        const needles = loreKeyNeedlesFromAssetRow(row);
        const candidateCount = 0;
        const metadataCount = 0;
        const defaultFilter = 'all';
        const title = row.querySelector('.naa-asset-card-name strong')?.textContent || t('assets');
        const candidateEmpty =
            '<div class="naa-empty wide" data-naa-candidate-empty hidden></div>';
        const emptyGridHtml = `<div class="naa-empty wide">${escapeHtml(t('noImageAssets'))}</div>`;
        const initialGridHtml = assetPickerLoadingHtml();
        document.body.insertAdjacentHTML(
            'beforeend',
            `
            <div class="naa-asset-picker-backdrop" data-naa-asset-picker-modal data-member-key="${escapeHtml(memberKey)}" data-prompt-key="${escapeHtml(promptKey)}" data-custom-lorebook-keys="${escapeHtml(JSON.stringify(manualSearchTerms))}" data-naa-asset-filter="${escapeHtml(defaultFilter)}" data-naa-metadata-filter="all" data-naa-generated-candidate-filter="all">
                <section class="naa-asset-picker-modal" role="dialog" aria-modal="true">
                    <header class="naa-asset-picker-head">
                        <strong>${escapeHtml(title)} - ${escapeHtml(t('assetSelection'))}</strong>
                        <div class="naa-inline compact">
                <button class="naa-btn primary naa-action-control" type="button" data-naa-asset-picker-apply>${escapeHtml(t('save'))}</button>
                <button class="naa-btn naa-action-control" type="button" data-naa-asset-picker-close>${escapeHtml(t('cancel'))}</button>
                        </div>
                    </header>
                    <div class="naa-asset-picker-body">
                        <div data-naa-asset-filter-controls>${assetPickerFilterControlsHtml(candidateCount, 0, metadataCount, defaultFilter, manualSearchTerms, {
                            showOutfitGeneratedFilter: true,
                            showChatGeneratedFilter: true,
                        })}</div>
                        <p class="naa-help">${escapeHtml(t('assetPickerHelp'))}</p>
                        ${candidateEmpty}
                        <div class="naa-asset-picker-grid" data-naa-asset-picker-grid>${initialGridHtml}</div>
                    </div>
                </section>
            </div>
        `,
        );
        const modal = document.querySelector('[data-naa-asset-picker-modal]');
        modal?.addEventListener('click', async (event) => {
            if (await handleAssetPickerFilterControls(event, modal)) return;
            if (handleAssetPickerZoomClick(event)) return;
            if (
                event.target === modal ||
                event.target?.closest?.('[data-naa-asset-picker-close]')
            ) {
                closeAssetPickerModal();
                return;
            }
            if (event.target?.closest?.('[data-naa-asset-picker-apply]')) {
                const applyButton = event.target.closest('[data-naa-asset-picker-apply]');
                if (applyButton) {
                    applyButton.disabled = true;
                    applyButton.textContent = t('saving');
                }
                await applyAssetPickerSelection(row, modal);
                closeAssetPickerModal();
                await renderCharacterPromptTab();
                return;
            }
            const card = event.target?.closest?.('[data-naa-picker-card]');
            if (card && !event.target?.closest?.('button,input,label,a,select,textarea')) {
                const input = card.querySelector('[data-naa-picker-check]');
                if (input) {
                    input.checked = !input.checked;
                    syncAssetPickerRenderedSelectionState(modal);
                }
            }
        });
        modal?.addEventListener('change', (event) => {
            if (!event.target?.matches?.('[data-naa-picker-check]')) return;
            syncAssetPickerRenderedSelectionState(modal);
        });
        if (modal) {
            bindAssetPickerFilterKeyboard(modal);
            scheduleAssetPickerModalHydration(modal, async () => {
                const prepared = prepareAssetPickerItems(
                    assetPickerItemsFromRow(row),
                    memberKey,
                    baseNeedles,
                    needles,
                    { deferMatching: true },
                );
                const prime = primeAssetPickerInitialCandidates(
                    prepared.items,
                    baseNeedles,
                    needles,
                );
                applyPreparedAssetPickerItemsToModal(modal, {
                    items: prepared.items,
                    candidateCount: prime.candidateCount,
                    metadataCount: prepared.metadataCount,
                    memberKey,
                    mode: 'asset',
                    customKeys: manualSearchTerms,
                    emptyGridHtml,
                    defaultFilter: prime.defaultFilter,
                    showOutfitGeneratedFilter: true,
                    showChatGeneratedFilter: true,
                    baseNeedles,
                    candidateNeedles: needles,
                });
                scheduleAssetPickerCandidateClassification(modal, baseNeedles, needles);
            });
        }
    }

    function openAssetPickerModal(row) {
        if (!row) return;
        renderAssetPickerModal(row);
    }

    async function openLorebookAssetPickerFromSelection(memberKey = '', lorebookId = '') {
        const normalizedMemberKey = safeString(memberKey).trim();
        const normalizedLorebookId = safeString(lorebookId).trim();
        if (!normalizedMemberKey || !normalizedLorebookId) return;
        const promptConfig = getCharacterPromptConfig();
        promptConfig.selectedLorebooks ||= {};
        const selected = new Set(selectedLorebookIdsForMember(promptConfig, normalizedMemberKey));
        selected.add(normalizedLorebookId);
        promptConfig.selectedLorebooks[normalizedMemberKey] = Array.from(selected);
        promptConfig.activeSubtab = 'assets';
        persistSettingsUiState({
            activeSettingsTab: 'character-prompts',
            activeSubtab: 'assets',
            selectedSourceId: promptConfig.selectedSourceId,
        });
        await saveConfig();
        await renderCharacterPromptTab({ forceSources: false });
        const row = Array.from(document.querySelectorAll('[data-naa-asset-row]')).find(
            (item) =>
                item.getAttribute('data-member-key') === normalizedMemberKey &&
                item.getAttribute('data-lorebook-id') === normalizedLorebookId,
        );
        if (!row) {

            return;
        }
        openAssetPickerModal(row);
    }

    function removeLorebookSelectionForRow(row, promptConfig = getCharacterPromptConfig()) {
        const memberKey = safeString(row?.getAttribute?.('data-member-key')).trim();
        const lorebookId = safeString(row?.getAttribute?.('data-lorebook-id')).trim();
        if (!memberKey || !lorebookId) return false;
        promptConfig.selectedLorebooks ||= {};
        const selected = new Set(selectedLorebookIdsForMember(promptConfig, memberKey));
        if (!selected.has(lorebookId)) return false;
        selected.delete(lorebookId);
        if (selected.size) promptConfig.selectedLorebooks[memberKey] = Array.from(selected);
        else delete promptConfig.selectedLorebooks[memberKey];
        return true;
    }

    async function disableLorebookSelectionRow(row) {
        if (!row) return false;
        collectCharacterIdentityPromptsFromForm();
        const promptConfig = getCharacterPromptConfig();
        const removed = removeLorebookSelectionForRow(row, promptConfig);
        if (!removed) return false;
        await saveConfig();
        await renderCharacterPromptTab({ forceSources: false });
        return true;
    }

    function assetMetadataRowStatusText(aiAnalysis) {
        if (!aiAnalysis || typeof aiAnalysis !== 'object') return t('assetMetadataStatusUnknown');
        if (aiAnalysis.status === 'error') return t('assetMetadataStatusFailed');
        if (aiAnalysis.status === 'done') {
            return [
                t('assetMetadataStatusComplete'),
                aiAnalysis.outfitCount
                    ? t('assetMetadataStatusOutfits', { count: aiAnalysis.outfitCount })
                    : '',
            ]
                .filter(Boolean)
                .join('\n');
        }
        return t('assetMetadataStatusUnknown');
    }

    function assetMetadataRowStatusHtml(aiAnalysis, options = {}) {
        return escapeHtml(assetMetadataRowStatusText(aiAnalysis)).replace(/\n/g, '<br>');
    }

    function characterAssetMetadataHtml(source) {
        const promptConfig = getCharacterPromptConfig();
        const entries = selectedLorebookEntries(source);
        if (!source) return `<div class="naa-empty">${escapeHtml(t('selectCharacterChat'))}</div>`;
        if (!entries.length)
            return `<div class="naa-empty">${escapeHtml(t('selectLorebooksFirst'))}</div>`;
        return entries
            .map(({ member, lore, key }) => {
                const saved = assetMetadataForPromptKey(promptConfig, key);
                const selectedKeys = new Set(saved.selectedAssets.map((asset) => asset.key));
                const selectedNames = selectedKeys.size
                    ? new Set()
                    : new Set(saved.selectedAssetNames);
                const assets = uniqueAssetEntries(member.assets);
                const selectedCardAssets = uniqueAssetEntries(
                    assets.filter(
                        (asset) => selectedKeys.has(asset.key) || selectedNames.has(asset.name),
                    ),
                );
                return `
                    <div class="naa-character-row naa-asset-metadata-row naa-surface-card" data-naa-asset-row data-member-key="${escapeHtml(member.key)}" data-member-name="${escapeHtml(member.name)}" data-lorebook-id="${escapeHtml(lore.id)}" data-lorebook-title="${escapeHtml(lore.title || '')}" data-lorebook-keys="${escapeHtml(JSON.stringify(lore.keys || []))}">
                        <div class="naa-asset-card-side">
                            <div class="naa-asset-card-name" title="${escapeHtml(lore.title)}">
                                <button class="naa-row-disable-x naa-action-control naa-action-control--icon" type="button" data-naa-disable-lorebook-row title="${escapeHtml(t('disableLorebook'))}" aria-label="${escapeHtml(t('disableLorebook'))}">-</button>
                                <strong>${escapeHtml(lore.title)}</strong>
                            </div>
                            <label class="naa-asset-control-row naa-asset-control-with-status" data-naa-asset-row-toggle>
                                <span class="naa-asset-control-main">
                                    <input type="checkbox" data-naa-analyze-enabled ${saved.analyzeEnabled ? 'checked' : ''}>
                                    <span>${escapeHtml(t('analysis'))}</span>
                                </span>
                                <span class="naa-asset-row-status" data-naa-asset-row-status>${assetMetadataRowStatusHtml(saved.aiAnalysis)}</span>
                            </label>
                            <button class="naa-asset-control-row naa-asset-control-button" type="button" data-naa-load-assets="${escapeHtml(key)}">${escapeHtml(t('loadAssets'))}</button>
                        </div>
                        <div class="naa-asset-card-selected" data-naa-selected-assets>
                            ${selectedAssetStripHtml(selectedCardAssets, member.key)}
                        </div>
                    </div>
                `;
            })
            .join('');
    }

    function artistPromptOriginLabel(artist, isUserArtist, source = null) {
        if (safeString(artist?.id).trim() === ARTIST_NONE_PRESET_ID) return '';
        if (!isUserArtist) return 'Default preset';
        return (
            safeString(artist?.sourceName).trim() ||
            safeString(artist?.sourceCharacterName).trim() ||
            characterNameForPromptKey(artist?.sourcePromptKey, source) ||
            ''
        );
    }

    function artistPromptDisplayTitle(artist, isUserArtist, source = null) {
        const id = safeString(artist?.label || artist?.title || artist?.id).trim();
        const origin = artistPromptOriginLabel(artist, isUserArtist, source);
        return origin ? [id, origin].filter(Boolean).join(' - ') : id;
    }

    function artistPromptListHtml(source = null) {
        const baseArtists = normalizePresetList(DEFAULT_ARTIST_PRESETS);
        const artists = mergeArtistPresets(baseArtists);
        const selectedId = selectedArtistIdForSource(artists, source);
        if (!artists.length)
            return `<div class="naa-empty">${escapeHtml(t('noArtistPrompts'))}</div>`;
        return artists
            .map((artist) => {
                const isUserArtist = getUserArtistPresets().some((item) => item.id === artist.id);
                const displayTitle = artistPromptDisplayTitle(artist, isUserArtist, source);
                return `
                    <div class="naa-artist-row" data-naa-artist-row data-artist-id="${escapeHtml(artist.id)}">
                        <label class="naa-lorebook-check">
                            <input type="radio" name="naa-selected-artist" data-naa-artist-radio value="${escapeHtml(artist.id)}" ${artist.id === selectedId ? 'checked' : ''}>
                            <span>
                                <strong>${escapeHtml(displayTitle)}</strong>
                                <em>${escapeHtml(artist.prompt || `(${t('emptyPrompt')})`)}</em>
                            </span>
                        </label>
                        ${
                            isUserArtist
                                ? `<div class="naa-inline compact naa-artist-icon-actions">
                    <button class="naa-btn naa-action-control naa-action-control--icon naa-artist-icon-btn" type="button" data-naa-edit-artist="${escapeHtml(artist.id)}" title="${escapeHtml(t('edit'))}" aria-label="${escapeHtml(t('edit'))}">✎</button>
                    <button class="naa-btn naa-action-control naa-action-control--icon naa-artist-icon-btn" type="button" data-naa-remove-artist="${escapeHtml(artist.id)}" title="${escapeHtml(t('remove'))}" aria-label="${escapeHtml(t('remove'))}">×</button>
                                </div>`
                                : ''
                        }
                    </div>
                `;
            })
            .join('');
    }

