    async function generateTagTesterNovelAIImage(payload = {}) {
        const endpoint = safeString(payload.endpoint || DEFAULT_CONFIG.novelai.endpoint).trim();
        const apiKey = safeString(payload.apiKey).trim();
        const body = payload.body && typeof payload.body === 'object' ? payload.body : null;
        if (!apiKey) throw new Error('NovelAI API key is empty.');
        if (!body) throw new Error('NovelAI request body is empty.');
        abortTagTesterNovelAIImage('Previous Tag Tester NovelAI request was replaced.');
        const requestId = ++tagTesterNovelAIRequestId;
        const requestController =
            typeof AbortController === 'function' ? new AbortController() : null;
        tagTesterNovelAIAbortController = requestController;
        try {
            const selectedPromptPayload = applySelectedTagTesterPromptToNovelAIBody(body);
            const selectedReferenceAssets = selectedTagTesterReferenceAssetsFromDom();
            const referenceAssets =
                selectedReferenceAssets === null
                    ? tagTesterCharacterReferencesFromContext()
                    : selectedReferenceAssets;
            const directorReferences = await buildNovelAICharacterReferencePayload(
                referenceAssets,
                body.model,
                config.novelai || {},
            );
            if (directorReferences.length) {
                body.parameters ||= {};
                applyCharacterReferencesToNovelAIParameters(body.parameters, directorReferences);
            }

            const response = await enqueueNovelAIRequest(
                async () => {
                    let response = null;
                    let lastError = null;
                    for (let attempt = 1; attempt <= TAG_TESTER_NOVELAI_MAX_ATTEMPTS; attempt++) {
                        try {
                            response = await fetchWithTimeout(
                                endpoint,
                                {
                                    method: 'POST',
                                    headers: {
                                        'Content-Type': 'application/json',
                                        Authorization: `Bearer ${apiKey}`,
                                    },
                                    body: JSON.stringify(body),
                                    ...(requestController
                                        ? { signal: requestController.signal }
                                        : {}),
                                },
                                TAG_TESTER_NOVELAI_TIMEOUT_MS,
                                'Tag Tester NovelAI image',
                            );
                            if (response.ok) break;
                            const responseText = (await readResponseError(response)).slice(0, 1000);
                            const error = new Error(
                                `NovelAI HTTP ${response.status}: ${responseText.slice(0, 500)}`,
                            );
                            error.status = response.status;
                            error.responseText = responseText;
                            throw error;
                        } catch (error) {
                            if (error?.name === 'AbortError' || error?.code === 'REQUEST_ABORTED') {
                                throw error;
                            }
                            lastError = error;
                            const retryable = isTagTesterRetryableNovelAIError(error);

                            if (!retryable || attempt >= TAG_TESTER_NOVELAI_MAX_ATTEMPTS)
                                throw error;
                            await sleepMs(4500 * attempt);
                        }
                    }
                    if (!response?.ok)
                        throw lastError || new Error('Tag Tester NovelAI generation failed.');
                    return response;
                },
                {
                    source: 'tag-tester',
                    model: safeString(body.model).trim(),
                    width: body.parameters?.width,
                    height: body.parameters?.height,
                    index: 1,
                    total: 1,
                },
            );
            if (requestId !== tagTesterNovelAIRequestId || requestController?.signal?.aborted) {
                throw requestAbortError(
                    'Tag Tester NovelAI image request was replaced before the response was rendered.',
                    'Tag Tester NovelAI image request was cancelled.',
                    'Tag Tester NovelAI image',
                );
            }
            const contentType = response.headers?.get?.('content-type') || '';
            const buffer = await response.arrayBuffer();
            const bufferBytes = new Uint8Array(buffer);

            const directImageBytes = bufferBytes;
            let imageResult = null;
            try {
                imageResult = contentType.includes('image/')
                    ? {
                          bytes: directImageBytes,
                          mimeType:
                              safeString(contentType.split(';')[0]).trim() ||
                              imageMimeFromBytes(directImageBytes),
                      }
                    : await extractImageBytesFromZip(buffer);
            } catch (error) {

                throw error;
            }
            const imageBytes =
                imageResult?.bytes instanceof Uint8Array
                    ? imageResult.bytes
                    : new Uint8Array(imageResult?.bytes || []);
            const mimeType = imageResult?.mimeType || imageMimeFromBytes(imageBytes);
            const bridgeReturnBytes = new Uint8Array(imageBytes);
            const bridgeImageBlob = createTagTesterBridgeImageBlob(bridgeReturnBytes, mimeType);
            if (requestId !== tagTesterNovelAIRequestId || requestController?.signal?.aborted) {
                throw requestAbortError(
                    'Tag Tester NovelAI image request was replaced after the response was decoded.',
                    'Tag Tester NovelAI image request was cancelled.',
                    'Tag Tester NovelAI image',
                );
            }
            if (!imageBytes.length)
                throw new Error('NovelAI response did not include a readable image.');

            return {
                ...(bridgeImageBlob
                    ? {
                          blobUrl: bridgeImageBlob.blobUrl,
                          blob: bridgeImageBlob.blob,
                      }
                    : {
                          bytes: Array.from(bridgeReturnBytes),
                      }),
                mimeType,
                contentType,
                requestId,
            };
        } finally {
            if (tagTesterNovelAIAbortController === requestController) {
                tagTesterNovelAIAbortController = null;
            }
        }
    }

    function tagTesterHtmlParts(html = '') {
        const parser = new DOMParser();
        const doc = parser.parseFromString(String(html || ''), 'text/html');
        const styles = Array.from(doc.querySelectorAll('style')).map(
            (style) => style.textContent || '',
        );
        const scripts = Array.from(doc.querySelectorAll('script')).map(
            (script) => script.textContent || '',
        );
        doc.querySelectorAll('script').forEach((script) => script.remove());
        return {
            styles,
            scripts,
            bodyHtml: doc.body?.innerHTML || '',
        };
    }

    function executeTagTesterScripts(scripts = []) {
        scripts.forEach((script, index) => {
            const source = safeString(script);
            if (!source.trim()) return;
            const runner = new Function(`${source}\n//# sourceURL=naa-tag-tester-${index}.js`);
            runner.call(globalThis);
        });
    }

    function unbindTagTesterFullscreenEvents() {
        if (tagTesterKeydownHandler) {
            document.removeEventListener('keydown', tagTesterKeydownHandler, true);
            tagTesterKeydownHandler = null;
        }
        if (tagTesterMessageHandler) {
            window.removeEventListener('message', tagTesterMessageHandler);
            tagTesterMessageHandler = null;
        }
        if (tagTesterPromptSyncEventsBound) {
            document.removeEventListener('click', queueTagTesterPromptSync, true);
            document.removeEventListener('change', queueTagTesterPromptSync, true);
            document.removeEventListener('input', queueTagTesterPromptSync, true);
            tagTesterPromptSyncEventsBound = false;
        }
    }

    function teardownTagTesterFullscreen() {
        abortTagTesterNovelAIImage('Tag Tester screen closed.');
        unbindTagTesterFullscreenEvents();
        try {
            delete globalThis.NAA_TAG_TESTER_GENERATE_IMAGE;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_GENERATE_IMAGE = undefined;
        }
        try {
            delete globalThis.NAA_TAG_TESTER_OPEN_OUTPUT_FOLDER;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_OPEN_OUTPUT_FOLDER = undefined;
        }
        try {
            delete globalThis.NAA_TAG_TESTER_GET_OUTPUT_FOLDER;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_GET_OUTPUT_FOLDER = undefined;
        }
        try {
            delete globalThis.NAA_TAG_TESTER_SAVE_OUTPUT_FOLDER;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_SAVE_OUTPUT_FOLDER = undefined;
        }
        try {
            delete globalThis.NAA_TAG_TESTER_SAVE_IMAGE;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_SAVE_IMAGE = undefined;
        }
        try {
            delete globalThis.NAA_TAG_TESTER_EXPORT_CONTEXT;
        } catch (_) {
            globalThis.NAA_TAG_TESTER_EXPORT_CONTEXT = undefined;
        }
    }

    function exitTagTesterFullscreen() {
        const fallbackTab = normalizeSettingsTabForRender(lastNonTagTesterSettingsTab, 'setting');
        activeSettingsTab = fallbackTab === 'tag-tester' ? 'setting' : fallbackTab;
        persistSettingsUiState({ activeSettingsTab });
        teardownTagTesterFullscreen();
        renderSettings();
    }

    function bindTagTesterFullscreenEvents() {
        unbindTagTesterFullscreenEvents();
        tagTesterKeydownHandler = (event) => {
            if (event.key !== 'Escape') return;
            event.preventDefault?.();
            exitTagTesterFullscreen();
        };
        tagTesterMessageHandler = (event) => {
            if (event?.data?.type === 'naa-tag-tester-exit') exitTagTesterFullscreen();
        };
        document.addEventListener('keydown', tagTesterKeydownHandler, true);
        window.addEventListener('message', tagTesterMessageHandler);
    }

